def load_conversation_memory_policy() -> tuple[dict[str, Any], str]:
    path = conversation_memory_policy_path()
    try:
        raw_text = path.read_text(encoding="utf-8")
    except OSError as exc:
        raise RuntimeError(
            f"failed to read conversation memory policy artifact: {path.as_posix()} ({exc})"
        ) from exc
    try:
        payload = json.loads(raw_text)
    except json.JSONDecodeError as exc:
        raise RuntimeError(
            f"malformed conversation memory policy artifact: {path.as_posix()} ({exc})"
        ) from exc
    if not isinstance(payload, dict):
        raise RuntimeError(
            "malformed conversation memory policy artifact: "
            f"{path.as_posix()} must contain a JSON object"
        )
    required_sections = (
        "repository_layout",
        "layer_boundary",
        "source_contract",
        "note_contract",
        "index_contract",
        "map_contract",
        "promotion_pressure_contract",
        "viewer_contract",
    )
    missing = [section for section in required_sections if section not in payload]
    if missing:
        raise RuntimeError(
            "malformed conversation memory policy artifact: missing top-level section(s): "
            + ", ".join(missing)
        )
    required_fields = {
        "repository_layout": (
            "index_artifact",
            "map_artifact",
            "promotion_pressure_artifact",
            "source_dir",
            "note_dir",
        ),
        "map_contract": ("artifact_kind", "schema_version", "named_filters"),
        "promotion_pressure_contract": (
            "artifact_kind",
            "schema_version",
            "target_kinds",
            "pressure_statuses",
            "named_filters",
        ),
    }
    missing_fields: list[str] = []
    for section, fields in required_fields.items():
        section_payload = payload.get(section)
        if not isinstance(section_payload, dict):
            missing_fields.append(section)
            continue
        missing_fields.extend(
            f"{section}.{field}" for field in fields if field not in section_payload
        )
    if missing_fields:
        raise RuntimeError(
            "malformed conversation memory policy artifact: missing required field(s): "
            + ", ".join(missing_fields)
        )
    list_fields = {
        "map_contract": ("named_filters",),
        "promotion_pressure_contract": ("target_kinds", "pressure_statuses", "named_filters"),
    }
    invalid_list_fields: list[str] = []
    for section, fields in list_fields.items():
        section_payload = payload.get(section)
        if not isinstance(section_payload, dict):
            continue
        for field in fields:
            raw_value = section_payload.get(field)
            if not isinstance(raw_value, list) or not any(str(item).strip() for item in raw_value):
                invalid_list_fields.append(f"{section}.{field}")
                continue
            if any(not isinstance(item, str) or not item.strip() for item in raw_value):
                invalid_list_fields.append(f"{section}.{field}")
    if invalid_list_fields:
        raise RuntimeError(
            "malformed conversation memory policy artifact: invalid list field(s): "
            + ", ".join(invalid_list_fields)
        )
    return payload, hashlib.sha256(raw_text.encode("utf-8")).hexdigest()


CONVERSATION_MEMORY_POLICY, CONVERSATION_MEMORY_POLICY_SHA256 = load_conversation_memory_policy()


