PROJECT_ENVIRONMENT_ARTIFACT_KIND = "project_environment"
PROJECT_ENVIRONMENT_SCHEMA_VERSION = 1


def project_environment_path() -> Path:
    return RUNS_DIR / "project_environment.json"


def project_environment_profile_by_id(
    policy: dict[str, Any],
) -> dict[str, dict[str, Any]]:
    profiles: dict[str, dict[str, Any]] = {}
    for entry in policy.get("governance_profiles", []):
        if not isinstance(entry, dict):
            continue
        profile_id = str(entry.get("profile_id", "")).strip()
        if profile_id:
            profiles[profile_id] = copy.deepcopy(entry)
    return profiles


def project_environment_policy_reference_for(
    policy: dict[str, Any] | None,
) -> dict[str, Any]:
    if policy is None:
        return project_environment_policy_reference()
    policy_text = json.dumps(policy, sort_keys=True, separators=(",", ":"))
    return {
        "artifact_path": "<injected-project-environment-policy>",
        "artifact_sha256": hashlib.sha256(policy_text.encode("utf-8")).hexdigest(),
        "version": policy.get("version"),
    }


def safe_project_environment_path_text(
    value: Any,
    *,
    path_safety: dict[str, Any] | None = None,
) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    safety = path_safety if isinstance(path_safety, dict) else {}
    if (
        (bool(safety.get("reject_absolute_paths", True)) and text.startswith("/"))
        or (bool(safety.get("reject_home_expansion", True)) and text.startswith("~"))
        or "\\" in text
        or (bool(safety.get("reject_windows_drive_or_uri_colon", True)) and ":" in text)
        or (bool(safety.get("reject_parent_traversal", True)) and ".." in PurePosixPath(text).parts)
    ):
        return ""
    return text


def load_project_config(config_path: Path | None = None) -> tuple[dict[str, Any], str, str]:
    path = config_path or project_config_path()
    try:
        raw_text = path.read_text(encoding="utf-8")
    except FileNotFoundError:
        return {}, "", "missing"
    except OSError as exc:
        raise RuntimeError(
            f"unreadable project config artifact: {path.as_posix()} ({exc})"
        ) from exc
    try:
        payload = get_yaml_module().safe_load(raw_text) or {}
    except Exception as exc:
        raise RuntimeError(f"malformed project config artifact: {path.as_posix()} ({exc})") from exc
    if not isinstance(payload, dict):
        raise RuntimeError(
            f"malformed project config artifact: {path.as_posix()} must contain a mapping"
        )
    return payload, hashlib.sha256(raw_text.encode("utf-8")).hexdigest(), "available"


def project_environment_fail_closed_profile(requested_profile_id: str) -> dict[str, Any]:
    return {
        "profile_id": "unknown_profile_fail_closed",
        "label": "Unknown profile (locked)",
        "requested_profile_id": requested_profile_id,
        "core_locked": True,
        "self_evolution_enabled": False,
        "project_graph_writable": False,
        "ordinary_core_mutation_policy": "locked",
        "upstream_export_required": True,
        "allowed_supervisor_focus": [],
        "forbidden_mutation_roots": [
            "tools/",
            "tests/",
            ".github/",
            "AGENTS.md",
            "CONSTITUTION.md",
        ],
        "enforcement_contract": {
            "allowed_mutation_roots": [],
            "forbidden_mutation_roots": [
                "tools/",
                "tests/",
                ".github/",
                "AGENTS.md",
                "CONSTITUTION.md",
            ],
            "allowed_target_domains": [],
            "forbidden_target_domains": [
                "specgraph_core",
                "project_graph",
                "runtime_tooling",
                "policy_feedback",
                "self_evolution",
            ],
            "self_evolution": "disabled",
            "review_feedback_routing": "blocked_until_profile_repaired",
            "default_next_move_behavior": "block_all_profile_sensitive_moves",
            "blocked_move_status": "blocked_by_unknown_governance_profile",
            "upstream_export_mode": "disabled_until_profile_repaired",
        },
    }


def project_environment_bool_value(
    value: Any,
    *,
    default: bool,
    field_path: str,
    validation_findings: list[dict[str, Any]],
) -> bool:
    if value is None:
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        normalized = value.strip().lower()
        if normalized == "true":
            return True
        if normalized == "false":
            return False
    validation_findings.append(
        {
            "finding_id": "invalid_boolean_value",
            "severity": "error",
            "field": field_path,
            "message": f"{field_path} must be a boolean value",
            "next_gap": "repair_project_config",
        }
    )
    return default


def project_environment_string_list(value: Any) -> list[str]:
    if not isinstance(value, list):
        return []
    return [str(item).strip() for item in value if str(item).strip()]


def project_environment_enforcement_contract(profile: dict[str, Any]) -> dict[str, Any]:
    raw_contract = profile.get("enforcement_contract", {})
    contract = raw_contract if isinstance(raw_contract, dict) else {}
    allowed_mutation_roots = project_environment_string_list(contract.get("allowed_mutation_roots"))
    if "forbidden_mutation_roots" in contract:
        forbidden_mutation_roots = project_environment_string_list(
            contract.get("forbidden_mutation_roots")
        )
    else:
        forbidden_mutation_roots = project_environment_string_list(
            profile.get("forbidden_mutation_roots")
        )
    if "allowed_target_domains" in contract:
        allowed_target_domains = project_environment_string_list(
            contract.get("allowed_target_domains")
        )
    else:
        allowed_target_domains = project_environment_string_list(
            profile.get("allowed_supervisor_focus")
        )

    return {
        "allowed_mutation_roots": allowed_mutation_roots,
        "forbidden_mutation_roots": forbidden_mutation_roots,
        "allowed_target_domains": allowed_target_domains,
        "forbidden_target_domains": project_environment_string_list(
            contract.get("forbidden_target_domains")
        ),
        "self_evolution": str(
            contract.get(
                "self_evolution",
                "enabled" if bool(profile.get("self_evolution_enabled", False)) else "disabled",
            )
        ).strip()
        or "disabled",
        "review_feedback_routing": str(
            contract.get("review_feedback_routing", "unspecified")
        ).strip()
        or "unspecified",
        "default_next_move_behavior": str(
            contract.get("default_next_move_behavior", "allow_profile_eligible_moves")
        ).strip()
        or "allow_profile_eligible_moves",
        "blocked_move_status": str(
            contract.get("blocked_move_status", "blocked_by_governance_profile")
        ).strip()
        or "blocked_by_governance_profile",
        "upstream_export_mode": str(contract.get("upstream_export_mode", "unspecified")).strip()
        or "unspecified",
    }


def build_project_environment(
    policy: dict[str, Any] | None = None,
    config_path: Path | None = None,
) -> dict[str, Any]:
    injected_policy = copy.deepcopy(policy) if isinstance(policy, dict) else None
    source_policy = copy.deepcopy(injected_policy or PROJECT_ENVIRONMENT_POLICY)
    try:
        config, config_sha256, config_status = load_project_config(config_path)
    except RuntimeError as exc:
        config = {}
        config_sha256 = ""
        config_status = "invalid"
        config_error = str(exc)
    else:
        config_error = ""

    profiles = project_environment_profile_by_id(source_policy)
    default_profile_id = str(
        source_policy.get("default_profile_id", "self_hosted_bootstrap")
    ).strip()
    requested_profile_id = str(config.get("governance_profile", default_profile_id)).strip()
    if not requested_profile_id:
        requested_profile_id = default_profile_id
    active_profile = copy.deepcopy(profiles.get(requested_profile_id, {}))
    profile_known = bool(active_profile)
    if not profile_known:
        active_profile = project_environment_fail_closed_profile(requested_profile_id)
    effective_profile_id = str(active_profile.get("profile_id", requested_profile_id)).strip()

    workspace = config.get("workspace", {})
    if not isinstance(workspace, dict):
        workspace = {}
    engine = config.get("engine", {})
    if not isinstance(engine, dict):
        engine = {}
    supervisor = config.get("supervisor", {})
    if not isinstance(supervisor, dict):
        supervisor = {}

    workspace_contract = source_policy.get("workspace_contract", {})
    required_workspace_fields = (
        workspace_contract.get("required_fields", [])
        if isinstance(workspace_contract, dict)
        else []
    )
    path_safety = source_policy.get("path_safety", {})
    if not isinstance(path_safety, dict):
        path_safety = {}
    validation_findings: list[dict[str, Any]] = []
    if config_status == "missing":
        validation_findings.append(
            {
                "finding_id": "missing_project_config",
                "severity": "warning",
                "message": (
                    f"{PROJECT_CONFIG_RELATIVE_PATH} is missing; using policy default profile"
                ),
                "next_gap": "create_project_config",
            }
        )
    elif config_status == "invalid":
        validation_findings.append(
            {
                "finding_id": "invalid_project_config",
                "severity": "error",
                "message": config_error,
                "next_gap": "repair_project_config",
            }
        )
    if config and str(config.get("artifact_kind", "")).strip() != "specgraph_project_config":
        validation_findings.append(
            {
                "finding_id": "wrong_project_config_kind",
                "severity": "error",
                "message": (
                    "specgraph.project.yaml must declare artifact_kind=specgraph_project_config"
                ),
                "next_gap": "repair_project_config",
            }
        )
    if not profile_known:
        validation_findings.append(
            {
                "finding_id": "unknown_governance_profile",
                "severity": "error",
                "message": f"unknown governance_profile: {requested_profile_id}",
                "next_gap": "select_supported_governance_profile",
            }
        )
    if config_status == "available":
        for field in required_workspace_fields:
            field_name = str(field).strip()
            if not field_name:
                continue
            path_text = safe_project_environment_path_text(
                workspace.get(field_name),
                path_safety=path_safety,
            )
            if not path_text:
                validation_findings.append(
                    {
                        "finding_id": "unsafe_or_missing_workspace_path",
                        "severity": "error",
                        "field": field_name,
                        "message": f"workspace.{field_name} must be a safe repo-relative path",
                        "next_gap": "repair_workspace_paths",
                    }
                )

    normalized_workspace = {
        str(field).strip(): safe_project_environment_path_text(
            workspace.get(str(field).strip()),
            path_safety=path_safety,
        )
        for field in required_workspace_fields
        if str(field).strip()
    }
    project_id = str(config.get("project_id", source_policy.get("default_project_id", ""))).strip()
    display_name = str(config.get("display_name", project_id)).strip() or project_id
    core_locked = bool(active_profile.get("core_locked", False))
    governance_enforcement = project_environment_enforcement_contract(active_profile)
    self_evolution_enabled = governance_enforcement["self_evolution"] == "enabled"
    project_graph_writable = bool(active_profile.get("project_graph_writable", True))
    mode_label = (
        str(active_profile.get("label", effective_profile_id)).strip() or effective_profile_id
    )
    self_evolution_label = "enabled" if self_evolution_enabled else "disabled"
    core_state = "locked" if core_locked else str(engine.get("mutation_policy", "")).strip()
    if not core_state:
        core_state = "proposal_first"
    supervisor_authority = {
        "allow_project_spec_refinement": project_environment_bool_value(
            supervisor.get("allow_project_spec_refinement"),
            default=True,
            field_path="supervisor.allow_project_spec_refinement",
            validation_findings=validation_findings,
        ),
        "allow_project_proposals": project_environment_bool_value(
            supervisor.get("allow_project_proposals"),
            default=True,
            field_path="supervisor.allow_project_proposals",
            validation_findings=validation_findings,
        ),
        "allow_project_retrospectives": project_environment_bool_value(
            supervisor.get("allow_project_retrospectives"),
            default=True,
            field_path="supervisor.allow_project_retrospectives",
            validation_findings=validation_findings,
        ),
        "allow_core_policy_mutation": project_environment_bool_value(
            supervisor.get("allow_core_policy_mutation"),
            default=not core_locked,
            field_path="supervisor.allow_core_policy_mutation",
            validation_findings=validation_findings,
        ),
        "allow_core_tooling_mutation": project_environment_bool_value(
            supervisor.get("allow_core_tooling_mutation"),
            default=not core_locked,
            field_path="supervisor.allow_core_tooling_mutation",
            validation_findings=validation_findings,
        ),
        "allow_self_evolution_proposals": project_environment_bool_value(
            supervisor.get("allow_self_evolution_proposals"),
            default=self_evolution_enabled,
            field_path="supervisor.allow_self_evolution_proposals",
            validation_findings=validation_findings,
        ),
    }
    summary_status = "valid" if not validation_findings else "needs_attention"
    return {
        "artifact_kind": PROJECT_ENVIRONMENT_ARTIFACT_KIND,
        "schema_version": PROJECT_ENVIRONMENT_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "canonical_mutations_allowed": False,
        "tracked_artifacts_written": False,
        "proposal_id": str(source_policy.get("proposal_id", "0052")).strip() or "0052",
        "policy_reference": project_environment_policy_reference_for(injected_policy),
        "source_config": {
            "artifact_path": repo_relative_or_absolute_path(config_path or project_config_path()),
            "artifact_sha256": config_sha256,
            "status": config_status,
        },
        "project": {
            "project_id": project_id,
            "display_name": display_name,
            "governance_profile": effective_profile_id,
            "requested_governance_profile": requested_profile_id,
            "active_profile_known": profile_known,
        },
        "engine": {
            "version_policy": str(engine.get("version_policy", "")).strip(),
            "mutation_policy": str(engine.get("mutation_policy", "")).strip(),
            "allowed_core_updates": str(engine.get("allowed_core_updates", "")).strip(),
            "core_locked": core_locked,
        },
        "workspace": normalized_workspace,
        "supervisor_authority": supervisor_authority,
        "governance_enforcement": governance_enforcement,
        "active_profile": active_profile,
        "validation_findings": validation_findings,
        "viewer_projection": {
            "environment_badge": {
                "mode_label": mode_label,
                "project_id": project_id,
                "governance_profile": effective_profile_id,
                "requested_governance_profile": requested_profile_id,
                "core_state": core_state,
                "self_evolution": self_evolution_label,
                "project_graph": "writable" if project_graph_writable else "read_only",
                "status": summary_status,
            },
            "enforcement_summary": {
                "allowed_target_domains": governance_enforcement["allowed_target_domains"],
                "forbidden_target_domains": governance_enforcement["forbidden_target_domains"],
                "allowed_mutation_roots": governance_enforcement["allowed_mutation_roots"],
                "forbidden_mutation_roots": governance_enforcement["forbidden_mutation_roots"],
                "default_next_move_behavior": governance_enforcement["default_next_move_behavior"],
                "blocked_move_status": governance_enforcement["blocked_move_status"],
                "review_feedback_routing": governance_enforcement["review_feedback_routing"],
                "upstream_export_mode": governance_enforcement["upstream_export_mode"],
            },
            "guardrails": {
                "core_locked": core_locked,
                "self_evolution_enabled": self_evolution_enabled,
                "project_graph_writable": project_graph_writable,
            },
        },
        "summary": {
            "status": summary_status,
            "project_id": project_id,
            "governance_profile": effective_profile_id,
            "requested_governance_profile": requested_profile_id,
            "core_locked": core_locked,
            "self_evolution_enabled": self_evolution_enabled,
            "default_next_move_behavior": governance_enforcement["default_next_move_behavior"],
            "review_feedback_routing": governance_enforcement["review_feedback_routing"],
            "validation_finding_count": len(validation_findings),
            "next_gap": "none" if not validation_findings else validation_findings[0]["next_gap"],
        },
    }


def write_project_environment(environment: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = project_environment_path()
    with artifact_lock(path):
        atomic_write_json(path, environment)
    return path


PRODUCT_WORKSPACE_INITIALIZATION_ARTIFACT_KIND = "product_workspace_initialization"
PRODUCT_WORKSPACE_INITIALIZATION_SCHEMA_VERSION = 1
PRODUCT_WORKSPACE_INITIALIZATION_PROPOSAL_ID = "0054"
PRODUCT_WORKSPACE_REQUIRED_DIRECTORIES = (
    "specs",
    "docs/proposals",
    "runs",
    ".specgraph",
)
PRODUCT_WORKSPACE_ALLOWED_TOP_LEVEL_ENTRIES = {
    "specgraph.project.yaml",
    "specs",
    "docs",
    "runs",
    ".specgraph",
    ".git",
    ".gitignore",
    ".env.example",
    "README",
    "README.md",
    "LICENSE",
    "LICENSE.md",
}
PRODUCT_WORKSPACE_PROJECT_ID_PATTERN = re.compile(r"^[A-Za-z0-9][A-Za-z0-9._-]*$")


def product_workspace_project_config_payload(
    *,
    project_id: str,
    display_name: str,
) -> dict[str, Any]:
    return {
        "artifact_kind": "specgraph_project_config",
        "schema_version": 1,
        "project_id": project_id,
        "display_name": display_name,
        "governance_profile": "product_workspace",
        "workspace": {
            "specs_root": "specs/",
            "proposals_root": "docs/proposals/",
            "runs_root": "runs/",
            "publish_root": f"projects/{project_id}/",
        },
        "supervisor": {
            "allow_project_spec_refinement": True,
            "allow_project_proposals": True,
            "allow_project_retrospectives": True,
            "allow_core_policy_mutation": False,
            "allow_core_tooling_mutation": False,
            "allow_self_evolution_proposals": False,
        },
    }


def dump_product_workspace_project_config(payload: dict[str, Any]) -> str:
    yaml_module = get_yaml_module()
    dump_kwargs = {"sort_keys": False, "allow_unicode": True}
    for kwargs in (dump_kwargs, {}):
        try:
            dumped = yaml_module.safe_dump(payload, **kwargs)
        except TypeError:
            continue
        if isinstance(dumped, str):
            return dumped if dumped.endswith("\n") else dumped + "\n"
    for kwargs in (dump_kwargs, {}):
        buffer = io.StringIO()
        try:
            yaml_module.safe_dump(payload, buffer, **kwargs)
        except TypeError:
            continue
        dumped = buffer.getvalue()
        return dumped if dumped.endswith("\n") else dumped + "\n"
    raise RuntimeError("unable to serialize product workspace project config")


def normalize_root_intent_text(root_intent: str | None) -> str:
    text = str(root_intent or "").strip()
    return text + "\n" if text else ""


def validate_product_workspace_initializer_inputs(
    *,
    project_id: str,
    workspace_root: Path,
    workspace_root_text: str | None = None,
) -> list[dict[str, Any]]:
    findings: list[dict[str, Any]] = []
    normalized_project_id = str(project_id).strip()
    if not normalized_project_id:
        findings.append(
            {
                "finding_id": "missing_project_id",
                "severity": "error",
                "field": "project_id",
                "message": "--project-id is required",
                "next_gap": "provide_project_identity",
            }
        )
    elif not PRODUCT_WORKSPACE_PROJECT_ID_PATTERN.fullmatch(normalized_project_id):
        findings.append(
            {
                "finding_id": "unsafe_project_id",
                "severity": "error",
                "field": "project_id",
                "message": "project_id must use only letters, numbers, dot, dash, and underscore",
                "next_gap": "repair_project_identity",
            }
        )

    root_value = workspace_root_text if workspace_root_text is not None else workspace_root
    root_text = str(root_value).strip()
    if not root_text:
        findings.append(
            {
                "finding_id": "missing_workspace_root",
                "severity": "error",
                "field": "workspace_root",
                "message": "--workspace-root is required",
                "next_gap": "provide_workspace_root",
            }
        )
        return findings

    root_resolved = workspace_root.expanduser().resolve(strict=False)
    specgraph_root = ROOT.resolve(strict=False)
    if root_resolved == specgraph_root or specgraph_root in root_resolved.parents:
        findings.append(
            {
                "finding_id": "workspace_root_inside_specgraph_core",
                "severity": "error",
                "field": "workspace_root",
                "message": "product workspace root must not be inside the SpecGraph core repo",
                "next_gap": "choose_external_product_workspace_root",
            }
        )
    return findings


def product_workspace_path_state(path: Path) -> str:
    if path.exists():
        return "directory" if path.is_dir() else "file"
    return "missing"


def product_workspace_conflict_findings(
    *,
    workspace_root: Path,
    expected_config_text: str,
    root_intent_text: str,
) -> list[dict[str, Any]]:
    findings: list[dict[str, Any]] = []
    if workspace_root.exists() and not workspace_root.is_dir():
        return [
            {
                "finding_id": "workspace_root_not_directory",
                "severity": "error",
                "path": ".",
                "message": "workspace root exists but is not a directory",
                "next_gap": "choose_external_product_workspace_root",
            }
        ]

    if not workspace_root.exists():
        return findings

    try:
        workspace_children = list(workspace_root.iterdir())
    except OSError as exc:
        findings.append(
            {
                "finding_id": "unreadable_workspace_root",
                "severity": "error",
                "path": ".",
                "message": f"workspace root is unreadable: {exc}",
                "next_gap": "repair_workspace_root_access",
            }
        )
        return findings

    unexpected_top_level = sorted(
        child.name
        for child in workspace_children
        if child.name not in PRODUCT_WORKSPACE_ALLOWED_TOP_LEVEL_ENTRIES
    )
    if unexpected_top_level:
        findings.append(
            {
                "finding_id": "unexpected_top_level_entries",
                "severity": "error",
                "path": ".",
                "entries": unexpected_top_level,
                "message": "existing workspace contains entries outside the initializer layout",
                "next_gap": "review_existing_workspace_before_initialization",
            }
        )

    for rel_dir in PRODUCT_WORKSPACE_REQUIRED_DIRECTORIES:
        target_dir = workspace_root / rel_dir
        parent = target_dir.parent
        while parent != workspace_root and workspace_root in parent.parents:
            if parent.exists() and not parent.is_dir():
                findings.append(
                    {
                        "finding_id": "required_workspace_parent_not_directory",
                        "severity": "error",
                        "path": rel_dir.rstrip("/") + "/",
                        "blocking_path": parent.relative_to(workspace_root).as_posix(),
                        "message": "required workspace directory parent exists as a file",
                        "next_gap": "repair_existing_workspace_before_initialization",
                    }
                )
                break
            parent = parent.parent
        if target_dir.exists() and not target_dir.is_dir():
            findings.append(
                {
                    "finding_id": "required_workspace_path_not_directory",
                    "severity": "error",
                    "path": rel_dir.rstrip("/") + "/",
                    "message": "required workspace directory path exists as a file",
                    "next_gap": "repair_existing_workspace_before_initialization",
                }
            )

    config_path = workspace_root / PROJECT_CONFIG_RELATIVE_PATH
    if config_path.exists():
        try:
            existing_config_text = config_path.read_text(encoding="utf-8")
        except OSError as exc:
            findings.append(
                {
                    "finding_id": "unreadable_existing_project_config",
                    "severity": "error",
                    "path": PROJECT_CONFIG_RELATIVE_PATH,
                    "message": f"existing project config is unreadable: {exc}",
                    "next_gap": "repair_existing_project_config",
                }
            )
        else:
            if existing_config_text != expected_config_text:
                findings.append(
                    {
                        "finding_id": "conflicting_project_config",
                        "severity": "error",
                        "path": PROJECT_CONFIG_RELATIVE_PATH,
                        "message": (
                            "existing specgraph.project.yaml differs from initializer output"
                        ),
                        "next_gap": "review_existing_workspace_before_initialization",
                    }
                )

    root_intent_path = workspace_root / ".specgraph" / "root_intent.md"
    if root_intent_text and root_intent_path.exists():
        try:
            existing_intent_text = root_intent_path.read_text(encoding="utf-8")
        except OSError as exc:
            findings.append(
                {
                    "finding_id": "unreadable_existing_root_intent",
                    "severity": "error",
                    "path": ".specgraph/root_intent.md",
                    "message": f"existing root intent is unreadable: {exc}",
                    "next_gap": "repair_existing_root_intent",
                }
            )
        else:
            if existing_intent_text != root_intent_text:
                findings.append(
                    {
                        "finding_id": "conflicting_root_intent",
                        "severity": "error",
                        "path": ".specgraph/root_intent.md",
                        "message": "existing root intent differs from requested root intent",
                        "next_gap": "review_existing_workspace_before_initialization",
                    }
                )

    return findings


def write_product_workspace_initialization_report(
    report: dict[str, Any],
    *,
    workspace_root: Path,
) -> Path:
    path = product_workspace_initialization_report_path(workspace_root)
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def initialize_product_workspace(
    *,
    project_id: str,
    display_name: str | None,
    workspace_root: str | Path,
    root_intent: str | None = None,
) -> dict[str, Any]:
    normalized_project_id = str(project_id or "").strip()
    normalized_display_name = str(display_name or "").strip() or normalized_project_id
    workspace_root_text = str(workspace_root or "").strip()
    root_path = Path(workspace_root_text).expanduser()
    root_resolved = root_path.resolve(strict=False)
    root_intent_text = normalize_root_intent_text(root_intent)
    config_payload = product_workspace_project_config_payload(
        project_id=normalized_project_id,
        display_name=normalized_display_name,
    )
    config_text = dump_product_workspace_project_config(config_payload)
    validation_findings = validate_product_workspace_initializer_inputs(
        project_id=normalized_project_id,
        workspace_root=root_path,
        workspace_root_text=workspace_root_text,
    )
    if not validation_findings:
        validation_findings.extend(
            product_workspace_conflict_findings(
                workspace_root=root_resolved,
                expected_config_text=config_text,
                root_intent_text=root_intent_text,
            )
        )

    report_blocking_findings = {
        "missing_workspace_root",
        "workspace_root_inside_specgraph_core",
        "workspace_root_not_directory",
    }
    can_probe_workspace = (
        root_resolved.exists()
        and root_resolved.is_dir()
        and not any(
            str(finding.get("finding_id", "")).strip() in report_blocking_findings
            for finding in validation_findings
        )
    )
    root_intent_path = root_resolved / ".specgraph" / "root_intent.md"
    root_intent_status = "not_provided"
    root_intent_content_sha256 = ""
    requested_root_intent_sha256 = (
        hashlib.sha256(root_intent_text.encode("utf-8")).hexdigest() if root_intent_text else ""
    )
    if not root_intent_text and can_probe_workspace and root_intent_path.exists():
        try:
            existing_root_intent_text = root_intent_path.read_text(encoding="utf-8")
        except OSError as exc:
            validation_findings.append(
                {
                    "finding_id": "unreadable_existing_root_intent",
                    "severity": "error",
                    "path": ".specgraph/root_intent.md",
                    "message": f"existing root intent is unreadable: {exc}",
                    "next_gap": "repair_existing_root_intent",
                }
            )
        else:
            root_intent_status = "captured_existing"
            root_intent_content_sha256 = hashlib.sha256(
                existing_root_intent_text.encode("utf-8")
            ).hexdigest()

    created_paths: list[str] = []
    existing_paths: list[str] = []
    written_artifacts: dict[str, Any] = {}
    has_errors = any(str(item.get("severity")) == "error" for item in validation_findings)

    if not has_errors:
        root_resolved.mkdir(parents=True, exist_ok=True)
        for rel_dir in PRODUCT_WORKSPACE_REQUIRED_DIRECTORIES:
            target_dir = root_resolved / rel_dir
            rel_display = rel_dir.rstrip("/") + "/"
            if target_dir.exists():
                existing_paths.append(rel_display)
            else:
                target_dir.mkdir(parents=True, exist_ok=True)
                created_paths.append(rel_display)

        config_path = root_resolved / PROJECT_CONFIG_RELATIVE_PATH
        if config_path.exists():
            existing_paths.append(PROJECT_CONFIG_RELATIVE_PATH)
        else:
            atomic_write_text(config_path, config_text)
            created_paths.append(PROJECT_CONFIG_RELATIVE_PATH)
            written_artifacts["project_config"] = {
                "artifact_path": PROJECT_CONFIG_RELATIVE_PATH,
                "artifact_sha256": hashlib.sha256(config_text.encode("utf-8")).hexdigest(),
            }

        if root_intent_text:
            root_intent_path = root_resolved / ".specgraph" / "root_intent.md"
            if root_intent_path.exists():
                existing_paths.append(".specgraph/root_intent.md")
            else:
                atomic_write_text(root_intent_path, root_intent_text)
                created_paths.append(".specgraph/root_intent.md")
            root_intent_status = "captured"
            root_intent_content_sha256 = requested_root_intent_sha256
            written_artifacts["root_intent"] = {
                "artifact_path": ".specgraph/root_intent.md",
                "artifact_sha256": root_intent_content_sha256,
            }
    elif root_intent_text:
        root_intent_status = "blocked"
        root_intent_content_sha256 = ""

    workspace_status = "blocked" if has_errors else ("initialized" if created_paths else "ready")
    report: dict[str, Any] = {
        "artifact_kind": PRODUCT_WORKSPACE_INITIALIZATION_ARTIFACT_KIND,
        "schema_version": PRODUCT_WORKSPACE_INITIALIZATION_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "proposal_id": PRODUCT_WORKSPACE_INITIALIZATION_PROPOSAL_ID,
        "canonical_mutations_allowed": False,
        "tracked_artifacts_written": False,
        "project": {
            "project_id": normalized_project_id,
            "display_name": normalized_display_name,
            "governance_profile": "product_workspace",
        },
        "workspace": {
            "root": ".",
            "root_reference": "workspace_relative",
            "local_input_path_persisted": False,
            "created_paths": created_paths,
            "existing_paths": sorted(set(existing_paths)),
            "required_paths": [
                PROJECT_CONFIG_RELATIVE_PATH,
                *[path.rstrip("/") + "/" for path in PRODUCT_WORKSPACE_REQUIRED_DIRECTORIES],
            ],
        },
        "root_intent": {
            "status": root_intent_status,
            "artifact_path": (
                ".specgraph/root_intent.md"
                if root_intent_status in {"captured", "captured_existing"}
                else ""
            ),
            "content_sha256": root_intent_content_sha256,
            "next_gap": "review_before_canonical_materialization",
        },
        "validation_findings": validation_findings,
        "review_state": "blocked" if has_errors else "ready_for_review",
        "next_gap": "repair_product_workspace_initialization"
        if has_errors
        else "review_before_first_spec_materialization",
        "summary": {
            "status": workspace_status,
            "project_id": normalized_project_id,
            "governance_profile": "product_workspace",
            "root_intent_status": root_intent_status,
            "created_path_count": len(created_paths),
            "validation_finding_count": len(validation_findings),
            "next_gap": "repair_product_workspace_initialization"
            if has_errors
            else "review_before_first_spec_materialization",
        },
        "written_artifacts": written_artifacts,
        "viewer_projection": {
            "initialization_badge": {
                "status": workspace_status,
                "project_id": normalized_project_id,
                "display_name": normalized_display_name,
                "governance_profile": "product_workspace",
                "root_intent": root_intent_status,
            },
            "safe_next_actions": [
                "review_root_intent_before_canonical_materialization"
                if not has_errors
                else "repair_workspace_conflict_before_retry"
            ],
        },
    }

    can_write_report = (
        root_resolved.exists()
        and root_resolved.is_dir()
        and not any(
            str(finding.get("finding_id", "")).strip() in report_blocking_findings
            for finding in validation_findings
        )
    )
    if can_write_report:
        report["written_artifacts"]["initialization_report"] = {
            "artifact_path": PRODUCT_WORKSPACE_INITIALIZATION_REPORT_RELATIVE_PATH,
            "artifact_kind": PRODUCT_WORKSPACE_INITIALIZATION_ARTIFACT_KIND,
        }
        report["summary"]["report_path"] = PRODUCT_WORKSPACE_INITIALIZATION_REPORT_RELATIVE_PATH
        try:
            write_product_workspace_initialization_report(
                report,
                workspace_root=root_resolved,
            )
        except (OSError, RuntimeError) as exc:
            report["written_artifacts"].pop("initialization_report", None)
            report["summary"].pop("report_path", None)
            report["validation_findings"].append(
                {
                    "finding_id": "initialization_report_write_failed",
                    "severity": "error",
                    "path": PRODUCT_WORKSPACE_INITIALIZATION_REPORT_RELATIVE_PATH,
                    "message": f"failed to write initialization report: {exc}",
                    "next_gap": "repair_product_workspace_report_path",
                }
            )
            report["review_state"] = "blocked"
            report["next_gap"] = "repair_product_workspace_initialization"
            report["summary"]["status"] = "blocked"
            report["summary"]["validation_finding_count"] = len(report["validation_findings"])
            report["summary"]["next_gap"] = "repair_product_workspace_initialization"
            report["viewer_projection"]["initialization_badge"]["status"] = "blocked"
            report["viewer_projection"]["safe_next_actions"] = [
                "repair_workspace_conflict_before_retry"
            ]
            return report

    return report


