def iter_vocabulary_entries() -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    contexts = SPECGRAPH_VOCABULARY.get("contexts", {})
    for family_name, family in sorted(SPECGRAPH_VOCABULARY_FAMILIES.items()):
        if not isinstance(family, dict):
            continue
        description = str(family.get("description", "")).strip()
        owner_specs = sorted(
            {
                str(spec_id).strip()
                for spec_id in family.get("owner_specs", [])
                if str(spec_id).strip()
            }
        )
        owner_artifacts = sorted(
            {str(path).strip() for path in family.get("owner_artifacts", []) if str(path).strip()}
        )
        family_contexts = sorted(
            {
                context_name
                for context_name, context in contexts.items()
                if isinstance(context, dict)
                and any(
                    spec_id in owner_specs
                    for spec_id in (str(item).strip() for item in context.get("owner_specs", []))
                    if spec_id
                )
            }
        )
        canonical_terms = family.get("canonical_terms", {})
        if not isinstance(canonical_terms, dict):
            continue
        for canonical_term, definition in sorted(canonical_terms.items()):
            if not isinstance(definition, dict):
                continue
            entries.append(
                {
                    "family": family_name,
                    "canonical_term": str(canonical_term).strip(),
                    "definition": str(definition.get("definition", "")).strip(),
                    "aliases": sorted(
                        {
                            str(alias).strip()
                            for alias in definition.get("aliases", [])
                            if str(alias).strip()
                        }
                    ),
                    "deprecated_aliases": sorted(
                        {
                            str(alias).strip()
                            for alias in definition.get("deprecated_aliases", [])
                            if str(alias).strip()
                        }
                    ),
                    "family_description": description,
                    "owner_specs": owner_specs,
                    "owner_artifacts": owner_artifacts,
                    "contexts": family_contexts,
                }
            )
    return entries


def vocabulary_term_resolution(
    term: str,
    *,
    family: str | None = None,
) -> dict[str, str] | None:
    normalized = str(term).strip()
    if not normalized:
        return None
    for entry in iter_vocabulary_entries():
        if family is not None and entry["family"] != family:
            continue
        canonical_term = str(entry["canonical_term"]).strip()
        if normalized == canonical_term:
            return {
                "family": str(entry["family"]),
                "canonical_term": canonical_term,
                "resolution_kind": "canonical",
            }
        if normalized in entry["aliases"]:
            return {
                "family": str(entry["family"]),
                "canonical_term": canonical_term,
                "resolution_kind": "alias",
            }
        if normalized in entry["deprecated_aliases"]:
            return {
                "family": str(entry["family"]),
                "canonical_term": canonical_term,
                "resolution_kind": "deprecated_alias",
            }
    return None


def build_vocabulary_index() -> dict[str, Any]:
    entries = iter_vocabulary_entries()
    alias_index: dict[str, list[str]] = {}
    deprecated_alias_index: dict[str, list[str]] = {}
    family_index: dict[str, list[str]] = {}
    for entry in entries:
        family = str(entry["family"]).strip()
        canonical_term = str(entry["canonical_term"]).strip()
        family_index.setdefault(family, []).append(canonical_term)
        for alias in entry["aliases"]:
            alias_index.setdefault(alias, []).append(f"{family}:{canonical_term}")
        for alias in entry["deprecated_aliases"]:
            deprecated_alias_index.setdefault(alias, []).append(f"{family}:{canonical_term}")

    contexts = SPECGRAPH_VOCABULARY.get("contexts", {})
    context_entries = []
    for context_name, context in sorted(contexts.items()):
        if not isinstance(context, dict):
            continue
        context_entries.append(
            {
                "context": context_name,
                "description": str(context.get("description", "")).strip(),
                "owner_specs": sorted(
                    {
                        str(spec_id).strip()
                        for spec_id in context.get("owner_specs", [])
                        if str(spec_id).strip()
                    }
                ),
                "owner_artifacts": sorted(
                    {
                        str(path).strip()
                        for path in context.get("owner_artifacts", [])
                        if str(path).strip()
                    }
                ),
            }
        )

    return {
        "artifact_kind": "specgraph_vocabulary_index",
        "schema_version": 1,
        "generated_at": utc_now_iso(),
        "vocabulary_reference": specgraph_vocabulary_reference(),
        "context_count": len(context_entries),
        "contexts": context_entries,
        "family_count": len(family_index),
        "term_count": len(entries),
        "entries": entries,
        "family_index": {family: sorted(values) for family, values in sorted(family_index.items())},
        "alias_index": {alias: sorted(values) for alias, values in sorted(alias_index.items())},
        "deprecated_alias_index": {
            alias: sorted(values) for alias, values in sorted(deprecated_alias_index.items())
        },
    }


def write_vocabulary_index(index: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = vocabulary_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def _vocabulary_surface_contracts(specs: list[SpecNode]) -> list[dict[str, Any]]:
    surfaces: list[dict[str, Any]] = [
        {
            "surface_kind": "policy_contract",
            "surface_id": INTENT_LAYER_POLICY_RELATIVE_PATH,
            "family": "runtime_artifact_kind",
            "terms": [
                INTENT_LAYER_NODE_ARTIFACT_KIND,
                INTENT_LAYER_OVERLAY_ARTIFACT_KIND,
            ],
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": INTENT_LAYER_POLICY_RELATIVE_PATH,
            "family": "pre_spec_artifact_class",
            "terms": sorted(INTENT_LAYER_ALLOWED_KINDS),
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": INTENT_LAYER_POLICY_RELATIVE_PATH,
            "family": "pre_spec_lifecycle_state",
            "terms": sorted(INTENT_LAYER_ALLOWED_STATES),
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": OPERATOR_REQUEST_BRIDGE_POLICY_RELATIVE_PATH,
            "family": "runtime_artifact_kind",
            "terms": [OPERATOR_REQUEST_PACKET_ARTIFACT_KIND],
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": OPERATOR_REQUEST_BRIDGE_POLICY_RELATIVE_PATH,
            "family": "operator_request_source_kind",
            "terms": sorted(OPERATOR_REQUEST_SOURCE_KINDS),
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": OPERATOR_REQUEST_BRIDGE_POLICY_RELATIVE_PATH,
            "family": "operator_request_run_mode",
            "terms": sorted(OPERATOR_REQUEST_RUN_MODES),
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": OPERATOR_REQUEST_BRIDGE_POLICY_RELATIVE_PATH,
            "family": "operator_request_stop_condition",
            "terms": sorted(set(OPERATOR_REQUEST_ALLOWED_STOP_CONDITIONS)),
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": PROPOSAL_LANE_POLICY_RELATIVE_PATH,
            "family": "runtime_artifact_kind",
            "terms": [
                PROPOSAL_LANE_NODE_ARTIFACT_KIND,
                PROPOSAL_LANE_OVERLAY_ARTIFACT_KIND,
            ],
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": PROPOSAL_LANE_POLICY_RELATIVE_PATH,
            "family": "proposal_authority_state",
            "allow_deprecated_aliases": True,
            "terms": sorted(
                {
                    str(term).strip()
                    for term in (
                        list(PROPOSAL_LANE_AUTHORITY_STATE_MAPPING.keys())
                        + list(PROPOSAL_LANE_AUTHORITY_STATE_MAPPING.values())
                    )
                    if str(term).strip()
                }
            ),
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": PROPOSAL_PROMOTION_POLICY_RELATIVE_PATH,
            "family": "proposal_artifact_class",
            "terms": sorted(
                {
                    str(term).strip()
                    for term in load_proposal_promotion_policy_report()[0]
                    .get("semantic_artifact_classes", {})
                    .keys()
                    if str(term).strip()
                }
            )
            if load_proposal_promotion_policy_report()[0]
            else [],
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": PRE_SPEC_SEMANTICS_POLICY_RELATIVE_PATH,
            "family": "runtime_artifact_kind",
            "terms": [PRE_SPEC_SEMANTICS_INDEX_ARTIFACT_KIND],
        },
        {
            "surface_kind": "policy_contract",
            "surface_id": PRE_SPEC_SEMANTICS_POLICY_RELATIVE_PATH,
            "family": "pre_spec_artifact_class",
            "terms": sorted(PRE_SPEC_IMPLEMENTED_ARTIFACT_CLASSES.keys()),
        },
        {
            "surface_kind": "canonical_spec_terminology",
            "surface_id": "canonical_spec_terminology",
            "family": "",
            "terms": [],
        },
    ]
    for spec in specs:
        terminology = spec.data.get("specification", {}).get("terminology", {})
        if not isinstance(terminology, dict):
            continue
        for term in sorted(str(key).strip() for key in terminology.keys() if str(key).strip()):
            resolution = vocabulary_term_resolution(term)
            surfaces.append(
                {
                    "surface_kind": "canonical_spec_terminology",
                    "surface_id": display_artifact_path(spec.path),
                    "spec_id": spec.id,
                    "family": str((resolution or {}).get("family", "")).strip(),
                    "terms": [term],
                }
            )
    return surfaces


def build_vocabulary_drift_report(specs: list[SpecNode]) -> dict[str, Any]:
    index = build_vocabulary_index()
    alias_index = index.get("alias_index", {})
    deprecated_alias_index = index.get("deprecated_alias_index", {})
    findings: list[dict[str, str]] = []

    for alias, resolutions in alias_index.items():
        if len(resolutions) > 1:
            findings.append(
                {
                    "code": "alias_collision",
                    "severity": "error",
                    "surface_kind": "vocabulary_artifact",
                    "surface_id": SPECGRAPH_VOCABULARY_RELATIVE_PATH,
                    "term": alias,
                    "message": (
                        "Alias resolves to multiple canonical terms: "
                        + ", ".join(sorted(resolutions))
                    ),
                }
            )
    for alias, resolutions in deprecated_alias_index.items():
        if len(resolutions) > 1:
            findings.append(
                {
                    "code": "deprecated_alias_collision",
                    "severity": "error",
                    "surface_kind": "vocabulary_artifact",
                    "surface_id": SPECGRAPH_VOCABULARY_RELATIVE_PATH,
                    "term": alias,
                    "message": (
                        "Deprecated alias resolves to multiple canonical terms: "
                        + ", ".join(sorted(resolutions))
                    ),
                }
            )

    for surface in _vocabulary_surface_contracts(specs):
        family = str(surface.get("family", "")).strip()
        surface_kind = str(surface.get("surface_kind", "")).strip()
        surface_id = str(surface.get("surface_id", "")).strip()
        spec_id = str(surface.get("spec_id", "")).strip()
        allow_deprecated_aliases = bool(surface.get("allow_deprecated_aliases"))
        for term in surface.get("terms", []):
            normalized_term = str(term).strip()
            if not normalized_term:
                continue
            resolution = vocabulary_term_resolution(normalized_term, family=family or None)
            if resolution is None:
                findings.append(
                    {
                        "code": "undefined_term",
                        "severity": "error",
                        "surface_kind": surface_kind,
                        "surface_id": surface_id,
                        "term": normalized_term,
                        "family": family,
                        "message": (
                            f"Term `{normalized_term}` is not defined in the shared vocabulary"
                            + (f" for family `{family}`." if family else ".")
                        ),
                    }
                )
                continue
            if resolution["resolution_kind"] == "deprecated_alias" and not allow_deprecated_aliases:
                findings.append(
                    {
                        "code": "deprecated_alias_usage",
                        "severity": "warning",
                        "surface_kind": surface_kind,
                        "surface_id": surface_id,
                        "term": normalized_term,
                        "family": resolution["family"],
                        "message": (
                            f"Surface still uses deprecated alias `{normalized_term}` for "
                            f"`{resolution['canonical_term']}`."
                        ),
                    }
                )
            if surface_kind == "canonical_spec_terminology":
                matching_entries = [
                    entry
                    for entry in index["entries"]
                    if entry["family"] == resolution["family"]
                    and entry["canonical_term"] == resolution["canonical_term"]
                ]
                owner_specs = set()
                for entry in matching_entries:
                    owner_specs.update(str(item).strip() for item in entry.get("owner_specs", []))
                if owner_specs and spec_id and spec_id not in owner_specs:
                    findings.append(
                        {
                            "code": "meaning_divergence",
                            "severity": "warning",
                            "surface_kind": surface_kind,
                            "surface_id": surface_id,
                            "term": normalized_term,
                            "family": resolution["family"],
                            "message": (
                                f"Canonical spec {spec_id} defines shared term `{normalized_term}` "
                                f"outside its owning spec set: {', '.join(sorted(owner_specs))}."
                            ),
                        }
                    )

    findings_by_code: dict[str, list[str]] = {}
    for finding in findings:
        findings_by_code.setdefault(str(finding["code"]), []).append(
            str(finding.get("surface_id", "")).strip() or str(finding.get("term", "")).strip()
        )

    return {
        "artifact_kind": "vocabulary_drift_report",
        "schema_version": 1,
        "generated_at": utc_now_iso(),
        "vocabulary_reference": specgraph_vocabulary_reference(),
        "source_spec_count": len(specs),
        "finding_count": len(findings),
        "findings": findings,
        "findings_by_code": {
            code: sorted(set(values)) for code, values in sorted(findings_by_code.items())
        },
    }


def write_vocabulary_drift_report(report: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = vocabulary_drift_report_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def refresh_vocabulary_artifacts(specs: list[SpecNode]) -> dict[str, Path]:
    index_path = write_vocabulary_index(build_vocabulary_index())
    drift_path = write_vocabulary_drift_report(build_vocabulary_drift_report(specs))
    return {
        "vocabulary_index": index_path,
        "vocabulary_drift_report": drift_path,
    }


def refresh_pre_spec_semantics_artifacts(specs: list[SpecNode]) -> dict[str, Path]:
    overlay_path = write_intent_layer_overlay(build_intent_layer_overlay())
    pre_spec_index = write_pre_spec_semantics_index(build_pre_spec_semantics_index(specs))
    return {
        "intent_layer_overlay": overlay_path,
        "pre_spec_semantics_index": pre_spec_index,
    }


def proposal_artifact_filename(*, proposal_type: str, spec_id: str, signal: str) -> str:
    safe_spec_id = sanitize_for_git(spec_id).replace("/", "-")
    safe_signal = sanitize_for_git(signal).replace("/", "-")
    safe_type = sanitize_for_git(proposal_type).replace("/", "-")
    return f"{safe_type}--{safe_spec_id}--{safe_signal}.json"


def proposal_artifact_path(*, proposal_type: str, spec_id: str, signal: str) -> Path:
    return proposals_dir_path() / proposal_artifact_filename(
        proposal_type=proposal_type,
        spec_id=spec_id,
        signal=signal,
    )


def proposal_artifact_relpath(*, proposal_type: str, spec_id: str, signal: str) -> str:
    return (
        proposal_artifact_path(
            proposal_type=proposal_type,
            spec_id=spec_id,
            signal=signal,
        )
        .relative_to(ROOT)
        .as_posix()
    )


def split_proposal_allowed_changed_paths(artifact_relpath: str) -> set[str]:
    """Allow the proposal artifact file plus any untracked parent dirs.

    `git status --porcelain` may surface a newly created artifact as
    `runs/proposals/` instead of the concrete JSON file. Split proposal mode
    should treat those parent directories as part of the single allowed write.
    """

    normalized = artifact_relpath.strip().rstrip("/")
    allowed = {normalized}
    current = PurePosixPath(normalized)
    for parent in current.parents:
        parent_text = parent.as_posix().rstrip("/")
        if not parent_text or parent_text == ".":
            continue
        allowed.add(parent_text)
        allowed.add(f"{parent_text}/")
    return allowed


def proposal_item_path(item: dict[str, Any]) -> Path:
    path_value = str(item.get("proposal_artifact_path", "")).strip()
    if not path_value:
        path_value = proposal_artifact_relpath(
            proposal_type=str(item.get("proposal_type", "")).strip() or "refactor_proposal",
            spec_id=str(item.get("target_spec_id", "")).strip()
            or str(item.get("spec_id", "")).strip(),
            signal=str(item.get("source_signal", "")).strip()
            or str(item.get("signal", "")).strip(),
        )
    return ROOT / path_value


def run_log_paths() -> list[Path]:
    return sorted(RUNS_DIR.glob("*-SG-SPEC-*.json"))


def classify_refactor_work_item(signal: str) -> str:
    governance_signals = set(policy_lookup("queue_policy.governance_proposal_signals"))
    if signal in governance_signals:
        return "governance_proposal"
    return "graph_refactor"


def default_action_for_signal(signal: str) -> str:
    default_actions = policy_lookup("queue_policy.default_actions")
    return str(default_actions.get(signal, "review_graph_health_signal"))


def proposal_is_active(item: dict[str, Any]) -> bool:
    status = str(item.get("status", "proposed")).strip()
    return status in {"proposed", "review_pending", "pending_review"}


def proposal_is_applicable(item: dict[str, Any]) -> bool:
    status = str(item.get("status", "proposed")).strip()
    return status in APPLICABLE_PROPOSAL_STATUSES


def has_active_proposal_for_signal(
    *,
    spec_id: str,
    signal: str,
    proposal_items: list[dict[str, Any]],
) -> bool:
    for item in proposal_items:
        if str(item.get("spec_id", "")).strip() != spec_id:
            continue
        if str(item.get("signal", "")).strip() != signal:
            continue
        if proposal_is_active(item):
            return True
    return False


def refactor_execution_policy(
    item: dict[str, Any],
    proposal_items: list[dict[str, Any]] | None = None,
) -> str:
    work_item_type = str(item.get("work_item_type", "")).strip()
    if work_item_type == "governance_proposal":
        return "emit_proposal"
    if work_item_type != "graph_refactor":
        return "review_graph_health_signal"

    proposal_items = proposal_items or []
    spec_id = str(item.get("spec_id", "")).strip()
    signal = str(item.get("signal", "")).strip()
    if has_active_proposal_for_signal(
        spec_id=spec_id,
        signal=signal,
        proposal_items=proposal_items,
    ):
        return "defer_to_active_proposal"
    if signal == RETROSPECTIVE_REFACTOR_SIGNAL:
        return "emit_proposal"
    if signal in SUBTREE_SHAPE_SIGNALS:
        return "emit_proposal"
    return "direct_graph_update"


def classify_proposal_type(work_item_type: str) -> str:
    if work_item_type == "governance_proposal":
        return "governance_proposal"
    return "refactor_proposal"


def handoff_metadata_for_signal(signal: str) -> dict[str, Any]:
    if str(signal).strip() != TECHSPEC_HANDOFF_PRIMARY_SIGNAL:
        return {}
    return {
        "target_layer": TECHSPEC_HANDOFF_TARGET_LAYER,
        "transition_profile": TECHSPEC_HANDOFF_TARGET_TRANSITION_PROFILE,
        "packet_type": TECHSPEC_HANDOFF_TARGET_PACKET_TYPE,
        "target_artifact_class": TECHSPEC_HANDOFF_TARGET_ARTIFACT_CLASS,
        "handoff_policy_reference": techspec_handoff_policy_reference(),
    }


def proposal_threshold_for_signal(*, signal: str, work_item_type: str) -> int:
    threshold_policy = policy_lookup("queue_policy.proposal_thresholds")
    if signal == RETROSPECTIVE_REFACTOR_SIGNAL:
        return int(threshold_policy["retrospective_refactor_candidate"])
    if work_item_type == "governance_proposal":
        return int(threshold_policy["governance_proposal"])
    return int(threshold_policy["default_graph_refactor"])


def signal_supporting_run_ids(spec_id: str, signal: str) -> list[str]:
    run_ids: list[str] = []
    for path in run_log_paths():
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(payload, dict):
            continue
        if str(payload.get("graph_health_truth_basis", "")).strip() != "accepted_canonical":
            continue
        graph_health = payload.get("graph_health")
        if not isinstance(graph_health, dict):
            continue
        if str(graph_health.get("source_spec_id", "")).strip() != spec_id:
            continue
        signals = graph_health.get("signals")
        if not isinstance(signals, list):
            continue
        if signal not in {str(item) for item in signals}:
            continue
        run_id = str(payload.get("run_id", "")).strip()
        if run_id:
            run_ids.append(run_id)
    return run_ids


def build_refactor_queue_items(
    *,
    graph_health: dict[str, Any],
    run_id: str,
    proposal_items: list[dict[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    observation_by_kind = {
        str(observation.get("kind", "")): observation
        for observation in graph_health.get("observations", [])
        if isinstance(observation, dict)
    }
    source_spec_id = str(graph_health.get("source_spec_id", "")).strip()
    items: list[dict[str, Any]] = []
    for signal in graph_health.get("signals", []):
        item_type = classify_refactor_work_item(signal)
        base_item = {
            "id": f"{item_type}::{source_spec_id}::{signal}",
            "work_item_type": item_type,
            "spec_id": source_spec_id,
            "signal": signal,
            "recommended_action": default_action_for_signal(signal),
            "status": "proposed",
            "source_run_id": run_id,
            "details": observation_by_kind.get(signal, {}).get("details"),
        }
        items.append(
            {
                **base_item,
                **handoff_metadata_for_signal(signal),
                "execution_policy": refactor_execution_policy(base_item, proposal_items),
            }
        )
    return items


def update_refactor_queue(
    *,
    graph_health: dict[str, Any],
    run_id: str,
    proposal_items: list[dict[str, Any]] | None = None,
) -> Path:
    """Refresh the derived refactor queue for one source spec.

    The queue is overwritten per source spec so the latest run owns the
    currently visible local graph-refactor suggestions for that node.
    """
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = refactor_queue_path()
    with artifact_lock(path):
        if path.exists():
            existing, error = load_json_list_report(path, artifact_kind="refactor queue artifact")
            if error:
                raise RuntimeError(error)
        else:
            existing = []

        source_spec_id = str(graph_health.get("source_spec_id", "")).strip()
        preserved = [
            item
            for item in (existing or [])
            if isinstance(item, dict) and str(item.get("spec_id", "")).strip() != source_spec_id
        ]
        updated = preserved + build_refactor_queue_items(
            graph_health=graph_health,
            run_id=run_id,
            proposal_items=proposal_items,
        )
        atomic_write_json(path, updated)
    return path


def build_proposal_queue_items(
    *,
    graph_health: dict[str, Any],
    run_id: str,
    operator_request_context: dict[str, Any] | None = None,
) -> list[dict[str, Any]]:
    observation_by_kind = {
        str(observation.get("kind", "")): observation
        for observation in graph_health.get("observations", [])
        if isinstance(observation, dict)
    }
    source_spec_id = str(graph_health.get("source_spec_id", "")).strip()
    items: list[dict[str, Any]] = []

    for signal in graph_health.get("signals", []):
        signal_name = str(signal).strip()
        work_item_type = classify_refactor_work_item(signal_name)
        supporting_run_ids = signal_supporting_run_ids(source_spec_id, signal_name)
        occurrence_count = len(supporting_run_ids) + 1
        if run_id not in supporting_run_ids:
            supporting_run_ids.append(run_id)
        threshold = proposal_threshold_for_signal(signal=signal_name, work_item_type=work_item_type)
        if occurrence_count < threshold:
            continue

        if signal_name == TECHSPEC_HANDOFF_PRIMARY_SIGNAL:
            proposal_type = "handoff_proposal"
        else:
            proposal_type = classify_proposal_type(work_item_type)
        if signal_name == TECHSPEC_HANDOFF_PRIMARY_SIGNAL:
            trigger = "handoff_boundary_signal"
        elif work_item_type == "governance_proposal":
            trigger = "governance_class_signal"
        elif signal_name == RETROSPECTIVE_REFACTOR_SIGNAL:
            trigger = "retrospective_signal"
        else:
            trigger = "recurring_signal"
        items.append(
            {
                "id": f"{proposal_type}::{source_spec_id}::{signal_name}",
                "proposal_type": proposal_type,
                "spec_id": source_spec_id,
                "signal": signal_name,
                "recommended_action": default_action_for_signal(signal_name),
                "status": "proposed",
                "trigger": trigger,
                "occurrence_count": occurrence_count,
                "threshold": threshold,
                "supporting_run_ids": supporting_run_ids,
                "source_work_item_type": work_item_type,
                "execution_policy": "emit_proposal",
                "details": observation_by_kind.get(signal_name, {}).get("details"),
                "user_intent_handle": str(
                    (operator_request_context or {}).get("user_intent_handle", "")
                ).strip(),
                "operator_request_handle": str(
                    (operator_request_context or {}).get("operator_request_handle", "")
                ).strip(),
                **handoff_metadata_for_signal(signal_name),
            }
        )
    return items


def update_proposal_queue(
    *,
    graph_health: dict[str, Any],
    run_id: str,
    operator_request_context: dict[str, Any] | None = None,
) -> tuple[Path, list[dict[str, Any]]]:
    """Refresh the derived proposal queue index for one source spec.

    The queue remains a lightweight index. Detailed split-refactor content
    lives in separate structured proposal artifacts under `runs/proposals/`.
    """
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = proposal_queue_path()
    with artifact_lock(path):
        if path.exists():
            existing, error = load_json_list_report(path, artifact_kind="proposal queue artifact")
            if error:
                raise RuntimeError(error)
        else:
            existing = []

        source_spec_id = str(graph_health.get("source_spec_id", "")).strip()
        preserved = [
            item
            for item in (existing or [])
            if isinstance(item, dict) and str(item.get("spec_id", "")).strip() != source_spec_id
        ]
        updated = preserved + build_proposal_queue_items(
            graph_health=graph_health,
            run_id=run_id,
            operator_request_context=operator_request_context,
        )
        atomic_write_json(path, updated)
    sync_tracked_proposal_lane_from_queue(updated, spec_id=source_spec_id)
    return path, updated


def clear_proposal_queue_items_for_spec(spec_id: str) -> list[str]:
    """Remove derived proposal-queue pressure for a spec after gate resolution."""
    normalized_spec_id = spec_id.strip()
    if not normalized_spec_id:
        return []
    path = proposal_queue_path()
    if not path.exists():
        return []
    with artifact_lock(path):
        existing, error = load_json_list_report(path, artifact_kind="proposal queue artifact")
        if error:
            raise RuntimeError(error)
        retained: list[dict[str, Any]] = []
        cleared_ids: list[str] = []
        for item in existing or []:
            if not isinstance(item, dict):
                continue
            if str(item.get("spec_id", "")).strip() == normalized_spec_id:
                item_id = str(item.get("id", "")).strip()
                if item_id:
                    cleared_ids.append(item_id)
                continue
            retained.append(item)
        if cleared_ids:
            atomic_write_json(path, retained)
    return cleared_ids


def summarize_queue_transition(
    *,
    source_spec_id: str,
    before_items: list[dict[str, Any]] | None,
    after_items: list[dict[str, Any]] | None,
) -> dict[str, Any]:
    """Summarize how one source spec's queue items changed across a run."""

    def scoped_by_id(items: list[dict[str, Any]] | None) -> dict[str, dict[str, Any]]:
        scoped: dict[str, dict[str, Any]] = {}
        for item in items or []:
            if not isinstance(item, dict):
                continue
            if str(item.get("spec_id", "")).strip() != source_spec_id:
                continue
            item_id = str(item.get("id", "")).strip()
            if not item_id:
                continue
            scoped[item_id] = item
        return scoped

    before_by_id = scoped_by_id(before_items)
    after_by_id = scoped_by_id(after_items)
    before_ids = set(before_by_id)
    after_ids = set(after_by_id)
    retained_ids = before_ids & after_ids
    updated_ids = sorted(
        item_id for item_id in retained_ids if before_by_id[item_id] != after_by_id[item_id]
    )
    return {
        "before_ids": sorted(before_ids),
        "after_ids": sorted(after_ids),
        "emitted_ids": sorted(after_ids - before_ids),
        "cleared_ids": sorted(before_ids - after_ids),
        "retained_ids": sorted(retained_ids),
        "updated_ids": updated_ids,
    }


def dedupe_decision_rules(rules: list[dict[str, Any]]) -> list[dict[str, Any]]:
    unique: list[dict[str, Any]] = []
    seen: set[str] = set()
    for rule in rules:
        token = json.dumps(rule, ensure_ascii=False, sort_keys=True)
        if token in seen:
            continue
        seen.add(token)
        unique.append(rule)
    return unique


def build_selection_decision_rules(selected_by_rule: dict[str, Any]) -> list[dict[str, Any]]:
    rules: list[dict[str, Any]] = []
    sort_order = list(selected_by_rule.get("sort_order", []))
    if sort_order == policy_lookup("selection_priorities.explicit_target_sort_order"):
        rules.append(
            policy_rule(
                "selection_priorities.explicit_target_sort_order",
                reason="explicit operator targeting bypassed heuristic selector ordering",
                inputs={"selection_mode": selected_by_rule.get("selection_mode")},
            )
        )
    elif sort_order == policy_lookup("selection_priorities.ordinary_sort_order"):
        rules.append(
            policy_rule(
                "selection_priorities.ordinary_sort_order",
                reason="ordinary selector ordering determined the candidate ranking for this run",
                inputs={"selection_mode": selected_by_rule.get("selection_mode")},
            )
        )

    signal = str(selected_by_rule.get("refactor_work_item", {}).get("signal", "")).strip()
    if signal:
        rules.append(
            policy_rule(
                f"selection_priorities.refactor_signal_priority.{signal}",
                reason=(
                    "queued graph-refactor candidates were ranked by declarative signal priority"
                ),
                matched_value=refactor_signal_priority(signal),
                inputs={"signal": signal},
            )
        )

    profile_name = str(selected_by_rule.get("execution_profile", "")).strip()
    if profile_name in EXECUTION_PROFILES:
        rules.append(
            policy_rule(
                f"execution_profiles.profiles.{profile_name}",
                reason="selected execution profile provided the nested executor configuration",
                matched_value=asdict(EXECUTION_PROFILES[profile_name]),
                inputs={"profile_name": profile_name},
            )
        )
        run_authorities = {str(value) for value in selected_by_rule.get("run_authority", [])}
        if (
            profile_name == AUTO_CHILD_MATERIALIZATION_PROFILE_NAME
            and RUN_AUTHORITY_MATERIALIZE_ONE_CHILD in run_authorities
        ):
            rules.append(
                policy_rule(
                    "execution_profiles.auto_child_materialization_profile",
                    reason=(
                        "explicit child-materialization authority promoted the materialize profile"
                    ),
                    inputs={"run_authority": selected_by_rule.get("run_authority", [])},
                )
            )
        elif profile_name == AUTO_HEURISTIC_PROFILE_NAME and not selected_by_rule.get(
            "operator_target"
        ):
            rules.append(
                policy_rule(
                    "execution_profiles.auto_heuristic_profile",
                    reason="ordinary heuristic runs default to the fast execution profile",
                    inputs={"selection_mode": selected_by_rule.get("selection_mode")},
                )
            )
        elif profile_name == DEFAULT_EXECUTION_PROFILE_NAME and selected_by_rule.get(
            "operator_target"
        ):
            rules.append(
                policy_rule(
                    "execution_profiles.default_profile",
                    reason="explicit operator-targeted runs default to the standard profile",
                    inputs={"selection_mode": selected_by_rule.get("selection_mode")},
                )
            )

    if str(selected_by_rule.get("selection_mode", "")).strip() == "linked_continuation":
        rules.append(
            policy_rule(
                "thresholds.linked_continuation_maturity",
                reason="linked-continuation eligibility consults the declarative maturity floor",
                inputs={"continuation_reasons": selected_by_rule.get("continuation_reasons", [])},
            )
        )
    return dedupe_decision_rules(rules)


def build_gate_decision_rules(
    *,
    gate_state: str,
    blocker: str,
    failing_validators: list[str],
    refinement_acceptance: dict[str, Any] | None,
) -> list[dict[str, Any]]:
    rules: list[dict[str, Any]] = []
    if gate_state in GATE_ACTION_PRIORITY:
        rules.append(
            policy_rule(
                f"selection_priorities.gate_action_priority.{gate_state}",
                reason="pending gate ordering uses the declarative gate-state priority map",
                matched_value=GATE_ACTION_PRIORITY.get(gate_state),
                inputs={"gate_state": gate_state},
            )
        )
    if refinement_acceptance is not None:
        change_class = str(refinement_acceptance.get("change_class", "")).strip()
        decision = str(refinement_acceptance.get("decision", "")).strip()
        if change_class:
            rules.append(
                policy_rule(
                    f"change_classification.change_classes.{change_class}",
                    reason="gate outcome used the classified semantic change scope",
                    inputs={"decision": decision, "change_class": change_class},
                )
            )
        for mutation_class in refinement_acceptance.get("mutation_classes", []):
            if mutation_class in KNOWN_MUTATION_CLASSES:
                rules.append(
                    policy_rule(
                        f"mutation_classes.{mutation_class}",
                        reason="detected mutation classes contributed to gate evaluation",
                        inputs={"decision": decision},
                    )
                )
        budget_exceeded = list(refinement_acceptance.get("budget_exceeded_classes", []))
        if budget_exceeded:
            rules.append(
                runtime_rule(
                    "gate.review_required_due_to_mutation_budget",
                    reason=(
                        "manual review was required because the requested mutation "
                        "budget was exceeded"
                    ),
                    matched_value=budget_exceeded,
                    inputs={"decision": decision},
                )
            )
        elif decision == REFINEMENT_ACCEPT_DECISION_REVIEW_REQUIRED:
            rules.append(
                runtime_rule(
                    "gate.review_required_due_to_non_local_change",
                    reason=(
                        "manual review was required because the change was not a local refinement"
                    ),
                    matched_value=change_class,
                )
            )
        elif decision == REFINEMENT_ACCEPT_DECISION_REJECT:
            rules.append(
                runtime_rule(
                    "gate.reject_due_to_refinement_acceptance",
                    reason=(
                        "refinement acceptance rejected the candidate change before gate promotion"
                    ),
                    matched_value=list(refinement_acceptance.get("errors", [])),
                )
            )
    if failing_validators:
        rules.append(
            runtime_rule(
                "gate.failing_validators",
                reason="failing validators contributed to the final gate state or blocker",
                matched_value=failing_validators,
            )
        )
    if blocker and blocker != "none":
        rules.append(
            runtime_rule(
                "gate.blocker",
                reason="a concrete runtime or validation blocker propagated into the gate result",
                matched_value=blocker,
            )
        )
    return dedupe_decision_rules(rules)


def build_diff_classification_rules(
    *,
    refinement_acceptance: dict[str, Any] | None,
) -> list[dict[str, Any]]:
    if refinement_acceptance is None:
        return []
    rules: list[dict[str, Any]] = []
    change_class = str(refinement_acceptance.get("change_class", "")).strip()
    if change_class:
        rules.append(
            policy_rule(
                f"change_classification.change_classes.{change_class}",
                reason="canonical diff paths were classified under this semantic change class",
                inputs={"diff_paths": refinement_acceptance.get("diff_paths", [])},
            )
        )
        if change_class in {REFINEMENT_CLASS_GRAPH_REFACTOR, REFINEMENT_CLASS_CONSTITUTIONAL}:
            rules.append(
                policy_rule(
                    f"change_classification.change_classes.{change_class}.diff_prefixes",
                    reason=(
                        "named diff-prefix families were consulted when classifying "
                        "the accepted change"
                    ),
                )
            )
    for mutation_class in refinement_acceptance.get("mutation_classes", []):
        if mutation_class in KNOWN_MUTATION_CLASSES:
            rules.append(
                policy_rule(
                    f"mutation_classes.{mutation_class}",
                    reason=(
                        "detected mutation classes summarize the accepted canonical change surface"
                    ),
                )
            )
    if any(
        path_matches_prefix(path, IMMUTABLE_DIFF_PREFIXES)
        for path in refinement_acceptance.get("diff_paths", [])
    ):
        rules.append(
            policy_rule(
                "change_classification.immutable_diff_prefixes",
                reason=(
                    "immutable identity prefixes were checked while classifying the canonical diff"
                ),
            )
        )
    return dedupe_decision_rules(rules)


def build_queue_effect_rules(
    *,
    graph_health: dict[str, Any],
    proposal_queue_transition: dict[str, Any],
    refactor_queue_transition: dict[str, Any],
) -> list[dict[str, Any]]:
    rules: list[dict[str, Any]] = []
    governance_signals = set(policy_lookup("queue_policy.governance_proposal_signals"))
    subtree_shape_signals = set(policy_lookup("queue_policy.subtree_shape_signals"))
    lower_boundary_signals = set(policy_lookup("queue_policy.lower_boundary_handoff_signals"))
    for signal_value in graph_health.get("signals", []):
        signal = str(signal_value).strip()
        if not signal:
            continue
        rules.append(
            policy_rule(
                f"queue_policy.default_actions.{signal}",
                reason=(
                    "each graph-health signal emits its default recommended action "
                    "from the policy layer"
                ),
                inputs={"signal": signal},
            )
        )
        if signal in governance_signals:
            rules.append(
                policy_rule(
                    "queue_policy.governance_proposal_signals",
                    reason="this signal is handled proposal-first as a governance concern",
                    matched_value=signal,
                )
            )
        if signal in subtree_shape_signals:
            rules.append(
                policy_rule(
                    "queue_policy.subtree_shape_signals",
                    reason=(
                        "this signal belongs to the subtree-shape family that prefers "
                        "rewrite/merge proposals"
                    ),
                    matched_value=signal,
                )
            )
        if signal in lower_boundary_signals:
            rules.append(
                policy_rule(
                    "queue_policy.lower_boundary_handoff_signals",
                    reason="this signal belongs to the lower-boundary handoff family",
                    matched_value=signal,
                )
            )
        work_item_type = classify_refactor_work_item(signal)
        threshold_policy_path = "queue_policy.proposal_thresholds.default_graph_refactor"
        if signal == RETROSPECTIVE_REFACTOR_SIGNAL:
            threshold_policy_path = (
                "queue_policy.proposal_thresholds.retrospective_refactor_candidate"
            )
        elif work_item_type == "governance_proposal":
            threshold_policy_path = "queue_policy.proposal_thresholds.governance_proposal"
        rules.append(
            policy_rule(
                threshold_policy_path,
                reason=(
                    "proposal emission consulted the declarative supporting-run "
                    "threshold for this signal family"
                ),
                matched_value=proposal_threshold_for_signal(
                    signal=signal,
                    work_item_type=work_item_type,
                ),
                inputs={"signal": signal, "work_item_type": work_item_type},
            )
        )

    if proposal_queue_transition["emitted_ids"] or proposal_queue_transition["updated_ids"]:
        rules.append(
            runtime_rule(
                "queue.proposal_queue_transition",
                reason="proposal queue changed after applying graph-health signal rules",
                matched_value=proposal_queue_transition,
            )
        )
    if refactor_queue_transition["emitted_ids"] or refactor_queue_transition["updated_ids"]:
        rules.append(
            runtime_rule(
                "queue.refactor_queue_transition",
                reason="refactor queue changed after applying graph-health signal rules",
                matched_value=refactor_queue_transition,
            )
        )
    return dedupe_decision_rules(rules)


def build_decision_inspector(
    *,
    run_id: str,
    spec_id: str,
    selected_by_rule: dict[str, Any],
    outcome: str,
    gate_state: str,
    required_human_action: str,
    blocker: str,
    changed_files: list[str],
    validator_results: dict[str, bool] | None,
    graph_health: dict[str, Any],
    graph_health_truth_basis: str,
    proposal_queue_before: list[dict[str, Any]] | None,
    proposal_queue_after: list[dict[str, Any]] | None,
    refactor_queue_before: list[dict[str, Any]] | None,
    refactor_queue_after: list[dict[str, Any]] | None,
    refinement_acceptance: dict[str, Any] | None = None,
    validation_errors: list[str] | None = None,
    validation_findings: list[dict[str, Any]] | None = None,
    pending_review_findings: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    normalized_validation_findings = coerce_validation_findings(validation_findings)
    normalized_pending_review_findings = coerce_validation_findings(pending_review_findings)
    if not normalized_validation_findings and validation_errors:
        normalized_validation_findings = string_errors_to_validation_findings(
            validation_errors,
            family="artifact",
            error_class="contract_failure",
            code="legacy_validation_error",
            spec_id=spec_id,
        )
    failing_validators = sorted(
        name for name, ok in (validator_results or {}).items() if not bool(ok)
    )
    proposal_queue_transition = summarize_queue_transition(
        source_spec_id=spec_id,
        before_items=proposal_queue_before,
        after_items=proposal_queue_after,
    )
    refactor_queue_transition = summarize_queue_transition(
        source_spec_id=spec_id,
        before_items=refactor_queue_before,
        after_items=refactor_queue_after,
    )
    diff_classification = {
        "changed_files": list(changed_files),
        "changed_spec_files": [path for path in changed_files if is_spec_node_path(path)],
        "validation_error_count": len(normalized_validation_findings),
        "validation_summary": validation_summary(normalized_validation_findings),
        "graph_health_truth_basis": graph_health_truth_basis,
    }
    if refinement_acceptance is not None:
        diff_classification.update(
            {
                "refinement_decision": str(refinement_acceptance.get("decision", "")).strip(),
                "change_class": str(refinement_acceptance.get("change_class", "")).strip(),
                "mutation_classes": list(refinement_acceptance.get("mutation_classes", [])),
                "review_reasons": list(refinement_acceptance.get("review_reasons", [])),
                "budget_exceeded_classes": list(
                    refinement_acceptance.get("budget_exceeded_classes", [])
                ),
            }
        )
    diff_classification["applied_rules"] = build_diff_classification_rules(
        refinement_acceptance=refinement_acceptance,
    )
    return {
        "artifact_kind": "decision_inspector",
        "run_id": run_id,
        "policy_reference": supervisor_policy_reference(),
        "selection": {
            "spec_id": spec_id,
            "mode": str(selected_by_rule.get("selection_mode", "")).strip(),
            "rule_inputs": copy.deepcopy(selected_by_rule),
            "applied_rules": build_selection_decision_rules(selected_by_rule),
        },
        "gate": {
            "outcome": outcome,
            "gate_state": gate_state,
            "required_human_action": required_human_action,
            "blocker": blocker,
            "failing_validators": failing_validators,
            "validation_findings": normalized_validation_findings,
            "pending_review_findings": normalized_pending_review_findings,
            "applied_rules": build_gate_decision_rules(
                gate_state=gate_state,
                blocker=blocker,
                failing_validators=failing_validators,
                refinement_acceptance=refinement_acceptance,
            ),
        },
        "diff_classification": diff_classification,
        "queue_effects": {
            "signals": list(graph_health.get("signals", [])),
            "recommended_actions": list(graph_health.get("recommended_actions", [])),
            "proposal_queue": proposal_queue_transition,
            "refactor_queue": refactor_queue_transition,
            "applied_rules": build_queue_effect_rules(
                graph_health=graph_health,
                proposal_queue_transition=proposal_queue_transition,
                refactor_queue_transition=refactor_queue_transition,
            ),
        },
    }


def artifact_lock_path(path: Path) -> Path:
    return path.with_name(f"{path.name}.lock")


@contextmanager
def artifact_lock(path: Path):
    path.parent.mkdir(parents=True, exist_ok=True)
    lock_path = artifact_lock_path(path)
    deadline = time.monotonic() + ARTIFACT_LOCK_TIMEOUT_SECONDS
    acquired = False
    while not acquired:
        try:
            fd = os.open(lock_path, os.O_CREAT | os.O_EXCL | os.O_WRONLY, 0o600)
        except FileExistsError as exc:
            if time.monotonic() >= deadline:
                try:
                    lock_display = lock_path.relative_to(ROOT).as_posix()
                except ValueError:
                    lock_display = lock_path.as_posix()
                raise RuntimeError(f"Timed out waiting for artifact lock: {lock_display}") from exc
            time.sleep(ARTIFACT_LOCK_POLL_SECONDS)
            continue
        with os.fdopen(fd, "w", encoding="utf-8") as lock_file:
            lock_file.write(
                json.dumps(
                    {
                        "pid": os.getpid(),
                        "thread": threading.get_ident(),
                        "locked_at": utc_now_iso(),
                    },
                    ensure_ascii=False,
                )
            )
        acquired = True
    try:
        yield
    finally:
        try:
            lock_path.unlink()
        except FileNotFoundError:
            pass


def atomic_write_text(path: Path, text: str) -> Path:
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp_path = path.with_name(f".{path.name}.{os.getpid()}.{threading.get_ident()}.tmp")
    try:
        tmp_path.write_text(text, encoding="utf-8")
        os.replace(tmp_path, path)
    finally:
        if tmp_path.exists():
            tmp_path.unlink()
    return path


def atomic_write_json(path: Path, payload: Any) -> Path:
    return atomic_write_text(path, json.dumps(payload, ensure_ascii=False, indent=2))


def display_artifact_path(path: Path) -> str:
    try:
        return path.relative_to(ROOT).as_posix()
    except ValueError:
        return path.as_posix()


def load_json_object_report(path: Path, *, artifact_kind: str) -> tuple[dict[str, Any] | None, str]:
    try:
        raw_text = path.read_text(encoding="utf-8")
    except OSError as exc:
        return None, f"Failed to read {artifact_kind}: {display_artifact_path(path)} ({exc})"
    try:
        data = json.loads(raw_text)
    except json.JSONDecodeError as exc:
        return (
            None,
            f"Malformed {artifact_kind}: {display_artifact_path(path)} ({exc})",
        )
    if not isinstance(data, dict):
        return (
            None,
            f"Malformed {artifact_kind}: {display_artifact_path(path)} must contain a JSON object",
        )
    return data, ""


def load_json_list_report(
    path: Path,
    *,
    artifact_kind: str,
) -> tuple[list[dict[str, Any]] | None, str]:
    try:
        raw_text = path.read_text(encoding="utf-8")
    except OSError as exc:
        return None, f"Failed to read {artifact_kind}: {display_artifact_path(path)} ({exc})"
    try:
        data = json.loads(raw_text)
    except json.JSONDecodeError as exc:
        return (
            None,
            f"Malformed {artifact_kind}: {display_artifact_path(path)} ({exc})",
        )
    if not isinstance(data, list):
        return (
            None,
            f"Malformed {artifact_kind}: {display_artifact_path(path)} must contain a JSON list",
        )
    if not all(isinstance(item, dict) for item in data):
        return (
            None,
            (
                f"Malformed {artifact_kind}: {display_artifact_path(path)} must contain only "
                "JSON objects"
            ),
        )
    return list(data), ""


def load_json_object(path: Path) -> dict[str, Any] | None:
    data, _error = load_json_object_report(path, artifact_kind="JSON artifact")
    return data


def intent_layer_valid_kinds() -> set[str]:
    return set(INTENT_LAYER_ALLOWED_KINDS)


def intent_layer_valid_states() -> set[str]:
    return set(INTENT_LAYER_ALLOWED_STATES)


def intent_layer_kind_required_sections(kind: str) -> tuple[str, ...]:
    raw_sections = INTENT_LAYER_REQUIRED_SECTIONS_BY_KIND.get(str(kind).strip(), [])
    return tuple(str(section).strip() for section in raw_sections if str(section).strip())


def build_intent_layer_overlay() -> dict[str, Any]:
    nodes_dir = intent_layer_nodes_dir_path()
    entries: list[dict[str, Any]] = []
    artifact_warnings: list[dict[str, str]] = []
    raw_nodes: list[dict[str, Any]] = []

    if nodes_dir.exists():
        for path in sorted(nodes_dir.glob("*.json")):
            data, error = load_json_object_report(path, artifact_kind="intent layer node artifact")
            if data is None:
                artifact_warnings.append(
                    {
                        "tracked_path": display_artifact_path(path),
                        "error": error,
                    }
                )
                continue
            raw_nodes.append({"tracked_path": display_artifact_path(path), "node": data})

    handle_counts: dict[str, int] = {}
    for raw in raw_nodes:
        node = raw["node"]
        presence = node.get("intent_repository_presence")
        handle = node.get("intent_handle")
        if (
            isinstance(presence, dict)
            and all(
                str(presence.get(key, "")).strip() == str(value)
                for key, value in INTENT_LAYER_PRESENCE_CONTRACT.items()
            )
            and isinstance(handle, dict)
            and str(handle.get("handle_status", "")).strip() == "active"
        ):
            handle_value = str(handle.get("handle_value", "")).strip()
            if handle_value:
                handle_counts[handle_value] = handle_counts.get(handle_value, 0) + 1

    by_kind: dict[str, list[str]] = {}
    by_state: dict[str, list[str]] = {}
    named_filters = {name: [] for name in INTENT_LAYER_NAMED_FILTERS}
    edges: list[dict[str, str]] = []

    for raw in raw_nodes:
        tracked_path = str(raw["tracked_path"])
        node = raw["node"]
        presence = node.get("intent_repository_presence")
        if not (
            isinstance(presence, dict)
            and all(
                str(presence.get(key, "")).strip() == str(value)
                for key, value in INTENT_LAYER_PRESENCE_CONTRACT.items()
            )
        ):
            continue

        handle = node.get("intent_handle", {})
        handle_value = str(handle.get("handle_value", "")).strip()
        intent_kind = str(node.get("intent_layer_kind", "")).strip()
        mediation_state = str(node.get("mediation_state", "")).strip()
        lineage_links = node.get("intent_lineage_link", [])
        runtime_bridge = node.get("runtime_bridge", {})
        request_bridge = node.get("request_bridge", {})
        query_findings: list[str] = []
        if not handle_value or str(handle.get("handle_status", "")).strip() != "active":
            query_findings.append("missing_active_handle")
        if intent_kind not in intent_layer_valid_kinds():
            query_findings.append("invalid_intent_layer_kind")
        if mediation_state not in intent_layer_valid_states():
            query_findings.append("invalid_mediation_state")
        if not (
            isinstance(lineage_links, list)
            and any(
                isinstance(link, dict)
                and str(link.get("lineage_role", "")).strip()
                and str(link.get("source_kind", "")).strip()
                and str(link.get("source_reference", "")).strip()
                for link in lineage_links
            )
        ):
            query_findings.append("missing_lineage_link")
        if handle_value and handle_counts.get(handle_value, 0) > 1:
            query_findings.append("colliding_active_handle")

        required_sections = intent_layer_kind_required_sections(intent_kind)
        for section_name in required_sections:
            if not isinstance(node.get(section_name), dict):
                query_findings.append(f"missing_kind_section::{section_name}")
        if intent_kind == "user_intent" and isinstance(request_bridge, dict) and request_bridge:
            query_findings.append("kind_contract_mismatch::user_intent_has_request_bridge")
        if intent_kind == "operator_request":
            if not (
                isinstance(request_bridge, dict)
                and str(request_bridge.get("run_mode", "")).strip()
                and str(request_bridge.get("target_spec_id", "")).strip()
            ):
                query_findings.append("missing_request_bridge_target")
        if any(field in node for field in INTENT_LAYER_CANONICAL_SPEC_FORBIDDEN_FIELDS):
            query_findings.append("masquerades_as_canonical_spec")
        if any(field in node for field in INTENT_LAYER_PROPOSAL_LANE_FORBIDDEN_FIELDS):
            query_findings.append("masquerades_as_proposal_lane")
        entry = {
            "tracked_path": tracked_path,
            "title": str(node.get("title", "")).strip(),
            "intent_handle": handle_value,
            "intent_layer_kind": intent_kind,
            "mediation_state": mediation_state,
            "distinction_contract": {
                "semantic_artifact_class": intent_kind or "unknown",
                "canonical_equivalence": False,
                "proposal_lane_equivalence": False,
                "pre_canonical_runtime_mediation": True,
            },
            "query_contract": {
                "status": "invalid_review_state" if query_findings else "ok",
                "findings": sorted(set(query_findings)),
            },
            "lineage_links": (
                copy.deepcopy(lineage_links) if isinstance(lineage_links, list) else []
            ),
            "runtime_bridge": (
                copy.deepcopy(runtime_bridge) if isinstance(runtime_bridge, dict) else {}
            ),
        }
        if isinstance(request_bridge, dict) and request_bridge:
            entry["request_bridge"] = copy.deepcopy(request_bridge)
        entries.append(entry)

        by_kind.setdefault(intent_kind or "unknown", []).append(handle_value or tracked_path)
        by_state.setdefault(mediation_state or "unknown", []).append(handle_value or tracked_path)
        if intent_kind in named_filters:
            named_filters[intent_kind].append(handle_value or tracked_path)
        if mediation_state in named_filters:
            named_filters[mediation_state].append(handle_value or tracked_path)
        if query_findings:
            named_filters["invalid_query_contract"].append(handle_value or tracked_path)

        for link in lineage_links if isinstance(lineage_links, list) else []:
            if not isinstance(link, dict):
                continue
            source_reference = str(link.get("source_reference", "")).strip()
            if not source_reference:
                continue
            edges.append(
                {
                    "source": handle_value or tracked_path,
                    "target": source_reference,
                    "edge_kind": (
                        f"lineage::{str(link.get('lineage_role', '')).strip()}::"
                        f"{str(link.get('source_kind', '')).strip()}"
                    ),
                }
            )

    for key, values in list(named_filters.items()):
        named_filters[key] = sorted(set(values))
    entries.sort(
        key=lambda item: (
            item["intent_layer_kind"],
            item["intent_handle"],
            item["tracked_path"],
        )
    )
    return {
        "artifact_kind": INTENT_LAYER_OVERLAY_ARTIFACT_KIND,
        "schema_version": INTENT_LAYER_OVERLAY_SCHEMA_VERSION,
        "layer_name": INTENT_LAYER_LAYER_NAME,
        "generated_at": utc_now_iso(),
        "policy_reference": intent_layer_policy_reference(),
        "source_dir": INTENT_LAYER_NODES_RELATIVE_DIR,
        "entry_count": len(entries),
        "entries": entries,
        "by_kind": {key: sorted(set(values)) for key, values in sorted(by_kind.items())},
        "by_mediation_state": {
            key: sorted(set(values)) for key, values in sorted(by_state.items())
        },
        "named_filters": named_filters,
        "edges": edges,
        "artifact_warnings": artifact_warnings,
    }


def write_intent_layer_overlay(overlay: dict[str, Any]) -> Path:
    path = intent_layer_overlay_path()
    with artifact_lock(path):
        atomic_write_json(path, overlay)
    return path


def _normalize_packet_string_list(
    *,
    field_name: str,
    value: Any,
) -> tuple[list[str], list[str]]:
    if value in (None, ""):
        return [], []
    raw_items: list[Any]
    if isinstance(value, str):
        raw_items = [item.strip() for item in value.split(",") if item.strip()]
    elif isinstance(value, list):
        raw_items = value
    else:
        return [], [f"{field_name} must be a string or list of strings"]

    normalized: list[str] = []
    errors: list[str] = []
    for idx, item in enumerate(raw_items):
        if not isinstance(item, str) or not item.strip():
            errors.append(f"{field_name}[{idx}] must be a non-empty string")
            continue
        normalized.append(item.strip())
    return normalized, errors


def _normalize_vocabulary_term(
    *,
    field_name: str,
    value: Any,
    family: str,
) -> tuple[str, list[str]]:
    normalized = str(value).strip()
    if not normalized:
        return "", []
    resolution = vocabulary_term_resolution(normalized, family=family)
    if resolution is None:
        return "", [f"{field_name} must use a defined {family} term"]
    return str(resolution["canonical_term"]).strip(), []


def _normalize_vocabulary_term_list(
    *,
    field_name: str,
    value: Any,
    family: str,
    default_terms: tuple[str, ...] = (),
) -> tuple[list[str], list[str]]:
    normalized_items, errors = _normalize_packet_string_list(field_name=field_name, value=value)
    if errors:
        return [], errors
    if not normalized_items:
        normalized_items = list(default_terms)

    normalized_terms: list[str] = []
    for idx, item in enumerate(normalized_items):
        canonical_term, term_errors = _normalize_vocabulary_term(
            field_name=f"{field_name}[{idx}]",
            value=item,
            family=family,
        )
        errors.extend(term_errors)
        if canonical_term:
            normalized_terms.append(canonical_term)
    if errors:
        return [], errors
    return list(dict.fromkeys(normalized_terms)), []


def default_user_intent_handle(source_summary: str) -> str:
    slug = sanitize_for_git(source_summary)[:48]
    return f"user_intent::{slug or 'intent'}"


def default_operator_request_handle(
    *,
    target_spec_id: str,
    run_mode: str,
    source_summary: str,
) -> str:
    target = sanitize_for_git(target_spec_id).upper() if target_spec_id else "UNSCOPED"
    mode = sanitize_for_git(run_mode) or "request"
    summary = sanitize_for_git(source_summary)[:32] or "intent"
    return f"operator_request::{target}::{mode}::{summary}"


def normalize_operator_request_packet(
    path: Path,
    *,
    specs: list[SpecNode],
) -> tuple[dict[str, Any] | None, list[str]]:
    # Trace anchor: SG-SPEC-0009 governs single-run OperatorRequest steering.
    packet, error = load_json_object_report(path, artifact_kind="operator request packet")
    if packet is None:
        return None, [error]

    errors: list[str] = []
    if str(packet.get("artifact_kind", "")).strip() != OPERATOR_REQUEST_PACKET_ARTIFACT_KIND:
        errors.append(
            "operator request packet must declare "
            f"artifact_kind: {OPERATOR_REQUEST_PACKET_ARTIFACT_KIND}"
        )
    raw_schema_version = packet.get("schema_version", 0)
    try:
        schema_version = int(raw_schema_version or 0)
    except (TypeError, ValueError):
        errors.append("operator request packet schema_version must be an integer")
        schema_version = None
    if schema_version is not None and schema_version != OPERATOR_REQUEST_PACKET_SCHEMA_VERSION:
        errors.append(
            "operator request packet must declare "
            f"schema_version: {OPERATOR_REQUEST_PACKET_SCHEMA_VERSION}"
        )

    for section_name in OPERATOR_REQUEST_REQUIRED_TOP_LEVEL_SECTIONS:
        if not isinstance(packet.get(section_name), dict):
            errors.append(f"operator request packet must contain object section: {section_name}")

    user_intent = packet.get("user_intent") if isinstance(packet.get("user_intent"), dict) else {}
    operator_request = (
        packet.get("operator_request") if isinstance(packet.get("operator_request"), dict) else {}
    )

    for field_name in OPERATOR_REQUEST_REQUIRED_USER_INTENT_FIELDS:
        if not str(user_intent.get(field_name, "")).strip():
            errors.append(f"user_intent.{field_name} must be a non-empty string")
    for field_name in OPERATOR_REQUEST_REQUIRED_REQUEST_FIELDS:
        if not str(operator_request.get(field_name, "")).strip():
            errors.append(f"operator_request.{field_name} must be a non-empty string")

    source_kind, source_kind_errors = _normalize_vocabulary_term(
        field_name="user_intent.source_kind",
        value=user_intent.get("source_kind"),
        family="operator_request_source_kind",
    )
    errors.extend(source_kind_errors)
    source_summary = str(user_intent.get("source_summary", "")).strip()
    selected_node_ref = str(user_intent.get("selected_node_ref", "")).strip()
    unresolved_questions, unresolved_question_errors = _normalize_packet_string_list(
        field_name="user_intent.unresolved_questions",
        value=user_intent.get("unresolved_questions"),
    )
    errors.extend(unresolved_question_errors)

    run_mode, run_mode_errors = _normalize_vocabulary_term(
        field_name="operator_request.run_mode",
        value=operator_request.get("run_mode"),
        family="operator_request_run_mode",
    )
    errors.extend(run_mode_errors)
    target_spec_id = str(operator_request.get("target_spec_id", "")).strip()
    if target_spec_id and target_spec_id not in {spec.id for spec in specs}:
        errors.append(f"operator_request.target_spec_id not found: {target_spec_id}")

    operator_note = str(operator_request.get("operator_note", "")).strip()
    mutation_budget_list, mutation_budget_errors = _normalize_packet_string_list(
        field_name="operator_request.mutation_budget",
        value=operator_request.get("mutation_budget"),
    )
    run_authority_list, run_authority_errors = _normalize_packet_string_list(
        field_name="operator_request.run_authority",
        value=operator_request.get("run_authority"),
    )
    errors.extend(mutation_budget_errors)
    errors.extend(run_authority_errors)
    stop_conditions, stop_condition_errors = _normalize_vocabulary_term_list(
        field_name="operator_request.stop_conditions",
        value=operator_request.get("stop_conditions"),
        family="operator_request_stop_condition",
        default_terms=OPERATOR_REQUEST_DEFAULT_STOP_CONDITIONS,
    )
    errors.extend(stop_condition_errors)

    mutation_budget: tuple[str, ...] = ()
    run_authority: tuple[str, ...] = ()
    if not mutation_budget_errors:
        try:
            mutation_budget = parse_mutation_budget(",".join(mutation_budget_list))
        except ValueError as exc:
            errors.append(str(exc))
    if not run_authority_errors:
        try:
            run_authority = parse_run_authority(",".join(run_authority_list))
        except ValueError as exc:
            errors.append(str(exc))

    execution_profile_value = str(operator_request.get("execution_profile", "")).strip()
    execution_profile: str | None = execution_profile_value or None
    if execution_profile is not None:
        try:
            execution_profile = resolve_execution_profile_name(
                requested_profile=execution_profile,
                run_authority=run_authority,
                operator_target=True,
            )
        except ValueError as exc:
            errors.append(str(exc))

    if errors:
        return None, errors

    user_intent_handle = str(user_intent.get("intent_handle", "")).strip() or (
        default_user_intent_handle(source_summary)
    )
    operator_request_handle = str(
        operator_request.get("request_handle", "")
    ).strip() or default_operator_request_handle(
        target_spec_id=target_spec_id,
        run_mode=run_mode,
        source_summary=source_summary,
    )
    packet_reference = display_artifact_path(path)
    execution_contract = {
        "authority": {
            "requested_run_authority": list(run_authority),
            "canonical_write_boundary": "forbidden",
            "allowed_downstream_routes": list(
                operator_request_bridge_policy_lookup("bridge_boundary.allowed_downstream_routes")
            ),
        },
        "mutation_budget": list(mutation_budget),
        "stop_conditions": list(stop_conditions),
        "execution_profile": execution_profile or "",
    }
    return (
        {
            "packet_reference": packet_reference,
            "policy_reference": operator_request_bridge_policy_reference(),
            "user_intent": {
                "handle": user_intent_handle,
                "source_kind": source_kind,
                "source_summary": source_summary,
                "selected_node_ref": selected_node_ref,
                "unresolved_questions": unresolved_questions,
            },
            "operator_request": {
                "handle": operator_request_handle,
                "target_spec_id": target_spec_id,
                "run_mode": run_mode,
                "operator_note": operator_note,
                "mutation_budget": mutation_budget,
                "run_authority": run_authority,
                "stop_conditions": tuple(stop_conditions),
                "execution_profile": execution_profile,
                "execution_contract": execution_contract,
            },
        },
        [],
    )


def sync_user_intent_node(context: dict[str, Any]) -> tuple[Path, dict[str, Any]]:
    user_intent = context["user_intent"]
    handle_value = str(user_intent["handle"]).strip()
    path = intent_layer_node_path(handle_value)
    tracked_path = path.relative_to(ROOT).as_posix()
    existing = load_json_object(path) if path.exists() else None
    created_at = str((existing or {}).get("created_at", "")).strip() or utc_now_iso()
    packet_reference = str(context.get("packet_reference", "")).strip()
    node = dict(existing or {})
    user_intent_status = (
        "mediated"
        if str(user_intent.get("source_kind", "")).strip() == "mediated_artifact"
        else "captured"
    )
    user_intent_authority = (
        "mediator"
        if str(user_intent.get("source_kind", "")).strip() == "mediated_artifact"
        else "external_actor"
    )
    node.update(
        {
            "artifact_kind": INTENT_LAYER_NODE_ARTIFACT_KIND,
            "schema_version": INTENT_LAYER_NODE_SCHEMA_VERSION,
            "title": f"User intent: {str(user_intent.get('source_summary', '')).strip()}",
            "created_at": created_at,
            "updated_at": utc_now_iso(),
            "policy_reference": intent_layer_policy_reference(),
            "vocabulary_reference": specgraph_vocabulary_reference(),
            "intent_repository_presence": {
                **copy.deepcopy(INTENT_LAYER_PRESENCE_CONTRACT),
                "tracked_path": tracked_path,
            },
            "intent_handle": {
                "handle_value": handle_value,
                "handle_status": "active",
            },
            "intent_layer_kind": "user_intent",
            "mediation_state": user_intent_status,
            "pre_spec_semantics": {
                "policy_reference": pre_spec_semantics_policy_reference(),
                "phase": PRE_SPEC_SEMANTICS_PHASE,
                "semantic_artifact_class": "user_intent",
                "status": user_intent_status,
                "authority": user_intent_authority,
                "required_axes": list(PRE_SPEC_REQUIRED_AXES),
                "implemented_axes": pre_spec_semantics_policy_lookup(
                    "axes_contract.implemented_axes"
                ),
                "adjacent_primary_kinds": list(
                    PRE_SPEC_IMPLEMENTED_ARTIFACT_CLASSES["user_intent"]["adjacent_primary_kinds"]
                ),
                "canonical_boundary": str(
                    pre_spec_semantics_policy_lookup("semantic_boundary.canonical_boundary")
                ),
            },
            "intent_capture": {
                "source_kind": str(user_intent.get("source_kind", "")).strip(),
                "source_summary": str(user_intent.get("source_summary", "")).strip(),
                "selected_node_ref": str(user_intent.get("selected_node_ref", "")).strip(),
                "unresolved_questions": list(user_intent.get("unresolved_questions", [])),
            },
            "intent_lineage_link": [
                {
                    "lineage_role": "captured_from",
                    "source_kind": "runtime_artifact",
                    "source_reference": packet_reference,
                }
            ],
            "runtime_bridge": {
                "latest_operator_request_handle": str(
                    context.get("operator_request", {}).get("handle", "")
                ).strip(),
                "latest_packet_reference": packet_reference,
            },
        }
    )
    path.parent.mkdir(parents=True, exist_ok=True)
    with artifact_lock(path):
        atomic_write_json(path, node)
    return path, node


def sync_operator_request_node(
    context: dict[str, Any],
    *,
    user_intent_handle: str,
) -> tuple[Path, dict[str, Any]]:
    request = context["operator_request"]
    handle_value = str(request["handle"]).strip()
    path = intent_layer_node_path(handle_value)
    tracked_path = path.relative_to(ROOT).as_posix()
    existing = load_json_object(path) if path.exists() else None
    created_at = str((existing or {}).get("created_at", "")).strip() or utc_now_iso()
    packet_reference = str(context.get("packet_reference", "")).strip()
    node = dict(existing or {})
    node.update(
        {
            "artifact_kind": INTENT_LAYER_NODE_ARTIFACT_KIND,
            "schema_version": INTENT_LAYER_NODE_SCHEMA_VERSION,
            "title": (
                "Operator request for "
                f"{str(request.get('target_spec_id', '')).strip() or 'unscoped target'}"
            ),
            "created_at": created_at,
            "updated_at": utc_now_iso(),
            "policy_reference": intent_layer_policy_reference(),
            "bridge_policy_reference": operator_request_bridge_policy_reference(),
            "vocabulary_reference": specgraph_vocabulary_reference(),
            "intent_repository_presence": {
                **copy.deepcopy(INTENT_LAYER_PRESENCE_CONTRACT),
                "tracked_path": tracked_path,
            },
            "intent_handle": {
                "handle_value": handle_value,
                "handle_status": "active",
            },
            "intent_layer_kind": "operator_request",
            "mediation_state": "ready_for_execution",
            "pre_spec_semantics": {
                "policy_reference": pre_spec_semantics_policy_reference(),
                "phase": PRE_SPEC_SEMANTICS_PHASE,
                "semantic_artifact_class": "operator_request",
                "status": "ready_for_execution",
                "authority": "operator",
                "required_axes": list(PRE_SPEC_REQUIRED_AXES),
                "implemented_axes": pre_spec_semantics_policy_lookup(
                    "axes_contract.implemented_axes"
                ),
                "adjacent_primary_kinds": list(
                    PRE_SPEC_IMPLEMENTED_ARTIFACT_CLASSES["operator_request"][
                        "adjacent_primary_kinds"
                    ]
                ),
                "canonical_boundary": str(
                    pre_spec_semantics_policy_lookup("semantic_boundary.canonical_boundary")
                ),
            },
            "request_bridge": {
                "target_spec_id": str(request.get("target_spec_id", "")).strip(),
                "run_mode": str(request.get("run_mode", "")).strip(),
                "operator_note": str(request.get("operator_note", "")).strip(),
                "mutation_budget": list(request.get("mutation_budget", ())),
                "run_authority": list(request.get("run_authority", ())),
                "stop_conditions": list(request.get("stop_conditions", ())),
                "execution_profile": str(request.get("execution_profile", "") or "").strip(),
                "execution_contract": copy.deepcopy(request.get("execution_contract", {})),
            },
            "intent_lineage_link": [
                {
                    "lineage_role": "derived_from",
                    "source_kind": "intent_layer_node",
                    "source_reference": user_intent_handle,
                },
                {
                    "lineage_role": "normalized_from",
                    "source_kind": "runtime_artifact",
                    "source_reference": packet_reference,
                },
            ],
            "runtime_bridge": {
                "latest_packet_reference": packet_reference,
                "bridge_state": "ready_for_execution",
            },
        }
    )
    path.parent.mkdir(parents=True, exist_ok=True)
    with artifact_lock(path):
        atomic_write_json(path, node)
    return path, node


def sync_intent_layer_from_operator_request(context: dict[str, Any]) -> dict[str, Any]:
    user_intent_path, user_intent_node = sync_user_intent_node(context)
    user_intent_handle = str(
        user_intent_node.get("intent_handle", {}).get("handle_value", "")
    ).strip()
    operator_request_path, operator_request_node = sync_operator_request_node(
        context,
        user_intent_handle=user_intent_handle,
    )
    specs = load_specs()
    refresh_vocabulary_artifacts(specs)
    refresh_pre_spec_semantics_artifacts(specs)
    return {
        "user_intent_path": user_intent_path.relative_to(ROOT).as_posix(),
        "user_intent_handle": str(
            user_intent_node.get("intent_handle", {}).get("handle_value", "")
        ).strip(),
        "operator_request_path": operator_request_path.relative_to(ROOT).as_posix(),
        "operator_request_handle": str(
            operator_request_node.get("intent_handle", {}).get("handle_value", "")
        ).strip(),
    }


def build_last_pre_spec_provenance(
    *,
    operator_request_context: dict[str, Any] | None,
    proposal_ids: list[str] | None = None,
) -> dict[str, Any] | None:
    if not operator_request_context:
        return None
    user_intent_handle = str(operator_request_context.get("user_intent_handle", "")).strip()
    operator_request_handle = str(
        operator_request_context.get("operator_request_handle", "")
    ).strip()
    packet_reference = str(operator_request_context.get("packet_reference", "")).strip()
    if not any((user_intent_handle, operator_request_handle, packet_reference)):
        return None
    return {
        "policy_reference": pre_spec_semantics_policy_reference(),
        "vocabulary_reference": specgraph_vocabulary_reference(),
        "packet_reference": packet_reference,
        "user_intent_handle": user_intent_handle,
        "operator_request_handle": operator_request_handle,
        "proposal_ids": sorted(
            {str(item).strip() for item in (proposal_ids or []) if str(item).strip()}
        ),
        "recorded_at": utc_now_iso(),
    }


def record_operator_request_execution(
    *,
    operator_request_context: dict[str, Any] | None,
    run_id: str,
    spec_id: str,
    outcome: str,
    gate_state: str,
    proposal_items: list[dict[str, Any]] | None = None,
) -> None:
    if not operator_request_context:
        return

    operator_request_handle = str(
        operator_request_context.get("operator_request_handle", "")
    ).strip()
    user_intent_handle = str(operator_request_context.get("user_intent_handle", "")).strip()
    if not operator_request_handle:
        return

    proposal_ids = sorted(
        {
            str(item.get("id", "")).strip()
            for item in (proposal_items or [])
            if isinstance(item, dict)
            and str(item.get("spec_id", "")).strip() == spec_id
            and str(item.get("operator_request_handle", "")).strip() == operator_request_handle
            and str(item.get("id", "")).strip()
        }
    )
    if proposal_ids:
        mediation_state = "proposal_linked"
        downstream_route = "proposal_lane_emission"
        canonical_spec_ids: list[str] = []
    elif str(gate_state).strip() == "blocked" or str(outcome).strip() == "blocked":
        mediation_state = "blocked"
        downstream_route = "execution_blocked"
        canonical_spec_ids = []
    else:
        mediation_state = "canonical_candidate"
        downstream_route = "supervisor_refinement_candidate"
        canonical_spec_ids = [spec_id]

    operator_request_path = intent_layer_node_path(operator_request_handle)
    operator_request_node = load_json_object(operator_request_path)
    if isinstance(operator_request_node, dict):
        runtime_bridge = dict(operator_request_node.get("runtime_bridge", {}))
        runtime_bridge.update(
            {
                "bridge_state": mediation_state,
                "last_executed_run_id": run_id,
                "last_executed_at": utc_now_iso(),
                "last_outcome": outcome,
                "last_gate_state": gate_state,
                "proposal_ids": proposal_ids,
                "canonical_spec_ids": canonical_spec_ids,
                "downstream_route": downstream_route,
            }
        )
        operator_request_node["mediation_state"] = mediation_state
        if isinstance(operator_request_node.get("pre_spec_semantics"), dict):
            operator_request_node["pre_spec_semantics"]["status"] = mediation_state
        operator_request_node["runtime_bridge"] = runtime_bridge
        operator_request_node["updated_at"] = utc_now_iso()
        with artifact_lock(operator_request_path):
            atomic_write_json(operator_request_path, operator_request_node)

    if user_intent_handle:
        user_intent_path = intent_layer_node_path(user_intent_handle)
        user_intent_node = load_json_object(user_intent_path)
        if isinstance(user_intent_node, dict):
            runtime_bridge = dict(user_intent_node.get("runtime_bridge", {}))
            runtime_bridge.update(
                {
                    "latest_operator_request_handle": operator_request_handle,
                    "latest_run_id": run_id,
                    "latest_outcome": outcome,
                    "latest_gate_state": gate_state,
                    "latest_proposal_ids": proposal_ids,
                    "latest_canonical_spec_ids": canonical_spec_ids,
                    "latest_downstream_route": downstream_route,
                }
            )
            user_intent_node["runtime_bridge"] = runtime_bridge
            user_intent_node["updated_at"] = utc_now_iso()
            with artifact_lock(user_intent_path):
                atomic_write_json(user_intent_path, user_intent_node)

    specs = load_specs()
    refresh_vocabulary_artifacts(specs)
    refresh_pre_spec_semantics_artifacts(specs)


def proposal_lane_valid_authority_states() -> set[str]:
    return {str(value).strip() for value in PROPOSAL_LANE_AUTHORITY_STATE_MAPPING.values()}


def proposal_lane_authority_state_for_status(status: str) -> str:
    normalized = str(status).strip()
    return str(PROPOSAL_LANE_AUTHORITY_STATE_MAPPING.get(normalized, "draft"))


def proposal_lane_target_reference(proposal_item: dict[str, Any]) -> str:
    return str(
        proposal_item.get("target_spec_id")
        or proposal_item.get("spec_id")
        or proposal_item.get("target_reference")
        or ""
    ).strip()


def proposal_lane_target_region(proposal_item: dict[str, Any]) -> dict[str, str]:
    target_reference = proposal_lane_target_reference(proposal_item)
    target_kind = "canonical_node" if target_reference else "draft_target_area"
    change_scope = str(
        proposal_item.get("signal") or proposal_item.get("proposal_type") or ""
    ).strip()
    if not change_scope:
        change_scope = str(proposal_item.get("id", "")).strip()
    return {
        "target_kind": target_kind,
        "target_reference": target_reference or str(proposal_item.get("id", "")).strip(),
        "change_scope": change_scope,
    }


def proposal_lane_lineage_links(proposal_item: dict[str, Any]) -> list[dict[str, str]]:
    lineage_links: list[dict[str, str]] = []
    target_reference = proposal_lane_target_reference(proposal_item)
    if target_reference:
        lineage_links.append(
            {
                "lineage_role": "motivated_by",
                "source_kind": "canonical_node",
                "source_reference": target_reference,
            }
        )
    proposal_artifact_path_value = str(proposal_item.get("proposal_artifact_path", "")).strip()
    if proposal_artifact_path_value:
        lineage_links.append(
            {
                "lineage_role": "derived_from",
                "source_kind": "runtime_artifact",
                "source_reference": proposal_artifact_path_value,
            }
        )
    user_intent_handle = str(proposal_item.get("user_intent_handle", "")).strip()
    if user_intent_handle:
        lineage_links.append(
            {
                "lineage_role": "motivated_by",
                "source_kind": "intent_layer_node",
                "source_reference": user_intent_handle,
            }
        )
    operator_request_handle = str(proposal_item.get("operator_request_handle", "")).strip()
    if operator_request_handle:
        lineage_links.append(
            {
                "lineage_role": "derived_from",
                "source_kind": "intent_layer_node",
                "source_reference": operator_request_handle,
            }
        )
    return lineage_links


def proposal_lane_artifact_links(proposal_item: dict[str, Any]) -> list[dict[str, str]]:
    proposal_artifact_path_value = str(proposal_item.get("proposal_artifact_path", "")).strip()
    if not proposal_artifact_path_value:
        return []
    return [
        {
            "artifact_role": "supporting_runtime_artifact",
            "reference_kind": "runtime_artifact",
            "reference_value": proposal_artifact_path_value,
        }
    ]


def proposal_lane_node_title(proposal_item: dict[str, Any]) -> str:
    proposal_type = str(proposal_item.get("proposal_type", "proposal")).strip().replace("_", " ")
    target_reference = proposal_lane_target_reference(proposal_item) or "unscoped target"
    signal = str(proposal_item.get("signal", "")).strip()
    suffix = f" ({signal})" if signal else ""
    return f"{proposal_type.title()} for {target_reference}{suffix}"


def proposal_lane_timestamp_text(value: object) -> str:
    parsed = parse_iso_datetime(value)
    if parsed is None:
        raise ValueError(f"invalid proposal-lane timestamp: {value!r}")
    return parsed.astimezone(dt.timezone.utc).isoformat()


def proposal_lane_optional_timestamp_text(value: object) -> str:
    if value is None:
        return ""
    text = str(value).strip()
    if not text:
        return ""
    return proposal_lane_timestamp_text(text)


def proposal_lane_timestamp_now() -> str:
    return proposal_lane_timestamp_text(utc_now_iso())


def is_proposal_lane_timestamp_text(value: object) -> bool:
    if not isinstance(value, str):
        return False
    text = value.strip()
    if not PROPOSAL_LANE_TIMESTAMP_RE.fullmatch(text):
        return False
    return parse_iso_datetime(text) is not None


def proposal_lane_timestamp_findings(node: dict[str, Any]) -> list[str]:
    findings: list[str] = []
    for field in PROPOSAL_LANE_REQUIRED_TIMESTAMP_FIELDS:
        if not is_proposal_lane_timestamp_text(node.get(field)):
            findings.append(f"invalid_timestamp::{field}")

    runtime_bridge = node.get("runtime_bridge")
    canonical_application_event = node.get("canonical_application_event")
    optional_contexts = {
        "runtime_bridge": runtime_bridge if isinstance(runtime_bridge, dict) else {},
        "canonical_application_event": (
            canonical_application_event if isinstance(canonical_application_event, dict) else {}
        ),
    }
    for field in PROPOSAL_LANE_OPTIONAL_TIMESTAMP_FIELDS:
        section_name, _, key = field.partition(".")
        value = optional_contexts.get(section_name, {}).get(key) if key else node.get(field)
        if str(value or "").strip() and not is_proposal_lane_timestamp_text(value):
            findings.append(f"invalid_timestamp::{field}")

    return findings


# Trace anchor: SG-SPEC-0006 governs repository-tracked proposal lane synchronization.
def sync_tracked_proposal_lane_node(
    proposal_item: dict[str, Any],
) -> tuple[Path, dict[str, Any]] | None:
    handle_value = str(proposal_item.get("id", "")).strip()
    if not handle_value:
        return None

    path = proposal_lane_node_path(handle_value)
    tracked_path = path.relative_to(ROOT).as_posix()
    existing = load_json_object(path) if path.exists() else None
    created_at = proposal_lane_timestamp_text(
        str((existing or {}).get("created_at", "")).strip() or proposal_lane_timestamp_now()
    )
    updated_at = proposal_lane_timestamp_now()
    applied_at = proposal_lane_optional_timestamp_text(proposal_item.get("applied_at", ""))
    authority_state = proposal_lane_authority_state_for_status(
        str(proposal_item.get("status", "")).strip() or "proposed"
    )
    node = dict(existing or {})
    node.update(
        {
            "artifact_kind": PROPOSAL_LANE_NODE_ARTIFACT_KIND,
            "schema_version": PROPOSAL_LANE_NODE_SCHEMA_VERSION,
            "title": proposal_lane_node_title(proposal_item),
            "created_at": created_at,
            "updated_at": updated_at,
            "policy_reference": proposal_lane_policy_reference(),
            "proposal_repository_presence": {
                **copy.deepcopy(PROPOSAL_LANE_PRESENCE_CONTRACT),
                "tracked_path": tracked_path,
            },
            "proposal_handle": {
                "handle_value": handle_value,
                "handle_status": "active",
            },
            "proposal_authority_state": authority_state,
            "proposal_target_region": proposal_lane_target_region(proposal_item),
            "proposal_lineage_link": proposal_lane_lineage_links(proposal_item),
            "proposal_artifact_link": proposal_lane_artifact_links(proposal_item),
            "proposal_payload": {
                "proposal_type": str(proposal_item.get("proposal_type", "")).strip(),
                "trigger": str(proposal_item.get("trigger", "")).strip(),
                "recommended_action": str(proposal_item.get("recommended_action", "")).strip(),
                "signal": str(proposal_item.get("signal", "")).strip(),
                "source_work_item_type": str(
                    proposal_item.get("source_work_item_type", "")
                ).strip(),
                "execution_policy": str(proposal_item.get("execution_policy", "")).strip(),
                "transition_profile": str(proposal_item.get("transition_profile", "")).strip(),
                "packet_type": str(proposal_item.get("packet_type", "")).strip(),
                "target_artifact_class": str(
                    proposal_item.get("target_artifact_class", "")
                ).strip(),
                "user_intent_handle": str(proposal_item.get("user_intent_handle", "")).strip(),
                "operator_request_handle": str(
                    proposal_item.get("operator_request_handle", "")
                ).strip(),
            },
            "runtime_bridge": {
                "proposal_queue_status": str(proposal_item.get("status", "")).strip(),
                "supporting_run_ids": list(proposal_item.get("supporting_run_ids", [])),
                "occurrence_count": proposal_item.get("occurrence_count"),
                "threshold": proposal_item.get("threshold"),
                "proposal_artifact_path": str(
                    proposal_item.get("proposal_artifact_path", "")
                ).strip(),
                "applied_run_id": str(proposal_item.get("applied_run_id", "")).strip(),
                "applied_at": applied_at,
                "operator_request_handle": str(
                    proposal_item.get("operator_request_handle", "")
                ).strip(),
            },
        }
    )
    if str(proposal_item.get("status", "")).strip() == "applied":
        node["canonical_application_event"] = {
            "event_status": "canonical_materialization_recorded",
            "applied_run_id": str(proposal_item.get("applied_run_id", "")).strip(),
            "applied_at": applied_at,
        }
    else:
        node.pop("canonical_application_event", None)

    path.parent.mkdir(parents=True, exist_ok=True)
    with artifact_lock(path):
        atomic_write_json(path, node)
    return path, node


def retire_stale_tracked_proposal_lane_nodes(
    *,
    spec_id: str,
    active_item_ids: set[str],
) -> list[Path]:
    nodes_dir = proposal_lane_nodes_dir_path()
    if not nodes_dir.exists():
        return []

    retired_paths: list[Path] = []
    for path in sorted(nodes_dir.glob("*.json")):
        node = load_json_object(path)
        if not isinstance(node, dict):
            continue
        handle = node.get("proposal_handle")
        handle_value = (
            str(handle.get("handle_value", "")).strip() if isinstance(handle, dict) else ""
        )
        if not handle_value or handle_value in active_item_ids:
            continue
        target_region = node.get("proposal_target_region")
        target_reference = (
            str(target_region.get("target_reference", "")).strip()
            if isinstance(target_region, dict)
            else ""
        )
        if target_reference != spec_id:
            continue
        runtime_bridge = node.get("runtime_bridge")
        if not isinstance(runtime_bridge, dict):
            continue
        if not str(runtime_bridge.get("proposal_queue_status", "")).strip():
            continue
        if str(node.get("proposal_authority_state", "")).strip() in {"rejected", "superseded"}:
            continue

        updated_runtime_bridge = dict(runtime_bridge)
        now = proposal_lane_timestamp_now()
        updated_runtime_bridge["proposal_queue_status"] = "superseded"
        updated_runtime_bridge["queue_presence"] = "retired_after_queue_refresh"
        updated_runtime_bridge["last_queue_sync_at"] = now
        node["proposal_authority_state"] = "superseded"
        node["runtime_bridge"] = updated_runtime_bridge
        node["updated_at"] = now
        with artifact_lock(path):
            atomic_write_json(path, node)
        retired_paths.append(path)
    return retired_paths


def sync_tracked_proposal_lane_from_queue(
    queue_items: list[dict[str, Any]],
    *,
    spec_id: str | None = None,
    item_ids: set[str] | None = None,
) -> list[Path]:
    written_paths: list[Path] = []
    active_item_ids: set[str] = set()
    for item in queue_items:
        if not isinstance(item, dict):
            continue
        item_id = str(item.get("id", "")).strip()
        if item_ids is not None and item_id not in item_ids:
            continue
        if spec_id is not None and str(item.get("spec_id", "")).strip() != spec_id:
            continue
        if item_id:
            active_item_ids.add(item_id)
        synced = sync_tracked_proposal_lane_node(item)
        if synced is None:
            continue
        path, _node = synced
        written_paths.append(path)
    retired_paths: list[Path] = []
    if spec_id is not None:
        retired_paths = retire_stale_tracked_proposal_lane_nodes(
            spec_id=spec_id,
            active_item_ids=active_item_ids,
        )
    if written_paths or retired_paths:
        write_proposal_lane_overlay(build_proposal_lane_overlay())
    return written_paths + retired_paths


def build_proposal_lane_overlay() -> dict[str, Any]:
    nodes_dir = proposal_lane_nodes_dir_path()
    entries: list[dict[str, Any]] = []
    artifact_warnings: list[dict[str, str]] = []
    raw_nodes: list[dict[str, Any]] = []

    if nodes_dir.exists():
        for path in sorted(nodes_dir.glob("*.json")):
            data, error = load_json_object_report(path, artifact_kind="proposal lane node artifact")
            if data is None:
                artifact_warnings.append(
                    {
                        "tracked_path": display_artifact_path(path),
                        "error": error,
                    }
                )
                continue
            raw_nodes.append({"tracked_path": display_artifact_path(path), "node": data})

    handle_counts: dict[str, int] = {}
    for raw in raw_nodes:
        node = raw["node"]
        presence = node.get("proposal_repository_presence")
        handle = node.get("proposal_handle")
        if (
            isinstance(presence, dict)
            and all(
                str(presence.get(key, "")).strip() == str(value)
                for key, value in PROPOSAL_LANE_PRESENCE_CONTRACT.items()
            )
            and isinstance(handle, dict)
            and str(handle.get("handle_status", "")).strip() == "active"
        ):
            handle_value = str(handle.get("handle_value", "")).strip()
            if handle_value:
                handle_counts[handle_value] = handle_counts.get(handle_value, 0) + 1

    by_authority: dict[str, list[str]] = {}
    named_filters = {name: [] for name in PROPOSAL_LANE_NAMED_FILTERS}
    edges: list[dict[str, str]] = []

    for raw in raw_nodes:
        tracked_path = str(raw["tracked_path"])
        node = raw["node"]
        presence = node.get("proposal_repository_presence")
        if not (
            isinstance(presence, dict)
            and all(
                str(presence.get(key, "")).strip() == str(value)
                for key, value in PROPOSAL_LANE_PRESENCE_CONTRACT.items()
            )
        ):
            continue

        handle = node.get("proposal_handle", {})
        handle_value = str(handle.get("handle_value", "")).strip()
        authority_state = str(node.get("proposal_authority_state", "")).strip()
        target_region = node.get("proposal_target_region", {})
        lineage_links = node.get("proposal_lineage_link", [])
        query_findings: list[str] = []
        if not handle_value or str(handle.get("handle_status", "")).strip() != "active":
            query_findings.append("missing_active_handle")
        if authority_state not in proposal_lane_valid_authority_states():
            query_findings.append("invalid_authority_state")
        if not (
            isinstance(target_region, dict)
            and str(target_region.get("target_kind", "")).strip()
            and str(target_region.get("target_reference", "")).strip()
            and str(target_region.get("change_scope", "")).strip()
        ):
            query_findings.append("missing_target_region")
        if not (
            isinstance(lineage_links, list)
            and any(
                isinstance(link, dict)
                and str(link.get("lineage_role", "")).strip()
                and str(link.get("source_kind", "")).strip()
                and str(link.get("source_reference", "")).strip()
                for link in lineage_links
            )
        ):
            query_findings.append("missing_lineage_link")
        if handle_value and handle_counts.get(handle_value, 0) > 1:
            query_findings.append("colliding_active_handle")
        query_findings.extend(proposal_lane_timestamp_findings(node))

        entry = {
            "tracked_path": tracked_path,
            "title": str(node.get("title", "")).strip(),
            "proposal_handle": handle_value,
            "proposal_authority_state": authority_state,
            "proposal_type": str(node.get("proposal_payload", {}).get("proposal_type", "")).strip(),
            "target_region": (
                copy.deepcopy(target_region) if isinstance(target_region, dict) else {}
            ),
            "lineage_links": (
                copy.deepcopy(lineage_links) if isinstance(lineage_links, list) else []
            ),
            "query_contract": {
                "required_fields": list(PROPOSAL_LANE_REQUIRED_QUERY_FIELDS),
                "status": "queryable" if not query_findings else "invalid_review_state",
                "findings": query_findings,
            },
        }
        entries.append(entry)

        by_authority.setdefault(authority_state or "unknown", []).append(
            handle_value or tracked_path
        )
        if authority_state == "under_review":
            named_filters["under_review"].append(handle_value or tracked_path)
        if authority_state == "approved_for_application":
            # Trace anchor: SG-SPEC-0013 governs this approved application gate surface.
            named_filters["approved_for_application"].append(handle_value or tracked_path)
        if authority_state in {"rejected", "superseded"}:
            named_filters["rejected_or_superseded"].append(handle_value or tracked_path)
        if query_findings:
            named_filters["invalid_query_contract"].append(handle_value or tracked_path)
        if str(target_region.get("target_kind", "")).strip() == "canonical_node":
            named_filters["canonical_node_targets"].append(handle_value or tracked_path)
            edges.append(
                {
                    "source": handle_value or tracked_path,
                    "target": str(target_region.get("target_reference", "")).strip(),
                    "edge_kind": "proposal_targets_canonical_node",
                }
            )
        for link in lineage_links if isinstance(lineage_links, list) else []:
            if not isinstance(link, dict):
                continue
            source_kind = str(link.get("source_kind", "")).strip()
            source_reference = str(link.get("source_reference", "")).strip()
            if source_kind == "runtime_artifact":
                named_filters["runtime_artifact_lineage"].append(handle_value or tracked_path)
            if source_reference:
                edges.append(
                    {
                        "source": handle_value or tracked_path,
                        "target": source_reference,
                        "edge_kind": (
                            f"lineage::{str(link.get('lineage_role', '')).strip()}::{source_kind}"
                        ),
                    }
                )

    return {
        "artifact_kind": PROPOSAL_LANE_OVERLAY_ARTIFACT_KIND,
        "schema_version": PROPOSAL_LANE_OVERLAY_SCHEMA_VERSION,
        "layer_name": PROPOSAL_LANE_LAYER_NAME,
        "generated_at": utc_now_iso(),
        "policy_reference": proposal_lane_policy_reference(),
        "source_dir": PROPOSAL_LANE_NODES_RELATIVE_DIR,
        "entry_count": len(entries),
        "entries": entries,
        "edges": edges,
        "by_authority_state": {key: sorted(value) for key, value in sorted(by_authority.items())},
        "named_filters": {key: sorted(set(value)) for key, value in sorted(named_filters.items())},
        "artifact_warnings": artifact_warnings,
    }


def write_proposal_lane_overlay(overlay: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = proposal_lane_overlay_path()
    with artifact_lock(path):
        atomic_write_json(path, overlay)
    return path


def load_intent_layer_nodes_report() -> tuple[list[dict[str, Any]], list[dict[str, str]]]:
    nodes_dir = intent_layer_nodes_dir_path()
    raw_nodes: list[dict[str, Any]] = []
    artifact_warnings: list[dict[str, str]] = []
    if not nodes_dir.exists():
        return raw_nodes, artifact_warnings
    for path in sorted(nodes_dir.glob("*.json")):
        data, error = load_json_object_report(path, artifact_kind="intent layer node artifact")
        if data is None:
            artifact_warnings.append(
                {
                    "tracked_path": display_artifact_path(path),
                    "error": error,
                }
            )
            continue
        raw_nodes.append({"tracked_path": display_artifact_path(path), "node": data})
    return raw_nodes, artifact_warnings


def load_proposal_lane_nodes_report() -> tuple[list[dict[str, Any]], list[dict[str, str]]]:
    nodes_dir = proposal_lane_nodes_dir_path()
    raw_nodes: list[dict[str, Any]] = []
    artifact_warnings: list[dict[str, str]] = []
    if not nodes_dir.exists():
        return raw_nodes, artifact_warnings
    for path in sorted(nodes_dir.glob("*.json")):
        data, error = load_json_object_report(path, artifact_kind="proposal lane node artifact")
        if data is None:
            artifact_warnings.append(
                {
                    "tracked_path": display_artifact_path(path),
                    "error": error,
                }
            )
            continue
        raw_nodes.append({"tracked_path": display_artifact_path(path), "node": data})
    return raw_nodes, artifact_warnings


def build_pre_spec_semantics_index(specs: list[SpecNode]) -> dict[str, Any]:
    raw_intent_nodes, intent_warnings = load_intent_layer_nodes_report()
    raw_proposal_nodes, proposal_warnings = load_proposal_lane_nodes_report()
    entries: list[dict[str, Any]] = []
    edges: list[dict[str, str]] = []
    named_filters = {name: [] for name in PRE_SPEC_SEMANTICS_NAMED_FILTERS}

    proposal_links_by_handle: dict[str, set[str]] = {}
    for raw in raw_proposal_nodes:
        node = raw["node"]
        proposal_handle = str(node.get("proposal_handle", {}).get("handle_value", "")).strip()
        for link in (
            node.get("proposal_lineage_link", [])
            if isinstance(node.get("proposal_lineage_link", []), list)
            else []
        ):
            if not isinstance(link, dict):
                continue
            if str(link.get("source_kind", "")).strip() != "intent_layer_node":
                continue
            handle = str(link.get("source_reference", "")).strip()
            if handle and proposal_handle:
                proposal_links_by_handle.setdefault(handle, set()).add(proposal_handle)

    canonical_links_by_handle: dict[str, set[str]] = {}
    for spec in specs:
        provenance = spec.data.get("last_pre_spec_provenance", {})
        if not isinstance(provenance, dict):
            continue
        for handle_field in ("user_intent_handle", "operator_request_handle"):
            handle = str(provenance.get(handle_field, "")).strip()
            if handle:
                canonical_links_by_handle.setdefault(handle, set()).add(spec.id)

    for raw in raw_intent_nodes:
        tracked_path = str(raw["tracked_path"])
        node = raw["node"]
        presence = node.get("intent_repository_presence")
        query_findings: list[str] = []
        if not (
            isinstance(presence, dict)
            and all(
                str(presence.get(key, "")).strip() == str(value)
                for key, value in INTENT_LAYER_PRESENCE_CONTRACT.items()
            )
        ):
            query_findings.append("invalid_presence_contract")
        handle = node.get("intent_handle", {})
        if not isinstance(handle, dict):
            query_findings.append("invalid_intent_handle_section")
            handle = {}
        handle_value = str(handle.get("handle_value", "")).strip()
        intent_kind = str(node.get("intent_layer_kind", "")).strip()
        mediation_state = str(node.get("mediation_state", "")).strip()
        if not handle_value:
            query_findings.append("missing_handle")
        if intent_kind not in PRE_SPEC_IMPLEMENTED_ARTIFACT_CLASSES:
            query_findings.append("unknown_pre_spec_artifact_class")
        if not isinstance(node.get("intent_lineage_link"), list) or not node.get(
            "intent_lineage_link"
        ):
            query_findings.append("missing_provenance")

        runtime_bridge = node.get("runtime_bridge", {})
        if not isinstance(runtime_bridge, dict):
            query_findings.append("invalid_runtime_bridge_section")
            runtime_bridge = {}
        pre_spec_semantics = node.get("pre_spec_semantics", {})
        if not isinstance(pre_spec_semantics, dict):
            query_findings.append("invalid_pre_spec_semantics_section")
            pre_spec_semantics = {}
        linked_proposals = sorted(
            set(
                list(proposal_links_by_handle.get(handle_value, set()))
                + list(
                    str(item).strip()
                    for item in (
                        runtime_bridge.get("proposal_ids", [])
                        if isinstance(runtime_bridge, dict)
                        else []
                    )
                    if str(item).strip()
                )
                + list(
                    str(item).strip()
                    for item in (
                        runtime_bridge.get("latest_proposal_ids", [])
                        if isinstance(runtime_bridge, dict)
                        else []
                    )
                    if str(item).strip()
                )
            )
        )
        linked_specs = sorted(
            set(
                list(canonical_links_by_handle.get(handle_value, set()))
                + list(
                    str(item).strip()
                    for item in (
                        runtime_bridge.get("canonical_spec_ids", [])
                        if isinstance(runtime_bridge, dict)
                        else []
                    )
                    if str(item).strip()
                )
                + list(
                    str(item).strip()
                    for item in (
                        runtime_bridge.get("latest_canonical_spec_ids", [])
                        if isinstance(runtime_bridge, dict)
                        else []
                    )
                    if str(item).strip()
                )
            )
        )
        entry = {
            "tracked_path": tracked_path,
            "title": str(node.get("title", "")).strip(),
            "intent_handle": handle_value,
            "semantic_artifact_class": intent_kind,
            "phase": str(pre_spec_semantics.get("phase", PRE_SPEC_SEMANTICS_PHASE)).strip(),
            "status": str(pre_spec_semantics.get("status", mediation_state)).strip(),
            "authority": str(pre_spec_semantics.get("authority", "")).strip(),
            "mediation_state": mediation_state,
            "required_axes": list(pre_spec_semantics.get("required_axes", PRE_SPEC_REQUIRED_AXES)),
            "downstream_proposal_ids": linked_proposals,
            "downstream_canonical_spec_ids": linked_specs,
            "query_contract": {
                "status": "queryable" if not query_findings else "invalid_pre_spec_state",
                "findings": query_findings,
            },
        }
        entries.append(entry)
        if intent_kind in named_filters:
            named_filters[intent_kind].append(handle_value or tracked_path)
        if mediation_state == "proposal_linked" or linked_proposals:
            named_filters["proposal_linked"].append(handle_value or tracked_path)
        if mediation_state == "canonical_candidate":
            named_filters["canonical_candidate"].append(handle_value or tracked_path)
        if linked_specs:
            named_filters["canonical_materialized"].append(handle_value or tracked_path)
        if mediation_state == "blocked":
            named_filters["blocked"].append(handle_value or tracked_path)
        if "missing_provenance" in query_findings:
            named_filters["missing_provenance"].append(handle_value or tracked_path)
        for proposal_id in linked_proposals:
            edges.append(
                {
                    "source": handle_value or tracked_path,
                    "target": proposal_id,
                    "edge_kind": "pre_spec::proposal_lane",
                }
            )
        for spec_id in linked_specs:
            edges.append(
                {
                    "source": handle_value or tracked_path,
                    "target": spec_id,
                    "edge_kind": "pre_spec::canonical_spec",
                }
            )

    return {
        "artifact_kind": PRE_SPEC_SEMANTICS_INDEX_ARTIFACT_KIND,
        "schema_version": PRE_SPEC_SEMANTICS_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": pre_spec_semantics_policy_reference(),
        "vocabulary_reference": specgraph_vocabulary_reference(),
        "layer_name": PRE_SPEC_SEMANTICS_LAYER_NAME,
        "source_dir": INTENT_LAYER_NODES_RELATIVE_DIR,
        "entry_count": len(entries),
        "entries": entries,
        "edges": edges,
        "named_filters": {key: sorted(set(value)) for key, value in sorted(named_filters.items())},
        "artifact_warnings": intent_warnings + proposal_warnings,
        "reserved_primary_kinds": PRE_SPEC_RESERVED_PRIMARY_KINDS,
    }


def write_pre_spec_semantics_index(index: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = pre_spec_semantics_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def exploration_label_from_text(text: str) -> str:
    normalized = " ".join(text.split())
    if len(normalized) <= 96:
        return normalized
    return normalized[:93].rstrip() + "..."


def validate_exploration_preview_contract(
    nodes: list[dict[str, Any]], edges: list[dict[str, str]]
) -> None:
    allowed_node_kinds = {str(kind) for kind in EXPLORATION_PREVIEW_NODE_KINDS}
    allowed_edge_kinds = {str(kind) for kind in EXPLORATION_PREVIEW_EDGE_KINDS}
    invalid_node_kinds = sorted(
        {
            str(node.get("kind", ""))
            for node in nodes
            if str(node.get("kind", "")) not in allowed_node_kinds
        }
    )
    invalid_edge_kinds = sorted(
        {
            str(edge.get("edge_kind", ""))
            for edge in edges
            if str(edge.get("edge_kind", "")) not in allowed_edge_kinds
        }
    )
    findings: list[str] = []
    if invalid_node_kinds:
        findings.append("invalid node kind(s): " + ", ".join(invalid_node_kinds))
    if invalid_edge_kinds:
        findings.append("invalid edge kind(s): " + ", ".join(invalid_edge_kinds))
    if findings:
        raise RuntimeError("exploration preview policy/artifact drift: " + "; ".join(findings))


def build_exploration_preview(root_intent_text: str | None = None) -> dict[str, Any]:
    intent_text = str(root_intent_text or "").strip()
    input_status = "root_intent_provided" if intent_text else "missing_root_intent"
    text_sha256 = hashlib.sha256(intent_text.encode("utf-8")).hexdigest() if intent_text else ""
    nodes: list[dict[str, Any]] = []
    edges: list[dict[str, str]] = []

    if intent_text:
        root_id = f"exploration:{text_sha256[:12]}:intent"
        assumption_id = f"exploration:{text_sha256[:12]}:assumptions"
        hypothesis_id = f"exploration:{text_sha256[:12]}:hypotheses"
        proposal_id = f"exploration:{text_sha256[:12]}:proposals"
        review_id = f"exploration:{text_sha256[:12]}:review"
        nodes = [
            {
                "id": root_id,
                "kind": "intent",
                "label": exploration_label_from_text(intent_text),
                "text": intent_text,
                "status": "captured",
                "authority": "operator",
                "confidence": "explicit",
                "layer": "intent",
            },
            {
                "id": assumption_id,
                "kind": "assumption_cluster",
                "label": "Unclaimed assumptions",
                "text": "Placeholder for assumptions that must be made explicit before promotion.",
                "status": "placeholder",
                "authority": "supervisor_assumption_mode",
                "confidence": "unclaimed",
                "layer": "hypothesis",
            },
            {
                "id": hypothesis_id,
                "kind": "hypothesis_cluster",
                "label": "Candidate hypotheses",
                "text": "Placeholder for candidate interpretations of the root intent.",
                "status": "placeholder",
                "authority": "supervisor_assumption_mode",
                "confidence": "planned",
                "layer": "hypothesis",
            },
            {
                "id": proposal_id,
                "kind": "proposal_cluster",
                "label": "Possible proposal moves",
                "text": (
                    "Placeholder for reviewable proposal directions derived from the exploration."
                ),
                "status": "placeholder",
                "authority": "supervisor_assumption_mode",
                "confidence": "planned",
                "layer": "proposal",
            },
            {
                "id": review_id,
                "kind": "review_gate",
                "label": "Human review before promotion",
                "text": "No exploration preview node is canonical until a human promotes it.",
                "status": "review_required",
                "authority": "human",
                "confidence": "required",
                "layer": "review",
            },
        ]
        edges = [
            {"source": root_id, "target": assumption_id, "edge_kind": "structures_assumptions"},
            {"source": root_id, "target": hypothesis_id, "edge_kind": "raises_hypotheses"},
            {"source": hypothesis_id, "target": proposal_id, "edge_kind": "suggests_proposals"},
            {"source": proposal_id, "target": review_id, "edge_kind": "requires_human_review"},
        ]

    validate_exploration_preview_contract(nodes, edges)
    mode_contract = copy.deepcopy(EXPLORATION_PREVIEW_POLICY["mode_contract"])
    canonical_mutations_allowed = mode_contract.get("canonical_mutations_allowed")
    tracked_artifacts_written = mode_contract.get("tracked_artifacts_written")
    if not isinstance(canonical_mutations_allowed, bool) or not isinstance(
        tracked_artifacts_written, bool
    ):
        raise RuntimeError(
            "malformed exploration preview mode contract: mutation flags must be booleans"
        )

    return {
        "artifact_kind": EXPLORATION_PREVIEW_ARTIFACT_KIND,
        "schema_version": EXPLORATION_PREVIEW_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": exploration_preview_policy_reference(),
        "mode": EXPLORATION_PREVIEW_MODE_NAME,
        "mode_contract": mode_contract,
        "input": {
            "source_kind": "inline_operator_intent" if intent_text else "none",
            "text": intent_text,
            "text_sha256": text_sha256,
            "input_status": input_status,
        },
        "review_state": "preview_only" if intent_text else "blocked",
        "next_gap": "human_review_before_promotion" if intent_text else "provide_root_intent_text",
        "canonical_mutations_allowed": canonical_mutations_allowed,
        "tracked_artifacts_written": tracked_artifacts_written,
        "node_count": len(nodes),
        "edge_count": len(edges),
        "nodes": nodes,
        "edges": edges,
        "promotion_candidates": [
            {"target_kind": target_kind, "review_required": True, "auto_promote": False}
            for target_kind in EXPLORATION_PREVIEW_POLICY["preview_contract"]["promotion_targets"]
        ]
        if intent_text
        else [],
        "viewer_contract": copy.deepcopy(EXPLORATION_PREVIEW_POLICY["viewer_contract"]),
    }


def write_exploration_preview(preview: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = exploration_preview_path()
    with artifact_lock(path):
        atomic_write_json(path, preview)
    return path


def conversation_memory_policy_hash(policy: dict[str, Any]) -> str:
    canonical = json.dumps(policy, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(canonical.encode("utf-8")).hexdigest()


def conversation_memory_policy_override_reference(policy: dict[str, Any]) -> dict[str, Any]:
    return {
        "artifact_path": "inline://conversation_memory_policy_override",
        "artifact_sha256": conversation_memory_policy_hash(policy),
        "version": policy.get("version"),
    }


def conversation_memory_storage_errors(record: dict[str, Any]) -> list[str]:
    raw_errors = record.get("_storage_errors", [])
    if raw_errors in (None, ""):
        return []
    if not isinstance(raw_errors, list):
        return ["invalid_storage_errors_shape"]
    return [str(error).strip() for error in raw_errors if str(error).strip()]


def conversation_memory_storage_dir(relative_dir: str, fallback: str) -> Path:
    normalized = str(relative_dir or fallback).strip() or fallback
    return ROOT / normalized


def load_conversation_memory_source_records(
    source_dir_relative: str | None = None,
) -> list[dict[str, Any]]:
    source_dir = conversation_memory_storage_dir(
        source_dir_relative or CONVERSATION_MEMORY_SOURCES_RELATIVE_DIR,
        CONVERSATION_MEMORY_SOURCES_RELATIVE_DIR,
    )
    if not source_dir.exists():
        return []
    records: list[dict[str, Any]] = []
    for path in sorted(source_dir.glob("*.json")):
        relative_path = path.relative_to(ROOT).as_posix()
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except OSError:
            records.append(
                {
                    "source_id": f"invalid_source_file_{path.stem}",
                    "source_type": "",
                    "source_state": "missing",
                    "source_ref": "",
                    "_storage_path": relative_path,
                    "_storage_errors": ["unreadable_source_json"],
                }
            )
            continue
        except json.JSONDecodeError:
            records.append(
                {
                    "source_id": f"invalid_source_file_{path.stem}",
                    "source_type": "",
                    "source_state": "declared",
                    "source_ref": "",
                    "_storage_path": relative_path,
                    "_storage_errors": ["malformed_source_json"],
                }
            )
            continue
        raw_items = payload if isinstance(payload, list) else [payload]
        for index, raw_item in enumerate(raw_items, start=1):
            item = copy.deepcopy(raw_item) if isinstance(raw_item, dict) else {}
            if not isinstance(raw_item, dict):
                item["_storage_errors"] = ["invalid_source_record_shape"]
            item["_storage_path"] = relative_path
            if len(raw_items) > 1:
                item["_storage_index"] = index
            records.append(item)
    return records


def parse_conversation_memory_note_frontmatter(path: Path) -> tuple[dict[str, Any], str, list[str]]:
    errors: list[str] = []
    try:
        text = path.read_text(encoding="utf-8")
    except OSError:
        return {}, "", ["unreadable_note_markdown"]
    lines = text.splitlines(keepends=True)
    if not lines or lines[0].strip() != "---":
        return {}, text, ["missing_frontmatter"]
    closing_index = next(
        (index for index, line in enumerate(lines[1:], start=1) if line.strip() == "---"),
        None,
    )
    if closing_index is None:
        return {}, text, ["unterminated_frontmatter"]
    raw_frontmatter = "".join(lines[1:closing_index]).strip()
    body = "".join(lines[closing_index + 1 :]).strip()
    try:
        if yaml is None:
            payload = json.loads(raw_frontmatter) if raw_frontmatter else {}
        else:
            payload = yaml.safe_load(raw_frontmatter) if raw_frontmatter else {}
    except Exception as exc:
        return {}, body, [f"malformed_frontmatter: {exc}"]
    if not isinstance(payload, dict):
        return {}, body, ["invalid_frontmatter_shape"]
    return payload, body, errors


def conversation_memory_summary_from_body(body: str) -> str:
    normalized = " ".join(line.strip() for line in body.splitlines() if line.strip())
    if len(normalized) <= 240:
        return normalized
    return normalized[:237].rstrip() + "..."


def load_conversation_memory_note_records(
    note_dir_relative: str | None = None,
) -> list[dict[str, Any]]:
    note_dir = conversation_memory_storage_dir(
        note_dir_relative or CONVERSATION_MEMORY_NOTES_RELATIVE_DIR,
        CONVERSATION_MEMORY_NOTES_RELATIVE_DIR,
    )
    if not note_dir.exists():
        return []
    records: list[dict[str, Any]] = []
    for path in sorted(note_dir.glob("*.md")):
        relative_path = path.relative_to(ROOT).as_posix()
        metadata, body, errors = parse_conversation_memory_note_frontmatter(path)
        note = copy.deepcopy(metadata)
        note["_storage_path"] = relative_path
        if errors:
            note["_storage_errors"] = errors
        if body and not str(note.get("summary", "")).strip():
            note["summary"] = conversation_memory_summary_from_body(body)
        records.append(note)
    return records


def conversation_memory_review_state(
    *,
    note_status: str,
    promotion_state: str,
) -> str:
    if note_status == "blocked_by_promotion_boundary":
        return "blocked"
    if note_status == "invalid_memory_note":
        return "not_ready"
    if promotion_state == "not_promoted":
        return "structured_reviewable"
    return "promotion_review_required"


def conversation_memory_next_gap(
    *,
    note_status: str,
    promotion_state: str,
    errors: list[str],
) -> str:
    if note_status == "blocked_by_promotion_boundary":
        return "block_direct_canonical_promotion"
    if any(error in errors for error in ("missing_source_refs", "undeclared_source_ref")):
        return "repair_conversation_memory_note_attribution"
    if note_status == "invalid_memory_note":
        return "repair_conversation_memory_note_contract"
    if promotion_state == "not_promoted":
        return "review_structured_memory_note"
    return "review_memory_promotion_pressure"


def conversation_memory_source_errors(
    source: dict[str, Any],
    *,
    allowed_source_types: set[str],
    allowed_source_states: set[str],
) -> list[str]:
    errors: list[str] = []
    if not str(source.get("source_id", "")).strip():
        errors.append("missing_source_id")
    source_type = str(source.get("source_type", "")).strip()
    if source_type not in allowed_source_types:
        errors.append("unknown_source_type")
    source_state = str(source.get("source_state", "")).strip()
    if source_state not in allowed_source_states:
        errors.append("unknown_source_state")
    if not str(source.get("source_ref", "")).strip():
        errors.append("missing_source_ref")
    return errors


def conversation_memory_note_errors(
    note: dict[str, Any],
    *,
    source_ids: set[str],
    allowed_note_kinds: set[str],
    allowed_promotion_states: set[str],
    canonical_promotion_states: set[str],
) -> list[str]:
    errors: list[str] = []
    if not str(note.get("memory_note_id", "")).strip():
        errors.append("missing_memory_note_id")
    note_kind = str(note.get("note_kind", "")).strip()
    if note_kind not in allowed_note_kinds:
        errors.append("unknown_note_kind")
    promotion_state = str(note.get("promotion_state", "")).strip() or "not_promoted"
    if promotion_state in canonical_promotion_states:
        errors.append("canonical_promotion_state")
    elif promotion_state not in allowed_promotion_states:
        errors.append("unknown_promotion_state")

    raw_source_refs = note.get("source_refs", [])
    source_refs = raw_source_refs if isinstance(raw_source_refs, list) else []
    normalized_source_refs = [str(item).strip() for item in source_refs if str(item).strip()]
    if not normalized_source_refs:
        errors.append("missing_source_refs")
    elif any(source_ref not in source_ids for source_ref in normalized_source_refs):
        errors.append("undeclared_source_ref")
    return errors


def build_conversation_memory_index(
    policy: dict[str, Any] | None = None,
    *,
    include_storage: bool = True,
) -> dict[str, Any]:
    # Trace anchor: SG-SPEC-0008 governs explicit project-memory consultation surfaces.
    active_policy = copy.deepcopy(policy or CONVERSATION_MEMORY_POLICY)
    policy_reference = (
        conversation_memory_policy_reference()
        if policy is None
        else conversation_memory_policy_override_reference(active_policy)
    )
    source_contract = active_policy.get("source_contract", {})
    note_contract = active_policy.get("note_contract", {})
    index_contract = active_policy.get("index_contract", {})
    layer_boundary = active_policy.get("layer_boundary", {})
    repository_layout = active_policy.get("repository_layout", {})
    if not isinstance(repository_layout, dict):
        repository_layout = {}
    source_dir_relative = (
        str(repository_layout.get("source_dir", CONVERSATION_MEMORY_SOURCES_RELATIVE_DIR)).strip()
        or CONVERSATION_MEMORY_SOURCES_RELATIVE_DIR
    )
    note_dir_relative = (
        str(repository_layout.get("note_dir", CONVERSATION_MEMORY_NOTES_RELATIVE_DIR)).strip()
        or CONVERSATION_MEMORY_NOTES_RELATIVE_DIR
    )
    allowed_source_types = {
        str(item).strip()
        for item in source_contract.get("source_types", CONVERSATION_MEMORY_SOURCE_TYPES)
        if str(item).strip()
    }
    allowed_source_states = {
        str(item).strip()
        for item in source_contract.get("source_states", CONVERSATION_MEMORY_SOURCE_STATES)
        if str(item).strip()
    }
    allowed_note_kinds = {
        str(item).strip()
        for item in note_contract.get("note_kinds", CONVERSATION_MEMORY_NOTE_KINDS)
        if str(item).strip()
    }
    allowed_promotion_states = {
        str(item).strip()
        for item in note_contract.get("promotion_states", CONVERSATION_MEMORY_PROMOTION_STATES)
        if str(item).strip()
    }
    canonical_promotion_states = {
        str(item).strip()
        for item in note_contract.get(
            "canonical_promotion_states",
            CONVERSATION_MEMORY_CANONICAL_PROMOTION_STATES,
        )
        if str(item).strip()
    }

    raw_sources = source_contract.get("sources", [])
    policy_sources = raw_sources if isinstance(raw_sources, list) else []
    storage_sources = (
        load_conversation_memory_source_records(source_dir_relative) if include_storage else []
    )
    sources = [*policy_sources, *storage_sources]
    source_entries: list[dict[str, Any]] = []
    source_ids: set[str] = set()
    source_type_groups: dict[str, list[str]] = {}
    source_state_groups: dict[str, list[str]] = {}
    source_error_groups: dict[str, list[str]] = {}

    for index, raw_source in enumerate(sources, start=1):
        source = copy.deepcopy(raw_source) if isinstance(raw_source, dict) else {}
        source_id = str(source.get("source_id", "")).strip() or f"invalid_source_{index}"
        source_type = str(source.get("source_type", "")).strip()
        source_state = str(source.get("source_state", "")).strip() or "declared"
        storage_errors = conversation_memory_storage_errors(source)
        errors = storage_errors + conversation_memory_source_errors(
            {**source, "source_state": source_state},
            allowed_source_types=allowed_source_types,
            allowed_source_states=allowed_source_states,
        )
        source_ids.add(source_id)
        source_entries.append(
            {
                "source_id": source_id,
                "source_type": source_type,
                "source_state": source_state,
                "source_ref": str(source.get("source_ref", "")).strip(),
                "captured_at": str(source.get("captured_at", "")).strip(),
                "selection_rationale": str(source.get("selection_rationale", "")).strip(),
                "source_boundary": str(source.get("source_boundary", "")).strip(),
                "storage_path": str(source.get("_storage_path", "")).strip(),
                "contract_errors": errors,
            }
        )
        source_type_groups.setdefault(source_type or "unknown", []).append(source_id)
        source_state_groups.setdefault(source_state or "unknown", []).append(source_id)
        for error in errors:
            source_error_groups.setdefault(error, []).append(source_id)

    raw_notes = note_contract.get("notes", [])
    policy_notes = raw_notes if isinstance(raw_notes, list) else []
    storage_notes = (
        load_conversation_memory_note_records(note_dir_relative) if include_storage else []
    )
    notes = [*policy_notes, *storage_notes]
    entries: list[dict[str, Any]] = []
    note_kind_groups: dict[str, list[str]] = {}
    note_status_groups: dict[str, list[str]] = {}
    promotion_state_groups: dict[str, list[str]] = {}
    review_state_groups: dict[str, list[str]] = {}
    next_gap_groups: dict[str, list[str]] = {}
    active_named_filters = index_contract.get("named_filters", CONVERSATION_MEMORY_NAMED_FILTERS)
    if not isinstance(active_named_filters, list):
        active_named_filters = CONVERSATION_MEMORY_NAMED_FILTERS
    named_filters: dict[str, list[str]] = {
        str(name).strip(): [] for name in active_named_filters if str(name).strip()
    }

    for index, raw_note in enumerate(notes, start=1):
        note = copy.deepcopy(raw_note) if isinstance(raw_note, dict) else {}
        memory_note_id = (
            str(note.get("memory_note_id", "")).strip() or f"invalid_memory_note_{index}"
        )
        note_kind = str(note.get("note_kind", "")).strip()
        promotion_state = str(note.get("promotion_state", "")).strip() or "not_promoted"
        raw_source_refs = note.get("source_refs", [])
        source_refs = (
            [str(item).strip() for item in raw_source_refs if str(item).strip()]
            if isinstance(raw_source_refs, list)
            else []
        )
        storage_errors = conversation_memory_storage_errors(note)
        errors = storage_errors + conversation_memory_note_errors(
            {**note, "promotion_state": promotion_state, "source_refs": source_refs},
            source_ids=source_ids,
            allowed_note_kinds=allowed_note_kinds,
            allowed_promotion_states=allowed_promotion_states,
            canonical_promotion_states=canonical_promotion_states,
        )
        if "canonical_promotion_state" in errors:
            note_status = "blocked_by_promotion_boundary"
        elif errors:
            note_status = "invalid_memory_note"
        else:
            note_status = "structured"
        review_state = conversation_memory_review_state(
            note_status=note_status,
            promotion_state=promotion_state,
        )
        next_gap = conversation_memory_next_gap(
            note_status=note_status,
            promotion_state=promotion_state,
            errors=errors,
        )
        entry = {
            "memory_note_id": memory_note_id,
            "note_kind": note_kind,
            "title": str(note.get("title", "")).strip(),
            "status": note_status,
            "promotion_state": promotion_state,
            "review_state": review_state,
            "next_gap": next_gap,
            "source_refs": source_refs,
            "links": copy.deepcopy(note.get("links", {}))
            if isinstance(note.get("links", {}), dict)
            else {},
            "staleness": str(note.get("staleness", "")).strip() or "current",
            "storage_path": str(note.get("_storage_path", "")).strip(),
            "summary": str(note.get("summary", "")).strip(),
            "contract_errors": errors,
        }
        entries.append(entry)

        note_kind_groups.setdefault(note_kind or "unknown", []).append(memory_note_id)
        note_status_groups.setdefault(note_status, []).append(memory_note_id)
        promotion_state_groups.setdefault(promotion_state or "unknown", []).append(memory_note_id)
        review_state_groups.setdefault(review_state, []).append(memory_note_id)
        next_gap_groups.setdefault(next_gap, []).append(memory_note_id)
        if review_state == "structured_reviewable":
            named_filters.setdefault("structured_reviewable", []).append(memory_note_id)
        if review_state == "promotion_review_required":
            named_filters.setdefault("promotion_review_required", []).append(memory_note_id)
        if any(error in errors for error in ("missing_source_refs", "undeclared_source_ref")):
            named_filters.setdefault("missing_attribution", []).append(memory_note_id)
        if entry["staleness"] == "stale":
            named_filters.setdefault("stale_notes", []).append(memory_note_id)
        if note_status == "invalid_memory_note":
            named_filters.setdefault("invalid_notes", []).append(memory_note_id)
        if note_kind == "source_summary":
            named_filters.setdefault("source_summaries", []).append(memory_note_id)

    def sorted_groups(groups: dict[str, list[str]]) -> dict[str, list[str]]:
        return {key: sorted(set(value)) for key, value in sorted(groups.items())}

    canonical_mutations_allowed = bool(layer_boundary.get("canonical_mutations_allowed"))
    tracked_artifacts_written = bool(layer_boundary.get("tracked_artifacts_written"))
    if entries:
        review_state = "ready_for_review"
        next_gap = "review_conversation_memory_index"
    else:
        review_state = "not_ready"
        next_gap = "capture_conversation_memory_source"

    return {
        "artifact_kind": CONVERSATION_MEMORY_INDEX_ARTIFACT_KIND,
        "schema_version": CONVERSATION_MEMORY_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": policy_reference,
        "source_snapshot": {
            "source_dir": source_dir_relative,
            "note_dir": note_dir_relative,
            "policy_source_count": len(policy_sources),
            "policy_note_count": len(policy_notes),
            "storage_source_count": len(storage_sources),
            "storage_note_count": len(storage_notes),
        },
        "layer_boundary": copy.deepcopy(layer_boundary),
        "review_state": review_state,
        "next_gap": next_gap,
        "source_count": len(source_entries),
        "structured_note_count": len(entries),
        "sources": source_entries,
        "entries": entries,
        "summary": {
            "source_count": len(source_entries),
            "structured_note_count": len(entries),
            "note_kind_counts": grouped_identifier_counts(sorted_groups(note_kind_groups)),
            "promotion_state_counts": grouped_identifier_counts(
                sorted_groups(promotion_state_groups)
            ),
            "review_state_counts": grouped_identifier_counts(sorted_groups(review_state_groups)),
            "missing_attribution_count": len(named_filters.get("missing_attribution", [])),
            "stale_note_count": len(named_filters.get("stale_notes", [])),
            "next_gap_counts": grouped_identifier_counts(sorted_groups(next_gap_groups)),
            "source_type_counts": grouped_identifier_counts(sorted_groups(source_type_groups)),
            "source_state_counts": grouped_identifier_counts(sorted_groups(source_state_groups)),
            "source_error_counts": grouped_identifier_counts(sorted_groups(source_error_groups)),
        },
        "viewer_projection": {
            "note_kind": sorted_groups(note_kind_groups),
            "note_status": sorted_groups(note_status_groups),
            "promotion_state": sorted_groups(promotion_state_groups),
            "review_state": sorted_groups(review_state_groups),
            "next_gap": sorted_groups(next_gap_groups),
            "source_type": sorted_groups(source_type_groups),
            "source_state": sorted_groups(source_state_groups),
            "named_filters": sorted_groups(named_filters),
        },
        "canonical_mutations_allowed": canonical_mutations_allowed,
        "tracked_artifacts_written": tracked_artifacts_written,
        "viewer_contract": copy.deepcopy(active_policy.get("viewer_contract", {})),
    }


def write_conversation_memory_index(index: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = conversation_memory_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def conversation_memory_promotion_target_kind(promotion_state: str) -> str:
    mapping = {
        "proposal_pressure_candidate": "proposal_candidate",
        "intent_fragment_candidate": "intent_fragment",
        "pre_spec_draft_candidate": "pre_spec_draft",
        "operator_question": "operator_question",
    }
    return mapping.get(str(promotion_state).strip(), "unknown")


def conversation_memory_entry_has_missing_attribution(entry: dict[str, Any]) -> bool:
    contract_errors = entry.get("contract_errors", [])
    if not isinstance(contract_errors, list):
        return False
    return any(
        str(error).strip() in {"missing_source_refs", "undeclared_source_ref"}
        for error in contract_errors
    )


def conversation_memory_entry_is_review_blocked(entry: dict[str, Any]) -> bool:
    if str(entry.get("status", "")).strip() != "structured":
        return True
    review_state = str(entry.get("review_state", "")).strip()
    return review_state in {
        "blocked",
        "not_ready",
    } or conversation_memory_entry_has_missing_attribution(entry)


def conversation_memory_entry_is_promotion_candidate(entry: dict[str, Any]) -> bool:
    promotion_state = str(entry.get("promotion_state", "")).strip()
    return (
        str(entry.get("status", "")).strip() == "structured"
        and promotion_state in CONVERSATION_MEMORY_PROMOTION_CANDIDATE_STATES
        and not conversation_memory_entry_has_missing_attribution(entry)
    )


def conversation_memory_unique_string_list(value: Any) -> list[str]:
    if not isinstance(value, list):
        return []
    result: list[str] = []
    seen: set[str] = set()
    for item in value:
        normalized = str(item).strip()
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        result.append(normalized)
    return result


def build_conversation_memory_map(index: dict[str, Any] | None = None) -> dict[str, Any]:
    source_index = (
        copy.deepcopy(index) if isinstance(index, dict) else build_conversation_memory_index()
    )
    entries = source_index.get("entries", [])
    if not isinstance(entries, list):
        entries = []
    sources = source_index.get("sources", [])
    if not isinstance(sources, list):
        sources = []

    source_ids = {
        str(source.get("source_id", "")).strip()
        for source in sources
        if isinstance(source, dict) and str(source.get("source_id", "")).strip()
    }
    cluster_members: dict[tuple[str, str], set[str]] = {}
    links: list[dict[str, Any]] = []
    related_specs: dict[str, set[str]] = {}
    related_proposals: dict[str, set[str]] = {}
    source_ref_counts: dict[str, set[str]] = {}
    missing_attribution_note_ids: list[str] = []
    attributed_note_ids: list[str] = []
    source_refs_note_ids: list[str] = []
    candidate_pressure: list[dict[str, Any]] = []
    review_blockers: list[dict[str, Any]] = []
    named_filters: dict[str, list[str]] = {
        str(name).strip(): [] for name in CONVERSATION_MEMORY_MAP_NAMED_FILTERS if str(name).strip()
    }

    for raw_entry in entries:
        if not isinstance(raw_entry, dict):
            continue
        entry = copy.deepcopy(raw_entry)
        memory_note_id = str(entry.get("memory_note_id", "")).strip()
        if not memory_note_id:
            continue
        note_kind = str(entry.get("note_kind", "")).strip() or "unknown"
        cluster_members.setdefault(("note_kind", note_kind), set()).add(memory_note_id)

        source_refs = entry.get("source_refs", [])
        normalized_source_refs = conversation_memory_unique_string_list(source_refs)
        if normalized_source_refs:
            source_refs_note_ids.append(memory_note_id)
            if all(source_ref in source_ids for source_ref in normalized_source_refs):
                attributed_note_ids.append(memory_note_id)
            for source_ref in normalized_source_refs:
                cluster_members.setdefault(("source", source_ref), set()).add(memory_note_id)
                source_ref_counts.setdefault(source_ref, set()).add(memory_note_id)
                links.append(
                    {
                        "link_id": f"{memory_note_id}::source_ref::{source_ref}",
                        "link_kind": "source_ref",
                        "from_id": memory_note_id,
                        "from_type": "memory_note",
                        "to_id": source_ref,
                        "to_type": "conversation_source"
                        if source_ref in source_ids
                        else "undeclared_source",
                    }
                )
        else:
            missing_attribution_note_ids.append(memory_note_id)

        links_record = entry.get("links", {})
        if not isinstance(links_record, dict):
            links_record = {}
        related_specs_raw = links_record.get("related_specs", [])
        related_proposals_raw = links_record.get("related_proposals", [])
        related_notes_raw = links_record.get("related_memory_notes", [])
        related_specs_list = conversation_memory_unique_string_list(related_specs_raw)
        related_proposals_list = conversation_memory_unique_string_list(related_proposals_raw)
        related_notes_list = conversation_memory_unique_string_list(related_notes_raw)
        for spec_id in related_specs_list:
            cluster_members.setdefault(("related_spec", spec_id), set()).add(memory_note_id)
            related_specs.setdefault(spec_id, set()).add(memory_note_id)
            links.append(
                {
                    "link_id": f"{memory_note_id}::related_spec::{spec_id}",
                    "link_kind": "related_spec",
                    "from_id": memory_note_id,
                    "from_type": "memory_note",
                    "to_id": spec_id,
                    "to_type": "spec_node",
                }
            )
        for proposal_id in related_proposals_list:
            cluster_members.setdefault(("related_proposal", proposal_id), set()).add(memory_note_id)
            related_proposals.setdefault(proposal_id, set()).add(memory_note_id)
            links.append(
                {
                    "link_id": f"{memory_note_id}::related_proposal::{proposal_id}",
                    "link_kind": "related_proposal",
                    "from_id": memory_note_id,
                    "from_type": "memory_note",
                    "to_id": proposal_id,
                    "to_type": "proposal",
                }
            )
        for related_note_id in related_notes_list:
            links.append(
                {
                    "link_id": f"{memory_note_id}::related_memory_note::{related_note_id}",
                    "link_kind": "related_memory_note",
                    "from_id": memory_note_id,
                    "from_type": "memory_note",
                    "to_id": related_note_id,
                    "to_type": "memory_note",
                }
            )

        promotion_state = str(entry.get("promotion_state", "")).strip() or "not_promoted"
        if conversation_memory_entry_is_promotion_candidate(entry):
            target_kind = conversation_memory_promotion_target_kind(promotion_state)
            candidate_pressure.append(
                {
                    "candidate_id": memory_note_id,
                    "target_kind": target_kind,
                    "promotion_state": promotion_state,
                    "source_memory_notes": [memory_note_id],
                    "source_refs": sorted(set(normalized_source_refs)),
                    "rationale": str(entry.get("summary", "")).strip(),
                    "review_state": str(entry.get("review_state", "")).strip(),
                    "next_gap": str(entry.get("next_gap", "")).strip(),
                }
            )
            named_filters.setdefault("promotion_candidates", []).append(memory_note_id)

        if conversation_memory_entry_is_review_blocked(entry):
            blocker_errors = entry.get("contract_errors", [])
            if not isinstance(blocker_errors, list):
                blocker_errors = []
            review_blockers.append(
                {
                    "memory_note_id": memory_note_id,
                    "status": str(entry.get("status", "")).strip(),
                    "review_state": str(entry.get("review_state", "")).strip(),
                    "next_gap": str(entry.get("next_gap", "")).strip(),
                    "contract_errors": [
                        str(error).strip() for error in blocker_errors if str(error).strip()
                    ],
                }
            )
            cluster_members.setdefault(("review_blocker", "blocked_notes"), set()).add(
                memory_note_id
            )
            named_filters.setdefault("has_review_blockers", []).append(memory_note_id)
        if conversation_memory_entry_has_missing_attribution(entry):
            if memory_note_id not in missing_attribution_note_ids:
                missing_attribution_note_ids.append(memory_note_id)
            named_filters.setdefault("missing_source_coverage", []).append(memory_note_id)
        if related_specs_list:
            named_filters.setdefault("linked_specs", []).append(memory_note_id)
        if related_proposals_list:
            named_filters.setdefault("linked_proposals", []).append(memory_note_id)

    clusters: list[dict[str, Any]] = []
    for (cluster_kind, cluster_value), member_ids in sorted(cluster_members.items()):
        normalized_members = sorted(member_ids)
        if not normalized_members:
            continue
        clusters.append(
            {
                "cluster_id": f"{cluster_kind}::{cluster_value}",
                "cluster_kind": cluster_kind,
                "label": cluster_value,
                "member_note_ids": normalized_members,
                "member_count": len(normalized_members),
            }
        )

    def sorted_group_counts(groups: dict[str, set[str]]) -> dict[str, int]:
        return {key: len(value) for key, value in sorted(groups.items())}

    sorted_named_filters = {key: sorted(set(value)) for key, value in sorted(named_filters.items())}
    layer_boundary = source_index.get("layer_boundary", {})
    if not isinstance(layer_boundary, dict):
        layer_boundary = {}
    canonical_mutations_allowed = bool(source_index.get("canonical_mutations_allowed"))
    tracked_artifacts_written = bool(source_index.get("tracked_artifacts_written"))
    review_state = "blocked" if review_blockers else source_index.get("review_state", "not_ready")
    if review_blockers:
        next_gap = "repair_conversation_memory_map_blockers"
    elif candidate_pressure:
        next_gap = "review_memory_promotion_pressure"
    else:
        next_gap = source_index.get("next_gap", "capture_conversation_memory_source")

    return {
        "artifact_kind": CONVERSATION_MEMORY_MAP_ARTIFACT_KIND,
        "schema_version": CONVERSATION_MEMORY_MAP_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": copy.deepcopy(source_index.get("policy_reference", {})),
        "index_reference": {
            "artifact_kind": source_index.get("artifact_kind"),
            "schema_version": source_index.get("schema_version"),
            "generated_at": source_index.get("generated_at"),
            "source_count": source_index.get("source_count", 0),
            "structured_note_count": source_index.get("structured_note_count", 0),
            "next_gap": source_index.get("next_gap"),
        },
        "source_snapshot": copy.deepcopy(source_index.get("source_snapshot", {})),
        "layer_boundary": copy.deepcopy(layer_boundary),
        "review_state": review_state,
        "next_gap": next_gap,
        "cluster_count": len(clusters),
        "link_count": len(links),
        "clusters": clusters,
        "links": sorted(links, key=lambda item: str(item.get("link_id", ""))),
        "source_coverage": {
            "declared_source_count": len(source_ids),
            "structured_note_count": len([entry for entry in entries if isinstance(entry, dict)]),
            "source_refs_note_count": len(set(source_refs_note_ids)),
            "attributed_note_count": len(set(attributed_note_ids)),
            "missing_attribution_count": len(set(missing_attribution_note_ids)),
            "missing_attribution_note_ids": sorted(set(missing_attribution_note_ids)),
            "source_ref_counts": sorted_group_counts(source_ref_counts),
        },
        "related_specs": {key: sorted(value) for key, value in sorted(related_specs.items())},
        "related_proposals": {
            key: sorted(value) for key, value in sorted(related_proposals.items())
        },
        "candidate_proposal_pressure": {
            "entry_count": len(candidate_pressure),
            "entries": sorted(candidate_pressure, key=lambda item: item["candidate_id"]),
        },
        "review_blockers": {
            "entry_count": len(review_blockers),
            "entries": sorted(review_blockers, key=lambda item: item["memory_note_id"]),
        },
        "summary": {
            "cluster_kind_counts": grouped_identifier_counts(
                {
                    key: [
                        cluster["cluster_id"]
                        for cluster in clusters
                        if cluster["cluster_kind"] == key
                    ]
                    for key in {cluster["cluster_kind"] for cluster in clusters}
                }
            ),
            "link_kind_counts": grouped_identifier_counts(
                {
                    key: [link["link_id"] for link in links if link["link_kind"] == key]
                    for key in {link["link_kind"] for link in links}
                }
            ),
            "candidate_pressure_count": len(candidate_pressure),
            "review_blocker_count": len(review_blockers),
            "missing_source_coverage_count": len(set(missing_attribution_note_ids)),
        },
        "viewer_projection": {
            "clusters_by_kind": {
                key: sorted(
                    cluster["cluster_id"] for cluster in clusters if cluster["cluster_kind"] == key
                )
                for key in sorted({cluster["cluster_kind"] for cluster in clusters})
            },
            "named_filters": sorted_named_filters,
        },
        "canonical_mutations_allowed": canonical_mutations_allowed,
        "tracked_artifacts_written": tracked_artifacts_written,
        "viewer_contract": copy.deepcopy(source_index.get("viewer_contract", {})),
    }


def write_conversation_memory_map(memory_map: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = conversation_memory_map_path()
    with artifact_lock(path):
        atomic_write_json(path, memory_map)
    return path


def conversation_memory_pressure_named_filter(target_kind: str) -> str:
    mapping = {
        "intent_fragment": "intent_fragment_candidates",
        "proposal_candidate": "proposal_candidates",
        "pre_spec_draft": "pre_spec_draft_candidates",
        "operator_question": "operator_questions",
    }
    return mapping.get(str(target_kind).strip(), "")


def build_conversation_memory_promotion_pressure(
    memory_map: dict[str, Any] | None = None,
) -> dict[str, Any]:
    source_map = (
        copy.deepcopy(memory_map)
        if isinstance(memory_map, dict)
        else build_conversation_memory_map()
    )
    candidate_block = source_map.get("candidate_proposal_pressure", {})
    raw_candidates = candidate_block.get("entries", []) if isinstance(candidate_block, dict) else []
    if not isinstance(raw_candidates, list):
        raw_candidates = []
    blocker_block = source_map.get("review_blockers", {})
    map_blocker_count = (
        int(blocker_block.get("entry_count", 0) or 0) if isinstance(blocker_block, dict) else 0
    )
    allowed_target_kinds = {
        str(kind).strip()
        for kind in CONVERSATION_MEMORY_POLICY["promotion_pressure_contract"]["target_kinds"]
        if str(kind).strip()
    }
    named_filters: dict[str, list[str]] = {
        str(name).strip(): []
        for name in CONVERSATION_MEMORY_PROMOTION_PRESSURE_NAMED_FILTERS
        if str(name).strip()
    }
    entries: list[dict[str, Any]] = []
    target_kind_groups: dict[str, list[str]] = {}
    pressure_status_groups: dict[str, list[str]] = {}

    for raw_candidate in raw_candidates:
        if not isinstance(raw_candidate, dict):
            continue
        candidate_id = str(raw_candidate.get("candidate_id", "")).strip()
        target_kind = str(raw_candidate.get("target_kind", "")).strip()
        if not candidate_id or target_kind not in allowed_target_kinds:
            continue
        pressure_id = f"conversation_memory_pressure::{candidate_id}"
        pressure_status = (
            "blocked_by_map_review" if map_blocker_count else "ready_for_promotion_review"
        )
        review_state = "blocked" if map_blocker_count else "promotion_review_required"
        next_gap = (
            "repair_conversation_memory_map_blockers"
            if map_blocker_count
            else "review_memory_promotion_pressure"
        )
        source_memory_notes = conversation_memory_unique_string_list(
            raw_candidate.get("source_memory_notes", [])
        )
        source_refs = conversation_memory_unique_string_list(raw_candidate.get("source_refs", []))
        entry = {
            "pressure_id": pressure_id,
            "candidate_id": candidate_id,
            "target_kind": target_kind,
            "promotion_state": str(raw_candidate.get("promotion_state", "")).strip(),
            "pressure_status": pressure_status,
            "review_state": review_state,
            "next_gap": next_gap,
            "source_memory_notes": source_memory_notes,
            "source_refs": source_refs,
            "rationale": str(raw_candidate.get("rationale", "")).strip(),
            "map_candidate": copy.deepcopy(raw_candidate),
        }
        entries.append(entry)
        target_kind_groups.setdefault(target_kind, []).append(pressure_id)
        pressure_status_groups.setdefault(pressure_status, []).append(pressure_id)
        named_filters.setdefault(pressure_status, []).append(pressure_id)
        target_filter = conversation_memory_pressure_named_filter(target_kind)
        if target_filter:
            named_filters.setdefault(target_filter, []).append(pressure_id)
        if map_blocker_count:
            named_filters.setdefault("blocked_by_map_review", []).append(pressure_id)

    if map_blocker_count:
        review_state = "blocked"
        next_gap = "repair_conversation_memory_map_blockers"
    elif entries:
        review_state = "ready_for_review"
        next_gap = "review_memory_promotion_pressure"
    else:
        review_state = "not_ready"
        next_gap = source_map.get("next_gap", "capture_conversation_memory_source")

    def sorted_groups(groups: dict[str, list[str]]) -> dict[str, list[str]]:
        return {key: sorted(set(value)) for key, value in sorted(groups.items())}

    sorted_named_filters = sorted_groups(named_filters)

    return {
        "artifact_kind": CONVERSATION_MEMORY_PROMOTION_PRESSURE_ARTIFACT_KIND,
        "schema_version": CONVERSATION_MEMORY_PROMOTION_PRESSURE_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": copy.deepcopy(source_map.get("policy_reference", {})),
        "map_reference": {
            "artifact_kind": source_map.get("artifact_kind"),
            "schema_version": source_map.get("schema_version"),
            "generated_at": source_map.get("generated_at"),
            "cluster_count": source_map.get("cluster_count", 0),
            "link_count": source_map.get("link_count", 0),
            "next_gap": source_map.get("next_gap"),
        },
        "index_reference": copy.deepcopy(source_map.get("index_reference", {})),
        "source_snapshot": copy.deepcopy(source_map.get("source_snapshot", {})),
        "layer_boundary": copy.deepcopy(source_map.get("layer_boundary", {})),
        "review_state": review_state,
        "next_gap": next_gap,
        "entry_count": len(entries),
        "entries": sorted(entries, key=lambda item: item["pressure_id"]),
        "review_blocker_count": map_blocker_count,
        "summary": {
            "entry_count": len(entries),
            "target_kind_counts": grouped_identifier_counts(sorted_groups(target_kind_groups)),
            "pressure_status_counts": grouped_identifier_counts(
                sorted_groups(pressure_status_groups)
            ),
            "review_blocker_count": map_blocker_count,
        },
        "viewer_projection": {
            "target_kind": sorted_groups(target_kind_groups),
            "pressure_status": sorted_groups(pressure_status_groups),
            "named_filters": sorted_named_filters,
        },
        "canonical_mutations_allowed": bool(source_map.get("canonical_mutations_allowed")),
        "tracked_artifacts_written": bool(source_map.get("tracked_artifacts_written")),
        "viewer_contract": copy.deepcopy(source_map.get("viewer_contract", {})),
    }


def write_conversation_memory_promotion_pressure(pressure: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = conversation_memory_promotion_pressure_path()
    with artifact_lock(path):
        atomic_write_json(path, pressure)
    return path


def branch_rewrite_status_mapping(preview_status: str) -> tuple[str, str]:
    normalized = str(preview_status).strip()
    try:
        mapping = branch_rewrite_preview_policy_lookup(f"status_mapping.{normalized}")
    except KeyError:
        return "blocked", "repair_branch_rewrite_preview_policy"
    if not isinstance(mapping, dict):
        return "blocked", "repair_branch_rewrite_preview_policy"
    review_state = str(mapping.get("review_state", "")).strip() or "blocked"
    next_gap = str(mapping.get("next_gap", "")).strip() or "repair_branch_rewrite_preview_policy"
    return review_state, next_gap


def validate_branch_rewrite_status_contract(preview_status: str, review_state: str) -> None:
    allowed_statuses = {
        str(item).strip() for item in BRANCH_REWRITE_PREVIEW_STATUS_VALUES if str(item).strip()
    }
    allowed_review_states = {
        str(item).strip() for item in BRANCH_REWRITE_REVIEW_STATE_VALUES if str(item).strip()
    }
    findings: list[str] = []
    if str(preview_status).strip() not in allowed_statuses:
        findings.append(f"invalid preview_status: {preview_status}")
    if str(review_state).strip() not in allowed_review_states:
        findings.append(f"invalid review_state: {review_state}")
    if findings:
        raise RuntimeError("branch rewrite preview policy/artifact drift: " + "; ".join(findings))


def validate_branch_rewrite_mode_contract() -> dict[str, Any]:
    mode_contract = copy.deepcopy(BRANCH_REWRITE_PREVIEW_POLICY["mode_contract"])
    canonical_mutations_allowed = mode_contract.get("canonical_mutations_allowed")
    tracked_artifacts_written = mode_contract.get("tracked_artifacts_written")
    if canonical_mutations_allowed is not False or tracked_artifacts_written is not False:
        raise RuntimeError(
            "malformed branch rewrite preview mode contract: mutation flags must be false"
        )
    return mode_contract


def branch_rewrite_presence_state(spec: SpecNode) -> str:
    state = presence_state(spec.data)
    if state:
        return state
    if is_historical_spec(spec.data):
        return "historical"
    return "active"


def branch_rewrite_resolve_branch(
    *,
    root: SpecNode,
    specs: list[SpecNode],
    max_depth: int,
    include_historical: bool,
) -> tuple[list[SpecNode], list[dict[str, str]]]:
    index = index_specs(specs)
    selected: list[SpecNode] = []
    inspected_edges: list[dict[str, str]] = []
    seen: set[str] = set()
    queue: deque[tuple[SpecNode, int]] = deque([(root, 0)])

    while queue:
        current, depth = queue.popleft()
        if not current.id or current.id in seen:
            continue
        seen.add(current.id)
        selected.append(current)
        if depth >= max_depth:
            continue
        children = (
            refining_child_specs(current, specs)
            if include_historical
            else active_refining_child_specs(current, specs)
        )
        for child in children:
            if not child.id:
                continue
            inspected_edges.append(
                {"source": current.id, "target": child.id, "edge_kind": "refines"}
            )
            queue.append((index.get(child.id, child), depth + 1))

    return selected, inspected_edges


def branch_rewrite_missing_relation_refs(
    selected_specs: list[SpecNode], all_specs: list[SpecNode]
) -> list[dict[str, str]]:
    index = index_specs(all_specs)
    missing_refs: list[dict[str, str]] = []
    for spec in selected_specs:
        for field in ("depends_on", "relates_to", "refines"):
            for ref in relation_ids(spec.data, field):
                if SPEC_ID_PATTERN.match(ref) and ref not in index:
                    missing_refs.append(
                        {
                            "source": spec.id,
                            "field": field,
                            "target": ref,
                            "finding": "missing_spec_reference",
                        }
                    )
    return sorted(missing_refs, key=lambda item: (item["source"], item["field"], item["target"]))


def branch_rewrite_role_summary(spec: SpecNode) -> str:
    candidates: list[str] = [spec.prompt, str(spec.data.get("objective", "")).strip()]
    acceptance = spec.data.get("acceptance")
    if isinstance(acceptance, list):
        candidates.extend(str(item).strip() for item in acceptance[:2])
    specification = spec.data.get("specification")
    if isinstance(specification, dict):
        candidates.append(json.dumps(specification, ensure_ascii=False, sort_keys=True))
    summary = " ".join(part for part in candidates if part)
    summary = " ".join(summary.split())
    if len(summary) > 220:
        return summary[:217].rstrip() + "..."
    return summary


def branch_rewrite_topology_pressure(profile: dict[str, Any]) -> bool:
    bookkeeping_hits = int(profile.get("bookkeeping_hits", 0) or 0)
    role_hits = int(profile.get("role_hits", 0) or 0)
    unique_refs = int(profile.get("unique_spec_references", 0) or 0)
    role_floor = max(role_hits, 1)
    bookkeeping_ratio = bookkeeping_hits / role_floor
    return (
        bookkeeping_hits >= 3
        and unique_refs >= ROLE_OBSCURED_SPEC_REFERENCE_THRESHOLD
        and bookkeeping_ratio >= BRANCH_REWRITE_TOPOLOGY_BOOKKEEPING_RATIO_THRESHOLD
    )


def branch_rewrite_candidate_for_spec(
    spec: SpecNode,
    *,
    graph_health_entry: dict[str, Any] | None = None,
) -> dict[str, Any]:
    presence = branch_rewrite_presence_state(spec)
    profile = node_role_legibility_profile(spec)
    signals = set()
    recommended_actions = set()
    if isinstance(graph_health_entry, dict):
        signals = {
            str(item).strip() for item in graph_health_entry.get("signals", []) if str(item).strip()
        }
        recommended_actions = {
            str(item).strip()
            for item in graph_health_entry.get("recommended_actions", [])
            if str(item).strip()
        }

    rewrite_classes: list[str] = []
    findings: list[str] = []
    suggested_action = "no_change"
    risk_level = "none"

    if presence in {"historical", "historical_lineage_only"}:
        rewrite_classes.append("archive_historical_semantics")
        findings.append("historical_lineage_should_be_visually_deemphasized")
        suggested_action = "deemphasize_historical_lineage"
        risk_level = "low"
    elif bool(profile.get("bookkeeping_only")) or "bookkeeping_only_node" in signals:
        rewrite_classes.extend(["remove_graph_topology_prose", "merge_bookkeeping_slice"])
        findings.append("bookkeeping_or_topology_prose_dominates_role_text")
        suggested_action = "merge_bookkeeping_slice"
        risk_level = "medium"
    elif (
        bool(profile.get("role_obscured"))
        or "role_obscured_node" in signals
        or branch_rewrite_topology_pressure(profile)
    ):
        rewrite_classes.extend(["remove_graph_topology_prose", "clarify_boundary"])
        findings.append("node_role_is_obscured_by_topology_or_neighbor_references")
        suggested_action = "rewrite_node_role_boundary"
        risk_level = "medium"
    elif "split_required" in {str(spec.data.get("last_outcome", "")).strip(), spec.gate_state}:
        # Trace anchor: SG-SPEC-0032 exposes proposal/split mechanics
        # as one reviewable readiness region.
        rewrite_classes.append("split_needed")
        findings.append("node_has_split_pressure")
        suggested_action = "emit_split_proposal"
        risk_level = "medium"
    elif "preserve_boundary_contract" in recommended_actions:
        rewrite_classes.append("preserve_boundary_contract")
        findings.append("boundary_contract_has_system_facing_role")
        suggested_action = "preserve_as_boundary_contract"
        risk_level = "low"

    if not rewrite_classes:
        rewrite_classes = ["no_change"]

    rewrite_classes = [
        item for item in dict.fromkeys(rewrite_classes) if item in BRANCH_REWRITE_REWRITE_CLASSES
    ]
    if suggested_action not in BRANCH_REWRITE_SUGGESTED_ACTIONS:
        suggested_action = "no_change"

    role_summary = branch_rewrite_role_summary(spec)
    if suggested_action == "no_change":
        recommendation = "No branch rewrite pressure detected for this node."
        proposed_summary = role_summary
        patch_preview: list[dict[str, str]] = []
    elif suggested_action == "merge_bookkeeping_slice":
        recommendation = (
            "Review whether this node carries a distinct system-facing contract or mostly "
            "bookkeeps graph topology."
        )
        proposed_summary = (
            "Merge or rewrite the bookkeeping slice so the remaining prose states the "
            "system-facing role before graph-routing details."
        )
        patch_preview = [
            {
                "field": "prompt",
                "recommendation": "Replace topology narration with a role-first boundary summary.",
            }
        ]
    elif suggested_action == "emit_split_proposal":
        recommendation = "Escalate the non-atomic concern through split proposal flow."
        proposed_summary = "Use proposal-first decomposition before canonical branch rewrite."
        patch_preview = []
    elif suggested_action == "deemphasize_historical_lineage":
        recommendation = "Keep historical lineage inspectable but visually de-emphasized."
        proposed_summary = "Treat this node as historical context rather than active branch prose."
        patch_preview = []
    elif suggested_action == "preserve_as_boundary_contract":
        recommendation = "Preserve this boundary if its contract remains system-facing."
        proposed_summary = role_summary
        patch_preview = []
    else:
        recommendation = "Rewrite the node in domain-first prose before restating graph topology."
        proposed_summary = (
            "Start from the capability, invariant, or review boundary this node owns; "
            "leave edge placement to graph metadata."
        )
        patch_preview = [
            {
                "field": "prompt",
                "recommendation": "Move SG-SPEC routing facts out of the primary prose.",
            }
        ]

    return {
        "spec_id": spec.id,
        "title": spec.title,
        "presence_state": presence,
        "status": spec.status,
        "gate_state": spec.gate_state,
        "current_role_summary": role_summary,
        "rewrite_recommendation": recommendation,
        "rewrite_classes": rewrite_classes,
        "findings": sorted(set(findings)),
        "suggested_action": suggested_action,
        "risk_level": risk_level,
        "proposed_summary": proposed_summary,
        "proposed_patch_preview": patch_preview,
        "blocked_by": [f"gate_state::{spec.gate_state}"] if spec.gate_state != "none" else [],
        "role_legibility_profile": profile,
    }


def build_branch_rewrite_preview(target_spec_id: str | None = None) -> dict[str, Any]:
    requested_root = str(target_spec_id or "").strip()
    mode_contract = validate_branch_rewrite_mode_contract()
    specs = load_specs()
    spec_index = index_specs(specs)
    selection_contract = copy.deepcopy(BRANCH_REWRITE_PREVIEW_POLICY["selection_contract"])
    max_depth = int(selection_contract.get("default_max_depth", 3) or 3)
    node_limit = int(selection_contract.get("default_node_limit", 24) or 24)
    include_historical = bool(selection_contract.get("include_historical_default", False))
    source_git_commit = git_head_commit()

    selected_specs: list[SpecNode] = []
    inspected_edges: list[dict[str, str]] = []
    missing_target_spec_ids: list[str] = []
    blocked_by: list[dict[str, Any]] = []

    if not requested_root or requested_root not in spec_index:
        preview_status = "invalid_root"
        missing_target_spec_ids = [requested_root] if requested_root else []
    elif is_historical_spec(spec_index[requested_root].data):
        preview_status = "invalid_root"
        blocked_by.append(
            {
                "blocker": "non_active_root",
                "root_spec_id": requested_root,
                "presence_state": branch_rewrite_presence_state(spec_index[requested_root]),
            }
        )
    else:
        selected_specs, inspected_edges = branch_rewrite_resolve_branch(
            root=spec_index[requested_root],
            specs=specs,
            max_depth=max_depth,
            include_historical=include_historical,
        )
        if not selected_specs:
            preview_status = "empty_branch"
        elif len(selected_specs) > node_limit:
            preview_status = "branch_too_large"
            blocked_by.append(
                {
                    "blocker": "branch_too_large",
                    "node_count": len(selected_specs),
                    "node_limit": node_limit,
                }
            )
        else:
            selected_missing_refs = branch_rewrite_missing_relation_refs(selected_specs, specs)
            gated_specs = [
                {"spec_id": spec.id, "gate_state": spec.gate_state}
                for spec in selected_specs
                if spec.gate_state != "none"
            ]
            if selected_missing_refs:
                preview_status = "broken_reference"
                blocked_by.extend(selected_missing_refs)
            elif gated_specs:
                preview_status = "blocked_by_unresolved_gate"
                blocked_by.extend(gated_specs)
            else:
                preview_status = "ready_for_review"

    graph_health = build_graph_health_overlay(specs) if selected_specs else {}
    graph_health_by_spec = {
        str(entry.get("spec_id", "")): entry
        for entry in graph_health.get("entries", [])
        if isinstance(entry, dict)
    }
    candidates = [
        branch_rewrite_candidate_for_spec(
            spec,
            graph_health_entry=graph_health_by_spec.get(spec.id),
        )
        for spec in selected_specs
    ]
    actionable_candidates = [
        candidate
        for candidate in candidates
        if str(candidate.get("suggested_action", "")) != "no_change"
    ]
    if preview_status == "ready_for_review" and not actionable_candidates:
        preview_status = "no_candidates"

    review_state, next_gap = branch_rewrite_status_mapping(preview_status)
    validate_branch_rewrite_status_contract(preview_status, review_state)
    candidate_class_counts: dict[str, int] = {}
    action_counts: dict[str, int] = {}
    for candidate in candidates:
        for rewrite_class in candidate.get("rewrite_classes", []):
            rewrite_class = str(rewrite_class).strip()
            if rewrite_class:
                candidate_class_counts[rewrite_class] = (
                    candidate_class_counts.get(rewrite_class, 0) + 1
                )
        action = str(candidate.get("suggested_action", "")).strip()
        if action:
            action_counts[action] = action_counts.get(action, 0) + 1

    selected_spec_ids = [spec.id for spec in selected_specs if spec.id]
    current_story_titles = [f"{spec.id}: {spec.title}" for spec in selected_specs]
    if actionable_candidates:
        proposed_summary = (
            f"{len(actionable_candidates)} node(s) need review-first rewrite pressure before "
            "the branch reads as domain-first prose."
        )
    elif selected_specs:
        proposed_summary = "No branch rewrite candidates were detected by the first-slice rules."
    else:
        proposed_summary = "No branch story could be built for the requested root."

    return {
        "artifact_kind": BRANCH_REWRITE_PREVIEW_ARTIFACT_KIND,
        "schema_version": BRANCH_REWRITE_PREVIEW_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": branch_rewrite_preview_policy_reference(),
        "mode": BRANCH_REWRITE_PREVIEW_MODE_NAME,
        "mode_contract": mode_contract,
        "preview_status": preview_status,
        "review_state": review_state,
        "next_gap": next_gap,
        "canonical_mutations_allowed": False,
        "tracked_artifacts_written": False,
        "target": {
            "root_spec_id": requested_root,
            "missing_target_spec_ids": missing_target_spec_ids,
            "resolved_spec_ids": selected_spec_ids,
            "selector": str(selection_contract.get("selector", "active_refines_subtree")),
            "max_depth": max_depth,
            "node_limit": node_limit,
            "include_historical": include_historical,
        },
        "provenance": {
            "source_graph_ref": source_git_commit,
            "source_git_commit": source_git_commit,
            "selected_spec_ids": selected_spec_ids,
            "inspected_edges": inspected_edges,
            "policy_refs": copy.deepcopy(BRANCH_REWRITE_PREVIEW_POLICY.get("policy_refs", [])),
        },
        "review_evidence": {
            "candidate_class_counts": dict(sorted(candidate_class_counts.items())),
            "suggested_action_counts": dict(sorted(action_counts.items())),
            "recommendation_basis": [
                "proposal_0036_topology_facts_are_not_spec_prose",
                "proposal_0017_role_first_semantic_bias",
                "graph_health_role_legibility_signals",
            ],
            "blocked_by": blocked_by,
        },
        "branch_story": {
            "current_summary": " | ".join(current_story_titles),
            "proposed_summary": proposed_summary,
            "story_gaps": [
                str(candidate.get("spec_id", ""))
                for candidate in actionable_candidates
                if str(candidate.get("spec_id", "")).strip()
            ],
        },
        "node_count": len(selected_specs),
        "edge_count": len(inspected_edges),
        "candidate_count": len(actionable_candidates),
        "node_rewrite_candidates": candidates,
        "viewer_contract": copy.deepcopy(BRANCH_REWRITE_PREVIEW_POLICY["viewer_contract"]),
    }


def write_branch_rewrite_preview(preview: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = branch_rewrite_preview_path()
    with artifact_lock(path):
        atomic_write_json(path, preview)
    return path


def implementation_policy_next_gap(status: str) -> str:
    # Trace anchor: SG-SPEC-0031 maps gateway prerequisite readiness to one bounded next-gap.
    normalized = str(status).strip()
    if not normalized:
        normalized = "ready_for_planning"
    try:
        return str(implementation_delta_policy_lookup(f"next_gap_defaults.{normalized}")).strip()
    except KeyError:
        return "review_implementation_delta"


def parse_implementation_target_spec_ids(
    value: str | tuple[str, ...] | list[str] | None,
) -> list[str]:
    raw_items: list[str] = []
    if isinstance(value, str):
        raw_items = value.split(",")
    elif isinstance(value, (tuple, list)):
        for item in value:
            raw_items.extend(str(item).split(","))
    seen: set[str] = set()
    spec_ids: list[str] = []
    for item in raw_items:
        spec_id = str(item).strip()
        if spec_id and spec_id not in seen:
            seen.add(spec_id)
            spec_ids.append(spec_id)
    return spec_ids


def resolve_implementation_target_scope(
    *,
    scope_kind: str,
    requested_spec_ids: list[str],
    specs: list[SpecNode],
    spec_index: dict[str, SpecNode],
) -> dict[str, Any]:
    missing_target_spec_ids = sorted(
        spec_id for spec_id in requested_spec_ids if spec_id not in spec_index
    )
    valid_target_spec_ids = [spec_id for spec_id in requested_spec_ids if spec_id in spec_index]
    resolved_target_spec_ids: list[str] = []
    selector = "none"
    if scope_kind == "spec":
        selector = "exact_spec_list"
        resolved_target_spec_ids = list(valid_target_spec_ids)
    elif scope_kind == "active_subtree":
        selector = "active_refines_subtree"
        seen: set[str] = set()
        for root_spec_id in valid_target_spec_ids:
            for spec in active_subtree_nodes(spec_index[root_spec_id], specs):
                if spec.id and spec.id not in seen:
                    seen.add(spec.id)
                    resolved_target_spec_ids.append(spec.id)

    return {
        "valid_target_spec_ids": valid_target_spec_ids,
        "missing_target_spec_ids": missing_target_spec_ids,
        "resolved_target_spec_ids": resolved_target_spec_ids,
        "scope_resolution": {
            "selector": selector,
            "expanded": scope_kind == "active_subtree",
            "root_spec_ids": valid_target_spec_ids,
            "resolved_count": len(resolved_target_spec_ids),
            "excludes_historical_or_superseded": scope_kind == "active_subtree",
        },
    }


def implementation_source_artifact_summary(
    path: Path,
    *,
    artifact_kind: str,
) -> tuple[dict[str, Any] | None, dict[str, Any]]:
    artifact_path = path.relative_to(ROOT).as_posix()
    if not path.exists():
        return None, {
            "artifact_path": artifact_path,
            "status": "missing",
            "generated_at": "",
            "error": "",
        }
    payload, error = load_json_object_report(path, artifact_kind=artifact_kind)
    if payload is None:
        return None, {
            "artifact_path": artifact_path,
            "status": "malformed",
            "generated_at": "",
            "error": error,
        }
    return payload, {
        "artifact_path": artifact_path,
        "status": "available",
        "generated_at": str(payload.get("generated_at", "")).strip(),
        "error": "",
    }


def implementation_projection_group(
    artifact: dict[str, Any] | None,
    *,
    projection_key: str,
    spec_id: str,
) -> str:
    if not isinstance(artifact, dict):
        return "unknown"
    projection = artifact.get("viewer_projection", {})
    if not isinstance(projection, dict):
        return "unknown"
    groups = projection.get(projection_key, {})
    if not isinstance(groups, dict):
        return "unknown"
    for group_name, raw_spec_ids in groups.items():
        if isinstance(raw_spec_ids, list) and spec_id in {str(item) for item in raw_spec_ids}:
            return str(group_name).strip() or "unknown"
    return "unknown"


def implementation_contract_refs_for_spec(spec: SpecNode) -> list[str]:
    refs: list[str] = []
    for idx, output in enumerate(spec.outputs, start=1):
        normalized = str(output).strip()
        if normalized:
            refs.append(f"{spec.id}:outputs:{idx}:{normalized}")
    return refs


def implementation_acceptance_refs_for_spec(spec: SpecNode) -> list[str]:
    raw_acceptance = spec.data.get("acceptance", [])
    if not isinstance(raw_acceptance, list):
        return []
    refs: list[str] = []
    for idx, criterion in enumerate(raw_acceptance, start=1):
        text = " ".join(str(criterion).split())
        if len(text) > 96:
            text = text[:93].rstrip() + "..."
        refs.append(f"{spec.id}:acceptance:{idx}:{text}")
    return refs


def implementation_required_tests_for_spec(spec: SpecNode) -> list[str]:
    raw_acceptance = spec.data.get("acceptance", [])
    if not isinstance(raw_acceptance, list):
        return []
    return [
        f"{spec.id}:acceptance:{idx}:test_required" for idx, _item in enumerate(raw_acceptance, 1)
    ]


def implementation_likely_code_refs_for_spec(spec: SpecNode) -> list[str]:
    refs: list[str] = []
    for raw_path in [*spec.allowed_paths, *spec.outputs]:
        path_text = str(raw_path).strip()
        if not path_text:
            continue
        if path_text.startswith(("specs/", "docs/proposals/", "runs/")):
            continue
        refs.append(path_text)
    return sorted(set(refs))


def build_implementation_delta_snapshot(
    *,
    target_scope_kind: str | None = None,
    target_spec_ids: str | tuple[str, ...] | list[str] | None = None,
    operator_intent: str | None = None,
) -> dict[str, Any]:
    scope_kind = str(target_scope_kind or "").strip()
    requested_spec_ids = parse_implementation_target_spec_ids(target_spec_ids)
    intent_text = str(operator_intent or "").strip()
    specs = load_specs()
    spec_index = index_specs(specs)
    current_commit = git_head_commit()

    trace_projection, trace_summary = implementation_source_artifact_summary(
        spec_trace_projection_path(),
        artifact_kind="spec trace projection",
    )
    evidence_overlay, evidence_summary = implementation_source_artifact_summary(
        evidence_plane_overlay_path(),
        artifact_kind="evidence plane overlay",
    )
    graph_health_overlay, graph_health_summary = implementation_source_artifact_summary(
        graph_health_overlay_path(),
        artifact_kind="graph health overlay",
    )

    validation_findings: list[str] = []
    if scope_kind not in IMPLEMENTATION_TARGET_SCOPE_KINDS:
        validation_findings.append("unsupported_or_missing_target_scope_kind")
    if not requested_spec_ids:
        validation_findings.append("missing_target_spec_ids")
    target_scope = resolve_implementation_target_scope(
        scope_kind=scope_kind,
        requested_spec_ids=requested_spec_ids,
        specs=specs,
        spec_index=spec_index,
    )
    valid_target_spec_ids = target_scope["valid_target_spec_ids"]
    missing_target_spec_ids = target_scope["missing_target_spec_ids"]
    resolved_target_spec_ids = target_scope["resolved_target_spec_ids"]
    scope_resolution = target_scope["scope_resolution"]
    if missing_target_spec_ids:
        validation_findings.extend(
            f"unknown_target_spec_id::{spec_id}" for spec_id in missing_target_spec_ids
        )
    if not intent_text:
        validation_findings.append("missing_operator_intent")

    implementation_state_projection = (
        (trace_projection or {}).get("viewer_projection", {}).get("implementation_state", {})
    )
    implemented_spec_ids = sorted(
        {
            str(item).strip()
            for state in ("implemented", "verified")
            for item in implementation_state_projection.get(state, [])
            if str(item).strip()
        }
    )
    implemented_set = set(implemented_spec_ids)

    target_specs = [spec_index[spec_id] for spec_id in resolved_target_spec_ids]
    quality_blockers = sorted(
        {
            spec.id
            for spec in target_specs
            if spec.gate_state not in {"", "none"} or spec.status in {"blocked", "review_pending"}
        }
    )

    new_spec_ids: list[str] = []
    changed_spec_ids: list[str] = []
    changed_contract_refs: list[str] = []
    changed_acceptance_refs: list[str] = []
    missing_trace_refs: list[str] = []
    required_test_refs: list[str] = []
    evidence_gap_refs: list[str] = []
    likely_affected_code_refs: list[str] = []
    likely_affected_code_refs_by_spec: dict[str, list[str]] = {}
    target_diagnostics: list[dict[str, Any]] = []

    for spec in target_specs:
        implementation_state = implementation_projection_group(
            trace_projection,
            projection_key="implementation_state",
            spec_id=spec.id,
        )
        evidence_chain_status = implementation_projection_group(
            evidence_overlay,
            projection_key="chain_status",
            spec_id=spec.id,
        )
        if spec.id not in implemented_set:
            if implementation_state == "unknown":
                new_spec_ids.append(spec.id)
            else:
                changed_spec_ids.append(spec.id)
            changed_contract_refs.extend(implementation_contract_refs_for_spec(spec))
            changed_acceptance_refs.extend(implementation_acceptance_refs_for_spec(spec))
            required_test_refs.extend(implementation_required_tests_for_spec(spec))
        if implementation_state in {"unknown", "unclaimed", "not_tracked", "planned"}:
            missing_trace_refs.append(f"trace::{spec.id}")
        if evidence_chain_status in {"unknown", "untracked", "contract_only"}:
            evidence_gap_refs.append(f"evidence::{spec.id}")
        spec_likely_code_refs = implementation_likely_code_refs_for_spec(spec)
        likely_affected_code_refs.extend(spec_likely_code_refs)
        likely_affected_code_refs_by_spec[spec.id] = spec_likely_code_refs
        target_diagnostics.append(
            {
                "spec_id": spec.id,
                "title": spec.title,
                "status": spec.status,
                "gate_state": spec.gate_state,
                "maturity": spec.maturity,
                "implementation_state": implementation_state,
                "evidence_chain_status": evidence_chain_status,
            }
        )

    if validation_findings:
        status = "invalid_target_scope"
        review_state = "needs_human_scope_review"
    elif quality_blockers:
        status = "blocked_by_spec_quality"
        review_state = "blocked"
    elif trace_summary["status"] != "available" and bool(
        IMPLEMENTATION_DELTA_POLICY["eligibility_contract"].get("blocks_on_missing_trace_baseline")
    ):
        status = "blocked_by_trace_gap"
        review_state = "blocked"
    elif evidence_summary["status"] != "available" and bool(
        IMPLEMENTATION_DELTA_POLICY["eligibility_contract"].get(
            "blocks_on_missing_evidence_baseline"
        )
    ):
        status = "blocked_by_evidence_gap"
        review_state = "blocked"
    elif not any(
        (
            new_spec_ids,
            changed_spec_ids,
            changed_contract_refs,
            changed_acceptance_refs,
            missing_trace_refs,
            required_test_refs,
            evidence_gap_refs,
            likely_affected_code_refs,
        )
    ):
        status = "empty_delta"
        review_state = "ready_for_planning"
    else:
        status = "ready_for_planning"
        review_state = "ready_for_planning"

    next_gap = implementation_policy_next_gap(status)
    layer_contract = copy.deepcopy(IMPLEMENTATION_DELTA_POLICY["layer_contract"])
    canonical_mutations_allowed = layer_contract.get("canonical_mutations_allowed")
    tracked_artifacts_written = layer_contract.get("tracked_artifacts_written")
    runtime_code_mutations_allowed = layer_contract.get("runtime_code_mutations_allowed")
    if not all(
        isinstance(flag, bool)
        for flag in (
            canonical_mutations_allowed,
            tracked_artifacts_written,
            runtime_code_mutations_allowed,
        )
    ):
        raise RuntimeError(
            "malformed implementation delta layer contract: mutation flags must be booleans"
        )

    return {
        "artifact_kind": IMPLEMENTATION_DELTA_SNAPSHOT_ARTIFACT_KIND,
        "schema_version": IMPLEMENTATION_DELTA_SNAPSHOT_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": implementation_delta_policy_reference(),
        "layer": IMPLEMENTATION_LAYER_NAME,
        "source_artifacts": {
            "spec_trace_projection": trace_summary,
            "evidence_plane_overlay": evidence_summary,
            "graph_health_overlay": graph_health_summary,
        },
        "baseline": {
            "git_commit": current_commit,
            "graph_version": current_commit,
            "implemented_spec_ids": implemented_spec_ids,
            "trace_baseline_status": trace_summary["status"],
            "evidence_baseline_status": evidence_summary["status"],
        },
        "target": {
            "target_scope_kind": scope_kind,
            "target_spec_ids": requested_spec_ids,
            "valid_target_spec_ids": valid_target_spec_ids,
            "resolved_target_spec_ids": resolved_target_spec_ids,
            "missing_target_spec_ids": missing_target_spec_ids,
            "target_git_commit": current_commit,
            "operator_intent": intent_text,
            "scope_resolution": scope_resolution,
            "target_diagnostics": target_diagnostics,
        },
        "delta": {
            "new_spec_ids": sorted(set(new_spec_ids)),
            "changed_spec_ids": sorted(set(changed_spec_ids)),
            "changed_contract_refs": sorted(set(changed_contract_refs)),
            "changed_acceptance_refs": sorted(set(changed_acceptance_refs)),
            "missing_trace_refs": sorted(set(missing_trace_refs)),
            "required_test_refs": sorted(set(required_test_refs)),
            "evidence_gap_refs": sorted(set(evidence_gap_refs)),
            "likely_affected_code_refs": sorted(set(likely_affected_code_refs)),
            "likely_affected_code_refs_by_spec": {
                spec_id: sorted(set(refs))
                for spec_id, refs in sorted(likely_affected_code_refs_by_spec.items())
            },
            "spec_quality_blocker_ids": quality_blockers,
        },
        "status": status,
        "review_state": review_state,
        "next_gap": next_gap,
        "validation_findings": validation_findings,
        "canonical_mutations_allowed": canonical_mutations_allowed,
        "tracked_artifacts_written": tracked_artifacts_written,
        "runtime_code_mutations_allowed": runtime_code_mutations_allowed,
        "layer_contract": layer_contract,
    }


def write_implementation_delta_snapshot(snapshot: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = implementation_delta_snapshot_path()
    with artifact_lock(path):
        atomic_write_json(path, snapshot)
    return path


def implementation_work_item_readiness(
    *,
    snapshot_status: str,
    has_quality_blocker: bool,
    has_trace_gap: bool,
    has_evidence_gap: bool,
) -> tuple[str, list[str]]:
    # Trace anchor: SG-SPEC-0030 governs prerequisite readiness as non-bypass input.
    blockers: list[str] = []
    if has_quality_blocker or snapshot_status == "blocked_by_spec_quality":
        blockers.append("spec_quality_gate")
    if has_trace_gap or snapshot_status == "blocked_by_trace_gap":
        blockers.append("trace_baseline_gap")
    if has_evidence_gap or snapshot_status == "blocked_by_evidence_gap":
        blockers.append("evidence_baseline_gap")
    if "spec_quality_gate" in blockers:
        return "blocked_by_spec_quality", blockers
    if "trace_baseline_gap" in blockers:
        return "blocked_by_trace_gap", blockers
    if "evidence_baseline_gap" in blockers:
        return "blocked_by_evidence_gap", blockers
    return "ready_for_planning", blockers


def implementation_work_backlog_item(entry: dict[str, Any]) -> dict[str, Any]:
    return {
        "work_item_id": str(entry.get("work_item_id", "")).strip(),
        "affected_spec_ids": [
            str(spec_id).strip()
            for spec_id in entry.get("affected_spec_ids", [])
            if str(spec_id).strip()
        ],
        "implementation_reason": str(entry.get("implementation_reason", "")).strip(),
        "readiness": str(entry.get("readiness", "")).strip(),
        "blockers": [
            str(blocker).strip() for blocker in entry.get("blockers", []) if str(blocker).strip()
        ],
        "next_gap": str(entry.get("next_gap", "")).strip() or "review_implementation_delta",
        "required_tests": [
            str(test_ref).strip()
            for test_ref in entry.get("required_tests", [])
            if str(test_ref).strip()
        ],
        "expected_evidence": [
            str(evidence_ref).strip()
            for evidence_ref in entry.get("expected_evidence", [])
            if str(evidence_ref).strip()
        ],
        "likely_code_refs": [
            str(code_ref).strip()
            for code_ref in entry.get("likely_code_refs", [])
            if str(code_ref).strip()
        ],
    }


def implementation_work_backlog_items_from_entries(
    entries: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    return [
        implementation_work_backlog_item(entry)
        for entry in entries
        if str(entry.get("work_item_id", "")).strip()
        and str(entry.get("next_gap", "")).strip() != "none"
    ]


def normalize_implementation_work_index_backlog(index: dict[str, Any]) -> dict[str, Any]:
    normalized = copy.deepcopy(index)
    backlog = normalized.get("implementation_backlog", {})
    if not isinstance(backlog, dict):
        backlog = {}
    if isinstance(backlog.get("items"), list):
        return normalized

    raw_entries = normalized.get("entries", [])
    entries = (
        [entry for entry in raw_entries if isinstance(entry, dict)]
        if isinstance(raw_entries, list)
        else []
    )
    items = implementation_work_backlog_items_from_entries(entries)

    grouped_by_next_gap = backlog.get("grouped_by_next_gap", {})
    if not items and isinstance(grouped_by_next_gap, dict):
        readiness_projection = normalized.get("viewer_projection", {}).get("readiness", {})
        readiness_by_work_item: dict[str, str] = {}
        if isinstance(readiness_projection, dict):
            for readiness, raw_ids in readiness_projection.items():
                if not isinstance(raw_ids, list):
                    continue
                for raw_id in raw_ids:
                    work_item_id = str(raw_id).strip()
                    if work_item_id:
                        readiness_by_work_item[work_item_id] = str(readiness).strip()
        for next_gap, raw_ids in sorted(grouped_by_next_gap.items()):
            if not isinstance(raw_ids, list):
                continue
            for raw_id in raw_ids:
                work_item_id = str(raw_id).strip()
                if not work_item_id:
                    continue
                items.append(
                    {
                        "work_item_id": work_item_id,
                        "affected_spec_ids": [],
                        "implementation_reason": "",
                        "readiness": readiness_by_work_item.get(work_item_id, ""),
                        "blockers": [],
                        "next_gap": str(next_gap).strip() or "review_implementation_delta",
                        "required_tests": [],
                        "expected_evidence": [],
                        "likely_code_refs": [],
                    }
                )

    backlog["items"] = items
    backlog["entry_count"] = len(items)
    normalized["implementation_backlog"] = backlog
    return normalized


def build_implementation_work_index(
    snapshot: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if snapshot is None:
        snapshot, error = load_json_object_report(
            implementation_delta_snapshot_path(),
            artifact_kind="implementation delta snapshot",
        )
        if snapshot is None:
            raise RuntimeError(error or "implementation delta snapshot is missing")
    if (
        str(snapshot.get("artifact_kind", "")).strip()
        != IMPLEMENTATION_DELTA_SNAPSHOT_ARTIFACT_KIND
    ):
        raise RuntimeError("implementation work index requires implementation_delta_snapshot input")

    delta = snapshot.get("delta", {})
    target = snapshot.get("target", {})
    if not isinstance(target, dict):
        raise RuntimeError("malformed implementation delta snapshot: target must be an object")
    target_spec_ids = [
        str(spec_id).strip()
        for spec_id in target.get(
            "resolved_target_spec_ids",
            target.get("valid_target_spec_ids", target.get("target_spec_ids", [])),
        )
        if str(spec_id).strip()
    ]
    if not isinstance(delta, dict):
        delta = {}
    delta_sets = {
        key: {str(item).strip() for item in delta.get(key, []) if str(item).strip()}
        for key in (
            "new_spec_ids",
            "changed_spec_ids",
            "missing_trace_refs",
            "evidence_gap_refs",
            "spec_quality_blocker_ids",
        )
    }
    changed_contract_refs = [
        str(item).strip() for item in delta.get("changed_contract_refs", []) if str(item).strip()
    ]
    changed_acceptance_refs = [
        str(item).strip() for item in delta.get("changed_acceptance_refs", []) if str(item).strip()
    ]
    required_test_refs = [
        str(item).strip() for item in delta.get("required_test_refs", []) if str(item).strip()
    ]
    likely_code_refs = [
        str(item).strip()
        for item in delta.get("likely_affected_code_refs", [])
        if str(item).strip()
    ]
    raw_likely_code_refs_by_spec = delta.get("likely_affected_code_refs_by_spec", {})
    likely_code_refs_by_spec: dict[str, list[str]] = {}
    if isinstance(raw_likely_code_refs_by_spec, dict):
        for spec_id, refs in raw_likely_code_refs_by_spec.items():
            if isinstance(refs, list):
                likely_code_refs_by_spec[str(spec_id).strip()] = sorted(
                    {str(ref).strip() for ref in refs if str(ref).strip()}
                )

    entries: list[dict[str, Any]] = []
    readiness_groups: dict[str, list[str]] = {}
    next_gap_groups: dict[str, list[str]] = {}
    named_filters: dict[str, list[str]] = {
        name: [] for name in IMPLEMENTATION_WORK_INDEX_NAMED_FILTERS
    }

    if str(snapshot.get("status", "")).strip() != "invalid_target_scope":
        for spec_id in target_spec_ids:
            spec_contract_refs = [
                ref for ref in changed_contract_refs if ref.startswith(f"{spec_id}:")
            ]
            spec_acceptance_refs = [
                ref for ref in changed_acceptance_refs if ref.startswith(f"{spec_id}:")
            ]
            spec_required_tests = [
                ref for ref in required_test_refs if ref.startswith(f"{spec_id}:")
            ]
            spec_likely_code_refs = likely_code_refs_by_spec.get(spec_id, [])
            if not spec_likely_code_refs and len(target_spec_ids) == 1:
                spec_likely_code_refs = likely_code_refs
            spec_trace_gap = f"trace::{spec_id}" in delta_sets["missing_trace_refs"]
            spec_evidence_gap = f"evidence::{spec_id}" in delta_sets["evidence_gap_refs"]
            spec_quality_gap = spec_id in delta_sets["spec_quality_blocker_ids"]
            if not any(
                (
                    spec_id in delta_sets["new_spec_ids"],
                    spec_id in delta_sets["changed_spec_ids"],
                    spec_contract_refs,
                    spec_acceptance_refs,
                    spec_required_tests,
                    spec_trace_gap,
                    spec_evidence_gap,
                    spec_quality_gap,
                )
            ):
                continue

            readiness, blockers = implementation_work_item_readiness(
                snapshot_status=str(snapshot.get("status", "")),
                has_quality_blocker=spec_quality_gap,
                has_trace_gap=spec_trace_gap,
                has_evidence_gap=spec_evidence_gap,
            )
            next_gap = implementation_policy_next_gap(readiness)
            if spec_id in delta_sets["new_spec_ids"]:
                implementation_reason = "new_spec"
            elif spec_acceptance_refs:
                implementation_reason = "changed_acceptance"
            elif spec_contract_refs:
                implementation_reason = "changed_contract"
            elif spec_trace_gap:
                implementation_reason = "missing_trace_baseline"
            elif spec_evidence_gap:
                implementation_reason = "missing_evidence_baseline"
            else:
                implementation_reason = "changed_spec"

            work_item_id = f"implementation_work::{spec_id}::{implementation_reason}"
            delta_refs = []
            if spec_id in delta_sets["new_spec_ids"]:
                delta_refs.append(f"new_spec_ids::{spec_id}")
            if spec_id in delta_sets["changed_spec_ids"]:
                delta_refs.append(f"changed_spec_ids::{spec_id}")
            delta_refs.extend(f"changed_contract_refs::{ref}" for ref in spec_contract_refs)
            delta_refs.extend(f"changed_acceptance_refs::{ref}" for ref in spec_acceptance_refs)
            if spec_trace_gap:
                delta_refs.append(f"missing_trace_refs::trace::{spec_id}")
            if spec_evidence_gap:
                delta_refs.append(f"evidence_gap_refs::evidence::{spec_id}")
            if spec_quality_gap:
                delta_refs.append(f"spec_quality_blocker_ids::{spec_id}")

            entry = {
                "work_item_id": work_item_id,
                "affected_spec_ids": [spec_id],
                "implementation_reason": implementation_reason,
                "delta_refs": sorted(delta_refs),
                "required_tests": sorted(spec_required_tests),
                "expected_evidence": [f"implementation_evidence::{spec_id}"],
                "likely_code_refs": spec_likely_code_refs,
                "readiness": readiness,
                "blockers": blockers,
                "next_gap": next_gap,
            }
            entries.append(entry)
            readiness_groups.setdefault(readiness, []).append(work_item_id)
            next_gap_groups.setdefault(next_gap, []).append(work_item_id)
            if readiness in named_filters:
                named_filters[readiness].append(work_item_id)

    backlog_items = implementation_work_backlog_items_from_entries(entries)

    return {
        "artifact_kind": IMPLEMENTATION_WORK_INDEX_ARTIFACT_KIND,
        "schema_version": IMPLEMENTATION_WORK_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": implementation_delta_policy_reference(),
        "source_delta_snapshot": {
            "artifact_path": implementation_delta_snapshot_path().relative_to(ROOT).as_posix(),
            "generated_at": str(snapshot.get("generated_at", "")).strip(),
            "status": str(snapshot.get("status", "")).strip(),
            "review_state": str(snapshot.get("review_state", "")).strip(),
            "next_gap": str(snapshot.get("next_gap", "")).strip(),
        },
        "entry_count": len(entries),
        "entries": entries,
        "viewer_projection": {
            "readiness": {key: sorted(value) for key, value in sorted(readiness_groups.items())},
            "next_gap": {key: sorted(value) for key, value in sorted(next_gap_groups.items())},
            "named_filters": {key: sorted(value) for key, value in sorted(named_filters.items())},
        },
        "implementation_backlog": {
            "entry_count": len(backlog_items),
            "items": backlog_items,
            "grouped_by_next_gap": {
                key: sorted(value)
                for key, value in sorted(next_gap_groups.items())
                if key != "none"
            },
        },
        "canonical_mutations_allowed": False,
        "runtime_code_mutations_allowed": False,
    }


def write_implementation_work_index(index: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = implementation_work_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def load_current_implementation_work_index() -> dict[str, Any]:
    existing = load_json_object(implementation_work_index_path())
    if isinstance(existing, dict):
        return normalize_implementation_work_index_backlog(existing)
    return {
        "artifact_kind": IMPLEMENTATION_WORK_INDEX_ARTIFACT_KIND,
        "schema_version": IMPLEMENTATION_WORK_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": implementation_delta_policy_reference(),
        "source_delta_snapshot": {},
        "entry_count": 0,
        "entries": [],
        "viewer_projection": {
            "readiness": {},
            "next_gap": {},
            "named_filters": {name: [] for name in IMPLEMENTATION_WORK_INDEX_NAMED_FILTERS},
        },
        "implementation_backlog": {
            "entry_count": 0,
            "items": [],
            "grouped_by_next_gap": {},
        },
        "canonical_mutations_allowed": False,
        "runtime_code_mutations_allowed": False,
    }


def load_review_feedback_records() -> list[dict[str, Any]]:
    records, error = load_json_list_report(
        review_feedback_records_path(),
        artifact_kind="review feedback records",
    )
    if records is None:
        raise RuntimeError(error or "review feedback records are missing")
    return records


def review_feedback_next_gap(status: str) -> str:
    normalized = status.strip()
    try:
        value = review_feedback_policy_lookup(f"next_gap_defaults.{normalized}")
    except KeyError:
        return "repair_review_feedback_record"
    return str(value).strip() or "repair_review_feedback_record"


def normalize_review_feedback_verification(value: object) -> list[str]:
    if not isinstance(value, list):
        return []
    return sorted({str(item).strip() for item in value if str(item).strip()})


def review_feedback_required_string(
    record: dict[str, Any],
    field: str,
    findings: list[str],
    *,
    allow_blank: bool = False,
) -> str:
    if field not in record:
        return ""
    value = record.get(field)
    if not isinstance(value, str):
        findings.append(f"invalid_field_type::{field}")
        if not allow_blank:
            findings.append(f"blank_required_field::{field}")
        return ""
    text = value.strip()
    if not text and not allow_blank:
        findings.append(f"blank_required_field::{field}")
    return text


def derive_review_feedback_status(record: dict[str, Any]) -> tuple[str, list[str]]:
    findings: list[str] = []
    missing_fields = [
        field for field in REVIEW_FEEDBACK_REQUIRED_CLOSURE_FIELDS if field not in record
    ]
    if missing_fields:
        findings.extend(f"missing_required_field::{field}" for field in missing_fields)

    string_values = {
        field: review_feedback_required_string(
            record,
            field,
            findings,
            allow_blank=field == "residual_risk",
        )
        for field in REVIEW_FEEDBACK_REQUIRED_CLOSURE_FIELDS
        if field != "verification"
    }
    root_cause_class = string_values.get("root_cause_class", "")
    prevention_action = string_values.get("prevention_action", "")
    verification = normalize_review_feedback_verification(record.get("verification"))
    residual_risk = string_values.get("residual_risk", "")
    recorded_at = review_feedback_required_string(
        record,
        "recorded_at",
        findings,
        allow_blank=True,
    )

    if recorded_at and parse_iso_datetime(recorded_at) is None:
        findings.append("invalid_recorded_at")
    if root_cause_class and root_cause_class not in REVIEW_FEEDBACK_ROOT_CAUSE_CLASSES:
        findings.append(f"unknown_root_cause_class::{root_cause_class}")
    if prevention_action and prevention_action not in REVIEW_FEEDBACK_PREVENTION_ACTIONS:
        findings.append(f"unknown_prevention_action::{prevention_action}")
    invalid_verification = [
        item for item in verification if item not in REVIEW_FEEDBACK_VERIFICATION_KINDS
    ]
    findings.extend(f"unknown_verification_kind::{item}" for item in invalid_verification)
    if record.get("verification") is not None and not isinstance(record.get("verification"), list):
        findings.append("verification_must_be_list")
    if prevention_action == REVIEW_FEEDBACK_ACCEPTED_RISK_ACTION and not residual_risk:
        findings.append("accepted_risk_requires_residual_risk")

    invalid_contract = any(
        finding.startswith(
            (
                "invalid_field_type::",
                "unknown_root_cause_class::",
                "unknown_prevention_action::",
                "unknown_verification_kind::",
            )
        )
        or finding
        in {
            "accepted_risk_requires_residual_risk",
            "invalid_recorded_at",
            "verification_must_be_list",
        }
        for finding in findings
    )
    if invalid_contract:
        return "invalid_feedback_record", sorted(findings)
    if not root_cause_class:
        return "missing_root_cause", sorted(findings)
    if not prevention_action:
        return "missing_prevention_action", sorted(findings)
    if not verification:
        return "missing_verification", sorted(findings)
    if findings:
        return "invalid_feedback_record", sorted(findings)
    if prevention_action == REVIEW_FEEDBACK_ACCEPTED_RISK_ACTION:
        return "accepted_risk_recorded", []
    return "prevention_recorded", []


def review_feedback_entry_id(record: dict[str, Any], index: int) -> str:
    raw_id = str(record.get("feedback_id", "")).strip()
    if raw_id:
        return raw_id
    thread_url = str(record.get("source_thread_url", "")).strip()
    if thread_url:
        digest = hashlib.sha256(thread_url.encode("utf-8")).hexdigest()[:12]
        return f"review_feedback::{digest}"
    return f"review_feedback::record_{index + 1}"


def review_feedback_revalidation_contract(status: str, next_gap: str) -> dict[str, Any]:
    contract_status = str(
        REVIEW_FEEDBACK_ACCEPTED_RISK_REVALIDATION_CONTRACT.get("status", "")
    ).strip()
    contract_next_gap = str(
        REVIEW_FEEDBACK_ACCEPTED_RISK_REVALIDATION_CONTRACT.get("next_gap", "")
    ).strip()
    if status != contract_status or next_gap != contract_next_gap:
        return {}
    contract = dict(REVIEW_FEEDBACK_ACCEPTED_RISK_REVALIDATION_CONTRACT)
    contract["triggered_context_change_signals"] = []
    return contract


def review_feedback_recorded_after(candidate: str, baseline: str) -> bool:
    candidate_text = str(candidate).strip()
    baseline_text = str(baseline).strip()
    if not candidate_text or not baseline_text:
        return False
    candidate_dt = parse_iso_datetime(candidate_text)
    baseline_dt = parse_iso_datetime(baseline_text)
    if candidate_dt is not None and baseline_dt is not None:
        return candidate_dt > baseline_dt
    return False


def review_feedback_revalidation_signals(
    entry: dict[str, Any],
    entries: list[dict[str, Any]],
) -> list[str]:
    revalidation = entry.get("revalidation")
    if not isinstance(revalidation, dict):
        return []

    signals: list[str] = []
    root_cause_class = str(entry.get("root_cause_class", "")).strip()
    recorded_at = str(entry.get("recorded_at", "")).strip()
    feedback_id = str(entry.get("feedback_id", "")).strip()
    later_same_cause_records = [
        other
        for other in entries
        if str(other.get("feedback_id", "")).strip() != feedback_id
        and str(other.get("root_cause_class", "")).strip() == root_cause_class
        and review_feedback_recorded_after(str(other.get("recorded_at", "")).strip(), recorded_at)
    ]
    accepted_risk_reviewed_at = str(entry.get("accepted_risk_reviewed_at", "")).strip()
    accepted_risk_review_decision = str(entry.get("accepted_risk_review_decision", "")).strip()
    accepted_risk_review_covers_context = (
        accepted_risk_review_decision == "keep_accepted_risk"
        and accepted_risk_reviewed_at
        and all(
            review_feedback_recorded_after(
                accepted_risk_reviewed_at,
                str(other.get("recorded_at", "")).strip(),
            )
            for other in later_same_cause_records
        )
    )
    if root_cause_class and later_same_cause_records and not accepted_risk_review_covers_context:
        signals.append("same_root_cause_reappears")
    return signals


def apply_review_feedback_revalidation_triggers(
    entries: list[dict[str, Any]],
    backlog_items: list[dict[str, Any]],
) -> None:
    backlog_by_feedback_id = {
        str(item.get("feedback_id", "")).strip(): item
        for item in backlog_items
        if isinstance(item, dict)
    }
    for entry in entries:
        revalidation = entry.get("revalidation")
        if not isinstance(revalidation, dict):
            continue
        triggered_signals = review_feedback_revalidation_signals(entry, entries)
        if triggered_signals:
            revalidation = dict(revalidation)
            revalidation["review_state"] = "review_due"
            revalidation["triggered_context_change_signals"] = triggered_signals
            entry["revalidation"] = revalidation
        review_state = str(revalidation.get("review_state", "")).strip()
        if review_state:
            entry["review_state"] = review_state
        feedback_id = str(entry.get("feedback_id", "")).strip()
        backlog_item = backlog_by_feedback_id.get(feedback_id)
        if backlog_item is not None:
            backlog_item["revalidation"] = entry["revalidation"]
            if review_state:
                backlog_item["review_state"] = review_state


def build_review_feedback_index(
    records: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    if records is None:
        records = load_review_feedback_records()

    entries: list[dict[str, Any]] = []
    status_groups: dict[str, list[str]] = {}
    root_cause_groups: dict[str, list[str]] = {}
    prevention_groups: dict[str, list[str]] = {}
    verification_groups: dict[str, list[str]] = {}
    next_gap_groups: dict[str, list[str]] = {}
    backlog_next_gap_groups: dict[str, list[str]] = {}
    named_filters: dict[str, list[str]] = {name: [] for name in REVIEW_FEEDBACK_INDEX_NAMED_FILTERS}
    backlog_items: list[dict[str, Any]] = []

    for index, record in enumerate(records):
        feedback_id = review_feedback_entry_id(record, index)
        root_cause_class = str(record.get("root_cause_class", "")).strip()
        prevention_action = str(record.get("prevention_action", "")).strip()
        verification = normalize_review_feedback_verification(record.get("verification"))
        status, findings = derive_review_feedback_status(record)
        next_gap = review_feedback_next_gap(status)
        revalidation_contract = review_feedback_revalidation_contract(status, next_gap)

        entry = {
            "feedback_id": feedback_id,
            "source_pr": record.get("source_pr"),
            "source_thread_url": str(record.get("source_thread_url", "")).strip(),
            "reviewer": str(record.get("reviewer", "")).strip(),
            "review_comment_summary": str(record.get("review_comment_summary", "")).strip(),
            "fix_summary": str(record.get("fix_summary", "")).strip(),
            "root_cause_class": root_cause_class,
            "prevention_action": prevention_action,
            "verification": verification,
            "residual_risk": str(record.get("residual_risk", "")).strip(),
            "resolved_commit": str(record.get("resolved_commit", "")).strip(),
            "recorded_at": str(record.get("recorded_at", "")).strip(),
            "status": status,
            "next_gap": next_gap,
            "findings": findings,
        }
        for optional_field in (
            "accepted_risk_reviewed_at",
            "accepted_risk_review_decision",
            "accepted_risk_review_summary",
        ):
            optional_value = str(record.get(optional_field, "")).strip()
            if optional_value:
                entry[optional_field] = optional_value
        if revalidation_contract:
            entry["revalidation"] = revalidation_contract
        entries.append(entry)

        status_groups.setdefault(status, []).append(feedback_id)
        if root_cause_class:
            root_cause_groups.setdefault(root_cause_class, []).append(feedback_id)
            if root_cause_class in named_filters:
                named_filters[root_cause_class].append(feedback_id)
        if prevention_action:
            prevention_groups.setdefault(prevention_action, []).append(feedback_id)
        for verification_kind in verification:
            verification_groups.setdefault(verification_kind, []).append(feedback_id)
        next_gap_groups.setdefault(next_gap, []).append(feedback_id)
        if status in named_filters:
            named_filters[status].append(feedback_id)
        if status != "prevention_recorded":
            backlog_item = {
                "feedback_id": feedback_id,
                "status": status,
                "root_cause_class": root_cause_class,
                "prevention_action": prevention_action,
                "next_gap": next_gap,
            }
            if revalidation_contract:
                backlog_item["revalidation"] = revalidation_contract
            backlog_items.append(backlog_item)
            backlog_next_gap_groups.setdefault(next_gap, []).append(feedback_id)

    apply_review_feedback_revalidation_triggers(entries, backlog_items)

    for bucket in (
        status_groups,
        root_cause_groups,
        prevention_groups,
        verification_groups,
        next_gap_groups,
        backlog_next_gap_groups,
        named_filters,
    ):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    return {
        "artifact_kind": REVIEW_FEEDBACK_INDEX_ARTIFACT_KIND,
        "schema_version": REVIEW_FEEDBACK_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": review_feedback_policy_reference(),
        "source_artifacts": {
            "review_feedback_records": {
                "artifact_path": REVIEW_FEEDBACK_RECORDS_RELATIVE_PATH,
                "record_count": len(records),
            }
        },
        "semantic_boundary": str(
            review_feedback_policy_lookup("learning_loop_contract.semantic_boundary")
        ),
        "entry_count": len(entries),
        "entries": entries,
        "viewer_projection": {
            "status": {key: sorted(value) for key, value in sorted(status_groups.items())},
            "root_cause_class": {
                key: sorted(value) for key, value in sorted(root_cause_groups.items())
            },
            "prevention_action": {
                key: sorted(value) for key, value in sorted(prevention_groups.items())
            },
            "verification_kind": {
                key: sorted(value) for key, value in sorted(verification_groups.items())
            },
            "next_gap": {key: sorted(value) for key, value in sorted(next_gap_groups.items())},
            "named_filters": {key: sorted(value) for key, value in sorted(named_filters.items())},
        },
        "review_feedback_backlog": {
            "entry_count": len(backlog_items),
            "items": backlog_items,
            "grouped_by_next_gap": {
                key: sorted(value) for key, value in sorted(backlog_next_gap_groups.items())
            },
        },
        "canonical_mutations_allowed": False,
        "runtime_code_mutations_allowed": False,
    }


def write_review_feedback_index(index: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = review_feedback_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def transition_packet_finding(
    *,
    code: str,
    message: str,
    field: str = "",
    severity: str = "error",
    family: str = "schema",
    profile: str = "",
) -> dict[str, str]:
    finding = {
        "code": code,
        "message": message,
        "severity": severity,
        "family": family,
    }
    if field:
        finding["field"] = field
    if profile:
        finding["profile"] = profile
    return finding


def product_spec_transition_policy_path() -> Path:
    return TOOLS_DIR / "product_spec_transition_policy.json"


def proposal_promotion_policy_path() -> Path:
    return TOOLS_DIR / "proposal_promotion_policy.json"


def load_product_spec_transition_policy_report() -> tuple[
    dict[str, Any] | None, list[dict[str, str]]
]:
    path = product_spec_transition_policy_path()
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return None, [
            transition_packet_finding(
                code="product_spec_transition_policy_unavailable",
                family="profile",
                profile="product_spec",
                message=(
                    "failed to read product_spec transition policy artifact: "
                    f"{path.as_posix()} ({exc})"
                ),
            )
        ]
    except json.JSONDecodeError as exc:
        return None, [
            transition_packet_finding(
                code="malformed_product_spec_transition_policy",
                family="profile",
                profile="product_spec",
                message=(
                    f"malformed product_spec transition policy artifact: {path.as_posix()} ({exc})"
                ),
            )
        ]
    if not isinstance(payload, dict):
        return None, [
            transition_packet_finding(
                code="malformed_product_spec_transition_policy",
                family="profile",
                profile="product_spec",
                message=(
                    "malformed product_spec transition policy artifact: "
                    f"{path.as_posix()} must contain a JSON object"
                ),
            )
        ]

    required_sections = (
        "inherits_transition_profile",
        "required_binding_fields",
        "required_provenance_links",
        "reviewable_source_prefixes",
        "forbidden_source_prefixes",
        "apply_scope_rule",
    )
    missing = [section for section in required_sections if section not in payload]
    if missing:
        return None, [
            transition_packet_finding(
                code="malformed_product_spec_transition_policy",
                family="profile",
                profile="product_spec",
                message=(
                    "malformed product_spec transition policy artifact: missing top-level "
                    f"section(s): {', '.join(missing)}"
                ),
            )
        ]

    return payload, []


def load_proposal_promotion_policy_report() -> tuple[dict[str, Any] | None, list[dict[str, str]]]:
    path = proposal_promotion_policy_path()
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return None, [
            transition_packet_finding(
                code="proposal_promotion_policy_unavailable",
                family="profile",
                profile="specgraph_core",
                message=(
                    f"failed to read proposal promotion policy artifact: {path.as_posix()} ({exc})"
                ),
            )
        ]
    except json.JSONDecodeError as exc:
        return None, [
            transition_packet_finding(
                code="malformed_proposal_promotion_policy",
                family="profile",
                profile="specgraph_core",
                message=(
                    f"malformed proposal promotion policy artifact: {path.as_posix()} ({exc})"
                ),
            )
        ]
    if not isinstance(payload, dict):
        return None, [
            transition_packet_finding(
                code="malformed_proposal_promotion_policy",
                family="profile",
                profile="specgraph_core",
                message=(
                    "malformed proposal promotion policy artifact: "
                    f"{path.as_posix()} must contain a JSON object"
                ),
            )
        ]

    required_sections = (
        "semantic_boundary_principle",
        "semantic_artifact_classes",
        "repository_projection_defaults",
    )
    missing = [section for section in required_sections if section not in payload]
    if missing:
        return None, [
            transition_packet_finding(
                code="malformed_proposal_promotion_policy",
                family="profile",
                profile="specgraph_core",
                message=(
                    "malformed proposal promotion policy artifact: missing top-level "
                    f"section(s): {', '.join(missing)}"
                ),
            )
        ]

    if not isinstance(payload.get("semantic_artifact_classes"), dict):
        return None, [
            transition_packet_finding(
                code="malformed_proposal_promotion_policy",
                family="profile",
                profile="specgraph_core",
                message=(
                    "malformed proposal promotion policy artifact: "
                    "semantic_artifact_classes must be an object"
                ),
            )
        ]
    if not isinstance(payload.get("repository_projection_defaults"), list):
        return None, [
            transition_packet_finding(
                code="malformed_proposal_promotion_policy",
                family="profile",
                profile="specgraph_core",
                message=(
                    "malformed proposal promotion policy artifact: "
                    "repository_projection_defaults must be a list"
                ),
            )
        ]

    return payload, []


def _transition_packet_string_list(
    *,
    field_name: str,
    value: Any,
) -> tuple[list[str], list[dict[str, str]]]:
    if not isinstance(value, list):
        return [], [
            transition_packet_finding(
                code="invalid_string_list",
                field=field_name,
                message=f"{field_name} must be a list of non-empty strings",
            )
        ]

    normalized: list[str] = []
    findings: list[dict[str, str]] = []
    for index, item in enumerate(value, start=1):
        if not isinstance(item, str):
            findings.append(
                transition_packet_finding(
                    code="invalid_string_list_item",
                    field=field_name,
                    message=f"{field_name}[{index}] must be a non-empty string",
                )
            )
            continue
        normalized_item = item.strip()
        if not normalized_item:
            findings.append(
                transition_packet_finding(
                    code="invalid_string_list_item",
                    field=field_name,
                    message=f"{field_name}[{index}] must be a non-empty string",
                )
            )
            continue
        normalized.append(normalized_item)
    return normalized, findings


def _transition_packet_optional_string(
    *,
    field_name: str,
    value: Any,
) -> tuple[str, list[dict[str, str]]]:
    if value is None:
        return "", []
    if not isinstance(value, str):
        return "", [
            transition_packet_finding(
                code="invalid_string",
                field=field_name,
                message=f"{field_name} must be a non-empty string when provided",
            )
        ]
    normalized = value.strip()
    if not normalized:
        return "", [
            transition_packet_finding(
                code="invalid_string",
                field=field_name,
                message=f"{field_name} must be a non-empty string when provided",
            )
        ]
    return normalized, []


def _transition_packet_duplicate_list_findings(
    *,
    field_name: str,
    values: list[str],
    family: str,
) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    seen: set[str] = set()
    duplicates: list[str] = []
    for value in values:
        if value in seen and value not in duplicates:
            duplicates.append(value)
        seen.add(value)
    for duplicate in duplicates:
        findings.append(
            transition_packet_finding(
                code="duplicate_list_item",
                field=field_name,
                family=family,
                message=f"{field_name} contains duplicate item: {duplicate}",
            )
        )
    return findings


def _looks_like_repo_path(value: str) -> bool:
    if not value:
        return False
    return "/" in value or value.endswith((".md", ".yaml", ".yml", ".json", ".toml"))


def _normalize_transition_repo_path(value: str) -> str:
    if not _looks_like_repo_path(value):
        return value
    return PurePosixPath(value).as_posix()


def _validate_transition_surface_path(
    *,
    field_name: str,
    value: str,
) -> list[dict[str, str]]:
    if not value or not _looks_like_repo_path(value):
        return []
    path = PurePosixPath(value)
    findings: list[dict[str, str]] = []
    if path.is_absolute():
        findings.append(
            transition_packet_finding(
                code="absolute_path_not_allowed",
                field=field_name,
                family="diff_scope",
                message=f"{field_name} must use repo-relative paths, not absolute paths",
            )
        )
    if ".." in path.parts:
        findings.append(
            transition_packet_finding(
                code="parent_traversal_not_allowed",
                field=field_name,
                family="diff_scope",
                message=f"{field_name} must not use parent traversal",
            )
        )
    return findings


def _normalize_transition_packet_context(
    packet: Any,
    *,
    validator_profile: str | None = None,
) -> tuple[dict[str, Any], list[dict[str, str]]]:
    if not isinstance(packet, dict):
        return {}, [
            transition_packet_finding(
                code="packet_not_object",
                field="packet",
                family="schema",
                message="transition packet must be a JSON object",
            )
        ]

    findings: list[dict[str, str]] = []
    packet_type, packet_type_findings = _transition_packet_optional_string(
        field_name="packet_type",
        value=packet.get("packet_type"),
    )
    findings.extend(packet_type_findings)
    if packet_type and packet_type not in VALID_TRANSITION_PACKET_TYPES:
        findings.append(
            transition_packet_finding(
                code="invalid_packet_type",
                field="packet_type",
                family="schema",
                message=(
                    "packet_type must be one of: "
                    + ", ".join(sorted(VALID_TRANSITION_PACKET_TYPES))
                ),
            )
        )

    transition_profile_source = (
        validator_profile if validator_profile is not None else packet.get("transition_profile")
    )
    transition_profile, transition_profile_findings = _transition_packet_optional_string(
        field_name="transition_profile",
        value=transition_profile_source,
    )
    findings.extend(transition_profile_findings)
    if not transition_profile:
        transition_profile = DEFAULT_TRANSITION_VALIDATOR_PROFILE
    if transition_profile not in VALID_TRANSITION_VALIDATOR_PROFILES:
        findings.append(
            transition_packet_finding(
                code="invalid_transition_profile",
                field="transition_profile",
                family="schema",
                message=(
                    "transition_profile must be one of: "
                    + ", ".join(sorted(VALID_TRANSITION_VALIDATOR_PROFILES))
                ),
            )
        )

    transition_intent, transition_intent_findings = _transition_packet_optional_string(
        field_name="transition_intent",
        value=packet.get("transition_intent"),
    )
    findings.extend(transition_intent_findings)
    actor_class, actor_class_findings = _transition_packet_optional_string(
        field_name="actor_class",
        value=packet.get("actor_class"),
    )
    findings.extend(actor_class_findings)
    authority_class, authority_class_findings = _transition_packet_optional_string(
        field_name="authority_class",
        value=packet.get("authority_class"),
    )
    findings.extend(authority_class_findings)
    target_artifact_class, target_artifact_class_findings = _transition_packet_optional_string(
        field_name="target_artifact_class",
        value=packet.get("target_artifact_class"),
    )
    findings.extend(target_artifact_class_findings)
    source_artifact_class, source_artifact_class_findings = _transition_packet_optional_string(
        field_name="source_artifact_class",
        value=packet.get("source_artifact_class"),
    )
    findings.extend(source_artifact_class_findings)
    target_scope, target_scope_findings = _transition_packet_optional_string(
        field_name="target_scope",
        value=packet.get("target_scope"),
    )
    findings.extend(target_scope_findings)
    motivating_concern, motivating_concern_findings = _transition_packet_optional_string(
        field_name="motivating_concern",
        value=packet.get("motivating_concern"),
    )
    findings.extend(motivating_concern_findings)
    lineage_root, lineage_root_findings = _transition_packet_optional_string(
        field_name="lineage_root",
        value=packet.get("lineage_root"),
    )
    findings.extend(lineage_root_findings)
    product_graph_root, product_graph_root_findings = _transition_packet_optional_string(
        field_name="product_graph_root",
        value=packet.get("product_graph_root"),
    )
    findings.extend(product_graph_root_findings)
    normalized_title, normalized_title_findings = _transition_packet_optional_string(
        field_name="normalized_title",
        value=packet.get("normalized_title"),
    )
    findings.extend(normalized_title_findings)
    bounded_scope, bounded_scope_findings = _transition_packet_optional_string(
        field_name="bounded_scope",
        value=packet.get("bounded_scope"),
    )
    findings.extend(bounded_scope_findings)

    source_refs, source_ref_findings = _transition_packet_string_list(
        field_name="source_refs",
        value=packet.get("source_refs"),
    )
    findings.extend(source_ref_findings)
    declared_change_surface, declared_change_findings = _transition_packet_string_list(
        field_name="declared_change_surface",
        value=packet.get("declared_change_surface"),
    )
    findings.extend(declared_change_findings)
    required_provenance_links, provenance_link_findings = _transition_packet_string_list(
        field_name="required_provenance_links",
        value=packet.get("required_provenance_links"),
    )
    findings.extend(provenance_link_findings)

    normalized_source_refs = [_normalize_transition_repo_path(item) for item in source_refs]
    normalized_declared_change_surface = [
        _normalize_transition_repo_path(item) for item in declared_change_surface
    ]
    normalized_target_scope = _normalize_transition_repo_path(target_scope)
    normalized_product_graph_root = _normalize_transition_repo_path(product_graph_root)

    return {
        "packet": packet,
        "packet_type": packet_type,
        "transition_profile": transition_profile,
        "transition_intent": transition_intent,
        "source_refs": normalized_source_refs,
        "actor_class": actor_class,
        "authority_class": authority_class,
        "target_artifact_class": target_artifact_class,
        "source_artifact_class": source_artifact_class,
        "target_scope": normalized_target_scope,
        "motivating_concern": motivating_concern,
        "lineage_root": lineage_root,
        "product_graph_root": normalized_product_graph_root,
        "normalized_title": normalized_title,
        "bounded_scope": bounded_scope,
        "declared_change_surface": normalized_declared_change_surface,
        "required_provenance_links": required_provenance_links,
    }, findings


def _validate_transition_packet_schema(context: dict[str, Any]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    packet_type = str(context.get("packet_type", "")).strip()
    transition_intent = str(context.get("transition_intent", "")).strip()
    if not packet_type:
        findings.append(
            transition_packet_finding(
                code="missing_packet_type",
                field="packet_type",
                family="schema",
                message="packet_type must be declared",
            )
        )
    if not transition_intent:
        findings.append(
            transition_packet_finding(
                code="missing_transition_intent",
                field="transition_intent",
                family="schema",
                message="transition_intent must be a non-empty string",
            )
        )
    if packet_type in TRANSITION_PACKET_TYPE_REQUIRED_FIELDS:
        for field_name in sorted(TRANSITION_PACKET_TYPE_REQUIRED_FIELDS[packet_type]):
            if not str(context.get(field_name, "")).strip():
                findings.append(
                    transition_packet_finding(
                        code="missing_packet_type_required_field",
                        field=field_name,
                        family="schema",
                        message=(f"{field_name} is required for packet_type={packet_type}"),
                    )
                )
    return findings


def _validate_transition_packet_legality(context: dict[str, Any]) -> list[dict[str, str]]:
    packet_type = str(context.get("packet_type", "")).strip()
    transition_profile = str(context.get("transition_profile", "")).strip()
    findings: list[dict[str, str]] = []
    if (
        not packet_type
        or transition_profile not in TRANSITION_VALIDATOR_PROFILE_DEFINITIONS
        or packet_type not in VALID_TRANSITION_PACKET_TYPES
    ):
        return findings
    allowed_packet_types = TRANSITION_VALIDATOR_PROFILE_DEFINITIONS[transition_profile][
        "allowed_packet_types"
    ]
    if packet_type not in allowed_packet_types:
        findings.append(
            transition_packet_finding(
                code="packet_type_not_allowed_for_profile",
                field="packet_type",
                family="legality",
                message=(
                    f"packet_type={packet_type} is not allowed for "
                    f"transition_profile={transition_profile}"
                ),
            )
        )
        return findings

    if packet_type == "promotion":
        if str(context.get("source_artifact_class", "")).strip() != "working_draft":
            findings.append(
                transition_packet_finding(
                    code="promotion_source_must_be_working_draft",
                    field="source_artifact_class",
                    family="legality",
                    message=(
                        "promotion packets must declare source_artifact_class=working_draft "
                        "for draft-to-proposal promotion"
                    ),
                )
            )
        if str(context.get("target_artifact_class", "")).strip() != "reviewable_proposal":
            findings.append(
                transition_packet_finding(
                    code="promotion_target_must_be_reviewable_proposal",
                    field="target_artifact_class",
                    family="legality",
                    message=(
                        "promotion packets must target target_artifact_class=reviewable_proposal"
                    ),
                )
            )
    return findings


def _validate_transition_packet_provenance(context: dict[str, Any]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    if not context.get("source_refs"):
        findings.append(
            transition_packet_finding(
                code="missing_source_refs",
                field="source_refs",
                family="provenance",
                message="source_refs must be a non-empty list of source artifact references",
            )
        )
    if not context.get("required_provenance_links"):
        findings.append(
            transition_packet_finding(
                code="missing_required_provenance_links",
                field="required_provenance_links",
                family="provenance",
                message=(
                    "required_provenance_links must be a non-empty list of provenance link "
                    "requirements"
                ),
            )
        )
    if not (context.get("motivating_concern") or context.get("lineage_root")):
        findings.append(
            transition_packet_finding(
                code="missing_motivating_concern_or_lineage_root",
                family="provenance",
                message="packet must declare motivating_concern or lineage_root",
            )
        )
    if str(context.get("packet_type", "")).strip() == "promotion":
        required_links = {
            str(item).strip()
            for item in context.get("required_provenance_links", [])
            if str(item).strip()
        }
        if "source_draft_ref" not in required_links:
            findings.append(
                transition_packet_finding(
                    code="promotion_requires_source_draft_ref",
                    field="required_provenance_links",
                    family="provenance",
                    message=(
                        "promotion packets must preserve source_draft_ref in "
                        "required_provenance_links"
                    ),
                )
            )
    return findings


def _validate_transition_packet_boundedness(context: dict[str, Any]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    if not context.get("declared_change_surface"):
        findings.append(
            transition_packet_finding(
                code="missing_declared_change_surface",
                field="declared_change_surface",
                family="boundedness",
                message=(
                    "declared_change_surface must be a non-empty list describing the intended "
                    "mutation surface"
                ),
            )
        )
    for field_name in ("source_refs", "declared_change_surface", "required_provenance_links"):
        findings.extend(
            _transition_packet_duplicate_list_findings(
                field_name=field_name,
                values=list(context.get(field_name, [])),
                family="boundedness",
            )
        )
    return findings


def _validate_transition_packet_authority(context: dict[str, Any]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    actor_class = str(context.get("actor_class", "")).strip()
    authority_class = str(context.get("authority_class", "")).strip()
    if not (actor_class or authority_class):
        findings.append(
            transition_packet_finding(
                code="missing_actor_or_authority_class",
                family="authority",
                message="packet must declare actor_class or authority_class",
            )
        )
    if str(context.get("packet_type", "")).strip() == "apply" and not authority_class:
        findings.append(
            transition_packet_finding(
                code="apply_requires_authority_class",
                field="authority_class",
                family="authority",
                message="apply packets must declare authority_class",
            )
        )
    return findings


def _validate_transition_packet_reconciliation(context: dict[str, Any]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    target_artifact_class = str(context.get("target_artifact_class", "")).strip()
    target_scope = str(context.get("target_scope", "")).strip()
    declared_change_surface = list(context.get("declared_change_surface", []))
    if not (target_artifact_class or target_scope):
        findings.append(
            transition_packet_finding(
                code="missing_target_binding",
                family="reconciliation",
                message="packet must declare target_artifact_class or target_scope",
            )
        )
    if target_scope and _looks_like_repo_path(target_scope):
        normalized_surface = {
            PurePosixPath(item).as_posix() if _looks_like_repo_path(item) else item
            for item in declared_change_surface
        }
        if PurePosixPath(target_scope).as_posix() not in normalized_surface:
            findings.append(
                transition_packet_finding(
                    code="target_scope_outside_declared_change_surface",
                    field="target_scope",
                    family="reconciliation",
                    message="target_scope must be included in declared_change_surface",
                )
            )
        return findings
    return findings


def _validate_transition_packet_diff_scope(context: dict[str, Any]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    for field_name in ("source_refs", "declared_change_surface"):
        for value in context.get(field_name, []):
            findings.extend(
                _validate_transition_surface_path(
                    field_name=field_name,
                    value=value,
                )
            )
    findings.extend(
        _validate_transition_surface_path(
            field_name="target_scope",
            value=str(context.get("target_scope", "")).strip(),
        )
    )
    findings.extend(
        _validate_transition_surface_path(
            field_name="product_graph_root",
            value=str(context.get("product_graph_root", "")).strip(),
        )
    )
    return findings


def _transition_path_within_root(path_text: str, root_text: str) -> bool:
    normalized_path = _normalize_transition_repo_path(path_text).rstrip("/")
    normalized_root = _normalize_transition_repo_path(root_text).rstrip("/")
    if not normalized_path or not normalized_root:
        return False
    return normalized_path == normalized_root or normalized_path.startswith(normalized_root + "/")


def _transition_path_matches_any_prefix(path_text: str, prefixes: list[str]) -> bool:
    normalized_path = _normalize_transition_repo_path(path_text).rstrip("/")
    for prefix in prefixes:
        normalized_prefix = _normalize_transition_repo_path(prefix).rstrip("/")
        if not normalized_prefix:
            continue
        if normalized_path == normalized_prefix or normalized_path.startswith(
            normalized_prefix + "/"
        ):
            return True
    return False


def _validate_transition_packet_profile(context: dict[str, Any]) -> list[dict[str, str]]:
    transition_profile = str(context.get("transition_profile", "")).strip()
    packet_type = str(context.get("packet_type", "")).strip()
    declared_change_surface = list(context.get("declared_change_surface", []))
    findings: list[dict[str, str]] = []

    if transition_profile == "specgraph_core":
        canonical_surface_hits = [
            path
            for path in declared_change_surface
            if any(path.startswith(prefix) for prefix in SPECGRAPH_CANONICAL_SURFACE_PREFIXES)
        ]
        if packet_type in {"promotion", "proposal"} and canonical_surface_hits:
            findings.append(
                transition_packet_finding(
                    code="profile_forbidden_canonical_mutation_surface",
                    field="declared_change_surface",
                    family="profile",
                    profile=transition_profile,
                    message=(
                        "specgraph_core promotion/proposal packets may not declare canonical "
                        "spec mutation surfaces; use an apply packet for canonical writeback"
                    ),
                )
            )
        if packet_type == "apply" and any(
            _transition_path_matches_any_prefix(ref, SPECGRAPH_RAW_DRAFT_SOURCE_PREFIXES)
            for ref in context.get("source_refs", [])
        ):
            findings.append(
                transition_packet_finding(
                    code="profile_apply_requires_reviewable_source",
                    field="source_refs",
                    family="profile",
                    profile=transition_profile,
                    message=(
                        "specgraph_core apply packets must source from reviewable proposal or "
                        "run artifacts, not raw proposal drafts"
                    ),
                )
            )
    if transition_profile == "product_spec":
        policy, policy_findings = load_product_spec_transition_policy_report()
        findings.extend(policy_findings)
        if policy is None:
            return findings

        product_graph_root = str(context.get("product_graph_root", "")).strip()
        required_binding_fields = [
            str(item).strip()
            for item in policy.get("required_binding_fields", [])
            if str(item).strip()
        ]
        if "product_graph_root" in required_binding_fields and not product_graph_root:
            findings.append(
                transition_packet_finding(
                    code="profile_missing_product_graph_root",
                    field="product_graph_root",
                    family="profile",
                    profile=transition_profile,
                    message=(
                        "product_spec packets must declare product_graph_root so product graphs "
                        "inherit one shared transition engine without redefining packet semantics"
                    ),
                )
            )
            return findings

        if product_graph_root:
            forbidden_source_prefixes = [
                str(item).strip()
                for item in policy.get("forbidden_source_prefixes", [])
                if str(item).strip()
            ]
            if packet_type == "apply" and any(
                _looks_like_repo_path(path)
                and _transition_path_matches_any_prefix(path, forbidden_source_prefixes)
                for path in context.get("source_refs", [])
            ):
                findings.append(
                    transition_packet_finding(
                        code="profile_apply_requires_reviewable_source",
                        field="source_refs",
                        family="profile",
                        profile=transition_profile,
                        message=(
                            "product_spec apply packets must source from reviewable proposal or "
                            "run artifacts, not raw drafts"
                        ),
                    )
                )

            required_provenance_links = {
                str(item).strip()
                for item in context.get("required_provenance_links", [])
                if str(item).strip()
            }
            for required_link in (
                str(item).strip()
                for item in policy.get("required_provenance_links", [])
                if str(item).strip()
            ):
                if required_link not in required_provenance_links:
                    findings.append(
                        transition_packet_finding(
                            code="profile_missing_required_product_provenance_link",
                            field="required_provenance_links",
                            family="profile",
                            profile=transition_profile,
                            message=(
                                "product_spec packets must preserve inherited provenance link: "
                                f"{required_link}"
                            ),
                        )
                    )

            reviewable_source_prefixes = [
                str(item).strip()
                for item in policy.get("reviewable_source_prefixes", [])
                if str(item).strip()
            ]
            if packet_type == "apply" and not any(
                _looks_like_repo_path(path)
                and _transition_path_matches_any_prefix(path, reviewable_source_prefixes)
                for path in context.get("source_refs", [])
            ):
                findings.append(
                    transition_packet_finding(
                        code="profile_apply_requires_reviewable_source",
                        field="source_refs",
                        family="profile",
                        profile=transition_profile,
                        message=(
                            "product_spec apply packets must inherit from reviewable proposal or "
                            "run artifacts before mutating a product graph"
                        ),
                    )
                )

            if (
                packet_type == "apply"
                and str(policy.get("apply_scope_rule", "")).strip() == "inside_product_graph_root"
            ):
                scoped_paths = [
                    path
                    for path in [
                        *context.get("declared_change_surface", []),
                        str(context.get("target_scope", "")).strip(),
                    ]
                    if str(path).strip() and _looks_like_repo_path(str(path).strip())
                ]
                outside_root = [
                    path
                    for path in scoped_paths
                    if not _transition_path_within_root(str(path), product_graph_root)
                ]
                if outside_root:
                    findings.append(
                        transition_packet_finding(
                            code="profile_apply_scope_outside_product_graph_root",
                            field="declared_change_surface",
                            family="profile",
                            profile=transition_profile,
                            message=(
                                "product_spec apply surfaces must remain inside "
                                "product_graph_root; "
                                f"outside paths: {', '.join(sorted(set(outside_root)))}"
                            ),
                        )
                    )
    return findings


def validate_transition_packet_report(
    packet: Any,
    *,
    validator_profile: str | None = None,
) -> dict[str, Any]:
    """Build a structured validation report for one normalized transition packet."""

    context, findings = _normalize_transition_packet_context(
        packet,
        validator_profile=validator_profile,
    )
    if not context:
        return {
            "ok": False,
            "packet_type": "",
            "packet_family": "",
            "packet_family_definition": {},
            "transition_profile": validator_profile or DEFAULT_TRANSITION_VALIDATOR_PROFILE,
            "validator_profile_definition": {},
            "proposal_promotion_policy_definition": {},
            "families_checked": list(TRANSITION_CHECK_FAMILIES),
            "finding_count": len(findings),
            "findings_by_family": {"schema": len(findings)},
            "findings": findings,
        }

    family_validators = {
        "schema": _validate_transition_packet_schema,
        "legality": _validate_transition_packet_legality,
        "provenance": _validate_transition_packet_provenance,
        "boundedness": _validate_transition_packet_boundedness,
        "authority": _validate_transition_packet_authority,
        "reconciliation": _validate_transition_packet_reconciliation,
        "diff_scope": _validate_transition_packet_diff_scope,
        "profile": _validate_transition_packet_profile,
    }
    for family in TRANSITION_CHECK_FAMILIES:
        findings.extend(family_validators[family](context))

    findings_by_family: dict[str, int] = {}
    for finding in findings:
        family = str(finding.get("family", "schema")).strip() or "schema"
        findings_by_family[family] = findings_by_family.get(family, 0) + 1

    packet_type = str(context.get("packet_type", "")).strip()
    transition_profile = str(context.get("transition_profile", "")).strip()
    product_spec_policy_definition = {}
    proposal_promotion_policy_definition = {}
    if transition_profile == "product_spec":
        policy, _findings = load_product_spec_transition_policy_report()
        if policy is not None:
            product_spec_policy_definition = policy
    if packet_type == "promotion":
        policy, _findings = load_proposal_promotion_policy_report()
        if policy is not None:
            proposal_promotion_policy_definition = policy
    return {
        "ok": not findings,
        "packet_type": packet_type,
        "packet_family": packet_type,
        "packet_family_definition": TRANSITION_PACKET_FAMILY_DEFINITIONS.get(packet_type, {}),
        "transition_profile": transition_profile,
        "validator_profile_definition": TRANSITION_VALIDATOR_PROFILE_DEFINITIONS.get(
            transition_profile, {}
        ),
        "product_spec_policy_definition": product_spec_policy_definition,
        "proposal_promotion_policy_definition": proposal_promotion_policy_definition,
        "families_checked": list(TRANSITION_CHECK_FAMILIES),
        "finding_count": len(findings),
        "findings_by_family": findings_by_family,
        "findings": findings,
    }


def validate_transition_packet(
    packet: Any,
    *,
    validator_profile: str | None = None,
) -> list[dict[str, str]]:
    """Validate one normalized transition packet.

    This validator is intentionally structural. It checks bounded transition
    legality and does not attempt to judge semantic quality.
    """

    return validate_transition_packet_report(
        packet,
        validator_profile=validator_profile,
    )["findings"]


def validate_transition_packet_file(
    path: Path,
    *,
    validator_profile: str | None = None,
) -> dict[str, Any]:
    packet, packet_error = load_json_object_report(path, artifact_kind="transition packet")
    if packet is None:
        findings = [
            transition_packet_finding(
                code="invalid_packet_file",
                field="path",
                family="schema",
                message=packet_error or "packet file must exist and contain a JSON object",
            )
        ]
        return {
            "ok": False,
            "path": path.as_posix(),
            "packet_type": "",
            "packet_family": "",
            "packet_family_definition": {},
            "transition_profile": validator_profile or DEFAULT_TRANSITION_VALIDATOR_PROFILE,
            "validator_profile_definition": {},
            "families_checked": list(TRANSITION_CHECK_FAMILIES),
            "finding_count": len(findings),
            "findings_by_family": {"schema": len(findings)},
            "findings": findings,
        }
    report = validate_transition_packet_report(
        packet,
        validator_profile=validator_profile,
    )
    report["path"] = path.as_posix()
    return report


