def is_executable_file(candidate: Path) -> bool:
    return candidate.is_file() and os.access(candidate, os.X_OK)


def command_availability_from_policy(
    *,
    executable_names: list[str],
    preferred_paths: list[str] | None = None,
    executable_env_var: str = "",
    sibling_release_binary: str = "",
) -> dict[str, Any]:
    env_override_present = bool(
        executable_env_var and os.environ.get(executable_env_var, "").strip()
    )
    if env_override_present:
        candidate = Path(str(os.environ.get(executable_env_var, "")).strip()).expanduser()
        status = "available" if is_executable_file(candidate) else "missing"
        return {
            "status": status,
            "resolution_source": "env_override",
            "env_var": executable_env_var,
            "command_name": candidate.name,
            "path_persisted": False,
        }

    for name in executable_names:
        if shutil.which(name):
            return {
                "status": "available",
                "resolution_source": "path",
                "env_var": executable_env_var,
                "command_name": name,
                "path_persisted": False,
            }

    for raw_path in preferred_paths or []:
        candidate = Path(str(raw_path)).expanduser()
        if is_executable_file(candidate):
            return {
                "status": "available",
                "resolution_source": "preferred_path",
                "env_var": executable_env_var,
                "command_name": candidate.name,
                "path_persisted": False,
            }

    if sibling_release_binary:
        candidate = (ROOT / sibling_release_binary).resolve()
        if is_executable_file(candidate):
            return {
                "status": "available",
                "resolution_source": "sibling_release_binary",
                "env_var": executable_env_var,
                "command_name": candidate.name,
                "path_persisted": False,
            }

    return {
        "status": "missing",
        "resolution_source": "not_found",
        "env_var": executable_env_var,
        "command_name": executable_names[0] if executable_names else "",
        "path_persisted": False,
    }


def supervisor_executor_adapter_passport_diagnostic() -> dict[str, Any]:
    policy = supervisor_executor_adapter_policy_lookup("agent_passport_cli")
    executable_names = [
        str(name).strip() for name in policy.get("executable_names", []) if str(name).strip()
    ]
    availability = command_availability_from_policy(
        executable_names=executable_names,
        sibling_release_binary=str(policy.get("sibling_release_binary", "")).strip(),
    )
    status = "available" if availability["status"] == "available" else "missing"
    return {
        "tool_id": str(policy.get("tool_id", "")).strip(),
        "diagnostic_kind": str(policy.get("diagnostic_kind", "")).strip(),
        "tool_status": status,
        "required_for_index": bool(policy.get("required_for_index", False)),
        "validation_state": "not_attempted",
        "availability": availability,
        "diagnostics": (
            []
            if status == "available"
            else [
                {
                    "severity": "warning",
                    "code": "agent_passport_cli_missing",
                    "message": "Agent Passport CLI is not available for report-only diagnostics.",
                }
            ]
        ),
    }


def supervisor_executor_runtime_environment_report() -> dict[str, Any]:
    contract = supervisor_executor_adapter_policy_lookup("runtime_environment_contract")
    contract = contract if isinstance(contract, dict) else {}
    allowed = {
        str(value).strip() for value in contract.get("environment_values", []) if str(value).strip()
    }
    default_environment = str(contract.get("default_environment", "")).strip()
    ci_environment = str(contract.get("ci_environment", "")).strip()
    override_env_var = (
        str(
            contract.get(
                "producer_environment_env_var",
                SUPERVISOR_EXECUTOR_RUNTIME_ENVIRONMENT_ENV_VAR,
            )
        ).strip()
        or SUPERVISOR_EXECUTOR_RUNTIME_ENVIRONMENT_ENV_VAR
    )
    override = os.environ.get(override_env_var, "").strip()
    if override:
        if override in allowed:
            return {
                "producer_environment": override,
                "override_env_var": override_env_var,
                "override_status": "valid",
                "diagnostics": [],
            }
        return {
            "producer_environment": "invalid_runtime_environment_override",
            "override_env_var": override_env_var,
            "override_status": "invalid",
            "diagnostics": [
                {
                    "severity": "error",
                    "code": "invalid_runtime_environment_override",
                    "message": (
                        "Executor runtime environment override is not one of the "
                        "policy-declared environment values."
                    ),
                    "invalid_value_persisted": False,
                }
            ],
        }
    if os.environ.get("GITHUB_ACTIONS", "").strip().lower() == "true":
        environment = ci_environment if ci_environment in allowed else "static_publish_environment"
    else:
        environment = (
            default_environment if default_environment in allowed else "local_operator_environment"
        )
    return {
        "producer_environment": environment,
        "override_env_var": override_env_var,
        "override_status": "not_set",
        "diagnostics": [],
    }


def current_supervisor_executor_runtime_environment() -> str:
    return str(
        supervisor_executor_runtime_environment_report().get(
            "producer_environment", "local_operator_environment"
        )
    ).strip()


def supervisor_executor_backend_executable_required(
    *,
    backend: dict[str, Any],
    producer_environment: str,
) -> bool:
    if producer_environment == "static_publish_environment":
        return bool(backend.get("static_publish_executable_required", False))
    if producer_environment == "local_operator_environment":
        return bool(backend.get("local_operator_executable_required", True))
    return True


def supervisor_executor_backend_status(
    *,
    backend: dict[str, Any],
    executable_availability: dict[str, Any],
    producer_environment: str,
    runtime_environment_valid: bool,
) -> str:
    if not runtime_environment_valid:
        return "runtime_environment_invalid"
    intended_environment = str(backend.get("intended_runtime_environment", "")).strip()
    executable_required = supervisor_executor_backend_executable_required(
        backend=backend,
        producer_environment=producer_environment,
    )
    if (
        intended_environment
        and producer_environment != intended_environment
        and not executable_required
    ):
        return "not_applicable_in_producer_environment"
    return (
        "available"
        if executable_availability.get("status") == "available"
        else "missing_executable"
    )


def supervisor_executor_runtime_environment(
    *,
    backend: dict[str, Any],
    backend_status: str,
    producer_environment: str,
) -> dict[str, Any]:
    contract = supervisor_executor_adapter_policy_lookup("runtime_environment_contract")
    contract = contract if isinstance(contract, dict) else {}
    status_semantics = contract.get("status_semantics", {})
    status_semantics = status_semantics if isinstance(status_semantics, dict) else {}
    intended_environment = str(backend.get("intended_runtime_environment", "")).strip()
    intended_environment = (
        intended_environment or str(contract.get("default_environment", "")).strip()
    )
    probe_scope = str(contract.get("executable_probe_scope", "")).strip()
    return {
        "producer_environment": producer_environment,
        "intended_environment": intended_environment,
        "executable_probe_scope": probe_scope or "current_process_environment",
        "backend_status_semantics": str(status_semantics.get(backend_status, "")).strip(),
        "static_publish_executable_required": bool(
            backend.get("static_publish_executable_required", False)
        ),
        "local_operator_executable_required": bool(
            backend.get("local_operator_executable_required", False)
        ),
        "producer_environment_executable_required": (
            supervisor_executor_backend_executable_required(
                backend=backend,
                producer_environment=producer_environment,
            )
        ),
        "missing_executable_is_static_publish_gap": (
            backend_status == "not_applicable_in_producer_environment"
            and producer_environment == "static_publish_environment"
            and intended_environment != "static_publish_environment"
        ),
        "producer_environment_execution_suppressed": (
            backend_status == "not_applicable_in_producer_environment"
        ),
        "operator_next_action": (
            "configure_local_operator_executable"
            if backend_status == "missing_executable"
            else "repair_executor_runtime_environment_override"
            if backend_status == "runtime_environment_invalid"
            else "run_in_intended_runtime_environment"
            if backend_status == "not_applicable_in_producer_environment"
            else "run_executor_adapter_smoke_benchmark"
        ),
    }


def build_supervisor_executor_adapter_index() -> dict[str, Any]:
    backend_registry = supervisor_executor_adapter_policy_lookup("backend_registry")
    default_backend_id = str(
        supervisor_executor_adapter_policy_lookup("default_backend_id")
    ).strip()
    passport_diagnostic = supervisor_executor_adapter_passport_diagnostic()
    runtime_environment_report = supervisor_executor_runtime_environment_report()
    producer_environment = str(runtime_environment_report.get("producer_environment", "")).strip()
    runtime_environment_valid = (
        str(runtime_environment_report.get("override_status", "")).strip() != "invalid"
    )
    named_filters = {name: [] for name in SUPERVISOR_EXECUTOR_ADAPTER_NAMED_FILTERS}
    backend_status: dict[str, list[str]] = {}
    authority_state: dict[str, list[str]] = {}
    entries: list[dict[str, Any]] = []
    capability_gaps: list[dict[str, Any]] = []

    for backend in backend_registry:
        if not isinstance(backend, dict):
            continue
        backend_id = str(backend.get("backend_id", "")).strip()
        if not backend_id:
            continue
        executable_names = [
            str(name).strip() for name in backend.get("executable_names", []) if str(name).strip()
        ]
        executable_availability = command_availability_from_policy(
            executable_names=executable_names,
            preferred_paths=[
                str(path).strip()
                for path in backend.get("preferred_paths", [])
                if str(path).strip()
            ],
            executable_env_var=str(backend.get("executable_env_var", "")).strip(),
        )
        status = supervisor_executor_backend_status(
            backend=backend,
            executable_availability=executable_availability,
            producer_environment=producer_environment,
            runtime_environment_valid=runtime_environment_valid,
        )
        runtime_environment = supervisor_executor_runtime_environment(
            backend=backend,
            backend_status=status,
            producer_environment=producer_environment,
        )
        backend_authority_state = str(backend.get("authority_state", "")).strip()
        gaps: list[dict[str, Any]] = []
        if status == "missing_executable":
            gaps.append(
                {
                    "gap_kind": "missing_executable",
                    "severity": "blocker",
                    "next_action": "configure_backend_executable",
                }
            )
        elif status == "not_applicable_in_producer_environment":
            gaps.append(
                {
                    "gap_kind": "producer_environment_not_executor_runtime",
                    "severity": "info",
                    "next_action": "run_in_intended_runtime_environment",
                }
            )
        elif status == "runtime_environment_invalid":
            gaps.append(
                {
                    "gap_kind": "invalid_runtime_environment_override",
                    "severity": "error",
                    "next_action": "repair_executor_runtime_environment_override",
                }
            )
        if passport_diagnostic["tool_status"] != "available":
            gaps.append(
                {
                    "gap_kind": "missing_agent_passport_cli",
                    "severity": "warning",
                    "next_action": "install_or_package_agent_passport_cli",
                }
            )
        if status == "available":
            gaps.append(
                {
                    "gap_kind": "smoke_not_run",
                    "severity": "advisory",
                    "next_action": "run_executor_adapter_smoke_benchmark",
                }
            )
            gaps.append(
                {
                    "gap_kind": "canonical_trial_blocked",
                    "severity": "advisory",
                    "next_action": "complete_smoke_before_canonical_trial",
                }
            )
        entry = {
            "backend_id": backend_id,
            "display_name": str(backend.get("display_name", "")).strip(),
            "backend_status": status,
            "authority_state": backend_authority_state,
            "runtime_environment": runtime_environment,
            "command_surface": str(backend.get("command_surface", "")).strip(),
            "protocol_contract": str(backend.get("protocol_contract", "")).strip(),
            "executable_availability": executable_availability,
            "capabilities": copy.deepcopy(backend.get("capabilities", {})),
            "auth_isolation": str(backend.get("auth_isolation", "")).strip(),
            "config_isolation": str(backend.get("config_isolation", "")).strip(),
            "passport_ref": str(backend.get("passport_ref", "")).strip(),
            "passport_validation": {
                **copy.deepcopy(backend.get("passport_validation", {})),
                "tool_status": passport_diagnostic["tool_status"],
                "diagnostic_kind": passport_diagnostic["diagnostic_kind"],
            },
            "smoke_status": "not_run",
            "canonical_trial_allowed": False,
            "safe_next_action": (
                "run_executor_adapter_smoke_benchmark"
                if status == "available"
                else "configure_backend_executable"
                if status == "missing_executable"
                else "repair_executor_runtime_environment_override"
                if status == "runtime_environment_invalid"
                else "run_in_intended_runtime_environment"
            ),
            "capability_gaps": gaps,
        }
        entries.append(entry)
        backend_status.setdefault(status, []).append(backend_id)
        authority_state.setdefault(backend_authority_state, []).append(backend_id)
        if backend_id == default_backend_id:
            named_filters["default_backend"].append(backend_id)
        if status == "available":
            named_filters["available"].append(backend_id)
            named_filters["safe_for_smoke"].append(backend_id)
        if status == "missing_executable":
            named_filters["missing_executable"].append(backend_id)
        if status == "not_applicable_in_producer_environment":
            named_filters["not_applicable_in_producer_environment"].append(backend_id)
        if status == "runtime_environment_invalid":
            named_filters["runtime_environment_invalid"].append(backend_id)
        if passport_diagnostic["tool_status"] != "available":
            named_filters["passport_diagnostic"].append(backend_id)
        if status == "available":
            named_filters["canonical_trial_blocked"].append(backend_id)
        capability_gaps.extend(
            {
                "backend_id": backend_id,
                **gap,
            }
            for gap in gaps
        )

    for bucket in (backend_status, authority_state, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    default_entry = next(
        (entry for entry in entries if entry["backend_id"] == default_backend_id),
        None,
    )
    stable_fields = [
        str(field).strip()
        for field in supervisor_executor_adapter_policy_lookup("index_contract.stable_fields")
        if str(field).strip()
    ]
    return {
        "artifact_kind": SUPERVISOR_EXECUTOR_ADAPTER_INDEX_ARTIFACT_KIND,
        "schema_version": SUPERVISOR_EXECUTOR_ADAPTER_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": supervisor_executor_adapter_policy_reference(),
        "stable_fields": stable_fields,
        "summary": {
            "backend_count": len(entries),
            "available_backend_count": len(backend_status.get("available", [])),
            "producer_environment": producer_environment,
            "runtime_environment_override_status": str(
                runtime_environment_report.get("override_status", "")
            ).strip(),
            "default_backend_id": default_backend_id,
            "default_backend_status": (
                str(default_entry.get("backend_status", "")).strip() if default_entry else "missing"
            ),
            "default_backend_intended_environment": (
                str(
                    (default_entry.get("runtime_environment", {}) if default_entry else {}).get(
                        "intended_environment", ""
                    )
                ).strip()
                if default_entry
                else ""
            ),
            "agent_passport_cli_status": passport_diagnostic["tool_status"],
            "canonical_trial_ready_count": 0,
            "next_gap": (
                "run_executor_adapter_smoke_benchmark"
                if default_entry and default_entry.get("backend_status") == "available"
                else "repair_executor_runtime_environment_override"
                if default_entry
                and default_entry.get("backend_status") == "runtime_environment_invalid"
                else "none"
                if default_entry
                and default_entry.get("backend_status") == "not_applicable_in_producer_environment"
                else "configure_default_executor_backend"
            ),
        },
        "entries": entries,
        "capability_gaps": capability_gaps,
        "passport_diagnostics": [passport_diagnostic],
        "runtime_environment_diagnostics": copy.deepcopy(
            runtime_environment_report.get("diagnostics", [])
        ),
        "viewer_projection": {
            "backend_status": backend_status,
            "authority_state": authority_state,
            "named_filters": named_filters,
        },
    }


def write_supervisor_executor_adapter_index(index: dict[str, Any]) -> Path:
    path = supervisor_executor_adapter_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def local_operator_readiness_check(
    *,
    check_id: str,
    status: str,
    message: str,
) -> dict[str, Any]:
    return {
        "check_id": check_id,
        "status": status,
        "message": message,
    }


def sanitize_executor_availability_for_readiness(
    availability: dict[str, Any],
) -> dict[str, Any]:
    return {
        "status": str(availability.get("status", "")).strip() or "missing",
        "resolution_source": str(availability.get("resolution_source", "")).strip(),
        "env_var": str(availability.get("env_var", "")).strip(),
        "command_name": str(availability.get("command_name", "")).strip(),
        "path_persisted": bool(availability.get("path_persisted", False)),
    }


def agent_passport_report_only_readiness_check() -> dict[str, Any]:
    surfaces = build_agent_passport_derived_surfaces()
    report = surfaces.get("agent_passport_verification_report", {})
    report = report if isinstance(report, dict) else {}
    summary = report.get("summary", {})
    summary = summary if isinstance(summary, dict) else {}
    cli_status = str(summary.get("agent_passport_cli_status", "")).strip()
    entry_count = int(summary.get("entry_count", 0) or 0)
    valid_count = int(summary.get("valid_count", 0) or 0)
    invalid_count = int(summary.get("invalid_count", 0) or 0)
    unavailable_count = int(summary.get("unavailable_count", 0) or 0)
    tool_unavailable_count = int(summary.get("tool_unavailable_count", 0) or 0)
    if cli_status != "available":
        status = "missing"
        message = "Agent Passport CLI is not available for report-only validation."
    elif (
        entry_count > 0
        and valid_count == entry_count
        and invalid_count == 0
        and unavailable_count == 0
        and tool_unavailable_count == 0
    ):
        status = "passed"
        message = "Agent Passport report-only validation is available and all entries are valid."
    else:
        status = "failed"
        message = "Agent Passport report-only validation is incomplete or has invalid entries."
    return local_operator_readiness_check(
        check_id="agent_passport_report_only_valid",
        status=status,
        message=message,
    )


def local_operator_executor_readiness_status(
    *,
    producer_environment: str,
    backend_status: str,
    checks: list[dict[str, Any]],
) -> str:
    if producer_environment == "invalid_runtime_environment_override":
        return "blocked_invalid_runtime_environment"
    if producer_environment != "local_operator_environment":
        return "not_applicable_non_local_environment"
    if backend_status == "runtime_environment_invalid":
        return "blocked_invalid_runtime_environment"
    if backend_status == "missing_executable":
        return "blocked_missing_executable"
    check_status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
    }
    if check_status_by_id.get("executor_adapter_invocation_boundary") != "passed":
        return "blocked_policy_contract"
    if check_status_by_id.get("agent_passport_report_only_valid") != "passed":
        return "blocked_passport_validation"
    if backend_status == "available":
        return "ready_for_local_smoke"
    return "blocked_policy_contract"


def local_operator_executor_readiness_next_gap(readiness_status: str) -> str:
    return {
        "ready_for_local_smoke": "run_executor_adapter_smoke_benchmark",
        "blocked_missing_executable": "configure_local_operator_executable",
        "blocked_invalid_runtime_environment": "repair_executor_runtime_environment_override",
        "blocked_policy_contract": "repair_executor_adapter_policy_contract",
        "blocked_passport_validation": "repair_agent_passport_report_only_validation",
        "not_applicable_non_local_environment": "run_in_local_operator_environment",
    }.get(readiness_status, "repair_executor_readiness")


def build_local_operator_executor_readiness() -> dict[str, Any]:
    adapter_index = build_supervisor_executor_adapter_index()
    contract = supervisor_executor_adapter_policy_lookup("local_operator_readiness_contract")
    contract = contract if isinstance(contract, dict) else {}
    producer_environment = str(
        adapter_index.get("summary", {}).get("producer_environment", "")
    ).strip()
    runtime_diagnostics = copy.deepcopy(adapter_index.get("runtime_environment_diagnostics", []))
    invocation_boundary_check = supervisor_executor_adapter_invocation_boundary_check(adapter_index)
    passport_check = agent_passport_report_only_readiness_check()
    named_filters = {
        str(name).strip(): [] for name in contract.get("named_filters", []) if str(name).strip()
    }
    entries: list[dict[str, Any]] = []

    for entry in adapter_index.get("entries", []):
        if not isinstance(entry, dict):
            continue
        backend_id = str(entry.get("backend_id", "")).strip()
        if not backend_id:
            continue
        backend_status = str(entry.get("backend_status", "")).strip()
        runtime_environment = copy.deepcopy(entry.get("runtime_environment", {}))
        runtime_environment = runtime_environment if isinstance(runtime_environment, dict) else {}
        environment_check_status = (
            "passed"
            if producer_environment == "local_operator_environment"
            else "failed"
            if producer_environment == "invalid_runtime_environment_override"
            else "not_applicable"
        )
        executable_check_status = (
            "passed"
            if producer_environment == "local_operator_environment"
            and backend_status == "available"
            else "missing"
            if producer_environment == "local_operator_environment"
            and backend_status == "missing_executable"
            else "failed"
            if backend_status == "runtime_environment_invalid"
            else "not_applicable"
        )
        checks = [
            local_operator_readiness_check(
                check_id="local_operator_environment_selected",
                status=environment_check_status,
                message=(
                    "Producer environment is local_operator_environment."
                    if environment_check_status == "passed"
                    else "Readiness was requested outside local_operator_environment."
                    if environment_check_status == "not_applicable"
                    else "Executor runtime environment override is invalid."
                ),
            ),
            local_operator_readiness_check(
                check_id="executable_available_in_local_operator_environment",
                status=executable_check_status,
                message=(
                    "Backend executable is available in the local operator environment."
                    if executable_check_status == "passed"
                    else "Backend executable is missing in the local operator environment."
                    if executable_check_status == "missing"
                    else "Executable readiness is not applicable outside local operator execution."
                    if executable_check_status == "not_applicable"
                    else "Runtime environment is invalid; executable readiness cannot be trusted."
                ),
            ),
            copy.deepcopy(invocation_boundary_check),
            copy.deepcopy(passport_check),
        ]
        readiness_status = local_operator_executor_readiness_status(
            producer_environment=producer_environment,
            backend_status=backend_status,
            checks=checks,
        )
        named_filters.setdefault(readiness_status, []).append(backend_id)
        entries.append(
            {
                "backend_id": backend_id,
                "display_name": str(entry.get("display_name", "")).strip(),
                "intended_environment": str(
                    runtime_environment.get("intended_environment", "")
                ).strip(),
                "producer_environment": producer_environment,
                "backend_status": backend_status,
                "readiness_status": readiness_status,
                "runtime_environment": runtime_environment,
                "executable_availability": sanitize_executor_availability_for_readiness(
                    entry.get("executable_availability", {})
                    if isinstance(entry.get("executable_availability", {}), dict)
                    else {}
                ),
                "checks": checks,
                "safe_next_action": local_operator_executor_readiness_next_gap(readiness_status),
            }
        )

    for key in list(named_filters):
        named_filters[key] = sorted(set(named_filters[key]))

    default_backend_id = str(adapter_index.get("summary", {}).get("default_backend_id", "")).strip()
    default_entry = next(
        (entry for entry in entries if entry["backend_id"] == default_backend_id),
        None,
    )
    status_counts: dict[str, int] = {}
    for entry in entries:
        status = str(entry.get("readiness_status", "")).strip()
        status_counts[status] = status_counts.get(status, 0) + 1

    return {
        "artifact_kind": LOCAL_OPERATOR_EXECUTOR_READINESS_ARTIFACT_KIND,
        "schema_version": LOCAL_OPERATOR_EXECUTOR_READINESS_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": supervisor_executor_adapter_policy_reference(),
        "local_only": bool(contract.get("local_only", True)),
        "privacy_boundary": copy.deepcopy(contract.get("privacy_boundary", {})),
        "producer_environment": producer_environment,
        "runtime_environment_diagnostics": runtime_diagnostics,
        "summary": {
            "backend_count": len(entries),
            "ready_backend_count": status_counts.get("ready_for_local_smoke", 0),
            "blocked_backend_count": sum(
                count for status, count in status_counts.items() if status.startswith("blocked_")
            ),
            "not_applicable_backend_count": status_counts.get(
                "not_applicable_non_local_environment", 0
            ),
            "default_backend_id": default_backend_id,
            "default_backend_readiness": (
                str(default_entry.get("readiness_status", "")).strip()
                if default_entry
                else "blocked_policy_contract"
            ),
            "next_gap": local_operator_executor_readiness_next_gap(
                str(default_entry.get("readiness_status", "")).strip()
                if default_entry
                else "blocked_policy_contract"
            ),
        },
        "entries": entries,
        "viewer_projection": {
            "readiness_status": {
                status: sorted(
                    entry["backend_id"] for entry in entries if entry["readiness_status"] == status
                )
                for status in sorted(status_counts)
            },
            "named_filters": named_filters,
        },
    }


def write_local_operator_executor_readiness(index: dict[str, Any]) -> Path:
    path = local_operator_executor_readiness_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def local_operator_smoke_check(
    *,
    check_id: str,
    status: str,
    message: str,
) -> dict[str, Any]:
    return {
        "check_id": check_id,
        "status": status,
        "message": message,
    }


def local_operator_executor_smoke_next_gap(status: str) -> str:
    return {
        "passed": "define_bounded_executor_task_smoke",
        "blocked_readiness_not_ready": "run_executor_readiness_until_ready",
        "failed_probe_invocation": "repair_executor_probe_invocation",
        "blocked_policy_contract": "repair_executor_adapter_policy_contract",
    }.get(status, "repair_executor_smoke")


def local_operator_executor_smoke_status(checks: list[dict[str, Any]]) -> str:
    status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
    }
    if status_by_id.get("readiness_artifact_present") != "passed":
        return "blocked_readiness_not_ready"
    if status_by_id.get("readiness_allows_local_smoke") != "passed":
        return "blocked_readiness_not_ready"
    if status_by_id.get("executor_probe_invocation_completed") != "passed":
        return "failed_probe_invocation"
    if status_by_id.get("no_canonical_mutation_attempted") != "passed":
        return "blocked_policy_contract"
    return "passed"


def load_local_operator_executor_readiness_artifact() -> dict[str, Any] | None:
    path = local_operator_executor_readiness_path()
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    return payload if isinstance(payload, dict) else None


def local_operator_executor_smoke_contract() -> dict[str, Any]:
    contract = supervisor_executor_adapter_policy_lookup("local_operator_smoke_contract")
    return contract if isinstance(contract, dict) else {}


def local_operator_smoke_probe_for_backend(backend_id: str) -> dict[str, Any]:
    contract = local_operator_executor_smoke_contract()
    default_args = [
        str(arg).strip() for arg in contract.get("default_probe_args", []) if str(arg).strip()
    ] or ["--version"]
    default_timeout = int(contract.get("default_timeout_seconds", 15) or 15)
    for backend in supervisor_executor_adapter_policy_lookup("backend_registry"):
        if not isinstance(backend, dict):
            continue
        if str(backend.get("backend_id", "")).strip() != backend_id:
            continue
        probe = backend.get("local_smoke_probe", {})
        probe = probe if isinstance(probe, dict) else {}
        args = [str(arg).strip() for arg in probe.get("args", []) if str(arg).strip()]
        timeout = int(probe.get("timeout_seconds", default_timeout) or default_timeout)
        return {
            "args": args or default_args,
            "timeout_seconds": max(1, min(timeout, 60)),
        }
    return {"args": default_args, "timeout_seconds": max(1, min(default_timeout, 60))}


def executable_invocation_command_from_backend(
    *,
    backend_id: str,
    probe_args: list[str],
) -> tuple[list[str], dict[str, Any]]:
    for backend in supervisor_executor_adapter_policy_lookup("backend_registry"):
        if not isinstance(backend, dict):
            continue
        if str(backend.get("backend_id", "")).strip() != backend_id:
            continue
        executable_env_var = str(backend.get("executable_env_var", "")).strip()
        if executable_env_var and os.environ.get(executable_env_var, "").strip():
            candidate = Path(str(os.environ.get(executable_env_var, "")).strip()).expanduser()
            if is_executable_file(candidate):
                return [
                    candidate.as_posix(),
                    *probe_args,
                ], {
                    "command_name": candidate.name,
                    "resolution_source": "env_override",
                    "env_var": executable_env_var,
                    "path_persisted": False,
                }
        for name in [
            str(item).strip() for item in backend.get("executable_names", []) if str(item).strip()
        ]:
            if shutil.which(name):
                return [
                    name,
                    *probe_args,
                ], {
                    "command_name": name,
                    "resolution_source": "path",
                    "env_var": executable_env_var,
                    "path_persisted": False,
                }
        for raw_path in [
            str(item).strip() for item in backend.get("preferred_paths", []) if str(item).strip()
        ]:
            candidate = Path(raw_path).expanduser()
            if is_executable_file(candidate):
                return [
                    candidate.as_posix(),
                    *probe_args,
                ], {
                    "command_name": candidate.name,
                    "resolution_source": "preferred_path",
                    "env_var": executable_env_var,
                    "path_persisted": False,
                }
    return [], {
        "command_name": "",
        "resolution_source": "not_found",
        "env_var": "",
        "path_persisted": False,
    }


def git_tracked_status_snapshot() -> str | None:
    try:
        result = subprocess.run(
            ["git", "status", "--porcelain", "--untracked-files=all"],
            cwd=ROOT,
            capture_output=True,
            text=True,
            check=False,
            timeout=10,
        )
    except (OSError, subprocess.TimeoutExpired):
        return None
    return result.stdout if result.returncode == 0 else None


def run_local_operator_executor_probe(
    *,
    backend_id: str,
    probe_args: list[str],
    timeout_seconds: int,
) -> dict[str, Any]:
    command, invocation = executable_invocation_command_from_backend(
        backend_id=backend_id,
        probe_args=probe_args,
    )
    if not command:
        return {
            "status": "failed",
            "exit_code": None,
            "timed_out": False,
            "command": invocation,
            "command_executed": False,
            "stdout_persisted": False,
            "stderr_persisted": False,
            "tracked_status_unchanged": None,
        }
    before_status = git_tracked_status_snapshot()
    try:
        result = subprocess.run(
            command,
            cwd=ROOT,
            capture_output=True,
            text=True,
            check=False,
            timeout=timeout_seconds,
        )
        timed_out = False
        exit_code: int | None = result.returncode
    except subprocess.TimeoutExpired:
        timed_out = True
        exit_code = None
    after_status = git_tracked_status_snapshot()
    return {
        "status": "passed" if exit_code == 0 and not timed_out else "failed",
        "exit_code": exit_code,
        "timed_out": timed_out,
        "command": invocation,
        "command_executed": True,
        "stdout_persisted": False,
        "stderr_persisted": False,
        "tracked_status_unchanged": (
            before_status is not None and after_status is not None and before_status == after_status
        ),
    }


def build_local_operator_executor_smoke(
    readiness: dict[str, Any] | None = None,
) -> dict[str, Any]:
    contract = local_operator_executor_smoke_contract()
    readiness = (
        readiness
        if isinstance(readiness, dict)
        else load_local_operator_executor_readiness_artifact()
    )
    readiness_present = isinstance(readiness, dict)
    readiness_summary = readiness.get("summary", {}) if readiness_present else {}
    readiness_summary = readiness_summary if isinstance(readiness_summary, dict) else {}
    default_backend_id = str(readiness_summary.get("default_backend_id", "")).strip()
    default_readiness = str(readiness_summary.get("default_backend_readiness", "")).strip()
    readiness_entries = readiness.get("entries", []) if readiness_present else []
    readiness_entries = readiness_entries if isinstance(readiness_entries, list) else []
    readiness_entry = next(
        (
            entry
            for entry in readiness_entries
            if isinstance(entry, dict)
            and str(entry.get("backend_id", "")).strip() == default_backend_id
        ),
        None,
    )
    readiness_allows_smoke = default_readiness == "ready_for_local_smoke"
    probe = local_operator_smoke_probe_for_backend(default_backend_id)
    probe_args = [str(arg).strip() for arg in probe.get("args", []) if str(arg).strip()]
    timeout_seconds = int(probe.get("timeout_seconds", 15) or 15)
    checks = [
        local_operator_smoke_check(
            check_id="readiness_artifact_present",
            status="passed" if readiness_present else "missing",
            message=(
                "Local operator executor readiness artifact is present."
                if readiness_present
                else "Local operator executor readiness artifact is missing."
            ),
        ),
        local_operator_smoke_check(
            check_id="readiness_allows_local_smoke",
            status="passed" if readiness_allows_smoke else "failed",
            message=(
                "Readiness status allows local executor smoke."
                if readiness_allows_smoke
                else "Readiness status does not allow local executor smoke."
            ),
        ),
    ]
    probe_result: dict[str, Any] = {
        "status": "not_run",
        "exit_code": None,
        "timed_out": False,
        "command": {"path_persisted": False},
        "command_executed": False,
        "stdout_persisted": False,
        "stderr_persisted": False,
        "tracked_status_unchanged": None,
    }
    if readiness_allows_smoke and default_backend_id:
        probe_result = run_local_operator_executor_probe(
            backend_id=default_backend_id,
            probe_args=probe_args,
            timeout_seconds=timeout_seconds,
        )
    checks.append(
        local_operator_smoke_check(
            check_id="executor_probe_invocation_completed",
            status=(
                "not_run"
                if probe_result.get("status") == "not_run"
                else "passed"
                if probe_result.get("status") == "passed"
                else "failed"
            ),
            message=(
                "Executor probe invocation completed successfully."
                if probe_result.get("status") == "passed"
                else "Executor probe invocation was not run because readiness gated it off."
                if probe_result.get("status") == "not_run"
                else "Executor probe invocation did not complete successfully."
            ),
        )
    )
    command_executed_value = probe_result.get("command_executed")
    probe_command_executed = (
        bool(command_executed_value)
        if command_executed_value is not None
        else probe_result.get("status") != "not_run" and bool(probe_result.get("command"))
    )
    checks.append(
        local_operator_smoke_check(
            check_id="no_canonical_mutation_attempted",
            status=(
                "not_run"
                if not probe_command_executed
                else "passed"
                if probe_result.get("tracked_status_unchanged") is True
                else "failed"
            ),
            message=(
                "No executor command was executed, so the mutation check was not run."
                if not probe_command_executed
                else "Worktree status did not change during the executor probe."
                if probe_result.get("tracked_status_unchanged") is True
                else (
                    "Worktree status changed or could not be proven unchanged "
                    "during the executor probe."
                )
            ),
        )
    )
    smoke_status = local_operator_executor_smoke_status(checks)
    entry = {
        "backend_id": default_backend_id,
        "readiness_status": default_readiness,
        "smoke_status": smoke_status,
        "source_readiness_entry_present": readiness_entry is not None,
        "probe": {
            "args": probe_args,
            "timeout_seconds": timeout_seconds,
            "exit_code": probe_result.get("exit_code"),
            "timed_out": bool(probe_result.get("timed_out", False)),
            "command": copy.deepcopy(probe_result.get("command", {})),
            "stdout_persisted": False,
            "stderr_persisted": False,
        },
        "checks": checks,
        "safe_next_action": local_operator_executor_smoke_next_gap(smoke_status),
    }
    named_filters = {
        str(name).strip(): [] for name in contract.get("named_filters", []) if str(name).strip()
    }
    named_filters.setdefault(smoke_status, []).append(
        default_backend_id or "missing_default_backend"
    )
    for key in list(named_filters):
        named_filters[key] = sorted(set(named_filters[key]))
    return {
        "artifact_kind": LOCAL_OPERATOR_EXECUTOR_SMOKE_ARTIFACT_KIND,
        "schema_version": LOCAL_OPERATOR_EXECUTOR_SMOKE_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": supervisor_executor_adapter_policy_reference(),
        "source_readiness_artifact": str(
            contract.get(
                "source_readiness_artifact",
                LOCAL_OPERATOR_EXECUTOR_READINESS_RELATIVE_PATH,
            )
        ).strip(),
        "local_only": bool(contract.get("local_only", True)),
        "privacy_boundary": copy.deepcopy(contract.get("privacy_boundary", {})),
        "summary": {
            "status": smoke_status,
            "backend_id": default_backend_id,
            "consumed_readiness_status": default_readiness,
            "next_gap": local_operator_executor_smoke_next_gap(smoke_status),
        },
        "entries": [entry],
        "checks": checks,
        "viewer_projection": {
            "named_filters": named_filters,
        },
    }


def write_local_operator_executor_smoke(index: dict[str, Any]) -> Path:
    path = local_operator_executor_smoke_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def local_operator_executor_task_smoke_next_gap(status: str) -> str:
    return {
        "passed": "define_executor_report_artifact_contract",
        "blocked_readiness_not_ready": "run_executor_readiness_until_ready",
        "blocked_smoke_not_passed": "run_executor_smoke_until_passed",
        "blocked_executor_unavailable": "configure_local_operator_executable",
        "failed_executor_nonzero": "repair_executor_task_smoke_invocation",
        "failed_invalid_response": "repair_executor_task_smoke_response_contract",
        "failed_mutation_guard": "repair_executor_task_smoke_mutation_boundary",
        "blocked_policy_contract": "repair_executor_adapter_policy_contract",
    }.get(status, "repair_executor_task_smoke")


def local_operator_executor_task_smoke_status(checks: list[dict[str, Any]]) -> str:
    status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
    }
    if status_by_id.get("readiness_allows_task_smoke") != "passed":
        return "blocked_readiness_not_ready"
    if status_by_id.get("executor_smoke_passed") != "passed":
        return "blocked_smoke_not_passed"
    invocation_status = status_by_id.get("executor_task_invocation_completed")
    if invocation_status == "not_run":
        return "blocked_policy_contract"
    if invocation_status == "missing":
        return "blocked_executor_unavailable"
    if invocation_status != "passed":
        return "failed_executor_nonzero"
    if status_by_id.get("executor_task_response_valid") != "passed":
        return "failed_invalid_response"
    if status_by_id.get("no_canonical_mutation_attempted") != "passed":
        return "failed_mutation_guard"
    return "passed"


def load_local_operator_executor_smoke_artifact() -> dict[str, Any] | None:
    path = local_operator_executor_smoke_path()
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    return payload if isinstance(payload, dict) else None


def local_operator_executor_task_smoke_contract() -> dict[str, Any]:
    contract = supervisor_executor_adapter_policy_lookup("local_operator_task_smoke_contract")
    return contract if isinstance(contract, dict) else {}


def local_operator_task_smoke_for_backend(backend_id: str) -> dict[str, Any]:
    contract = local_operator_executor_task_smoke_contract()
    default_timeout = int(contract.get("default_timeout_seconds", 120) or 120)
    for backend in supervisor_executor_adapter_policy_lookup("backend_registry"):
        if not isinstance(backend, dict):
            continue
        if str(backend.get("backend_id", "")).strip() != backend_id:
            continue
        task = backend.get("local_task_smoke", {})
        task = task if isinstance(task, dict) else {}
        args = [str(arg).strip() for arg in task.get("args", []) if str(arg).strip()]
        timeout = int(task.get("timeout_seconds", default_timeout) or default_timeout)
        return {
            "args": args,
            "timeout_seconds": max(1, min(timeout, 300)),
        }
    return {"args": [], "timeout_seconds": max(1, min(default_timeout, 300))}


def bounded_executor_task_smoke_response_schema() -> dict[str, Any]:
    return {
        "$schema": "https://json-schema.org/draft/2020-12/schema",
        "type": "object",
        "additionalProperties": False,
        "required": [
            "task_kind",
            "status",
            "canonical_mutation_attempted",
            "message",
        ],
        "properties": {
            "task_kind": {"const": "bounded_executor_task_smoke"},
            "status": {"const": "acknowledged"},
            "canonical_mutation_attempted": {"const": False},
            "message": {"type": "string", "minLength": 1, "maxLength": 240},
        },
    }


def bounded_executor_task_smoke_prompt() -> str:
    contract = local_operator_executor_task_smoke_contract()
    prompt = str(contract.get("prompt", "")).strip()
    return prompt or (
        "Return only a JSON object with task_kind=bounded_executor_task_smoke, "
        "status=acknowledged, canonical_mutation_attempted=false, and a short message. "
        "Do not inspect, edit, or create repository files."
    )


def parse_bounded_executor_task_smoke_response(raw_text: str) -> dict[str, Any]:
    try:
        payload = json.loads(raw_text.strip())
    except json.JSONDecodeError:
        return {
            "parsed": False,
            "valid": False,
            "task_kind": "",
            "status": "",
            "canonical_mutation_attempted": None,
            "message_length": 0,
        }
    if not isinstance(payload, dict):
        return {
            "parsed": True,
            "valid": False,
            "task_kind": "",
            "status": "",
            "canonical_mutation_attempted": None,
            "message_length": 0,
        }
    task_kind = str(payload.get("task_kind", "")).strip()
    status = str(payload.get("status", "")).strip()
    canonical_mutation_attempted = payload.get("canonical_mutation_attempted")
    message = payload.get("message", "")
    message_length = len(message) if isinstance(message, str) else 0
    valid = (
        task_kind == "bounded_executor_task_smoke"
        and status == "acknowledged"
        and canonical_mutation_attempted is False
        and isinstance(message, str)
        and 0 < message_length <= 240
    )
    return {
        "parsed": True,
        "valid": valid,
        "task_kind": task_kind,
        "status": status,
        "canonical_mutation_attempted": canonical_mutation_attempted,
        "message_length": message_length,
    }


def executor_task_invocation_command_from_backend(
    *,
    backend_id: str,
    output_schema_path: Path,
    output_last_message_path: Path,
    prompt: str,
) -> tuple[list[str], dict[str, Any]]:
    task = local_operator_task_smoke_for_backend(backend_id)
    base_args = [str(arg).strip() for arg in task.get("args", []) if str(arg).strip()]
    task_args = [
        *base_args,
        "-C",
        ROOT.as_posix(),
        "--output-schema",
        output_schema_path.as_posix(),
        "--output-last-message",
        output_last_message_path.as_posix(),
        prompt,
    ]
    return executable_invocation_command_from_backend(
        backend_id=backend_id,
        probe_args=task_args,
    )


def run_local_operator_executor_task(
    *,
    backend_id: str,
    timeout_seconds: int,
) -> dict[str, Any]:
    with tempfile.TemporaryDirectory(prefix="specgraph-executor-task-smoke-") as temp_dir:
        temp_path = Path(temp_dir)
        output_schema_path = temp_path / "response.schema.json"
        output_last_message_path = temp_path / "last-message.json"
        output_schema_path.write_text(
            json.dumps(bounded_executor_task_smoke_response_schema(), indent=2, sort_keys=True)
            + "\n",
            encoding="utf-8",
        )
        command, invocation = executor_task_invocation_command_from_backend(
            backend_id=backend_id,
            output_schema_path=output_schema_path,
            output_last_message_path=output_last_message_path,
            prompt=bounded_executor_task_smoke_prompt(),
        )
        if not command:
            return {
                "status": "missing",
                "exit_code": None,
                "timed_out": False,
                "command": invocation,
                "command_executed": False,
                "stdout_persisted": False,
                "stderr_persisted": False,
                "raw_response_persisted": False,
                "tracked_status_unchanged": None,
                "response": {
                    "parsed": False,
                    "valid": False,
                    "task_kind": "",
                    "status": "",
                    "canonical_mutation_attempted": None,
                    "message_length": 0,
                },
            }
        before_status = git_tracked_status_snapshot()
        try:
            result = subprocess.run(
                command,
                cwd=ROOT,
                capture_output=True,
                text=True,
                check=False,
                timeout=timeout_seconds,
            )
            timed_out = False
            exit_code: int | None = result.returncode
        except subprocess.TimeoutExpired:
            timed_out = True
            exit_code = None
        after_status = git_tracked_status_snapshot()
        try:
            raw_response = output_last_message_path.read_text(encoding="utf-8")
        except OSError:
            raw_response = ""
        response = parse_bounded_executor_task_smoke_response(raw_response)
        return {
            "status": (
                "passed"
                if exit_code == 0 and not timed_out and bool(response.get("valid"))
                else "failed"
            ),
            "exit_code": exit_code,
            "timed_out": timed_out,
            "command": invocation,
            "command_executed": True,
            "stdout_persisted": False,
            "stderr_persisted": False,
            "raw_response_persisted": False,
            "tracked_status_unchanged": (
                before_status is not None
                and after_status is not None
                and before_status == after_status
            ),
            "response": response,
        }


def build_local_operator_executor_task_smoke(
    readiness: dict[str, Any] | None = None,
    smoke: dict[str, Any] | None = None,
) -> dict[str, Any]:
    contract = local_operator_executor_task_smoke_contract()
    readiness = (
        readiness
        if isinstance(readiness, dict)
        else load_local_operator_executor_readiness_artifact()
    )
    smoke = smoke if isinstance(smoke, dict) else load_local_operator_executor_smoke_artifact()
    readiness_summary = readiness.get("summary", {}) if isinstance(readiness, dict) else {}
    readiness_summary = readiness_summary if isinstance(readiness_summary, dict) else {}
    smoke_summary = smoke.get("summary", {}) if isinstance(smoke, dict) else {}
    smoke_summary = smoke_summary if isinstance(smoke_summary, dict) else {}
    default_backend_id = str(
        readiness_summary.get("default_backend_id") or smoke_summary.get("backend_id") or ""
    ).strip()
    readiness_status = str(readiness_summary.get("default_backend_readiness", "")).strip()
    smoke_status = str(smoke_summary.get("status", "")).strip()
    readiness_allows_task = readiness_status == "ready_for_local_smoke"
    smoke_passed = smoke_status == "passed"
    task = local_operator_task_smoke_for_backend(default_backend_id)
    timeout_seconds = int(task.get("timeout_seconds", 120) or 120)
    checks = [
        local_operator_smoke_check(
            check_id="readiness_allows_task_smoke",
            status="passed" if readiness_allows_task else "failed",
            message=(
                "Readiness allows bounded executor task smoke."
                if readiness_allows_task
                else "Readiness does not allow bounded executor task smoke."
            ),
        ),
        local_operator_smoke_check(
            check_id="executor_smoke_passed",
            status="passed" if smoke_passed else "failed",
            message=(
                "Local operator executor smoke passed."
                if smoke_passed
                else "Local operator executor smoke is missing or not passed."
            ),
        ),
    ]
    task_result: dict[str, Any] = {
        "status": "not_run",
        "exit_code": None,
        "timed_out": False,
        "command": {"path_persisted": False},
        "command_executed": False,
        "stdout_persisted": False,
        "stderr_persisted": False,
        "raw_response_persisted": False,
        "tracked_status_unchanged": None,
        "response": {
            "parsed": False,
            "valid": False,
            "task_kind": "",
            "status": "",
            "canonical_mutation_attempted": None,
            "message_length": 0,
        },
    }
    if readiness_allows_task and smoke_passed and default_backend_id:
        task_result = run_local_operator_executor_task(
            backend_id=default_backend_id,
            timeout_seconds=timeout_seconds,
        )
    checks.append(
        local_operator_smoke_check(
            check_id="executor_task_invocation_completed",
            status=(
                "not_run"
                if task_result.get("status") == "not_run"
                else "missing"
                if task_result.get("status") == "missing"
                else "passed"
                if task_result.get("exit_code") == 0 and not task_result.get("timed_out")
                else "failed"
            ),
            message=(
                "Executor task invocation completed successfully."
                if task_result.get("exit_code") == 0 and not task_result.get("timed_out")
                else "Executor task invocation was not run because source artifacts gated it off."
                if task_result.get("status") == "not_run"
                else "Executor executable was not available for bounded task smoke."
                if task_result.get("status") == "missing"
                else "Executor task invocation did not complete successfully."
            ),
        )
    )
    response = task_result.get("response", {})
    response = response if isinstance(response, dict) else {}
    checks.append(
        local_operator_smoke_check(
            check_id="executor_task_response_valid",
            status=(
                "not_run"
                if task_result.get("status") == "not_run"
                else "passed"
                if response.get("valid") is True
                else "failed"
            ),
            message=(
                "Executor task response matched the bounded JSON contract."
                if response.get("valid") is True
                else "Executor task response was not checked because invocation was gated off."
                if task_result.get("status") == "not_run"
                else "Executor task response did not match the bounded JSON contract."
            ),
        )
    )
    task_command_executed = bool(task_result.get("command_executed"))
    checks.append(
        local_operator_smoke_check(
            check_id="no_canonical_mutation_attempted",
            status=(
                "not_run"
                if not task_command_executed
                else "passed"
                if task_result.get("tracked_status_unchanged") is True
                else "failed"
            ),
            message=(
                "No executor task command was executed, so the mutation check was not run."
                if not task_command_executed
                else "Worktree status did not change during the executor task smoke."
                if task_result.get("tracked_status_unchanged") is True
                else (
                    "Worktree status changed or could not be proven unchanged "
                    "during the executor task smoke."
                )
            ),
        )
    )
    task_smoke_status = local_operator_executor_task_smoke_status(checks)
    entry = {
        "backend_id": default_backend_id,
        "readiness_status": readiness_status,
        "smoke_status": smoke_status,
        "task_smoke_status": task_smoke_status,
        "source_readiness_artifact_present": isinstance(readiness, dict),
        "source_smoke_artifact_present": isinstance(smoke, dict),
        "request_contract": {
            "task_kind": str(contract.get("task_kind", "bounded_executor_task_smoke")).strip(),
            "canonical_mutation_allowed": False,
            "expected_response_format": str(
                contract.get("expected_response_format", "json_object")
            ).strip(),
            "prompt_persisted": False,
        },
        "execution": {
            "timeout_seconds": timeout_seconds,
            "exit_code": task_result.get("exit_code"),
            "timed_out": bool(task_result.get("timed_out", False)),
            "command": copy.deepcopy(task_result.get("command", {})),
            "command_executed": bool(task_result.get("command_executed", False)),
            "stdout_persisted": False,
            "stderr_persisted": False,
            "raw_response_persisted": False,
        },
        "response": copy.deepcopy(response),
        "checks": checks,
        "safe_next_action": local_operator_executor_task_smoke_next_gap(task_smoke_status),
    }
    named_filters = {
        str(name).strip(): [] for name in contract.get("named_filters", []) if str(name).strip()
    }
    named_filters.setdefault(task_smoke_status, []).append(
        default_backend_id or "missing_default_backend"
    )
    for key in list(named_filters):
        named_filters[key] = sorted(set(named_filters[key]))
    return {
        "artifact_kind": LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_ARTIFACT_KIND,
        "schema_version": LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": supervisor_executor_adapter_policy_reference(),
        "source_readiness_artifact": str(
            contract.get(
                "source_readiness_artifact",
                LOCAL_OPERATOR_EXECUTOR_READINESS_RELATIVE_PATH,
            )
        ).strip(),
        "source_smoke_artifact": str(
            contract.get(
                "source_smoke_artifact",
                LOCAL_OPERATOR_EXECUTOR_SMOKE_RELATIVE_PATH,
            )
        ).strip(),
        "local_only": bool(contract.get("local_only", True)),
        "privacy_boundary": copy.deepcopy(contract.get("privacy_boundary", {})),
        "summary": {
            "status": task_smoke_status,
            "backend_id": default_backend_id,
            "consumed_readiness_status": readiness_status,
            "consumed_smoke_status": smoke_status,
            "next_gap": local_operator_executor_task_smoke_next_gap(task_smoke_status),
        },
        "entries": [entry],
        "checks": checks,
        "viewer_projection": {
            "named_filters": named_filters,
        },
    }


def write_local_operator_executor_task_smoke(index: dict[str, Any]) -> Path:
    path = local_operator_executor_task_smoke_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def local_operator_executor_report_contract_next_gap(status: str) -> str:
    return {
        "ready_for_report_smoke": "run_bounded_executor_report_smoke",
        "blocked_task_smoke_not_passed": "run_executor_task_smoke_until_passed",
        "invalid_contract": "repair_executor_report_contract",
        "blocked_policy_contract": "repair_executor_adapter_policy_contract",
    }.get(status, "repair_executor_report_contract")


def load_local_operator_executor_task_smoke_artifact() -> dict[str, Any] | None:
    path = local_operator_executor_task_smoke_path()
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    return payload if isinstance(payload, dict) else None


def local_operator_executor_report_contract() -> dict[str, Any]:
    contract = supervisor_executor_adapter_policy_lookup("executor_report_contract")
    return contract if isinstance(contract, dict) else {}


def executor_report_contract_values(key: str) -> set[str]:
    contract = local_operator_executor_report_contract()
    values = contract.get(key, [])
    if not isinstance(values, list):
        return set()
    return {str(value).strip() for value in values if str(value).strip()}


def executor_report_finding(*, code: str, field: str, message: str) -> dict[str, str]:
    return {
        "code": code,
        "field": field,
        "message": message,
    }


def normalized_executor_report_key(raw_key: object) -> str:
    return re.sub(r"[^a-z0-9]+", "_", str(raw_key).strip().lower()).strip("_")


def executor_report_forbidden_key_findings(payload: object) -> list[dict[str, str]]:
    forbidden_keys = {
        "api_key",
        "authorization",
        "password",
        "raw_logs",
        "raw_prompt",
        "raw_response",
        "secret",
        "stderr",
        "stdout",
    }
    findings: list[dict[str, str]] = []

    def visit(value: object, path: str) -> None:
        if isinstance(value, dict):
            for key, child in value.items():
                key_text = str(key).strip()
                normalized_key = normalized_executor_report_key(key)
                child_path = f"{path}.{key_text}" if path else key_text
                if normalized_key in forbidden_keys:
                    findings.append(
                        executor_report_finding(
                            code="forbidden_raw_or_secret_field",
                            field=child_path,
                            message=f"{child_path} must not be persisted in executor reports.",
                        )
                    )
                visit(child, child_path)
        elif isinstance(value, list):
            for index, child in enumerate(value):
                visit(child, f"{path}[{index}]")

    visit(payload, "")
    return findings


def executor_report_string_contains_machine_local_path(value: str) -> bool:
    text = value.strip()
    if not text:
        return False
    if text.startswith(("file://", "~/", "~\\")):
        return True
    if re.search(r"(?<![A-Za-z0-9_])[A-Za-z]:[\\/]", text):
        return True
    if re.search(
        r"(^|[\s\"'=(])/(Users|tmp|private|var|home|Volumes|opt|etc|app|mnt|root|workspace)(/|$)",
        text,
    ):
        return True
    return bool(re.search(r"(^|[\s\"'=(])\\\\(Users|tmp|private|home)(\\\\|$)", text))


def executor_report_machine_local_path_findings(payload: object) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []

    def visit(value: object, path: str) -> None:
        if isinstance(value, dict):
            for key, child in value.items():
                key_text = str(key).strip()
                child_path = f"{path}.{key_text}" if path else key_text
                visit(child, child_path)
        elif isinstance(value, list):
            for index, child in enumerate(value):
                visit(child, f"{path}[{index}]")
        elif isinstance(value, str) and executor_report_string_contains_machine_local_path(value):
            findings.append(
                executor_report_finding(
                    code="machine_local_path_persisted",
                    field=path or "report",
                    message=(
                        f"{path or 'report'} must not persist machine-local filesystem paths."
                    ),
                )
            )

    visit(payload, "")
    return findings


def safe_executor_report_evidence_ref(raw_ref: object) -> str:
    candidate = safe_repo_relative_path_text(raw_ref)
    if not candidate:
        return ""
    if candidate.startswith("."):
        return ""
    return candidate


def default_local_operator_executor_report_sample(
    *,
    producer_kind: str = "coding_agent",
    producer_id: str = "codex",
    report_kind: str = "analysis_report",
    authority_level: str = "report_only",
) -> dict[str, Any]:
    return {
        "artifact_kind": LOCAL_OPERATOR_EXECUTOR_REPORT_ARTIFACT_KIND,
        "schema_version": LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_SCHEMA_VERSION,
        "local_only": True,
        "source_task_smoke_artifact": LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_RELATIVE_PATH,
        "producer": {
            "producer_kind": producer_kind,
            "producer_id": producer_id,
            "authority_level": authority_level,
        },
        "summary": {
            "status": "valid_report",
            "report_kind": report_kind,
            "curation_required": True,
            "canonical_mutation_attempted": False,
            "next_gap": "run_bounded_executor_report_smoke",
        },
        "report": {
            "report_kind": report_kind,
            "status": "completed",
            "findings": [],
            "source_evidence_refs": [
                LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_RELATIVE_PATH,
            ],
            "proposed_artifacts": [],
        },
        "privacy_boundary": {
            "absolute_paths_persisted": False,
            "raw_logs_persisted": False,
            "raw_prompt_persisted": False,
            "raw_response_persisted": False,
            "secrets_persisted": False,
        },
    }


def validate_local_operator_executor_report(report: object) -> dict[str, Any]:
    contract = local_operator_executor_report_contract()
    findings: list[dict[str, str]] = []
    if not isinstance(report, dict):
        return {
            "valid": False,
            "findings": [
                executor_report_finding(
                    code="report_not_object",
                    field="report",
                    message="Executor report must be a JSON object.",
                )
            ],
            "normalized": {},
        }
    findings.extend(executor_report_forbidden_key_findings(report))
    findings.extend(executor_report_machine_local_path_findings(report))
    required_fields = [
        str(field).strip()
        for field in contract.get("required_report_fields", [])
        if str(field).strip()
    ]
    for field in required_fields:
        if field not in report:
            findings.append(
                executor_report_finding(
                    code="missing_required_field",
                    field=field,
                    message=f"Executor report is missing required field {field}.",
                )
            )
    if report.get("artifact_kind") != LOCAL_OPERATOR_EXECUTOR_REPORT_ARTIFACT_KIND:
        findings.append(
            executor_report_finding(
                code="invalid_artifact_kind",
                field="artifact_kind",
                message=(
                    "Executor report artifact_kind must be "
                    f"{LOCAL_OPERATOR_EXECUTOR_REPORT_ARTIFACT_KIND}."
                ),
            )
        )
    if report.get("schema_version") != LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_SCHEMA_VERSION:
        findings.append(
            executor_report_finding(
                code="invalid_schema_version",
                field="schema_version",
                message=(
                    "Executor report schema_version must match the report contract "
                    f"schema version {LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_SCHEMA_VERSION}."
                ),
            )
        )
    if report.get("local_only") is not True:
        findings.append(
            executor_report_finding(
                code="local_only_required",
                field="local_only",
                message="Executor report must be local_only=true.",
            )
        )
    if report.get("source_task_smoke_artifact") != LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_RELATIVE_PATH:
        findings.append(
            executor_report_finding(
                code="invalid_source_task_smoke_artifact",
                field="source_task_smoke_artifact",
                message="Executor report must reference the local task smoke artifact.",
            )
        )

    producer = report.get("producer", {})
    producer = producer if isinstance(producer, dict) else {}
    for field in [
        str(field).strip()
        for field in contract.get("required_producer_fields", [])
        if str(field).strip()
    ]:
        if field not in producer or not str(producer.get(field, "")).strip():
            findings.append(
                executor_report_finding(
                    code="missing_required_producer_field",
                    field=f"producer.{field}",
                    message=f"Executor report producer is missing required field {field}.",
                )
            )
    producer_kind = str(producer.get("producer_kind", "")).strip()
    producer_id = str(producer.get("producer_id", "")).strip()
    authority_level = str(producer.get("authority_level", "")).strip()
    if producer_kind not in executor_report_contract_values("producer_kinds"):
        findings.append(
            executor_report_finding(
                code="unknown_producer_kind",
                field="producer.producer_kind",
                message=f"Unknown executor report producer_kind: {producer_kind}.",
            )
        )
    if authority_level not in executor_report_contract_values("authority_levels"):
        findings.append(
            executor_report_finding(
                code="unknown_authority_level",
                field="producer.authority_level",
                message=f"Unknown executor report authority_level: {authority_level}.",
            )
        )

    summary = report.get("summary", {})
    summary = summary if isinstance(summary, dict) else {}
    for field in [
        str(field).strip()
        for field in contract.get("required_summary_fields", [])
        if str(field).strip()
    ]:
        if field not in summary:
            findings.append(
                executor_report_finding(
                    code="missing_required_summary_field",
                    field=f"summary.{field}",
                    message=f"Executor report summary is missing required field {field}.",
                )
            )
    summary_status = str(summary.get("status", "")).strip()
    if summary_status not in executor_report_contract_values("report_status_values"):
        findings.append(
            executor_report_finding(
                code="unknown_report_status",
                field="summary.status",
                message=f"Unknown executor report summary.status: {summary_status}.",
            )
        )
    report_kind = str(summary.get("report_kind", "")).strip()
    if report_kind not in executor_report_contract_values("report_kinds"):
        findings.append(
            executor_report_finding(
                code="unknown_report_kind",
                field="summary.report_kind",
                message=f"Unknown executor report report_kind: {report_kind}.",
            )
        )
    curation_required = summary.get("curation_required")
    if not isinstance(curation_required, bool):
        findings.append(
            executor_report_finding(
                code="curation_required_not_boolean",
                field="summary.curation_required",
                message="Executor report summary.curation_required must be boolean.",
            )
        )
    canonical_mutation_attempted = summary.get("canonical_mutation_attempted")
    if canonical_mutation_attempted is not False:
        findings.append(
            executor_report_finding(
                code="canonical_mutation_attempted",
                field="summary.canonical_mutation_attempted",
                message="Executor report must declare canonical_mutation_attempted=false.",
            )
        )

    nested_report = report.get("report", {})
    nested_report = nested_report if isinstance(nested_report, dict) else {}
    for field in [
        str(field).strip()
        for field in contract.get("required_report_fields_nested", [])
        if str(field).strip()
    ]:
        if field not in nested_report:
            findings.append(
                executor_report_finding(
                    code="missing_required_nested_report_field",
                    field=f"report.{field}",
                    message=f"Executor report payload is missing required field {field}.",
                )
            )
    nested_report_kind = str(nested_report.get("report_kind", "")).strip()
    if nested_report_kind != report_kind:
        findings.append(
            executor_report_finding(
                code="report_kind_mismatch",
                field="report.report_kind",
                message="Executor report payload report_kind must match summary.report_kind.",
            )
        )
    if not isinstance(nested_report.get("findings", []), list):
        findings.append(
            executor_report_finding(
                code="findings_not_list",
                field="report.findings",
                message="Executor report findings must be a list.",
            )
        )
    source_evidence_refs = nested_report.get("source_evidence_refs", [])
    if not isinstance(source_evidence_refs, list):
        findings.append(
            executor_report_finding(
                code="source_evidence_refs_not_list",
                field="report.source_evidence_refs",
                message="Executor report source_evidence_refs must be a list.",
            )
        )
        source_evidence_refs = []
    safe_source_evidence_refs = []
    for index, raw_ref in enumerate(source_evidence_refs):
        safe_ref = safe_executor_report_evidence_ref(raw_ref)
        if not safe_ref:
            findings.append(
                executor_report_finding(
                    code="unsafe_source_evidence_ref",
                    field=f"report.source_evidence_refs[{index}]",
                    message=(
                        "Executor report source evidence refs must be safe repo-relative paths."
                    ),
                )
            )
        else:
            safe_source_evidence_refs.append(safe_ref)
    proposed_artifacts = nested_report.get("proposed_artifacts", [])
    if not isinstance(proposed_artifacts, list):
        findings.append(
            executor_report_finding(
                code="proposed_artifacts_not_list",
                field="report.proposed_artifacts",
                message="Executor report proposed_artifacts must be a list.",
            )
        )
        proposed_artifacts = []
    for index, proposed_artifact in enumerate(proposed_artifacts):
        if not isinstance(proposed_artifact, dict):
            continue
        for field in ("artifact_ref", "artifact_path", "path"):
            if field in proposed_artifact and not safe_executor_report_evidence_ref(
                proposed_artifact.get(field)
            ):
                findings.append(
                    executor_report_finding(
                        code="unsafe_proposed_artifact_ref",
                        field=f"report.proposed_artifacts[{index}].{field}",
                        message=(
                            "Executor report proposed artifact refs must be safe "
                            "repo-relative paths."
                        ),
                    )
                )
    if nested_report.get("canonical_mutation_attempted") is True:
        findings.append(
            executor_report_finding(
                code="canonical_mutation_attempted",
                field="report.canonical_mutation_attempted",
                message="Executor report payload must not declare canonical mutation attempts.",
            )
        )

    privacy = report.get("privacy_boundary", {})
    privacy = privacy if isinstance(privacy, dict) else {}
    for field in (
        "absolute_paths_persisted",
        "raw_logs_persisted",
        "raw_prompt_persisted",
        "raw_response_persisted",
        "secrets_persisted",
    ):
        if privacy.get(field) is not False:
            findings.append(
                executor_report_finding(
                    code="privacy_boundary_not_closed",
                    field=f"privacy_boundary.{field}",
                    message=f"Executor report privacy_boundary.{field} must be false.",
                )
            )

    normalized = {
        "producer_kind": producer_kind,
        "producer_id": producer_id,
        "authority_level": authority_level,
        "report_kind": report_kind,
        "summary_status": summary_status,
        "curation_required": curation_required if isinstance(curation_required, bool) else None,
        "canonical_mutation_attempted": canonical_mutation_attempted,
        "source_evidence_ref_count": len(safe_source_evidence_refs),
        "proposed_artifact_count": len(proposed_artifacts),
    }
    return {
        "valid": not findings,
        "findings": findings,
        "normalized": normalized,
    }


def validate_local_operator_executor_task_smoke_source(
    task_smoke: object,
) -> dict[str, Any]:
    contract = local_operator_executor_task_smoke_contract()
    required_check_ids = [
        str(check_id).strip() for check_id in contract.get("check_ids", []) if str(check_id).strip()
    ]
    findings: list[dict[str, str]] = []
    if not isinstance(task_smoke, dict):
        return {
            "valid": False,
            "status": "",
            "required_check_ids": required_check_ids,
            "findings": [
                executor_report_finding(
                    code="source_task_smoke_missing",
                    field="source_task_smoke_artifact",
                    message="Local operator executor task smoke artifact is missing.",
                )
            ],
        }
    if task_smoke.get("artifact_kind") != LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_ARTIFACT_KIND:
        findings.append(
            executor_report_finding(
                code="invalid_source_task_smoke_artifact_kind",
                field="source_task_smoke_artifact.artifact_kind",
                message="Source task smoke artifact has an unexpected artifact_kind.",
            )
        )
    if task_smoke.get("schema_version") != LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_SCHEMA_VERSION:
        findings.append(
            executor_report_finding(
                code="invalid_source_task_smoke_schema_version",
                field="source_task_smoke_artifact.schema_version",
                message="Source task smoke artifact has an unexpected schema_version.",
            )
        )
    if task_smoke.get("local_only") is not True:
        findings.append(
            executor_report_finding(
                code="source_task_smoke_local_only_required",
                field="source_task_smoke_artifact.local_only",
                message="Source task smoke artifact must declare local_only=true.",
            )
        )
    summary = task_smoke.get("summary", {})
    summary = summary if isinstance(summary, dict) else {}
    task_smoke_status = str(summary.get("status", "")).strip()
    if task_smoke_status != "passed":
        findings.append(
            executor_report_finding(
                code="source_task_smoke_not_passed",
                field="source_task_smoke_artifact.summary.status",
                message="Source task smoke artifact summary.status must be passed.",
            )
        )
    checks = task_smoke.get("checks", [])
    if not isinstance(checks, list):
        findings.append(
            executor_report_finding(
                code="source_task_smoke_checks_not_list",
                field="source_task_smoke_artifact.checks",
                message="Source task smoke artifact checks must be a list.",
            )
        )
        checks = []
    check_status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
        if isinstance(check, dict)
    }
    for check_id in required_check_ids:
        check_status = check_status_by_id.get(check_id, "")
        if not check_status:
            findings.append(
                executor_report_finding(
                    code="missing_source_task_smoke_check",
                    field=f"source_task_smoke_artifact.checks.{check_id}",
                    message=f"Source task smoke artifact is missing check {check_id}.",
                )
            )
        elif check_status != "passed":
            findings.append(
                executor_report_finding(
                    code="source_task_smoke_check_not_passed",
                    field=f"source_task_smoke_artifact.checks.{check_id}",
                    message=f"Source task smoke check {check_id} must be passed.",
                )
            )
    return {
        "valid": not findings,
        "status": task_smoke_status,
        "required_check_ids": required_check_ids,
        "findings": findings,
    }


def local_operator_executor_report_contract_status(checks: list[dict[str, Any]]) -> str:
    status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
    }
    if status_by_id.get("task_smoke_passed") != "passed":
        return "blocked_task_smoke_not_passed"
    if status_by_id.get("report_contract_sample_valid") != "passed":
        return "invalid_contract"
    if (
        status_by_id.get("privacy_boundary_declared") != "passed"
        or status_by_id.get("static_publish_excluded") != "passed"
    ):
        return "blocked_policy_contract"
    return "ready_for_report_smoke"


def build_local_operator_executor_report_contract(
    task_smoke: dict[str, Any] | None = None,
    sample_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    contract = local_operator_executor_report_contract()
    task_smoke = (
        task_smoke
        if isinstance(task_smoke, dict)
        else load_local_operator_executor_task_smoke_artifact()
    )
    task_smoke_validation = validate_local_operator_executor_task_smoke_source(task_smoke)
    task_smoke_status = str(task_smoke_validation.get("status", "")).strip()
    task_smoke_passed = task_smoke_validation.get("valid") is True
    sample_report = (
        sample_report
        if isinstance(sample_report, dict)
        else default_local_operator_executor_report_sample()
    )
    sample_validation = validate_local_operator_executor_report(sample_report)
    privacy_boundary = contract.get("privacy_boundary", {})
    privacy_boundary = privacy_boundary if isinstance(privacy_boundary, dict) else {}
    privacy_declared = (
        privacy_boundary.get("public_static_publish") is False
        and privacy_boundary.get("canonical_mutations_allowed") is False
        and privacy_boundary.get("must_not_persist_absolute_paths") is True
        and privacy_boundary.get("must_not_persist_raw_logs") is True
        and privacy_boundary.get("must_not_persist_raw_prompt") is True
        and privacy_boundary.get("must_not_persist_raw_response") is True
        and privacy_boundary.get("must_not_persist_secrets") is True
    )
    static_excluded = bool(contract.get("local_only", True)) and (
        privacy_boundary.get("public_static_publish") is False
    )
    checks = [
        local_operator_smoke_check(
            check_id="task_smoke_passed",
            status="passed" if task_smoke_passed else "failed",
            message=(
                "Local operator executor task smoke passed and matched the source contract."
                if task_smoke_passed
                else "Local operator executor task smoke is missing, malformed, or not passed."
            ),
        ),
        local_operator_smoke_check(
            check_id="report_contract_sample_valid",
            status="passed" if sample_validation.get("valid") is True else "failed",
            message=(
                "Executor report contract sample is valid."
                if sample_validation.get("valid") is True
                else "Executor report contract sample is invalid."
            ),
        ),
        local_operator_smoke_check(
            check_id="privacy_boundary_declared",
            status="passed" if privacy_declared else "failed",
            message=(
                "Executor report contract declares a closed privacy boundary."
                if privacy_declared
                else "Executor report contract does not declare a closed privacy boundary."
            ),
        ),
        local_operator_smoke_check(
            check_id="static_publish_excluded",
            status="passed" if static_excluded else "failed",
            message=(
                "Executor report contract is local-only and excluded from static publish."
                if static_excluded
                else "Executor report contract is not safely excluded from static publish."
            ),
        ),
    ]
    contract_status = local_operator_executor_report_contract_status(checks)
    normalized_sample = sample_validation.get("normalized", {})
    normalized_sample = normalized_sample if isinstance(normalized_sample, dict) else {}
    named_filters = {
        str(name).strip(): [] for name in contract.get("named_filters", []) if str(name).strip()
    }
    named_filters.setdefault(contract_status, []).append(
        str(normalized_sample.get("producer_id") or "contract")
    )
    for key in list(named_filters):
        named_filters[key] = sorted(set(named_filters[key]))
    return {
        "artifact_kind": LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_ARTIFACT_KIND,
        "schema_version": LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": supervisor_executor_adapter_policy_reference(),
        "source_task_smoke_artifact": str(
            contract.get(
                "source_task_smoke_artifact",
                LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_RELATIVE_PATH,
            )
        ).strip(),
        "target_report_artifact": str(
            contract.get("target_report_artifact", LOCAL_OPERATOR_EXECUTOR_REPORT_RELATIVE_PATH)
        ).strip(),
        "target_report_artifact_kind": LOCAL_OPERATOR_EXECUTOR_REPORT_ARTIFACT_KIND,
        "local_only": bool(contract.get("local_only", True)),
        "privacy_boundary": copy.deepcopy(privacy_boundary),
        "producer_contract": {
            "producer_kinds": sorted(executor_report_contract_values("producer_kinds")),
            "authority_levels": sorted(executor_report_contract_values("authority_levels")),
        },
        "report_contract": {
            "report_kinds": sorted(executor_report_contract_values("report_kinds")),
            "report_status_values": sorted(executor_report_contract_values("report_status_values")),
            "required_report_fields": [
                str(field).strip()
                for field in contract.get("required_report_fields", [])
                if str(field).strip()
            ],
        },
        "sample_report_validation": {
            "valid": bool(sample_validation.get("valid", False)),
            "finding_count": len(sample_validation.get("findings", [])),
            "findings": copy.deepcopy(sample_validation.get("findings", [])),
            "normalized": copy.deepcopy(normalized_sample),
            "raw_sample_persisted": False,
        },
        "source_task_smoke_validation": {
            "valid": bool(task_smoke_validation.get("valid", False)),
            "finding_count": len(task_smoke_validation.get("findings", [])),
            "findings": copy.deepcopy(task_smoke_validation.get("findings", [])),
            "required_check_ids": copy.deepcopy(
                task_smoke_validation.get("required_check_ids", [])
            ),
        },
        "summary": {
            "status": contract_status,
            "source_task_smoke_status": task_smoke_status,
            "sample_report_valid": bool(sample_validation.get("valid", False)),
            "next_gap": local_operator_executor_report_contract_next_gap(contract_status),
        },
        "checks": checks,
        "viewer_projection": {
            "named_filters": named_filters,
        },
    }


def write_local_operator_executor_report_contract(index: dict[str, Any]) -> Path:
    path = local_operator_executor_report_contract_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def local_operator_executor_report_smoke_next_gap(status: str) -> str:
    return {
        "passed": "define_executor_report_consumption_policy",
        "blocked_task_smoke_not_passed": "run_executor_task_smoke_until_passed",
        "blocked_report_contract_not_ready": "run_executor_report_contract_until_ready",
        "blocked_executor_unavailable": "configure_local_operator_executable",
        "failed_executor_nonzero": "repair_executor_report_smoke_invocation",
        "failed_invalid_report": "repair_executor_report_contract",
        "failed_mutation_guard": "repair_executor_report_smoke_mutation_boundary",
        "blocked_policy_contract": "repair_executor_adapter_policy_contract",
    }.get(status, "repair_executor_report_smoke")


def local_operator_executor_report_smoke_status(checks: list[dict[str, Any]]) -> str:
    status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
    }
    if status_by_id.get("task_smoke_passed") != "passed":
        return "blocked_task_smoke_not_passed"
    if status_by_id.get("report_contract_ready") != "passed":
        return "blocked_report_contract_not_ready"
    invocation_status = status_by_id.get("executor_report_invocation_completed")
    if invocation_status == "not_run":
        return "blocked_policy_contract"
    if invocation_status == "missing":
        return "blocked_executor_unavailable"
    if invocation_status != "passed":
        return "failed_executor_nonzero"
    if status_by_id.get("executor_report_valid") != "passed":
        return "failed_invalid_report"
    if status_by_id.get("no_canonical_mutation_attempted") != "passed":
        return "failed_mutation_guard"
    return "passed"


def load_local_operator_executor_report_contract_artifact() -> dict[str, Any] | None:
    path = local_operator_executor_report_contract_path()
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    return payload if isinstance(payload, dict) else None


def local_operator_executor_report_smoke_contract() -> dict[str, Any]:
    contract = supervisor_executor_adapter_policy_lookup("local_operator_report_smoke_contract")
    return contract if isinstance(contract, dict) else {}


def validate_local_operator_executor_report_contract_source(
    report_contract: object,
) -> dict[str, Any]:
    contract = local_operator_executor_report_contract()
    required_check_ids = [
        str(check_id).strip() for check_id in contract.get("check_ids", []) if str(check_id).strip()
    ]
    findings: list[dict[str, str]] = []
    if not isinstance(report_contract, dict):
        return {
            "valid": False,
            "status": "",
            "required_check_ids": required_check_ids,
            "findings": [
                executor_report_finding(
                    code="source_report_contract_missing",
                    field="source_report_contract_artifact",
                    message="Local operator executor report contract artifact is missing.",
                )
            ],
        }
    if (
        report_contract.get("artifact_kind")
        != LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_ARTIFACT_KIND
    ):
        findings.append(
            executor_report_finding(
                code="invalid_source_report_contract_artifact_kind",
                field="source_report_contract_artifact.artifact_kind",
                message="Source report contract artifact has an unexpected artifact_kind.",
            )
        )
    if (
        report_contract.get("schema_version")
        != LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_SCHEMA_VERSION
    ):
        findings.append(
            executor_report_finding(
                code="invalid_source_report_contract_schema_version",
                field="source_report_contract_artifact.schema_version",
                message="Source report contract artifact has an unexpected schema_version.",
            )
        )
    if report_contract.get("local_only") is not True:
        findings.append(
            executor_report_finding(
                code="source_report_contract_local_only_required",
                field="source_report_contract_artifact.local_only",
                message="Source report contract artifact must declare local_only=true.",
            )
        )
    summary = report_contract.get("summary", {})
    summary = summary if isinstance(summary, dict) else {}
    report_contract_status = str(summary.get("status", "")).strip()
    if report_contract_status != "ready_for_report_smoke":
        findings.append(
            executor_report_finding(
                code="source_report_contract_not_ready",
                field="source_report_contract_artifact.summary.status",
                message=(
                    "Source report contract artifact summary.status must be ready_for_report_smoke."
                ),
            )
        )
    checks = report_contract.get("checks", [])
    if not isinstance(checks, list):
        findings.append(
            executor_report_finding(
                code="source_report_contract_checks_not_list",
                field="source_report_contract_artifact.checks",
                message="Source report contract artifact checks must be a list.",
            )
        )
        checks = []
    check_status_by_id = {
        str(check.get("check_id", "")).strip(): str(check.get("status", "")).strip()
        for check in checks
        if isinstance(check, dict)
    }
    for check_id in required_check_ids:
        check_status = check_status_by_id.get(check_id, "")
        if not check_status:
            findings.append(
                executor_report_finding(
                    code="missing_source_report_contract_check",
                    field=f"source_report_contract_artifact.checks.{check_id}",
                    message=f"Source report contract artifact is missing check {check_id}.",
                )
            )
        elif check_status != "passed":
            findings.append(
                executor_report_finding(
                    code="source_report_contract_check_not_passed",
                    field=f"source_report_contract_artifact.checks.{check_id}",
                    message=f"Source report contract check {check_id} must be passed.",
                )
            )
    return {
        "valid": not findings,
        "status": report_contract_status,
        "required_check_ids": required_check_ids,
        "findings": findings,
    }


def local_operator_report_smoke_for_backend(backend_id: str) -> dict[str, Any]:
    contract = local_operator_executor_report_smoke_contract()
    default_timeout = int(contract.get("default_timeout_seconds", 120) or 120)
    for backend in supervisor_executor_adapter_policy_lookup("backend_registry"):
        if not isinstance(backend, dict):
            continue
        if str(backend.get("backend_id", "")).strip() != backend_id:
            continue
        report_smoke = backend.get("local_report_smoke", {})
        report_smoke = report_smoke if isinstance(report_smoke, dict) else {}
        fallback_task = backend.get("local_task_smoke", {})
        fallback_task = fallback_task if isinstance(fallback_task, dict) else {}
        args = [str(arg).strip() for arg in report_smoke.get("args", []) if str(arg).strip()] or [
            str(arg).strip() for arg in fallback_task.get("args", []) if str(arg).strip()
        ]
        timeout = int(
            report_smoke.get(
                "timeout_seconds",
                fallback_task.get("timeout_seconds", default_timeout),
            )
            or default_timeout
        )
        return {
            "args": args,
            "timeout_seconds": max(1, min(timeout, 300)),
        }
    return {"args": [], "timeout_seconds": max(1, min(default_timeout, 300))}


def bounded_executor_report_response_schema() -> dict[str, Any]:
    return {
        "$schema": "https://json-schema.org/draft/2020-12/schema",
        "type": "object",
        "additionalProperties": False,
        "required": [
            "artifact_kind",
            "schema_version",
            "local_only",
            "source_task_smoke_artifact",
            "producer",
            "summary",
            "report",
            "privacy_boundary",
        ],
        "properties": {
            "artifact_kind": {"const": LOCAL_OPERATOR_EXECUTOR_REPORT_ARTIFACT_KIND},
            "schema_version": {"const": LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_SCHEMA_VERSION},
            "local_only": {"const": True},
            "source_task_smoke_artifact": {
                "const": LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_RELATIVE_PATH
            },
            "producer": {
                "type": "object",
                "additionalProperties": False,
                "required": ["producer_kind", "producer_id", "authority_level"],
                "properties": {
                    "producer_kind": {"const": "coding_agent"},
                    "producer_id": {"const": "codex"},
                    "authority_level": {"const": "report_only"},
                },
            },
            "summary": {
                "type": "object",
                "additionalProperties": False,
                "required": [
                    "status",
                    "report_kind",
                    "curation_required",
                    "canonical_mutation_attempted",
                    "next_gap",
                ],
                "properties": {
                    "status": {"const": "valid_report"},
                    "report_kind": {"const": "analysis_report"},
                    "curation_required": {"const": True},
                    "canonical_mutation_attempted": {"const": False},
                    "next_gap": {"const": "run_bounded_executor_report_smoke"},
                },
            },
            "report": {
                "type": "object",
                "additionalProperties": False,
                "required": [
                    "report_kind",
                    "status",
                    "findings",
                    "source_evidence_refs",
                    "proposed_artifacts",
                ],
                "properties": {
                    "report_kind": {"const": "analysis_report"},
                    "status": {"const": "completed"},
                    "findings": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "additionalProperties": False,
                            "properties": {},
                        },
                        "maxItems": 0,
                    },
                    "source_evidence_refs": {
                        "type": "array",
                        "items": {"const": LOCAL_OPERATOR_EXECUTOR_TASK_SMOKE_RELATIVE_PATH},
                        "minItems": 1,
                        "maxItems": 1,
                    },
                    "proposed_artifacts": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "additionalProperties": False,
                            "properties": {},
                        },
                        "maxItems": 0,
                    },
                },
            },
            "privacy_boundary": {
                "type": "object",
                "additionalProperties": False,
                "required": [
                    "absolute_paths_persisted",
                    "raw_logs_persisted",
                    "raw_prompt_persisted",
                    "raw_response_persisted",
                    "secrets_persisted",
                ],
                "properties": {
                    "absolute_paths_persisted": {"const": False},
                    "raw_logs_persisted": {"const": False},
                    "raw_prompt_persisted": {"const": False},
                    "raw_response_persisted": {"const": False},
                    "secrets_persisted": {"const": False},
                },
            },
        },
    }


def bounded_executor_report_prompt() -> str:
    contract = local_operator_executor_report_smoke_contract()
    prompt = str(contract.get("prompt", "")).strip()
    return prompt or (
        "Return only a JSON object matching the local_operator_executor_report contract. "
        "Do not inspect, edit, or create repository files."
    )


def executor_report_invocation_command_from_backend(
    *,
    backend_id: str,
    output_schema_path: Path,
    output_last_message_path: Path,
    prompt: str,
) -> tuple[list[str], dict[str, Any]]:
    report_smoke = local_operator_report_smoke_for_backend(backend_id)
    base_args = [str(arg).strip() for arg in report_smoke.get("args", []) if str(arg).strip()]
    report_args = [
        *base_args,
        "-C",
        ROOT.as_posix(),
        "--output-schema",
        output_schema_path.as_posix(),
        "--output-last-message",
        output_last_message_path.as_posix(),
        prompt,
    ]
    return executable_invocation_command_from_backend(
        backend_id=backend_id,
        probe_args=report_args,
    )


def parse_bounded_executor_report_response(raw_text: str) -> dict[str, Any]:
    try:
        payload = json.loads(raw_text.strip())
    except json.JSONDecodeError:
        validation = validate_local_operator_executor_report({})
        return {
            "parsed": False,
            "valid": False,
            "safe_report": None,
            "validation": {
                "valid": False,
                "finding_count": len(validation.get("findings", [])),
                "findings": copy.deepcopy(validation.get("findings", [])),
                "normalized": {},
            },
        }
    validation = validate_local_operator_executor_report(payload)
    safe_report = copy.deepcopy(payload) if validation.get("valid") is True else None
    normalized = validation.get("normalized", {})
    normalized = normalized if isinstance(normalized, dict) else {}
    return {
        "parsed": isinstance(payload, dict),
        "valid": bool(validation.get("valid", False)),
        "safe_report": safe_report if isinstance(safe_report, dict) else None,
        "validation": {
            "valid": bool(validation.get("valid", False)),
            "finding_count": len(validation.get("findings", [])),
            "findings": copy.deepcopy(validation.get("findings", [])),
            "normalized": copy.deepcopy(normalized),
        },
    }


def run_local_operator_executor_report_task(
    *,
    backend_id: str,
    timeout_seconds: int,
) -> dict[str, Any]:
    with tempfile.TemporaryDirectory(prefix="specgraph-executor-report-smoke-") as temp_dir:
        temp_path = Path(temp_dir)
        output_schema_path = temp_path / "response.schema.json"
        output_last_message_path = temp_path / "last-message.json"
        output_schema_path.write_text(
            json.dumps(bounded_executor_report_response_schema(), indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        command, invocation = executor_report_invocation_command_from_backend(
            backend_id=backend_id,
            output_schema_path=output_schema_path,
            output_last_message_path=output_last_message_path,
            prompt=bounded_executor_report_prompt(),
        )
        if not command:
            return {
                "status": "missing",
                "exit_code": None,
                "timed_out": False,
                "command": invocation,
                "command_executed": False,
                "stdout_persisted": False,
                "stderr_persisted": False,
                "raw_response_persisted": False,
                "tracked_status_unchanged": None,
                "response": {
                    "parsed": False,
                    "valid": False,
                    "safe_report": None,
                    "validation": {
                        "valid": False,
                        "finding_count": 0,
                        "findings": [],
                        "normalized": {},
                    },
                },
            }
        before_status = git_tracked_status_snapshot()
        try:
            result = subprocess.run(
                command,
                cwd=ROOT,
                capture_output=True,
                text=True,
                check=False,
                timeout=timeout_seconds,
            )
            timed_out = False
            exit_code: int | None = result.returncode
        except subprocess.TimeoutExpired:
            timed_out = True
            exit_code = None
        after_status = git_tracked_status_snapshot()
        try:
            raw_response = output_last_message_path.read_text(encoding="utf-8")
        except OSError:
            raw_response = ""
        response = parse_bounded_executor_report_response(raw_response)
        return {
            "status": (
                "passed"
                if exit_code == 0 and not timed_out and bool(response.get("valid"))
                else "failed"
            ),
            "exit_code": exit_code,
            "timed_out": timed_out,
            "command": invocation,
            "command_executed": True,
            "stdout_persisted": False,
            "stderr_persisted": False,
            "raw_response_persisted": False,
            "tracked_status_unchanged": (
                before_status is not None
                and after_status is not None
                and before_status == after_status
            ),
            "response": response,
        }


def sanitized_local_operator_executor_report_fallback(
    *,
    smoke_status: str,
    backend_id: str,
    report_validation: dict[str, Any],
) -> dict[str, Any]:
    report = default_local_operator_executor_report_sample(producer_id=backend_id or "codex")
    report["summary"]["status"] = "invalid_report"
    report["summary"]["next_gap"] = local_operator_executor_report_smoke_next_gap(smoke_status)
    report["report"]["status"] = "invalid"
    report["report"]["findings"] = copy.deepcopy(report_validation.get("findings", []))
    return report


def build_local_operator_executor_report_smoke(
    task_smoke: dict[str, Any] | None = None,
    report_contract: dict[str, Any] | None = None,
) -> dict[str, Any]:
    smoke_contract = local_operator_executor_report_smoke_contract()
    task_smoke = (
        task_smoke
        if isinstance(task_smoke, dict)
        else load_local_operator_executor_task_smoke_artifact()
    )
    report_contract = (
        report_contract
        if isinstance(report_contract, dict)
        else load_local_operator_executor_report_contract_artifact()
    )
    task_smoke_validation = validate_local_operator_executor_task_smoke_source(task_smoke)
    report_contract_validation = validate_local_operator_executor_report_contract_source(
        report_contract
    )
    task_smoke_summary = task_smoke.get("summary", {}) if isinstance(task_smoke, dict) else {}
    task_smoke_summary = task_smoke_summary if isinstance(task_smoke_summary, dict) else {}
    default_backend_id = str(task_smoke_summary.get("backend_id", "")).strip()
    task_smoke_passed = task_smoke_validation.get("valid") is True
    report_contract_ready = report_contract_validation.get("valid") is True
    report_smoke = local_operator_report_smoke_for_backend(default_backend_id)
    timeout_seconds = int(report_smoke.get("timeout_seconds", 120) or 120)
    checks = [
        local_operator_smoke_check(
            check_id="task_smoke_passed",
            status="passed" if task_smoke_passed else "failed",
            message=(
                "Local operator executor task smoke passed and matched the source contract."
                if task_smoke_passed
                else "Local operator executor task smoke is missing, malformed, or not passed."
            ),
        ),
        local_operator_smoke_check(
            check_id="report_contract_ready",
            status="passed" if report_contract_ready else "failed",
            message=(
                "Local operator executor report contract is ready for report smoke."
                if report_contract_ready
                else "Local operator executor report contract is missing, malformed, or not ready."
            ),
        ),
    ]
    report_result: dict[str, Any] = {
        "status": "not_run",
        "exit_code": None,
        "timed_out": False,
        "command": {"path_persisted": False},
        "command_executed": False,
        "stdout_persisted": False,
        "stderr_persisted": False,
        "raw_response_persisted": False,
        "tracked_status_unchanged": None,
        "response": {
            "parsed": False,
            "valid": False,
            "safe_report": None,
            "validation": {
                "valid": False,
                "finding_count": 0,
                "findings": [],
                "normalized": {},
            },
        },
    }
    if task_smoke_passed and report_contract_ready and default_backend_id:
        report_result = run_local_operator_executor_report_task(
            backend_id=default_backend_id,
            timeout_seconds=timeout_seconds,
        )
    checks.append(
        local_operator_smoke_check(
            check_id="executor_report_invocation_completed",
            status=(
                "not_run"
                if report_result.get("status") == "not_run"
                else "missing"
                if report_result.get("status") == "missing"
                else "passed"
                if report_result.get("exit_code") == 0 and not report_result.get("timed_out")
                else "failed"
            ),
            message=(
                "Executor report invocation completed successfully."
                if report_result.get("exit_code") == 0 and not report_result.get("timed_out")
                else "Executor report invocation was not run because source artifacts gated it off."
                if report_result.get("status") == "not_run"
                else "Executor executable was not available for bounded report smoke."
                if report_result.get("status") == "missing"
                else "Executor report invocation did not complete successfully."
            ),
        )
    )
    response = report_result.get("response", {})
    response = response if isinstance(response, dict) else {}
    report_validation = response.get("validation", {})
    report_validation = report_validation if isinstance(report_validation, dict) else {}
    checks.append(
        local_operator_smoke_check(
            check_id="executor_report_valid",
            status=(
                "not_run"
                if report_result.get("status") == "not_run"
                else "passed"
                if response.get("valid") is True
                else "failed"
            ),
            message=(
                "Executor report response matched the generic report contract."
                if response.get("valid") is True
                else "Executor report response was not checked because invocation was gated off."
                if report_result.get("status") == "not_run"
                else "Executor report response did not match the generic report contract."
            ),
        )
    )
    report_command_executed = bool(report_result.get("command_executed"))
    checks.append(
        local_operator_smoke_check(
            check_id="no_canonical_mutation_attempted",
            status=(
                "not_run"
                if not report_command_executed
                else "passed"
                if report_result.get("tracked_status_unchanged") is True
                else "failed"
            ),
            message=(
                "No executor report command was executed, so the mutation check was not run."
                if not report_command_executed
                else "Worktree status did not change during the executor report smoke."
                if report_result.get("tracked_status_unchanged") is True
                else (
                    "Worktree status changed or could not be proven unchanged "
                    "during the executor report smoke."
                )
            ),
        )
    )
    report_smoke_status = local_operator_executor_report_smoke_status(checks)
    safe_report = response.get("safe_report")
    if isinstance(safe_report, dict) and report_smoke_status == "passed":
        artifact = copy.deepcopy(safe_report)
    else:
        artifact = sanitized_local_operator_executor_report_fallback(
            smoke_status=report_smoke_status,
            backend_id=default_backend_id,
            report_validation=report_validation,
        )
    normalized_report = report_validation.get("normalized", {})
    normalized_report = normalized_report if isinstance(normalized_report, dict) else {}
    named_filters = {
        str(name).strip(): []
        for name in smoke_contract.get("named_filters", [])
        if str(name).strip()
    }
    named_filters.setdefault(report_smoke_status, []).append(
        default_backend_id or "missing_default_backend"
    )
    for key in list(named_filters):
        named_filters[key] = sorted(set(named_filters[key]))
    artifact["generated_at"] = utc_now_iso()
    artifact["policy_reference"] = supervisor_executor_adapter_policy_reference()
    artifact["source_report_contract_artifact"] = str(
        smoke_contract.get(
            "source_report_contract_artifact",
            LOCAL_OPERATOR_EXECUTOR_REPORT_CONTRACT_RELATIVE_PATH,
        )
    ).strip()
    artifact["smoke_summary"] = {
        "status": report_smoke_status,
        "backend_id": default_backend_id,
        "source_task_smoke_status": str(task_smoke_validation.get("status", "")).strip(),
        "source_report_contract_status": str(report_contract_validation.get("status", "")).strip(),
        "report_valid": bool(response.get("valid", False)),
        "next_gap": local_operator_executor_report_smoke_next_gap(report_smoke_status),
    }
    artifact["execution"] = {
        "timeout_seconds": timeout_seconds,
        "exit_code": report_result.get("exit_code"),
        "timed_out": bool(report_result.get("timed_out", False)),
        "command": copy.deepcopy(report_result.get("command", {})),
        "command_executed": bool(report_result.get("command_executed", False)),
        "stdout_persisted": False,
        "stderr_persisted": False,
        "raw_response_persisted": False,
    }
    artifact["report_validation"] = {
        "valid": bool(report_validation.get("valid", False)),
        "finding_count": int(report_validation.get("finding_count", 0) or 0),
        "findings": copy.deepcopy(report_validation.get("findings", [])),
        "normalized": copy.deepcopy(normalized_report),
        "raw_report_persisted": bool(
            isinstance(safe_report, dict) and report_smoke_status == "passed"
        ),
    }
    artifact["source_task_smoke_validation"] = {
        "valid": bool(task_smoke_validation.get("valid", False)),
        "finding_count": len(task_smoke_validation.get("findings", [])),
        "findings": copy.deepcopy(task_smoke_validation.get("findings", [])),
        "required_check_ids": copy.deepcopy(task_smoke_validation.get("required_check_ids", [])),
    }
    artifact["source_report_contract_validation"] = {
        "valid": bool(report_contract_validation.get("valid", False)),
        "finding_count": len(report_contract_validation.get("findings", [])),
        "findings": copy.deepcopy(report_contract_validation.get("findings", [])),
        "required_check_ids": copy.deepcopy(
            report_contract_validation.get("required_check_ids", [])
        ),
    }
    artifact["checks"] = checks
    artifact["viewer_projection"] = {
        "named_filters": named_filters,
    }
    return artifact


def write_local_operator_executor_report(index: dict[str, Any]) -> Path:
    path = local_operator_executor_report_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def agent_passport_contract_stable_fields(contract_name: str) -> list[str]:
    return [
        str(field).strip()
        for field in agent_passport_adoption_policy_lookup(f"{contract_name}.stable_fields")
        if str(field).strip()
    ]


def safe_runtime_enforcement_evidence_ref(raw_ref: object) -> str:
    if raw_ref is None:
        return ""
    candidate = str(raw_ref).strip()
    if not candidate:
        return ""
    if candidate.startswith(("https://", "http://")):
        return candidate
    if candidate.lower().startswith("file:") or "://" in candidate:
        return ""
    if "\\" in candidate:
        return ""
    if re.match(r"^[A-Za-z]:[\\/]", candidate):
        return ""
    if candidate == "~" or candidate.startswith(("~/", "~\\")):
        return ""
    return safe_repo_relative_path(candidate)


def safe_agent_runtime_enforcement_evidence_artifact_path(raw_ref: object) -> str:
    if raw_ref is None:
        return ""
    candidate = str(raw_ref).strip()
    if not candidate:
        return ""
    if candidate.lower().startswith("file:") or "://" in candidate:
        return ""
    if "\\" in candidate:
        return ""
    if re.match(r"^[A-Za-z]:[\\/]", candidate):
        return ""
    if candidate == "~" or candidate.startswith(("~/", "~\\")):
        return ""
    evidence_ref = safe_repo_relative_path(candidate)
    if not evidence_ref:
        return ""
    evidence_dir = AGENT_RUNTIME_ENFORCEMENT_EVIDENCE_DIR.as_posix().rstrip("/")
    if evidence_ref == evidence_dir or not evidence_ref.startswith(f"{evidence_dir}/"):
        return ""
    return evidence_ref


def agent_passport_surface_from_policy(raw_surface: dict[str, Any]) -> dict[str, Any]:
    passport_ref = str(raw_surface.get("passport_ref", "")).strip()
    verification_state = str(raw_surface.get("verification_state", "")).strip()
    if not verification_state:
        verification_state = "V2_passport_referenced" if passport_ref else "V1_known_surface"
    raw_runtime_enforcement_state = raw_surface.get("runtime_enforcement_state")
    runtime_enforcement_state = (
        str(raw_runtime_enforcement_state).strip() if raw_runtime_enforcement_state else "unknown"
    )
    runtime_enforcement_evidence_ref = safe_runtime_enforcement_evidence_ref(
        raw_surface.get("runtime_enforcement_evidence_ref")
    )
    return {
        "surface_id": str(raw_surface.get("surface_id", "")).strip(),
        "title": str(raw_surface.get("title", "")).strip(),
        "surface_type": str(raw_surface.get("surface_type", "")).strip(),
        "source": str(raw_surface.get("source", "policy")).strip() or "policy",
        "source_proposal_ids": [
            str(proposal_id).strip()
            for proposal_id in raw_surface.get("source_proposal_ids", [])
            if str(proposal_id).strip()
        ],
        "requires_passport": bool(raw_surface.get("requires_passport", False)),
        "launches_agents": bool(raw_surface.get("launches_agents", False)),
        "prepares_handoffs": bool(raw_surface.get("prepares_handoffs", False)),
        "passport_ref": passport_ref or None,
        "verification_state": verification_state,
        "runtime_enforcement_state": runtime_enforcement_state,
        "runtime_enforcement_evidence_ref": runtime_enforcement_evidence_ref,
        "consumer_id": str(raw_surface.get("consumer_id", "")).strip(),
        "future_surface": bool(raw_surface.get("future_surface", False)),
        "notes": str(raw_surface.get("notes", "")).strip(),
    }


def agent_passport_surface_from_executor_entry(entry: dict[str, Any]) -> dict[str, Any]:
    binding = agent_passport_adoption_policy_lookup("executor_adapter_binding")
    backend_id = str(entry.get("backend_id", "")).strip()
    surface_id_prefix = str(binding.get("surface_id_prefix", "specgraph.executor")).strip()
    passport_ref = str(entry.get("passport_ref", "")).strip()
    passport_validation = entry.get("passport_validation", {})
    passport_validation = passport_validation if isinstance(passport_validation, dict) else {}
    verification_state = "V2_passport_referenced" if passport_ref else "V1_known_surface"
    return {
        "surface_id": f"{surface_id_prefix}.{backend_id}",
        "title": str(entry.get("display_name", backend_id)).strip() or backend_id,
        "surface_type": str(binding.get("surface_type", "executor_backend")).strip(),
        "source": "supervisor_executor_adapter_index",
        "source_proposal_ids": [
            str(proposal_id).strip()
            for proposal_id in binding.get("source_proposal_ids", [])
            if str(proposal_id).strip()
        ],
        "requires_passport": True,
        "launches_agents": True,
        "prepares_handoffs": False,
        "passport_ref": passport_ref or None,
        "verification_state": verification_state,
        "runtime_enforcement_state": "policy_only",
        "runtime_enforcement_evidence_ref": "",
        "executor_backend_id": backend_id,
        "backend_status": str(entry.get("backend_status", "")).strip(),
        "runtime_environment": copy.deepcopy(entry.get("runtime_environment", {})),
        "passport_validation": {
            "required": bool(passport_validation.get("required", False)),
            "validation_state": str(
                passport_validation.get("validation_state", "not_attempted")
            ).strip()
            or "not_attempted",
            "tool_status": str(passport_validation.get("tool_status", "")).strip(),
            "diagnostic_kind": str(passport_validation.get("diagnostic_kind", "")).strip(),
        },
        "notes": "Derived from the 0056 supervisor executor adapter index.",
    }


def build_agent_surface_index(
    supervisor_executor_adapter_index: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if supervisor_executor_adapter_index is None:
        supervisor_executor_adapter_index = build_supervisor_executor_adapter_index()
    surfaces_by_id: dict[str, dict[str, Any]] = {}

    for raw_surface in agent_passport_adoption_policy_lookup("agent_surfaces"):
        if not isinstance(raw_surface, dict):
            continue
        surface = agent_passport_surface_from_policy(raw_surface)
        if surface["surface_id"]:
            surfaces_by_id[surface["surface_id"]] = surface

    binding = agent_passport_adoption_policy_lookup("executor_adapter_binding")
    if bool(binding.get("enabled", False)):
        for entry in supervisor_executor_adapter_index.get("entries", []):
            if not isinstance(entry, dict):
                continue
            backend_id = str(entry.get("backend_id", "")).strip()
            if not backend_id:
                continue
            surface = agent_passport_surface_from_executor_entry(entry)
            surfaces_by_id[surface["surface_id"]] = surface

    surfaces = [copy.deepcopy(surfaces_by_id[key]) for key in sorted(surfaces_by_id)]
    by_surface_type: dict[str, list[str]] = {}
    by_verification_state: dict[str, list[str]] = {}
    named_filters = {name: [] for name in AGENT_SURFACE_NAMED_FILTERS}
    for surface in surfaces:
        surface_id = str(surface.get("surface_id", "")).strip()
        surface_type = str(surface.get("surface_type", "")).strip()
        verification_state = str(surface.get("verification_state", "")).strip()
        by_surface_type.setdefault(surface_type, []).append(surface_id)
        by_verification_state.setdefault(verification_state, []).append(surface_id)
        if surface.get("requires_passport"):
            named_filters["requires_passport"].append(surface_id)
        if surface.get("passport_ref"):
            named_filters["passport_referenced"].append(surface_id)
        if surface.get("requires_passport") and not surface.get("passport_ref"):
            named_filters["missing_passport"].append(surface_id)
        if surface_type == "executor_backend":
            named_filters["executor_backend"].append(surface_id)
        if str(surface.get("consumer_id", "")).strip() == "specspace":
            named_filters["specspace_consumer"].append(surface_id)
        runtime_enforcement_state = str(surface.get("runtime_enforcement_state", "")).strip()
        if runtime_enforcement_state == "observed":
            named_filters["runtime_enforcement_observed"].append(surface_id)
        elif runtime_enforcement_state == "policy_only":
            named_filters["runtime_enforcement_policy_only"].append(surface_id)
        elif runtime_enforcement_state == "boundary_only":
            named_filters["runtime_enforcement_boundary_only"].append(surface_id)
        elif runtime_enforcement_state == "deferred":
            named_filters["runtime_enforcement_deferred"].append(surface_id)
        else:
            named_filters["runtime_enforcement_unknown"].append(surface_id)

    for bucket in (by_surface_type, by_verification_state, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    passport_referenced_count = sum(1 for surface in surfaces if surface.get("passport_ref"))
    requires_passport_count = sum(1 for surface in surfaces if surface.get("requires_passport"))
    required_passport_referenced_count = sum(
        1
        for surface in surfaces
        if surface.get("requires_passport") and surface.get("passport_ref")
    )
    missing_passport_count = sum(
        1
        for surface in surfaces
        if surface.get("requires_passport") and not surface.get("passport_ref")
    )
    return {
        "artifact_kind": AGENT_SURFACE_INDEX_ARTIFACT_KIND,
        "schema_version": AGENT_SURFACE_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "stable_fields": agent_passport_contract_stable_fields("surface_index_contract"),
        "source_artifacts": {
            "policy": AGENT_PASSPORT_ADOPTION_POLICY_RELATIVE_PATH,
            "supervisor_executor_adapter_index": (SUPERVISOR_EXECUTOR_ADAPTER_INDEX_RELATIVE_PATH),
        },
        "summary": {
            "surface_count": len(surfaces),
            "requires_passport_count": requires_passport_count,
            "passport_referenced_count": passport_referenced_count,
            "required_passport_referenced_count": required_passport_referenced_count,
            "missing_passport_count": missing_passport_count,
            "executor_backend_surface_count": len(by_surface_type.get("executor_backend", [])),
            "agent_passport_cli_status": str(
                supervisor_executor_adapter_index.get("summary", {}).get(
                    "agent_passport_cli_status", ""
                )
            ).strip(),
            "next_gap": (
                "close_agent_verification_gaps"
                if missing_passport_count
                else "run_report_only_passport_verification"
            ),
        },
        "surfaces": surfaces,
        "viewer_projection": {
            "surface_type": by_surface_type,
            "verification_state": by_verification_state,
            "named_filters": named_filters,
        },
    }


def agent_passport_verification_gap_next_gap(gap_kind: dict[str, list[str]]) -> str:
    if gap_kind.get("missing_passport"):
        return "declare_missing_agent_passports"
    if gap_kind.get("verification_tool_unavailable") or gap_kind.get("verification_not_attempted"):
        return "run_report_only_passport_verification"
    if any(gap_kind.get(key) for key in gap_kind):
        return "close_agent_verification_gaps"
    return "none"


def align_agent_surface_index_next_gap(
    agent_surface_index: dict[str, Any],
    known_agent_passport_index: dict[str, Any],
    agent_verification_gap_index: dict[str, Any],
) -> dict[str, Any]:
    aligned = copy.deepcopy(agent_surface_index)
    summary = aligned.setdefault("summary", {})
    known_next_gap = str(known_agent_passport_index.get("summary", {}).get("next_gap", "")).strip()
    gap_next_gap = str(agent_verification_gap_index.get("summary", {}).get("next_gap", "")).strip()
    summary["next_gap"] = (
        gap_next_gap or known_next_gap or str(summary.get("next_gap", "")).strip() or "none"
    )
    source_artifacts = aligned.setdefault("source_artifacts", {})
    source_artifacts["known_agent_passport_index"] = KNOWN_AGENT_PASSPORT_INDEX_RELATIVE_PATH
    source_artifacts["agent_verification_gap_index"] = AGENT_VERIFICATION_GAP_INDEX_RELATIVE_PATH
    return aligned


def agent_passport_ref_registry() -> dict[str, dict[str, Any]]:
    registry: dict[str, dict[str, Any]] = {}
    for entry in agent_passport_adoption_policy_lookup("passport_ref_registry"):
        if not isinstance(entry, dict):
            continue
        passport_ref = str(entry.get("passport_ref", "")).strip()
        if passport_ref:
            registry[passport_ref] = copy.deepcopy(entry)
    return registry


def agent_passport_cli_availability() -> dict[str, Any]:
    policy = supervisor_executor_adapter_policy_lookup("agent_passport_cli")
    executable_names = [
        str(name).strip() for name in policy.get("executable_names", []) if str(name).strip()
    ]
    return command_availability_from_policy(
        executable_names=executable_names,
        sibling_release_binary=str(policy.get("sibling_release_binary", "")).strip(),
    )


def agent_passport_cli_command() -> str:
    policy = supervisor_executor_adapter_policy_lookup("agent_passport_cli")
    for name in policy.get("executable_names", []):
        candidate = shutil.which(str(name).strip())
        if candidate:
            return candidate
    sibling_release_binary = str(policy.get("sibling_release_binary", "")).strip()
    if sibling_release_binary:
        candidate = (ROOT / sibling_release_binary).resolve()
        if is_executable_file(candidate):
            return candidate.as_posix()
    return ""


def safe_repo_relative_path(raw_path: str) -> str:
    candidate = str(raw_path).strip()
    if not candidate:
        return ""
    path = Path(candidate)
    if path.is_absolute():
        return ""
    if any(part == ".." for part in path.parts):
        return ""
    return path.as_posix()


def repo_relative_path_for_artifact(path: Path) -> str:
    try:
        return path.resolve().relative_to(ROOT.resolve()).as_posix()
    except (OSError, ValueError):
        return safe_repo_relative_path(path.as_posix())


def sanitized_cli_report_path(raw_path: str) -> str:
    candidate = str(raw_path).strip()
    if not candidate:
        return ""
    path = Path(candidate)
    if path.is_absolute():
        try:
            return path.resolve().relative_to(ROOT.resolve()).as_posix()
        except (OSError, ValueError):
            return ""
    return safe_repo_relative_path(candidate)


def run_agent_passport_validate(command: str, document_path: Path) -> dict[str, Any]:
    cli_document_path = repo_relative_path_for_artifact(document_path)
    if not cli_document_path:
        return {
            "verification_status": "invalid",
            "verification_state": "V2_passport_referenced",
            "valid": False,
            "exit_code": None,
            "checks": [],
            "diagnostics": [
                {
                    "severity": "error",
                    "code": "agent_passport_document_path_unsafe",
                    "message": (
                        "Agent Passport document path is not safe for report-only validation."
                    ),
                }
            ],
        }
    try:
        result = subprocess.run(
            [command, "validate", "--json", cli_document_path],
            cwd=ROOT,
            capture_output=True,
            text=True,
            check=False,
            timeout=30,
        )
    except subprocess.TimeoutExpired:
        return {
            "verification_status": "invalid",
            "verification_state": "V2_passport_referenced",
            "valid": False,
            "exit_code": None,
            "checks": [],
            "diagnostics": [
                {
                    "severity": "error",
                    "code": "agent_passport_cli_timeout",
                    "message": "Agent Passport CLI validation timed out.",
                }
            ],
        }
    except OSError:
        return {
            "verification_status": "tool_unavailable",
            "verification_state": "V2_passport_referenced",
            "valid": False,
            "exit_code": None,
            "checks": [],
            "diagnostics": [
                {
                    "severity": "warning",
                    "code": "agent_passport_cli_unavailable",
                    "message": "Agent Passport CLI could not be executed.",
                }
            ],
        }
    diagnostics: list[dict[str, Any]] = []
    try:
        payload = json.loads(result.stdout)
    except json.JSONDecodeError:
        payload = None
        diagnostics.append(
            {
                "severity": "error",
                "code": "agent_passport_cli_json_unparseable",
                "message": "Agent Passport CLI did not emit parseable JSON.",
            }
        )
    if isinstance(payload, list):
        report = payload[0] if payload and isinstance(payload[0], dict) else {}
    elif isinstance(payload, dict):
        report = payload
    else:
        report = {}
    if payload is not None and not report:
        diagnostics.append(
            {
                "severity": "error",
                "code": "agent_passport_cli_json_unexpected_shape",
                "message": "Agent Passport CLI JSON did not contain a validation report object.",
            }
        )
    checks = []
    for check in report.get("checks", []):
        if not isinstance(check, dict):
            continue
        checks.append(
            {
                "severity": str(check.get("severity", "")).strip(),
                "path": sanitized_cli_report_path(str(check.get("path", ""))),
                "message": str(check.get("message", "")).strip(),
            }
        )
    valid = bool(report.get("valid", False)) and result.returncode == 0
    return {
        "verification_status": "valid" if valid else "invalid",
        "verification_state": "V3_schema_valid" if valid else "V2_passport_referenced",
        "valid": valid,
        "exit_code": result.returncode,
        "checks": checks,
        "diagnostics": diagnostics,
    }


def build_agent_passport_verification_report(
    known_agent_passport_index: dict[str, Any],
) -> dict[str, Any]:
    cli_availability = agent_passport_cli_availability()
    cli_status = "available" if cli_availability.get("status") == "available" else "missing"
    cli_command = agent_passport_cli_command() if cli_status == "available" else ""
    registry = agent_passport_ref_registry()
    entries: list[dict[str, Any]] = []
    by_status: dict[str, list[str]] = {}
    named_filters = {name: [] for name in AGENT_PASSPORT_VERIFICATION_NAMED_FILTERS}

    for known in known_agent_passport_index.get("entries", []):
        if not isinstance(known, dict):
            continue
        passport_ref = str(known.get("passport_ref") or "").strip()
        agent_surface = str(known.get("agent_surface", "")).strip()
        if not passport_ref or not agent_surface:
            continue
        registry_entry = registry.get(passport_ref, {})
        document_path = safe_repo_relative_path(str(registry_entry.get("document_path", "")))
        status = "tool_unavailable" if cli_status != "available" else "unavailable"
        verification_state = "V2_passport_referenced"
        valid = False
        checks: list[dict[str, Any]] = []
        diagnostics: list[dict[str, Any]] = []

        if cli_status != "available":
            diagnostics.append(
                {
                    "severity": "warning",
                    "code": "agent_passport_cli_missing",
                    "message": "Agent Passport CLI is not available for report-only verification.",
                }
            )
        elif not document_path:
            diagnostics.append(
                {
                    "severity": "error",
                    "code": "agent_passport_ref_unmapped",
                    "message": "Passport ref has no safe repository-relative document path.",
                }
            )
        else:
            absolute_document_path = ROOT / document_path
            if not absolute_document_path.exists():
                diagnostics.append(
                    {
                        "severity": "error",
                        "code": "agent_passport_document_missing",
                        "message": (
                            "Passport document is not present at the declared repository path."
                        ),
                    }
                )
            else:
                validation = run_agent_passport_validate(cli_command, absolute_document_path)
                status = str(validation.get("verification_status", "invalid")).strip()
                verification_state = str(
                    validation.get("verification_state", "V2_passport_referenced")
                ).strip()
                valid = bool(validation.get("valid", False))
                checks = copy.deepcopy(validation.get("checks", []))
                diagnostics = copy.deepcopy(validation.get("diagnostics", []))

        entry = {
            "agent_surface": agent_surface,
            "surface_type": str(known.get("surface_type", "")).strip(),
            "passport_ref": passport_ref,
            "document_path": document_path,
            "verification_status": status,
            "verification_state": verification_state,
            "valid": valid,
            "tool_status": cli_status,
            "checks": checks,
            "diagnostics": diagnostics,
            "source_proposal_ids": [
                str(proposal_id).strip()
                for proposal_id in known.get("source_proposal_ids", [])
                if str(proposal_id).strip()
            ],
        }
        if str(known.get("consumer_id", "")).strip():
            entry["consumer_id"] = str(known.get("consumer_id", "")).strip()
        if str(known.get("executor_backend_id", "")).strip():
            entry["executor_backend_id"] = str(known.get("executor_backend_id", "")).strip()
        entries.append(entry)
        by_status.setdefault(status, []).append(agent_surface)
        if status in named_filters:
            named_filters[status].append(agent_surface)
        if entry["surface_type"] == "executor_backend":
            named_filters["executor_backend"].append(agent_surface)
        if entry.get("consumer_id") == "specspace":
            named_filters["specspace_consumer"].append(agent_surface)

    for bucket in (by_status, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    entries = sorted(entries, key=lambda item: item["agent_surface"])
    return {
        "artifact_kind": AGENT_PASSPORT_VERIFICATION_REPORT_ARTIFACT_KIND,
        "schema_version": AGENT_PASSPORT_VERIFICATION_REPORT_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "stable_fields": agent_passport_contract_stable_fields("verification_report_contract"),
        "source_artifacts": {
            "known_agent_passport_index": KNOWN_AGENT_PASSPORT_INDEX_RELATIVE_PATH,
            "policy": AGENT_PASSPORT_ADOPTION_POLICY_RELATIVE_PATH,
        },
        "summary": {
            "entry_count": len(entries),
            "valid_count": len(by_status.get("valid", [])),
            "invalid_count": len(by_status.get("invalid", [])),
            "unavailable_count": len(by_status.get("unavailable", [])),
            "tool_unavailable_count": len(by_status.get("tool_unavailable", [])),
            "agent_passport_cli_status": cli_status,
            "next_gap": (
                "none"
                if entries and len(by_status.get("valid", [])) == len(entries)
                else "repair_or_provide_agent_passport_documents"
            ),
        },
        "entries": entries,
        "viewer_projection": {
            "verification_status": by_status,
            "named_filters": named_filters,
        },
    }


def build_known_agent_passport_index(
    agent_surface_index: dict[str, Any],
    agent_passport_verification_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    verification_by_surface = {
        str(entry.get("agent_surface", "")).strip(): entry
        for entry in (agent_passport_verification_report or {}).get("entries", [])
        if isinstance(entry, dict) and str(entry.get("agent_surface", "")).strip()
    }
    entries: list[dict[str, Any]] = []
    verification_state: dict[str, list[str]] = {}
    named_filters = {
        "passport_referenced": [],
        "missing_passport": [],
        "executor_backend": [],
        "specspace_consumer": [],
    }
    for surface in agent_surface_index.get("surfaces", []):
        if not isinstance(surface, dict):
            continue
        surface_id = str(surface.get("surface_id", "")).strip()
        if not surface_id:
            continue
        passport_ref = surface.get("passport_ref")
        passport_ref = str(passport_ref).strip() if passport_ref else None
        verification_result = copy.deepcopy(verification_by_surface.get(surface_id, {}))
        state = (
            str(verification_result.get("verification_state", "")).strip()
            or str(surface.get("verification_state", "")).strip()
            or "V1_known_surface"
        )
        entry = {
            "agent_surface": surface_id,
            "surface_type": str(surface.get("surface_type", "")).strip(),
            "passport_ref": passport_ref,
            "verification_state": state,
            "verification_source": (
                "declared_reference" if passport_ref else "known_surface_without_reference"
            ),
            "last_checked_at": None,
            "requires_passport": bool(surface.get("requires_passport", False)),
            "runtime_enforcement_state": str(surface.get("runtime_enforcement_state", "")).strip(),
            "source_proposal_ids": [
                str(proposal_id).strip()
                for proposal_id in surface.get("source_proposal_ids", [])
                if str(proposal_id).strip()
            ],
            "source": str(surface.get("source", "")).strip(),
        }
        if verification_result:
            entry["verification_result"] = {
                "verification_status": str(
                    verification_result.get("verification_status", "")
                ).strip(),
                "document_path": str(verification_result.get("document_path", "")).strip(),
                "valid": bool(verification_result.get("valid", False)),
                "tool_status": str(verification_result.get("tool_status", "")).strip(),
                "check_count": len(verification_result.get("checks", [])),
                "diagnostic_count": len(verification_result.get("diagnostics", [])),
            }
        if "executor_backend_id" in surface:
            entry["executor_backend_id"] = str(surface.get("executor_backend_id", "")).strip()
        if str(surface.get("consumer_id", "")).strip():
            entry["consumer_id"] = str(surface.get("consumer_id", "")).strip()
        entries.append(entry)
        verification_state.setdefault(state, []).append(surface_id)
        if passport_ref:
            named_filters["passport_referenced"].append(surface_id)
        if entry["requires_passport"] and not passport_ref:
            named_filters["missing_passport"].append(surface_id)
        if entry["surface_type"] == "executor_backend":
            named_filters["executor_backend"].append(surface_id)
        if entry.get("consumer_id") == "specspace":
            named_filters["specspace_consumer"].append(surface_id)

    for bucket in (verification_state, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    entries = sorted(entries, key=lambda item: item["agent_surface"])
    verification_attempted_count = sum(
        1
        for entry in entries
        if str((entry.get("verification_result", {}) or {}).get("verification_status", "")).strip()
        in {"valid", "invalid"}
    )
    if named_filters["missing_passport"]:
        next_gap = "declare_missing_agent_passports"
    elif agent_passport_verification_report is None or verification_attempted_count == 0:
        next_gap = "run_report_only_passport_verification"
    else:
        next_gap = "close_agent_verification_gaps"
    return {
        "artifact_kind": KNOWN_AGENT_PASSPORT_INDEX_ARTIFACT_KIND,
        "schema_version": KNOWN_AGENT_PASSPORT_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "stable_fields": agent_passport_contract_stable_fields("known_passport_index_contract"),
        "source_artifacts": {
            "agent_surface_index": AGENT_SURFACE_INDEX_RELATIVE_PATH,
            **(
                {
                    "agent_passport_verification_report": (
                        AGENT_PASSPORT_VERIFICATION_REPORT_RELATIVE_PATH
                    )
                }
                if agent_passport_verification_report is not None
                else {}
            ),
        },
        "summary": {
            "agent_count": len(entries),
            "passport_referenced_count": len(named_filters["passport_referenced"]),
            "missing_passport_count": len(named_filters["missing_passport"]),
            "verified_count": len(verification_state.get("V4_signature_verified", [])),
            "schema_valid_count": len(verification_state.get("V3_schema_valid", [])),
            "verification_attempted_count": verification_attempted_count,
            "next_gap": next_gap,
        },
        "entries": entries,
        "agents": copy.deepcopy(entries),
        "viewer_projection": {
            "verification_state": verification_state,
            "named_filters": named_filters,
        },
    }


def agent_passport_gap_default(gap_kind: str, field: str) -> str:
    return str(agent_passport_adoption_policy_lookup(f"gap_defaults.{gap_kind}.{field}")).strip()


def runtime_enforcement_evidence_plan_for_gap(gap_kind: str) -> dict[str, Any]:
    contract = agent_passport_adoption_policy_lookup("runtime_enforcement_evidence_contract")
    if not isinstance(contract, dict):
        return {}
    requirements = contract.get("posture_requirements", {})
    requirements = requirements if isinstance(requirements, dict) else {}
    posture_requirement = requirements.get(gap_kind, {})
    if not isinstance(posture_requirement, dict):
        return {}
    return {
        "contract_artifact_kind": str(contract.get("artifact_kind", "")).strip(),
        "contract_schema_version": contract.get("schema_version"),
        "contract_status": str(contract.get("status", "")).strip(),
        "eligible_for_observed": bool(posture_requirement.get("eligible_for_observed", False)),
        "required_evidence_kinds": [
            str(kind).strip()
            for kind in posture_requirement.get("required_evidence_kinds", [])
            if str(kind).strip()
        ],
        "next_action": str(posture_requirement.get("next_action", "")).strip(),
        "privacy_boundary": copy.deepcopy(contract.get("privacy_boundary", {})),
    }


def agent_verification_gap_record(
    *,
    surface: dict[str, Any],
    gap_kind: str,
    reason: str,
    source_artifacts: list[str],
) -> dict[str, Any]:
    surface_id = str(surface.get("surface_id") or surface.get("agent_surface", "")).strip()
    record = {
        "gap_id": f"agent_verification_gap::{surface_id}::{gap_kind}",
        "agent_surface": surface_id,
        "surface_type": str(surface.get("surface_type", "")).strip(),
        "gap": gap_kind,
        "severity": agent_passport_gap_default(gap_kind, "severity"),
        "reason": reason,
        "next_action": agent_passport_gap_default(gap_kind, "next_action"),
        "source_artifacts": source_artifacts,
        "source_proposal_ids": [
            str(proposal_id).strip()
            for proposal_id in surface.get("source_proposal_ids", [])
            if str(proposal_id).strip()
        ],
    }
    evidence_plan = runtime_enforcement_evidence_plan_for_gap(gap_kind)
    if evidence_plan:
        record["runtime_enforcement_evidence_plan"] = evidence_plan
    return record


def build_agent_verification_gap_index(
    agent_surface_index: dict[str, Any],
    known_agent_passport_index: dict[str, Any],
    supervisor_executor_adapter_index: dict[str, Any],
) -> dict[str, Any]:
    executor_cli_status = str(
        supervisor_executor_adapter_index.get("summary", {}).get("agent_passport_cli_status", "")
    ).strip()
    source_artifacts = [
        AGENT_SURFACE_INDEX_RELATIVE_PATH,
        KNOWN_AGENT_PASSPORT_INDEX_RELATIVE_PATH,
        AGENT_PASSPORT_VERIFICATION_REPORT_RELATIVE_PATH,
        SUPERVISOR_EXECUTOR_ADAPTER_INDEX_RELATIVE_PATH,
    ]
    surfaces_by_id = {
        str(surface.get("surface_id", "")).strip(): surface
        for surface in agent_surface_index.get("surfaces", [])
        if isinstance(surface, dict) and str(surface.get("surface_id", "")).strip()
    }
    gaps: list[dict[str, Any]] = []
    for known in known_agent_passport_index.get("entries", []):
        if not isinstance(known, dict):
            continue
        surface_id = str(known.get("agent_surface", "")).strip()
        surface = surfaces_by_id.get(surface_id, {})
        if not surface:
            continue
        passport_ref = known.get("passport_ref")
        if known.get("requires_passport") and not passport_ref:
            gaps.append(
                agent_verification_gap_record(
                    surface=surface,
                    gap_kind="missing_passport",
                    reason=(
                        "Agent surface requires an Agent Passport reference, but none is "
                        "declared in the adoption policy or executor adapter index."
                    ),
                    source_artifacts=source_artifacts,
                )
            )
        if passport_ref:
            verification_result = known.get("verification_result", {})
            verification_result = (
                verification_result if isinstance(verification_result, dict) else {}
            )
            verification_status = str(verification_result.get("verification_status", "")).strip()
            if verification_status == "valid":
                pass
            elif verification_status == "tool_unavailable" or (
                not verification_status and executor_cli_status != "available"
            ):
                gaps.append(
                    agent_verification_gap_record(
                        surface=surface,
                        gap_kind="verification_tool_unavailable",
                        reason=(
                            "The 0056 executor adapter index reports Agent Passport CLI "
                            "diagnostics as unavailable, so report-only verification cannot run."
                        ),
                        source_artifacts=source_artifacts,
                    )
                )
            elif verification_status == "invalid":
                gaps.append(
                    agent_verification_gap_record(
                        surface=surface,
                        gap_kind="verification_failed",
                        reason=(
                            "Agent Passport CLI report-only verification found an invalid "
                            "passport document for the declared reference."
                        ),
                        source_artifacts=source_artifacts,
                    )
                )
            elif verification_status == "unavailable":
                gaps.append(
                    agent_verification_gap_record(
                        surface=surface,
                        gap_kind="verification_unavailable",
                        reason=(
                            "Agent Passport reference is declared, but no safe repository "
                            "passport document was available for report-only verification."
                        ),
                        source_artifacts=source_artifacts,
                    )
                )
            else:
                gaps.append(
                    agent_verification_gap_record(
                        surface=surface,
                        gap_kind="verification_not_attempted",
                        reason=(
                            "A passport reference is declared, but this slice does not perform "
                            "schema, signature, lifecycle, or revocation verification."
                        ),
                        source_artifacts=source_artifacts,
                    )
                )
        if known.get("requires_passport"):
            runtime_enforcement_state = str(surface.get("runtime_enforcement_state", "")).strip()
            runtime_gap_kind = ""
            runtime_gap_reason = ""
            if runtime_enforcement_state == "observed":
                if not str(surface.get("runtime_enforcement_evidence_ref", "")).strip():
                    runtime_gap_kind = "runtime_enforcement_evidence_missing"
                    runtime_gap_reason = (
                        "Agent Passport runtime enforcement is marked observed, but no safe "
                        "runtime enforcement evidence reference is attached to the surface."
                    )
            elif runtime_enforcement_state == "policy_only":
                runtime_gap_kind = "runtime_enforcement_policy_only"
                runtime_gap_reason = (
                    "Agent Passport runtime enforcement posture is known: policy is declared, "
                    "but no dedicated enforcement runtime is implemented for this surface yet."
                )
            elif runtime_enforcement_state == "boundary_only":
                runtime_gap_kind = "runtime_enforcement_boundary_only"
                runtime_gap_reason = (
                    "Agent Passport runtime enforcement posture is known: this surface is an "
                    "external consumer or handoff boundary, so enforcement belongs to a "
                    "consumer-boundary contract rather than SpecGraph core runtime."
                )
            elif runtime_enforcement_state == "deferred":
                runtime_gap_kind = "runtime_enforcement_deferred"
                runtime_gap_reason = (
                    "Agent Passport runtime enforcement posture is known: this future surface "
                    "is declared before the runtime exists, so enforcement is deferred."
                )
            else:
                runtime_gap_kind = "runtime_enforcement_unknown"
                runtime_gap_reason = (
                    "Agent Passport runtime enforcement posture has not been classified for "
                    "this surface."
                )
            if runtime_gap_kind:
                gaps.append(
                    agent_verification_gap_record(
                        surface=surface,
                        gap_kind=runtime_gap_kind,
                        reason=runtime_gap_reason,
                        source_artifacts=source_artifacts,
                    )
                )

    gap_kind: dict[str, list[str]] = {}
    severity: dict[str, list[str]] = {}
    named_filters = {name: [] for name in AGENT_VERIFICATION_GAP_NAMED_FILTERS}
    for gap in gaps:
        surface_id = str(gap.get("agent_surface", "")).strip()
        kind = str(gap.get("gap", "")).strip()
        gap_kind.setdefault(kind, []).append(surface_id)
        severity.setdefault(str(gap.get("severity", "")).strip(), []).append(gap["gap_id"])
        if kind in named_filters:
            named_filters[kind].append(surface_id)
        surface = surfaces_by_id.get(surface_id, {})
        if str(surface.get("surface_type", "")).strip() == "executor_backend":
            named_filters["executor_backend"].append(surface_id)
        if str(surface.get("consumer_id", "")).strip() == "specspace":
            named_filters["specspace_consumer"].append(surface_id)

    for bucket in (gap_kind, severity, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    gaps = sorted(gaps, key=lambda item: item["gap_id"])
    return {
        "artifact_kind": AGENT_VERIFICATION_GAP_INDEX_ARTIFACT_KIND,
        "schema_version": AGENT_VERIFICATION_GAP_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "stable_fields": agent_passport_contract_stable_fields("verification_gap_index_contract"),
        "source_artifacts": {
            "agent_surface_index": AGENT_SURFACE_INDEX_RELATIVE_PATH,
            "known_agent_passport_index": KNOWN_AGENT_PASSPORT_INDEX_RELATIVE_PATH,
            "agent_passport_verification_report": (
                AGENT_PASSPORT_VERIFICATION_REPORT_RELATIVE_PATH
            ),
            "supervisor_executor_adapter_index": SUPERVISOR_EXECUTOR_ADAPTER_INDEX_RELATIVE_PATH,
        },
        "summary": {
            "gap_count": len(gaps),
            "missing_passport_count": len(gap_kind.get("missing_passport", [])),
            "verification_tool_unavailable_count": len(
                gap_kind.get("verification_tool_unavailable", [])
            ),
            "verification_failed_count": len(gap_kind.get("verification_failed", [])),
            "verification_unavailable_count": len(gap_kind.get("verification_unavailable", [])),
            "verification_not_attempted_count": len(gap_kind.get("verification_not_attempted", [])),
            "runtime_enforcement_policy_only_count": len(
                gap_kind.get("runtime_enforcement_policy_only", [])
            ),
            "runtime_enforcement_boundary_only_count": len(
                gap_kind.get("runtime_enforcement_boundary_only", [])
            ),
            "runtime_enforcement_deferred_count": len(
                gap_kind.get("runtime_enforcement_deferred", [])
            ),
            "runtime_enforcement_evidence_missing_count": len(
                gap_kind.get("runtime_enforcement_evidence_missing", [])
            ),
            "runtime_enforcement_unknown_count": len(
                gap_kind.get("runtime_enforcement_unknown", [])
            ),
            "agent_passport_cli_status": executor_cli_status,
            "next_gap": agent_passport_verification_gap_next_gap(gap_kind),
        },
        "gaps": gaps,
        "viewer_projection": {
            "gap": gap_kind,
            "severity": severity,
            "named_filters": named_filters,
        },
    }


def build_agent_passport_derived_surfaces() -> dict[str, Any]:
    supervisor_executor_adapter_index = build_supervisor_executor_adapter_index()
    agent_surface_index = build_agent_surface_index(supervisor_executor_adapter_index)
    known_agent_passport_index = build_known_agent_passport_index(agent_surface_index)
    agent_passport_verification_report = build_agent_passport_verification_report(
        known_agent_passport_index
    )
    known_agent_passport_index = build_known_agent_passport_index(
        agent_surface_index,
        agent_passport_verification_report,
    )
    agent_verification_gap_index = build_agent_verification_gap_index(
        agent_surface_index,
        known_agent_passport_index,
        supervisor_executor_adapter_index,
    )
    agent_surface_index = align_agent_surface_index_next_gap(
        agent_surface_index,
        known_agent_passport_index,
        agent_verification_gap_index,
    )
    return {
        "artifact_kind": "agent_passport_derived_surfaces",
        "schema_version": 1,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "supervisor_executor_adapter_index": supervisor_executor_adapter_index,
        "agent_surface_index": agent_surface_index,
        "known_agent_passport_index": known_agent_passport_index,
        "agent_passport_verification_report": agent_passport_verification_report,
        "agent_verification_gap_index": agent_verification_gap_index,
    }


def write_agent_surface_index(index: dict[str, Any]) -> Path:
    path = agent_surface_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def write_known_agent_passport_index(index: dict[str, Any]) -> Path:
    path = known_agent_passport_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def write_agent_passport_verification_report(report: dict[str, Any]) -> Path:
    path = agent_passport_verification_report_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def write_agent_verification_gap_index(index: dict[str, Any]) -> Path:
    path = agent_verification_gap_index_path()
    with artifact_lock(path):
        atomic_write_json(path, index)
    return path


def write_agent_passport_derived_surfaces(surfaces: dict[str, Any]) -> dict[str, Path]:
    return {
        "supervisor_executor_adapter_index": write_supervisor_executor_adapter_index(
            surfaces["supervisor_executor_adapter_index"]
        ),
        "agent_surface_index": write_agent_surface_index(surfaces["agent_surface_index"]),
        "known_agent_passport_index": write_known_agent_passport_index(
            surfaces["known_agent_passport_index"]
        ),
        "agent_passport_verification_report": write_agent_passport_verification_report(
            surfaces["agent_passport_verification_report"]
        ),
        "agent_verification_gap_index": write_agent_verification_gap_index(
            surfaces["agent_verification_gap_index"]
        ),
    }


def agent_passport_derived_surfaces_report(surfaces: dict[str, Any]) -> dict[str, Any]:
    written_paths = write_agent_passport_derived_surfaces(surfaces)
    surface_index = surfaces["agent_surface_index"]
    known_index = surfaces["known_agent_passport_index"]
    verification_report = surfaces["agent_passport_verification_report"]
    gap_index = surfaces["agent_verification_gap_index"]
    return {
        "artifact_kind": "agent_passport_derived_surfaces_build_report",
        "schema_version": 1,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "written_artifacts": {
            key: {"artifact_path": path.relative_to(ROOT).as_posix()}
            for key, path in written_paths.items()
        },
        "summary": {
            "surface_count": surface_index.get("summary", {}).get("surface_count", 0),
            "known_agent_count": known_index.get("summary", {}).get("agent_count", 0),
            "passport_verification_valid_count": verification_report.get("summary", {}).get(
                "valid_count", 0
            ),
            "gap_count": gap_index.get("summary", {}).get("gap_count", 0),
            "agent_passport_cli_status": gap_index.get("summary", {}).get(
                "agent_passport_cli_status", ""
            ),
            "next_gap": gap_index.get("summary", {}).get("next_gap", "none"),
        },
    }


def agent_runtime_enforcement_evidence_contract() -> dict[str, Any]:
    contract = agent_passport_adoption_policy_lookup("runtime_enforcement_evidence_contract")
    return contract if isinstance(contract, dict) else {}


def agent_runtime_enforcement_evidence_smokes() -> list[dict[str, Any]]:
    smokes = agent_passport_adoption_policy_lookup("runtime_enforcement_evidence_smokes")
    return [copy.deepcopy(smoke) for smoke in smokes if isinstance(smoke, dict)]


def agent_runtime_enforcement_evidence_check(
    *,
    check_id: str,
    status: str,
    message: str,
) -> dict[str, Any]:
    return {
        "check_id": check_id,
        "status": status,
        "message": message,
    }


def agent_runtime_enforcement_evidence_status(checks: list[dict[str, Any]]) -> str:
    statuses = {str(check.get("status", "")).strip() for check in checks}
    if not statuses:
        return "missing"
    if "failed" in statuses:
        return "failed"
    if "missing" in statuses:
        return "missing"
    if statuses == {"passed"}:
        return "passed"
    return "failed"


def supervisor_executor_adapter_invocation_boundary_check(
    supervisor_executor_adapter_index: dict[str, Any],
) -> dict[str, Any]:
    def executable_names(raw_backend: dict[str, Any]) -> list[str]:
        raw_names = raw_backend.get("executable_names", [])
        if not isinstance(raw_names, list):
            return []
        return [str(name).strip() for name in raw_names if str(name).strip()]

    def path_like_value(value: object) -> bool:
        if value is None:
            return False
        candidate = str(value).strip()
        if not candidate:
            return False
        if candidate.lower().startswith("file:"):
            return True
        if candidate == "~" or candidate.startswith(("~/", "~\\")):
            return True
        if re.match(r"^[A-Za-z]:[\\/]", candidate):
            return True
        return Path(candidate).is_absolute()

    policy_backends = [
        backend
        for backend in SUPERVISOR_EXECUTOR_ADAPTER_POLICY.get("backend_registry", [])
        if isinstance(backend, dict)
    ]
    index_entries = [
        entry
        for entry in supervisor_executor_adapter_index.get("entries", [])
        if isinstance(entry, dict)
    ]
    forbidden_policy_fields = {
        "command",
        "command_line",
        "command_template",
        "shell",
        "shell_command",
    }
    policy_forbidden_hits = sorted(
        {
            field
            for backend in policy_backends
            for field in forbidden_policy_fields
            if field in backend
        }
    )
    index_forbidden_hits = sorted(
        {field for entry in index_entries for field in forbidden_policy_fields if field in entry}
    )
    cli_backends = [
        backend
        for backend in policy_backends
        if str(backend.get("command_surface", "")).strip() == "cli" and executable_names(backend)
    ]
    policy_backend_ids = {
        str(backend.get("backend_id", "")).strip()
        for backend in policy_backends
        if str(backend.get("backend_id", "")).strip()
    }
    index_backend_ids = {
        str(entry.get("backend_id", "")).strip()
        for entry in index_entries
        if str(entry.get("backend_id", "")).strip()
    }
    missing_index_backend_ids = sorted(policy_backend_ids - index_backend_ids)
    malformed_availability_entries = []
    persisted_paths = [
        str(entry.get("backend_id", "")).strip()
        for entry in index_entries
        if isinstance(entry.get("executable_availability"), dict)
        and bool(entry.get("executable_availability", {}).get("path_persisted", False))
    ]
    persisted_path_fields = []
    path_field_names = {
        "absolute_path",
        "command_path",
        "executable_path",
        "path",
        "resolved_path",
    }
    for entry in index_entries:
        backend_id = str(entry.get("backend_id", "")).strip()
        availability = entry.get("executable_availability")
        if not isinstance(availability, dict):
            malformed_availability_entries.append(backend_id or "<missing backend_id>")
            continue
        for field, value in availability.items():
            field_text = str(field)
            if (field_text in path_field_names and str(value).strip()) or path_like_value(value):
                persisted_path_fields.append(f"{backend_id or '<missing backend_id>'}.{field_text}")
    passed = (
        bool(policy_backends)
        and len(cli_backends) == len(policy_backends)
        and bool(index_entries)
        and not missing_index_backend_ids
        and not malformed_availability_entries
        and not policy_forbidden_hits
        and not index_forbidden_hits
        and not persisted_paths
        and not persisted_path_fields
    )
    if passed:
        message = (
            "Supervisor executor adapter policy uses declarative CLI executable lookup, and "
            "the generated adapter index does not persist executable paths or command lines."
        )
    else:
        details = []
        if not policy_backends:
            details.append("backend_registry is empty")
        if len(cli_backends) != len(policy_backends):
            details.append("one or more backends lack CLI executable lookup metadata")
        if not index_entries:
            details.append("executor adapter index has no entries")
        if missing_index_backend_ids:
            details.append(
                "executor adapter index is missing policy backends: "
                + ", ".join(missing_index_backend_ids)
            )
        if malformed_availability_entries:
            details.append(
                "index has malformed executable availability for: "
                + ", ".join(malformed_availability_entries)
            )
        if policy_forbidden_hits:
            details.append(
                "policy declares forbidden shell/command fields: "
                + ", ".join(policy_forbidden_hits)
            )
        if index_forbidden_hits:
            details.append(
                "index persists forbidden shell/command fields: " + ", ".join(index_forbidden_hits)
            )
        if persisted_paths:
            details.append("index persists executable paths for: " + ", ".join(persisted_paths))
        if persisted_path_fields:
            details.append(
                "index persists executable path fields: " + ", ".join(persisted_path_fields)
            )
        message = "Supervisor executor adapter invocation boundary failed: " + "; ".join(details)
    return agent_runtime_enforcement_evidence_check(
        check_id="executor_adapter_invocation_boundary",
        status="passed" if passed else "failed",
        message=message,
    )


def build_agent_runtime_enforcement_evidence_record(
    *,
    smoke: dict[str, Any],
    agent_surface_index: dict[str, Any],
    known_agent_passport_index: dict[str, Any],
    supervisor_executor_adapter_index: dict[str, Any],
) -> dict[str, Any]:
    evidence_id = str(smoke.get("evidence_id", "")).strip()
    agent_surface = str(smoke.get("agent_surface", "")).strip()
    evidence_kind = str(smoke.get("evidence_kind", "")).strip()
    evidence_ref = safe_agent_runtime_enforcement_evidence_artifact_path(smoke.get("artifact_path"))
    surfaces_by_id = {
        str(surface.get("surface_id", "")).strip(): surface
        for surface in agent_surface_index.get("surfaces", [])
        if isinstance(surface, dict) and str(surface.get("surface_id", "")).strip()
    }
    known_by_surface = {
        str(entry.get("agent_surface", "")).strip(): entry
        for entry in known_agent_passport_index.get("entries", [])
        if isinstance(entry, dict) and str(entry.get("agent_surface", "")).strip()
    }
    surface = surfaces_by_id.get(agent_surface, {})
    known = known_by_surface.get(agent_surface, {})
    runtime_enforcement_state = str(
        surface.get("runtime_enforcement_state", smoke.get("runtime_enforcement_state", ""))
    ).strip()
    posture_claim = str(smoke.get("posture_claim", "")).strip()
    passport_ref = str(surface.get("passport_ref") or known.get("passport_ref") or "").strip()
    executor_adapter_index_present = (
        str(supervisor_executor_adapter_index.get("artifact_kind", "")).strip()
        == SUPERVISOR_EXECUTOR_ADAPTER_INDEX_ARTIFACT_KIND
    )
    checks = [
        agent_runtime_enforcement_evidence_check(
            check_id="agent_surface_present",
            status="passed" if surface else "missing",
            message=(
                "Agent surface is present in runs/agent_surface_index.json."
                if surface
                else "Agent surface is missing from runs/agent_surface_index.json."
            ),
        ),
        agent_runtime_enforcement_evidence_check(
            check_id="agent_passport_ref_declared",
            status="passed" if passport_ref else "failed",
            message=(
                "Agent Passport reference is declared for the surface."
                if passport_ref
                else "Agent Passport reference is not declared for the surface."
            ),
        ),
        agent_runtime_enforcement_evidence_check(
            check_id="executor_adapter_index_present",
            status="passed" if executor_adapter_index_present else "missing",
            message=(
                "Supervisor executor adapter index is available."
                if executor_adapter_index_present
                else "Supervisor executor adapter index is unavailable."
            ),
        ),
        agent_runtime_enforcement_evidence_check(
            check_id="evidence_ref_safe",
            status="passed" if evidence_ref else "missing",
            message=(
                "Evidence artifact path is a safe repository-relative reference."
                if evidence_ref
                else "Evidence artifact path is missing or unsafe."
            ),
        ),
        agent_runtime_enforcement_evidence_check(
            check_id="no_observed_enforcement_claim",
            status="passed" if runtime_enforcement_state != "observed" else "failed",
            message=(
                "Smoke evidence does not claim observed runtime enforcement."
                if runtime_enforcement_state != "observed"
                else "Smoke evidence must not be used to claim observed runtime enforcement."
            ),
        ),
        supervisor_executor_adapter_invocation_boundary_check(supervisor_executor_adapter_index),
    ]
    required_check_ids = [
        str(check_id).strip()
        for check_id in smoke.get("required_checks", [])
        if str(check_id).strip()
    ]
    checks_by_id = {str(check.get("check_id", "")).strip(): check for check in checks}
    missing_required_checks = [
        check_id for check_id in required_check_ids if check_id not in checks_by_id
    ]
    nonpassing_required_checks = [
        check_id
        for check_id in required_check_ids
        if str(checks_by_id.get(check_id, {}).get("status", "")).strip() != "passed"
    ]
    checks.append(
        agent_runtime_enforcement_evidence_check(
            check_id="policy_required_checks_satisfied",
            status=(
                "passed"
                if not missing_required_checks and not nonpassing_required_checks
                else "failed"
            ),
            message=(
                "All policy-declared runtime evidence smoke checks are present and passing."
                if not missing_required_checks and not nonpassing_required_checks
                else (
                    "Policy-declared runtime evidence smoke checks are missing or non-passing: "
                    + ", ".join(sorted(set(missing_required_checks + nonpassing_required_checks)))
                    + "."
                )
            ),
        )
    )
    status = agent_runtime_enforcement_evidence_status(checks)
    return {
        "artifact_kind": agent_runtime_enforcement_evidence_contract().get(
            "artifact_kind", "agent_runtime_enforcement_evidence"
        ),
        "schema_version": agent_runtime_enforcement_evidence_contract().get("schema_version", 1),
        "generated_at": utc_now_iso(),
        "evidence_id": evidence_id,
        "agent_surface": agent_surface,
        "surface_id": agent_surface,
        "evidence_kind": evidence_kind,
        "runtime_enforcement_state": runtime_enforcement_state,
        "posture_claim": posture_claim,
        "status": status,
        "safe_evidence_ref": evidence_ref,
        "source_proposal_ids": [
            str(proposal_id).strip()
            for proposal_id in smoke.get("source_proposal_ids", [])
            if str(proposal_id).strip()
        ],
        "source_artifacts": {
            "agent_surface_index": AGENT_SURFACE_INDEX_RELATIVE_PATH,
            "known_agent_passport_index": KNOWN_AGENT_PASSPORT_INDEX_RELATIVE_PATH,
            "supervisor_executor_adapter_index": SUPERVISOR_EXECUTOR_ADAPTER_INDEX_RELATIVE_PATH,
            "policy": AGENT_PASSPORT_ADOPTION_POLICY_RELATIVE_PATH,
        },
        "evidence": {
            "kind": evidence_kind,
            "checks": checks,
            "privacy_boundary": copy.deepcopy(
                agent_runtime_enforcement_evidence_contract().get("privacy_boundary", {})
            ),
        },
        "result": {
            "status": status,
            "summary": (
                "Report-only runtime smoke passed; no observed enforcement is claimed."
                if status == "passed"
                else "Report-only runtime smoke is not sufficient evidence."
            ),
        },
        "limitations": [
            "Does not launch agents.",
            "Does not verify signatures, trust stores, lifecycle, revocation, or integrity.",
            "Does not prove sandbox, seccomp, or runtime policy enforcement.",
            "Does not include raw supervisor logs, raw prompts, secrets, or machine-local paths.",
        ],
        "notes": str(smoke.get("notes", "")).strip(),
    }


def build_agent_runtime_enforcement_evidence_index(
    agent_passport_surfaces: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if agent_passport_surfaces is None:
        agent_passport_surfaces = build_agent_passport_derived_surfaces()
    supervisor_executor_adapter_index = agent_passport_surfaces["supervisor_executor_adapter_index"]
    agent_surface_index = agent_passport_surfaces["agent_surface_index"]
    known_agent_passport_index = agent_passport_surfaces["known_agent_passport_index"]
    records = [
        build_agent_runtime_enforcement_evidence_record(
            smoke=smoke,
            agent_surface_index=agent_surface_index,
            known_agent_passport_index=known_agent_passport_index,
            supervisor_executor_adapter_index=supervisor_executor_adapter_index,
        )
        for smoke in agent_runtime_enforcement_evidence_smokes()
    ]
    named_filters = {name: [] for name in AGENT_RUNTIME_ENFORCEMENT_EVIDENCE_NAMED_FILTERS}
    status: dict[str, list[str]] = {}
    evidence_kind: dict[str, list[str]] = {}
    entries: list[dict[str, Any]] = []
    for record in records:
        evidence_id = str(record.get("evidence_id", "")).strip()
        agent_surface = str(record.get("agent_surface", "")).strip()
        record_status = str(record.get("status", "")).strip()
        kind = str(record.get("evidence_kind", "")).strip()
        runtime_state = str(record.get("runtime_enforcement_state", "")).strip()
        status.setdefault(record_status, []).append(evidence_id)
        evidence_kind.setdefault(kind, []).append(evidence_id)
        if record_status in named_filters:
            named_filters[record_status].append(evidence_id)
        if kind == "runtime_smoke":
            named_filters["runtime_smoke"].append(evidence_id)
        if runtime_state in {"policy_only", "boundary_only", "deferred"}:
            named_filters[runtime_state].append(evidence_id)
        if agent_surface == "specgraph.supervisor.executor_adapter":
            named_filters["executor_gateway"].append(evidence_id)
        entries.append(
            {
                "evidence_id": evidence_id,
                "agent_surface": agent_surface,
                "surface_id": agent_surface,
                "evidence_kind": kind,
                "runtime_enforcement_state": runtime_state,
                "posture_claim": str(record.get("posture_claim", "")).strip(),
                "status": record_status,
                "evidence_ref": str(record.get("safe_evidence_ref", "")).strip(),
                "result_status": str(record.get("result", {}).get("status", "")).strip(),
                "source_proposal_ids": copy.deepcopy(record.get("source_proposal_ids", [])),
            }
        )
    for bucket in (status, evidence_kind, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))
    entries = sorted(entries, key=lambda item: item["evidence_id"])
    return {
        "artifact_kind": AGENT_RUNTIME_ENFORCEMENT_EVIDENCE_INDEX_ARTIFACT_KIND,
        "schema_version": AGENT_RUNTIME_ENFORCEMENT_EVIDENCE_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "stable_fields": agent_passport_contract_stable_fields(
            "runtime_enforcement_evidence_index_contract"
        ),
        "source_artifacts": {
            "agent_surface_index": AGENT_SURFACE_INDEX_RELATIVE_PATH,
            "known_agent_passport_index": KNOWN_AGENT_PASSPORT_INDEX_RELATIVE_PATH,
            "supervisor_executor_adapter_index": SUPERVISOR_EXECUTOR_ADAPTER_INDEX_RELATIVE_PATH,
            "policy": AGENT_PASSPORT_ADOPTION_POLICY_RELATIVE_PATH,
        },
        "summary": {
            "evidence_count": len(entries),
            "passed_count": len(status.get("passed", [])),
            "failed_count": len(status.get("failed", [])),
            "missing_count": len(status.get("missing", [])),
            "runtime_smoke_count": len(evidence_kind.get("runtime_smoke", [])),
            "runtime_smoke_passed_count": len(
                [
                    entry
                    for entry in entries
                    if entry["evidence_kind"] == "runtime_smoke" and entry["status"] == "passed"
                ]
            ),
            "observed_enforcement_claim_count": 0,
            "next_gap": (
                "review_runtime_enforcement_evidence"
                if entries and len(status.get("passed", [])) == len(entries)
                else "repair_runtime_enforcement_evidence"
            ),
        },
        "entries": entries,
        "viewer_projection": {
            "status": status,
            "evidence_kind": evidence_kind,
            "named_filters": named_filters,
        },
        "_records": records,
    }


def write_agent_runtime_enforcement_evidence_index(index: dict[str, Any]) -> dict[str, Path]:
    written: dict[str, Path] = {}
    for record in index.pop("_records", []):
        evidence_ref = safe_agent_runtime_enforcement_evidence_artifact_path(
            record.get("safe_evidence_ref")
        )
        if not evidence_ref:
            continue
        path = ROOT / evidence_ref
        with artifact_lock(path):
            atomic_write_json(path, record)
        written[str(record.get("evidence_id", "")).strip()] = path
    index_path = agent_runtime_enforcement_evidence_index_path()
    with artifact_lock(index_path):
        atomic_write_json(index_path, index)
    written["agent_runtime_enforcement_evidence_index"] = index_path
    return written


def agent_runtime_enforcement_evidence_report(
    agent_passport_surfaces: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if agent_passport_surfaces is None:
        agent_passport_surfaces = build_agent_passport_derived_surfaces()
    write_agent_passport_derived_surfaces(agent_passport_surfaces)
    index = build_agent_runtime_enforcement_evidence_index(agent_passport_surfaces)
    written_paths = write_agent_runtime_enforcement_evidence_index(index)
    return {
        "artifact_kind": "agent_runtime_enforcement_evidence_build_report",
        "schema_version": 1,
        "generated_at": utc_now_iso(),
        "policy_reference": agent_passport_adoption_policy_reference(),
        "written_artifacts": {
            key: {"artifact_path": path.relative_to(ROOT).as_posix()}
            for key, path in written_paths.items()
        },
        "summary": {
            "evidence_count": index.get("summary", {}).get("evidence_count", 0),
            "passed_count": index.get("summary", {}).get("passed_count", 0),
            "failed_count": index.get("summary", {}).get("failed_count", 0),
            "missing_count": index.get("summary", {}).get("missing_count", 0),
            "next_gap": index.get("summary", {}).get("next_gap", ""),
        },
    }


def load_spec_trace_registry() -> dict[str, dict[str, Any]]:
    path = spec_trace_registry_path()
    if not path.exists():
        return {}
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        raise RuntimeError(
            f"failed to read spec trace registry: {path.as_posix()} ({exc})"
        ) from exc
    except json.JSONDecodeError as exc:
        raise RuntimeError(f"malformed spec trace registry: {path.as_posix()} ({exc})") from exc
    if not isinstance(payload, list):
        raise RuntimeError(
            f"malformed spec trace registry: {path.as_posix()} must contain a JSON list"
        )

    registry: dict[str, dict[str, Any]] = {}
    for index, item in enumerate(payload, start=1):
        if not isinstance(item, dict):
            raise RuntimeError(
                "malformed spec trace registry: "
                f"entry {index} in {path.as_posix()} must be an object"
            )
        spec_id = str(item.get("spec_id", "")).strip()
        if not spec_id:
            raise RuntimeError(
                f"malformed spec trace registry: entry {index} in {path.as_posix()} missing spec_id"
            )
        registry[spec_id] = item
    return registry


