def metric_pack_entry_required_inputs(pack_entry: dict[str, Any]) -> dict[str, list[str]]:
    required_by_metric: dict[str, list[str]] = {}
    for item in pack_entry.get("inputs", []):
        input_id = str(item).strip()
        if input_id:
            required_by_metric.setdefault(input_id, []).append("__pack__")
    for metric in pack_entry.get("metrics", []):
        if not isinstance(metric, dict):
            continue
        metric_id = str(metric.get("metric_id", "")).strip() or "unknown_metric"
        for item in metric_pack_metric_requires(metric):
            input_id = str(item).strip()
            if input_id:
                required_by_metric.setdefault(input_id, []).append(metric_id)
    return {
        input_id: sorted(set(metric_ids))
        for input_id, metric_ids in sorted(required_by_metric.items())
    }


def metric_pack_adapter_input_record(input_id: str, metric_ids: list[str]) -> dict[str, Any]:
    catalog_entry = METRIC_PACK_ADAPTER_INPUT_CATALOG.get(input_id)
    if catalog_entry:
        computability = str(catalog_entry.get("computability", "")).strip() or "available"
        source_artifact = str(catalog_entry.get("source_artifact", "")).strip()
        source_field = str(catalog_entry.get("source_field", "")).strip()
        next_gap = str(catalog_entry.get("next_gap", "")).strip() or "none"
    else:
        computability = "not_computable"
        source_artifact = ""
        source_field = ""
        next_gap = METRIC_PACK_ADAPTER_INPUT_GAP_DEFAULTS.get(
            input_id,
            "define_metric_pack_input_adapter",
        )
    return {
        "input_id": input_id,
        "computability": computability,
        "source_artifact": source_artifact,
        "source_field": source_field,
        "required_by_metric_ids": [item for item in metric_ids if item != "__pack__"],
        "required_by_pack": "__pack__" in metric_ids,
        "next_gap": next_gap,
    }


def metric_pack_adapter_status(input_records: list[dict[str, Any]]) -> str:
    if not input_records:
        return "invalid_pack_contract"
    if any(
        str(item.get("computability", "")).strip() == "not_computable" for item in input_records
    ):
        return "missing_input_adapters"
    if any(str(item.get("computability", "")).strip() == "stale" for item in input_records):
        return "stale_input_adapters"
    return "ready_for_adapter_review"


def metric_pack_adapter_next_gap(adapter_status: str, input_records: list[dict[str, Any]]) -> str:
    for item in input_records:
        computability = str(item.get("computability", "")).strip()
        next_gap = str(item.get("next_gap", "")).strip()
        if computability != "available" and next_gap and next_gap != "none":
            return next_gap
    mapping = {
        "ready_for_adapter_review": "review_metric_pack_adapter_index",
        "missing_input_adapters": "define_metric_pack_input_adapter",
        "stale_input_adapters": "refresh_metric_pack_input_adapter",
        "invalid_pack_contract": "repair_metric_pack_contract",
    }
    return mapping.get(adapter_status, "review_metric_pack_adapter_index")


def metric_pack_adapter_backlog_item(
    *,
    metric_pack_id: str,
    title: str,
    input_record: dict[str, Any],
) -> dict[str, Any]:
    input_id = str(input_record.get("input_id", "")).strip()
    next_gap = str(input_record.get("next_gap", "")).strip() or "define_metric_pack_input_adapter"
    return {
        "adapter_backlog_id": f"metric_pack_adapter::{metric_pack_id}::{input_id}",
        "metric_pack_id": metric_pack_id,
        "title": title,
        "input_id": input_id,
        "computability": str(input_record.get("computability", "")).strip(),
        "source_artifact": str(input_record.get("source_artifact", "")).strip(),
        "required_by_metric_ids": copy.deepcopy(
            input_record.get("required_by_metric_ids", []),
        ),
        "review_state": "ready_for_review",
        "next_gap": next_gap,
    }


def build_metric_pack_adapter_index(metric_pack_index: dict[str, Any]) -> dict[str, Any]:
    entries: list[dict[str, Any]] = []
    backlog_items: list[dict[str, Any]] = []
    status_groups: dict[str, list[str]] = {}
    computability_groups: dict[str, list[str]] = {}
    missing_input_groups: dict[str, list[str]] = {}
    next_gap_groups: dict[str, list[str]] = {}
    named_filters: dict[str, list[str]] = {
        "ready_for_adapter_review": [],
        "missing_input_adapters": [],
        "not_computable_inputs": [],
        "execution_deferred": [],
    }

    for item in metric_pack_index.get("entries", []):
        if not isinstance(item, dict):
            continue
        metric_pack_id = str(item.get("metric_pack_id", "")).strip()
        if not metric_pack_id:
            continue
        title = str(item.get("title", "")).strip()
        required_inputs = metric_pack_entry_required_inputs(item)
        input_records = [
            metric_pack_adapter_input_record(input_id, metric_ids)
            for input_id, metric_ids in required_inputs.items()
        ]
        adapter_status = metric_pack_adapter_status(input_records)
        next_gap = metric_pack_adapter_next_gap(adapter_status, input_records)
        review_state = "ready_for_review" if input_records else "not_ready"
        missing_inputs = sorted(
            str(record.get("input_id", "")).strip()
            for record in input_records
            if str(record.get("computability", "")).strip() == "not_computable"
            and str(record.get("input_id", "")).strip()
        )
        for record in input_records:
            computability = str(record.get("computability", "")).strip() or "unknown"
            input_id = str(record.get("input_id", "")).strip()
            computability_groups.setdefault(computability, []).append(
                f"{metric_pack_id}::{input_id}",
            )
            if computability == "not_computable":
                missing_input_groups.setdefault(input_id, []).append(metric_pack_id)
                backlog_items.append(
                    metric_pack_adapter_backlog_item(
                        metric_pack_id=metric_pack_id,
                        title=title,
                        input_record=record,
                    )
                )
        status_groups.setdefault(adapter_status, []).append(metric_pack_id)
        next_gap_groups.setdefault(next_gap, []).append(metric_pack_id)
        if adapter_status in named_filters:
            named_filters[adapter_status].append(metric_pack_id)
        if missing_inputs:
            named_filters["not_computable_inputs"].append(metric_pack_id)
        if adapter_status == "ready_for_adapter_review":
            named_filters["execution_deferred"].append(metric_pack_id)
        entries.append(
            {
                "metric_pack_id": metric_pack_id,
                "title": title,
                "adapter_status": adapter_status,
                "review_state": review_state,
                "next_gap": next_gap,
                "pack_status": str(item.get("pack_status", "")).strip(),
                "pack_authority_state": str(item.get("pack_authority_state", "")).strip(),
                "reference_state": str(item.get("reference_state", "")).strip(),
                "metric_count": int(item.get("metric_count", 0) or 0),
                "input_count": len(input_records),
                "missing_input_count": len(missing_inputs),
                "missing_inputs": missing_inputs,
                "inputs": input_records,
                "adapter_execution": {
                    "status": "deferred",
                    "next_gap": "add_metric_pack_execution_runtime",
                },
            }
        )

    for bucket in (
        status_groups,
        computability_groups,
        missing_input_groups,
        next_gap_groups,
        named_filters,
    ):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))
    grouped_backlog: dict[str, list[str]] = {}
    for item in backlog_items:
        next_gap = str(item.get("next_gap", "")).strip() or "define_metric_pack_input_adapter"
        backlog_id = str(item.get("adapter_backlog_id", "")).strip()
        if backlog_id:
            grouped_backlog.setdefault(next_gap, []).append(backlog_id)
    for key in list(grouped_backlog):
        grouped_backlog[key] = sorted(set(grouped_backlog[key]))

    return {
        "artifact_kind": METRIC_PACK_ADAPTER_INDEX_ARTIFACT_KIND,
        "schema_version": METRIC_PACK_ADAPTER_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "review_state": "ready_for_review" if entries else "not_ready",
        "next_gap": "review_metric_pack_adapter_index"
        if entries
        else "declare_metric_pack_registry",
        "source_snapshot": {
            "artifact_path": METRIC_PACK_ADAPTER_INDEX_RELATIVE_PATH,
            "metric_pack_index": {
                "artifact_path": metric_pack_index_path().relative_to(ROOT).as_posix(),
                "generated_at": metric_pack_index.get("generated_at"),
                "entry_count": metric_pack_index.get("entry_count"),
            },
            "input_catalog_version": 4,
        },
        "summary": {
            "pack_count": len(entries),
            "input_binding_count": sum(int(entry.get("input_count", 0) or 0) for entry in entries),
            "status_counts": {key: len(value) for key, value in sorted(status_groups.items())},
            "computability_counts": {
                key: len(value) for key, value in sorted(computability_groups.items())
            },
            "missing_input_counts": {
                key: len(value) for key, value in sorted(missing_input_groups.items())
            },
        },
        "entry_count": len(entries),
        "entries": entries,
        "adapter_backlog": {
            "entry_count": len(backlog_items),
            "items": backlog_items,
            "grouped_by_next_gap": {key: value for key, value in sorted(grouped_backlog.items())},
        },
        "viewer_projection": {
            "adapter_status": {key: value for key, value in sorted(status_groups.items())},
            "computability": {key: value for key, value in sorted(computability_groups.items())},
            "missing_inputs": {key: value for key, value in sorted(missing_input_groups.items())},
            "next_gap": {key: value for key, value in sorted(next_gap_groups.items())},
            "named_filters": {key: value for key, value in sorted(named_filters.items())},
        },
        "canonical_mutations_allowed": False,
        "tracked_artifacts_written": False,
    }


def write_metric_pack_adapter_index(report: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = metric_pack_adapter_index_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def metric_pack_run_status(
    adapter_entry: dict[str, Any],
    value_records: list[dict[str, Any]],
    gap_records: list[dict[str, Any]],
) -> str:
    adapter_status = str(adapter_entry.get("adapter_status", "")).strip()
    if adapter_status == "invalid_pack_contract":
        return "invalid_pack_contract"
    if adapter_status != "ready_for_adapter_review":
        return "not_computable"
    if value_records and gap_records:
        return "partial"
    if value_records:
        return "computed"
    return "not_computable"


def metric_pack_run_next_gap(run_status: str, gap_records: list[dict[str, Any]]) -> str:
    if run_status == "invalid_pack_contract":
        return "repair_metric_pack_contract"
    if gap_records:
        for gap in gap_records:
            next_gap = str(gap.get("next_gap", "")).strip()
            if next_gap and next_gap != "none":
                return next_gap
    mapping = {
        "computed": "review_metric_pack_run_snapshot",
        "partial": "define_metric_value_adapter",
        "not_computable": "define_metric_pack_input_adapter",
        "invalid_pack_contract": "repair_metric_pack_contract",
    }
    return mapping.get(run_status, "review_metric_pack_run_snapshot")


def metric_pack_run_value_record(
    metric_definition: dict[str, Any],
    metric_signal_entry: dict[str, Any],
) -> dict[str, Any]:
    metric_id = str(metric_definition.get("metric_id", "")).strip()
    record = {
        "metric_id": metric_id,
        "label": str(metric_definition.get("label", "")).strip(),
        "kind": str(metric_definition.get("kind", "")).strip(),
        "phase": str(metric_definition.get("phase", "")).strip(),
        "value_status": "computed_from_existing_signal",
        "source_metric_id": str(metric_signal_entry.get("metric_id", "")).strip(),
        "score": copy.deepcopy(metric_signal_entry.get("score")),
        "minimum_score": copy.deepcopy(metric_signal_entry.get("minimum_score")),
        "threshold_gap": copy.deepcopy(metric_signal_entry.get("threshold_gap")),
        "status": str(metric_signal_entry.get("status", "")).strip(),
        "signal_emitted": bool(metric_signal_entry.get("signal_emitted", False)),
        "derivation_mode": str(metric_signal_entry.get("derivation_mode", "")).strip(),
        "threshold_authority_state": str(
            metric_signal_entry.get("threshold_authority_state", "")
        ).strip(),
        "basis": str(metric_signal_entry.get("basis", "")).strip(),
    }
    for field in (
        "value",
        "unit",
        "value_kind",
        "price_status",
        "source_artifacts",
        "input_summary",
    ):
        if field in metric_signal_entry:
            record[field] = copy.deepcopy(metric_signal_entry[field])
    return record


def metric_pack_run_gap_records(
    *,
    adapter_entry: dict[str, Any],
    metric_definitions: list[dict[str, Any]],
    metric_signal_by_id: dict[str, dict[str, Any]],
) -> list[dict[str, Any]]:
    gaps: list[dict[str, Any]] = []
    adapter_status = str(adapter_entry.get("adapter_status", "")).strip()
    if adapter_status != "ready_for_adapter_review":
        adapter_next_gap = str(adapter_entry.get("next_gap", "")).strip()
        for input_id in adapter_entry.get("missing_inputs", []):
            normalized_input_id = str(input_id).strip()
            if not normalized_input_id:
                continue
            gaps.append(
                {
                    "gap_id": (
                        f"{adapter_entry.get('metric_pack_id', '')}::input::{normalized_input_id}"
                    ),
                    "gap_status": "missing_input_adapter",
                    "input_id": normalized_input_id,
                    "metric_id": "",
                    "next_gap": METRIC_PACK_ADAPTER_INPUT_GAP_DEFAULTS.get(
                        normalized_input_id,
                        "define_metric_pack_input_adapter",
                    ),
                }
            )
        if gaps:
            return gaps
        gap_status = adapter_status or "adapter_not_ready"
        gaps.append(
            {
                "gap_id": f"{adapter_entry.get('metric_pack_id', '')}::adapter::{gap_status}",
                "gap_status": gap_status,
                "input_id": "",
                "metric_id": "",
                "next_gap": adapter_next_gap or metric_pack_adapter_next_gap(adapter_status, []),
            }
        )
        return gaps

    for metric in metric_definitions:
        metric_id = str(metric.get("metric_id", "")).strip()
        if not metric_id or metric_id in metric_signal_by_id:
            continue
        gaps.append(
            {
                "gap_id": f"{adapter_entry.get('metric_pack_id', '')}::metric::{metric_id}",
                "gap_status": "missing_metric_signal_adapter",
                "input_id": "",
                "metric_id": metric_id,
                "next_gap": "define_metric_value_adapter",
            }
        )
    return gaps


def build_metric_pack_runs(
    metric_pack_index: dict[str, Any],
    metric_pack_adapter_index: dict[str, Any],
    metric_signal_index: dict[str, Any],
) -> dict[str, Any]:
    pack_entries = {
        str(item.get("metric_pack_id", "")).strip(): item
        for item in metric_pack_index.get("entries", [])
        if isinstance(item, dict) and str(item.get("metric_pack_id", "")).strip()
    }
    adapter_entries = {
        str(item.get("metric_pack_id", "")).strip(): item
        for item in metric_pack_adapter_index.get("entries", [])
        if isinstance(item, dict) and str(item.get("metric_pack_id", "")).strip()
    }
    metric_signal_by_id = {
        str(item.get("metric_id", "")).strip(): item
        for item in metric_signal_index.get("metrics", [])
        if isinstance(item, dict) and str(item.get("metric_id", "")).strip()
    }

    entries: list[dict[str, Any]] = []
    run_status_groups: dict[str, list[str]] = {}
    metric_value_groups: dict[str, list[str]] = {}
    named_filters: dict[str, list[str]] = {
        "computed": [],
        "partial": [],
        "not_computable": [],
        "missing_metric_signal_adapter": [],
        "proposal_pressure_deferred": [],
    }
    value_count = 0
    gap_count = 0

    for metric_pack_id, pack_entry in sorted(pack_entries.items()):
        adapter_entry = adapter_entries.get(metric_pack_id, {})
        adapter_status = str(adapter_entry.get("adapter_status", "")).strip()
        metric_definitions = [
            item for item in pack_entry.get("metrics", []) if isinstance(item, dict)
        ]
        value_records: list[dict[str, Any]] = []
        if adapter_status == "ready_for_adapter_review":
            value_records = [
                metric_pack_run_value_record(metric, metric_signal_by_id[metric_id])
                for metric in metric_definitions
                if (metric_id := str(metric.get("metric_id", "")).strip())
                and metric_id in metric_signal_by_id
            ]
        gap_records = metric_pack_run_gap_records(
            adapter_entry={**adapter_entry, "metric_pack_id": metric_pack_id},
            metric_definitions=metric_definitions,
            metric_signal_by_id=metric_signal_by_id,
        )
        run_status = metric_pack_run_status(adapter_entry, value_records, gap_records)
        next_gap = metric_pack_run_next_gap(run_status, gap_records)
        run_id = f"metric_pack_run::{metric_pack_id}::latest"
        value_count += len(value_records)
        gap_count += len(gap_records)
        run_status_groups.setdefault(run_status, []).append(metric_pack_id)
        if run_status in named_filters:
            named_filters[run_status].append(metric_pack_id)
        named_filters["proposal_pressure_deferred"].append(metric_pack_id)
        if any(
            str(gap.get("gap_status", "")).strip() == "missing_metric_signal_adapter"
            for gap in gap_records
        ):
            named_filters["missing_metric_signal_adapter"].append(metric_pack_id)
        for value in value_records:
            metric_id = str(value.get("metric_id", "")).strip()
            if metric_id:
                metric_value_groups.setdefault(metric_id, []).append(metric_pack_id)
        entries.append(
            {
                "run_id": run_id,
                "metric_pack_id": metric_pack_id,
                "title": str(pack_entry.get("title", "")).strip(),
                "run_status": run_status,
                "review_state": "ready_for_review",
                "next_gap": next_gap,
                "pack_status": str(pack_entry.get("pack_status", "")).strip(),
                "pack_authority_state": str(pack_entry.get("pack_authority_state", "")).strip(),
                "reference_state": str(pack_entry.get("reference_state", "")).strip(),
                "adapter_status": str(adapter_entry.get("adapter_status", "")).strip(),
                "input_snapshot": {
                    "adapter_inputs": copy.deepcopy(adapter_entry.get("inputs", [])),
                    "missing_inputs": copy.deepcopy(adapter_entry.get("missing_inputs", [])),
                    "adapter_next_gap": str(adapter_entry.get("next_gap", "")).strip(),
                },
                "computed_values": value_records,
                "gaps": gap_records,
                "finding_projection": {
                    "status": "deferred",
                    "next_gap": "add_metric_pack_finding_index",
                },
                "threshold_authority_granted": False,
                "canonical_mutations_allowed": False,
                "tracked_artifacts_written": False,
            }
        )

    for bucket in (run_status_groups, metric_value_groups, named_filters):
        for key in list(bucket):
            bucket[key] = sorted(set(bucket[key]))

    return {
        "artifact_kind": METRIC_PACK_RUNS_ARTIFACT_KIND,
        "schema_version": METRIC_PACK_RUNS_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "review_state": "ready_for_review" if entries else "not_ready",
        "next_gap": "review_metric_pack_runs" if entries else "declare_metric_pack_registry",
        "source_snapshot": {
            "artifact_path": METRIC_PACK_RUNS_RELATIVE_PATH,
            "metric_pack_index": {
                "artifact_path": metric_pack_index_path().relative_to(ROOT).as_posix(),
                "generated_at": metric_pack_index.get("generated_at"),
                "entry_count": metric_pack_index.get("entry_count"),
            },
            "metric_pack_adapter_index": {
                "artifact_path": metric_pack_adapter_index_path().relative_to(ROOT).as_posix(),
                "generated_at": metric_pack_adapter_index.get("generated_at"),
                "entry_count": metric_pack_adapter_index.get("entry_count"),
            },
            "metric_signal_index": {
                "artifact_path": metric_signal_index_path().relative_to(ROOT).as_posix(),
                "generated_at": metric_signal_index.get("generated_at"),
                "entry_count": metric_signal_index.get("entry_count"),
            },
        },
        "summary": {
            "pack_count": len(entries),
            "run_status_counts": {
                key: len(value) for key, value in sorted(run_status_groups.items())
            },
            "computed_value_count": value_count,
            "gap_count": gap_count,
        },
        "entry_count": len(entries),
        "entries": entries,
        "viewer_projection": {
            "run_status": {key: value for key, value in sorted(run_status_groups.items())},
            "metric_values": {key: value for key, value in sorted(metric_value_groups.items())},
            "named_filters": {key: value for key, value in sorted(named_filters.items())},
        },
        "canonical_mutations_allowed": False,
        "tracked_artifacts_written": False,
    }


def write_metric_pack_runs(report: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = metric_pack_runs_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def supervisor_problem_diagnosis_problem_policy(problem_class: str) -> dict[str, Any]:
    for problem in supervisor_problem_diagnosis_policy_lookup("problem_classes"):
        if str(problem.get("id", "")).strip() == problem_class:
            return problem
    return {}


def supervisor_problem_diagnosis_default_action(problem_class: str) -> str:
    policy = supervisor_problem_diagnosis_problem_policy(problem_class)
    actions = policy.get("safe_actions", [])
    if isinstance(actions, list):
        for action in actions:
            normalized = str(action).strip()
            if normalized:
                return normalized
    return ""


def supervisor_problem_diagnosis_default_severity(problem_class: str) -> str:
    policy = supervisor_problem_diagnosis_problem_policy(problem_class)
    severity = str(policy.get("default_severity", "")).strip()
    return severity or "actionable"


def supervisor_problem_diagnosis_source_reference(path: Path | None) -> dict[str, Any]:
    if path is None:
        return {"artifact_path": "", "local_path_redacted": False}
    resolved = path.resolve(strict=False)
    try:
        return {
            "artifact_path": resolved.relative_to(ROOT.resolve(strict=False)).as_posix(),
            "local_path_redacted": False,
        }
    except ValueError:
        return {
            "artifact_path": resolved.name,
            "local_path_redacted": True,
        }


def supervisor_problem_diagnosis_sanitized_error(error: str, path: Path | None) -> str:
    text = str(error).strip()
    if not text or path is None:
        return text
    resolved = path.resolve(strict=False)
    replacement = str(
        supervisor_problem_diagnosis_source_reference(path).get("artifact_path", "<run-artifact>")
    )
    return text.replace(resolved.as_posix(), replacement)


SUPERVISOR_PROBLEM_DIAGNOSIS_REQUIRED_RUN_FIELDS = (
    "run_id",
    "spec_id",
    "completion_status",
    "outcome",
    "gate_state",
)


def supervisor_problem_diagnosis_run_schema_errors(payload: dict[str, Any]) -> list[str]:
    errors: list[str] = []
    for field in SUPERVISOR_PROBLEM_DIAGNOSIS_REQUIRED_RUN_FIELDS:
        if not str(payload.get(field, "")).strip():
            errors.append(f"missing required run field: {field}")
    return errors


def supervisor_problem_diagnosis_run_log_candidate_paths() -> list[Path]:
    if not RUNS_DIR.exists():
        return []
    return sorted(path for path in RUNS_DIR.glob("*.json") if path.is_file())


def supervisor_problem_diagnosis_explicit_run_timestamp(
    payload: dict[str, Any],
) -> dt.datetime | None:
    for field in ("finished_at_utc", "started_at_utc", "timestamp_utc"):
        parsed = parse_iso_datetime(payload.get(field, ""))
        if parsed is not None:
            return parsed
    run_id = str(payload.get("run_id", "")).strip()
    prefix = run_id.split("-", 1)[0]
    try:
        return dt.datetime.strptime(prefix, "%Y%m%dT%H%M%SZ").replace(tzinfo=dt.timezone.utc)
    except ValueError:
        return None


def latest_supervisor_run_log_path() -> Path | None:
    records: list[tuple[dt.datetime | None, str, Path]] = []
    for path in supervisor_problem_diagnosis_run_log_candidate_paths():
        payload, error = load_json_object_report(path, artifact_kind="run log")
        if payload is None or supervisor_problem_diagnosis_run_schema_errors(payload):
            continue
        run_id = str(payload.get("run_id", path.stem)).strip() or path.stem
        records.append((supervisor_problem_diagnosis_explicit_run_timestamp(payload), run_id, path))
    if not records:
        return None
    timestamped = [item for item in records if item[0] is not None]
    if timestamped:
        timestamped.sort(
            key=lambda item: (
                item[0] or dt.datetime.min.replace(tzinfo=dt.timezone.utc),
                item[1],
            )
        )
        return timestamped[-1][2]
    records.sort(key=lambda item: (item[2].stat().st_mtime, item[1]))
    return records[-1][2]


def resolve_supervisor_problem_diagnosis_run_path(
    supervisor_run_path: str | None,
) -> tuple[Path | None, str]:
    value = str(supervisor_run_path or "").strip()
    if value:
        try:
            return resolve_supervisor_run_reference(value), ""
        except RuntimeError as exc:
            if any(sep in value for sep in ("/", "\\")):
                return Path(value), str(exc)
            run_filename = value if Path(value).suffix == ".json" else f"{value}.json"
            return RUNS_DIR / run_filename, str(exc)
    path = latest_supervisor_run_log_path()
    if path is None:
        return None, "no supervisor run logs found under runs/"
    return path, ""


def supervisor_problem_diagnosis_text_surface(payload: dict[str, Any]) -> str:
    fields: list[str] = []
    for key in (
        "completion_status",
        "outcome",
        "blocker",
        "gate_state",
        "required_human_action",
        "recovery_status",
    ):
        fields.append(str(payload.get(key, "")))
    validation_errors = payload.get("validation_errors", [])
    if isinstance(validation_errors, list):
        fields.extend(str(item) for item in validation_errors)
    for finding in coerce_validation_findings(payload.get("validation_findings", [])):
        fields.extend(
            str(finding.get(key, ""))
            for key in ("code", "family", "error_class", "severity", "message")
        )
    validator_results = payload.get("validator_results", {})
    if isinstance(validator_results, dict):
        for key, value in sorted(validator_results.items()):
            fields.append(f"{key}:{value}")
    executor_environment = payload.get("executor_environment", {})
    if isinstance(executor_environment, dict):
        fields.append(str(executor_environment.get("primary_failure", "")))
        issue_kinds = executor_environment.get("issue_kinds", [])
        if isinstance(issue_kinds, list):
            fields.extend(str(item) for item in issue_kinds)
        issues = executor_environment.get("issues", [])
        if isinstance(issues, list):
            for issue in issues:
                if isinstance(issue, dict):
                    fields.extend(str(issue.get(key, "")) for key in ("kind", "code", "summary"))
                else:
                    fields.append(str(issue))
    return "\n".join(fields).lower()


def supervisor_run_has_provider_failure(payload: dict[str, Any]) -> bool:
    text = supervisor_problem_diagnosis_text_surface(payload)
    provider_markers = (
        "quota",
        "usage limit",
        "provider",
        "transport",
        "rate limit",
        "account",
        "authentication",
        "channel error",
        "network",
        "timeout",
    )
    executor_environment = payload.get("executor_environment", {})
    primary_failure = (
        bool(executor_environment.get("primary_failure"))
        if isinstance(executor_environment, dict)
        else False
    )
    validator_results = payload.get("validator_results", {})
    executor_failed = (
        isinstance(validator_results, dict)
        and validator_results.get("executor_environment") is False
    )
    return (primary_failure or executor_failed) and any(
        marker in text for marker in provider_markers
    )


def supervisor_run_has_runtime_residue(payload: dict[str, Any]) -> bool:
    spec_id = str(payload.get("spec_id", "")).strip()
    changed_files = _supervisor_packet_string_list(payload.get("changed_files"))
    spec_path = f"specs/nodes/{spec_id}.yaml" if spec_id else ""
    touched_target = bool(spec_path and spec_path in changed_files)
    if not touched_target:
        return False
    completion_status = str(payload.get("completion_status", "")).strip()
    outcome = str(payload.get("outcome", "")).strip()
    gate_state = str(payload.get("gate_state", "")).strip()
    validator_results = payload.get("validator_results", {})
    executor_failed = (
        isinstance(validator_results, dict)
        and validator_results.get("executor_environment") is False
    )
    return (
        completion_status == "failed"
        and outcome == "blocked"
        and (gate_state in {"blocked", "review_pending"} or executor_failed)
    )


def canonical_acceptance_count_for_spec(spec_id: str) -> int | None:
    normalized = str(spec_id).strip()
    if not normalized:
        return None
    for spec in load_specs():
        if spec.id == normalized:
            return node_acceptance_count(spec)
    return None


def supervisor_run_has_split_required_candidate_without_proposal_path(
    payload: dict[str, Any],
    *,
    target_spec: str | None = None,
) -> tuple[bool, int | None, str]:
    text = supervisor_problem_diagnosis_text_surface(payload)
    findings = coerce_validation_findings(payload.get("validation_findings", []))
    finding_codes = {str(finding.get("code", "")).strip() for finding in findings}
    has_atomicity_pressure = (
        "atomicity_violation" in finding_codes
        or "atomicity gate exceeded" in text
        or str(payload.get("outcome", "")).strip() == "split_required"
    )
    if not has_atomicity_pressure:
        return False, None, ""
    decision_inspector = payload.get("decision_inspector", {})
    if not isinstance(decision_inspector, dict):
        return False, None, "missing explicit proposal queue evidence"
    queue_effects = decision_inspector.get("queue_effects")
    if not isinstance(queue_effects, dict):
        return False, None, "missing explicit proposal queue evidence"
    proposal_queue = queue_effects.get("proposal_queue")
    if not isinstance(proposal_queue, dict) or "emitted_ids" not in proposal_queue:
        return False, None, "missing explicit proposal queue evidence"
    emitted_ids = proposal_queue.get("emitted_ids", [])
    if not isinstance(emitted_ids, list):
        return False, None, "malformed explicit proposal queue evidence"
    if isinstance(emitted_ids, list) and any(str(item).strip() for item in emitted_ids):
        return False, None, ""
    spec_id = str(target_spec or payload.get("spec_id", "")).strip()
    canonical_count = canonical_acceptance_count_for_spec(spec_id)
    if canonical_count is None:
        return False, None, f"unknown target spec: {spec_id}"
    return canonical_count <= ATOMICITY_MAX_ACCEPTANCE, canonical_count, ""


def supervisor_problem_diagnosis_problem(
    *,
    run_id: str,
    problem_class: str,
    root_cause: str,
    evidence: list[str],
    deterministic: bool = True,
) -> dict[str, Any]:
    return {
        "problem_id": sanitize_for_git(f"{run_id}-{problem_class}")[:96],
        "problem_class": problem_class,
        "severity": supervisor_problem_diagnosis_default_severity(problem_class),
        "root_cause": root_cause,
        "evidence": evidence,
        "recommended_action": supervisor_problem_diagnosis_default_action(problem_class),
        "deterministic": deterministic,
        "requires_human_review": True,
    }


def build_supervisor_problem_diagnosis(
    *,
    supervisor_run_path: str | None = None,
    target_spec: str | None = None,
) -> dict[str, Any]:
    path, path_error = resolve_supervisor_problem_diagnosis_run_path(supervisor_run_path)
    source_reference = supervisor_problem_diagnosis_source_reference(path)
    run_payload: dict[str, Any] | None = None
    load_error = supervisor_problem_diagnosis_sanitized_error(path_error, path)
    raw_sha256 = ""
    if path is not None and not path_error:
        try:
            run_payload, raw_sha256 = load_supervisor_run_artifact(path)
        except RuntimeError as exc:
            load_error = supervisor_problem_diagnosis_sanitized_error(str(exc), path)

    run_id = ""
    spec_id = str(target_spec or "").strip()
    detected_problems: list[dict[str, Any]] = []
    schema_errors: list[str] = []
    insufficient_evidence_reasons: list[str] = []

    if run_payload is not None:
        run_id = str(run_payload.get("run_id", "")).strip() or (path.stem if path else "")
        run_spec_id = str(run_payload.get("spec_id", "")).strip()
        spec_id = spec_id or run_spec_id
        schema_errors = supervisor_problem_diagnosis_run_schema_errors(run_payload)
        if schema_errors:
            insufficient_evidence_reasons.extend(schema_errors)
        if not schema_errors and supervisor_run_has_provider_failure(run_payload):
            detected_problems.append(
                supervisor_problem_diagnosis_problem(
                    run_id=run_id,
                    problem_class="quota_or_provider_failure",
                    root_cause=(
                        "Supervisor child execution failed because the provider, transport, "
                        "quota, or account state blocked the run."
                    ),
                    evidence=[
                        "executor_environment.primary_failure_or_validator_failure",
                        "run_log.provider_failure_marker_observed",
                    ],
                )
            )
        if not schema_errors and supervisor_run_has_runtime_residue(run_payload):
            detected_problems.append(
                supervisor_problem_diagnosis_problem(
                    run_id=run_id,
                    problem_class="runtime_residue",
                    root_cause=(
                        "A failed or blocked runtime run touched the target spec and may have "
                        "left misleading gate or metadata residue."
                    ),
                    evidence=[
                        "completion_status=failed",
                        "outcome=blocked",
                        f"changed_files includes specs/nodes/{run_spec_id}.yaml",
                    ],
                )
            )
        split_problem, canonical_acceptance_count, split_insufficient_evidence = (
            supervisor_run_has_split_required_candidate_without_proposal_path(
                run_payload,
                target_spec=spec_id,
            )
        )
        if schema_errors:
            split_problem = False
        if split_insufficient_evidence:
            insufficient_evidence_reasons.append(split_insufficient_evidence)
        if not schema_errors and split_problem:
            detected_problems.append(
                supervisor_problem_diagnosis_problem(
                    run_id=run_id,
                    problem_class="split_required_candidate_without_proposal_path",
                    root_cause=(
                        "The candidate hit atomicity pressure, but accepted canonical content "
                        "does not itself exceed the acceptance-count threshold."
                    ),
                    evidence=[
                        "run_log.atomicity_pressure_observed",
                        f"canonical_acceptance_count={canonical_acceptance_count}",
                        f"atomicity_max_acceptance={ATOMICITY_MAX_ACCEPTANCE}",
                        "proposal_queue.emitted_ids empty_or_absent",
                    ],
                )
            )

    blocking_count = sum(
        1 for problem in detected_problems if str(problem.get("severity", "")).strip() == "blocking"
    )
    if load_error:
        overall_status = "insufficient_evidence"
    elif blocking_count:
        overall_status = "hard_stop"
    elif detected_problems:
        overall_status = "actionable"
    elif insufficient_evidence_reasons:
        overall_status = "insufficient_evidence"
    else:
        overall_status = "clean"
    source_status = "unavailable" if load_error else "loaded"
    if not load_error and schema_errors:
        source_status = "schema_incomplete"

    artifact = {
        "artifact_kind": SUPERVISOR_PROBLEM_DIAGNOSIS_ARTIFACT_KIND,
        "schema_version": SUPERVISOR_PROBLEM_DIAGNOSIS_SCHEMA_VERSION,
        "canonical_mutations_allowed": False,
        "tracked_artifacts_written": False,
        "generated_at": utc_now_iso(),
        "target": {
            "spec_id": spec_id,
            "run_id": run_id,
        },
        "source": {
            **source_reference,
            "source_status": source_status,
            "content_sha256": f"sha256:{raw_sha256}" if raw_sha256 else "",
            "error": load_error,
            "schema_errors": schema_errors,
        },
        "diagnosis": {
            "overall_status": overall_status,
            "detected_problem_count": len(detected_problems),
            "hard_stop": overall_status == "hard_stop",
        },
        "detected_problems": detected_problems,
        "safe_next_actions": [],
        "blocked_actions": [],
        "validation_plan": [],
        "insufficient_evidence": insufficient_evidence_reasons,
        "policy_reference": supervisor_problem_diagnosis_policy_reference(),
        "summary": {
            "status": overall_status,
            "top_problem_class": (
                str(detected_problems[0].get("problem_class", "")) if detected_problems else ""
            ),
            "detected_problem_count": len(detected_problems),
            "source_status": source_status,
            "insufficient_evidence_count": len(insufficient_evidence_reasons),
        },
    }
    return artifact


def write_supervisor_problem_diagnosis(report: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = supervisor_problem_diagnosis_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def _iso_or_empty(value: dt.datetime | None) -> str:
    if value is None:
        return ""
    return value.astimezone(dt.timezone.utc).isoformat().replace("+00:00", "Z")


def performance_run_timestamp(payload: dict[str, Any], path: Path) -> dt.datetime | None:
    finished_at = parse_iso_datetime(payload.get("finished_at_utc", ""))
    if finished_at is not None:
        return finished_at
    started_at = parse_iso_datetime(payload.get("started_at_utc", ""))
    if started_at is not None:
        return started_at
    return graph_health_event_timestamp(payload, path)


def performance_run_kind(payload: dict[str, Any]) -> str:
    explicit = str(payload.get("run_kind", "")).strip()
    if explicit:
        return explicit
    selected_by_rule = payload.get("selected_by_rule", {})
    if not isinstance(selected_by_rule, dict):
        selected_by_rule = {}
    selection_mode = str(selected_by_rule.get("selection_mode", "")).strip()
    if selection_mode == "split_refactor_proposal":
        return "split_proposal"
    if selection_mode == "apply_split_proposal":
        return "apply_split_proposal"
    refactor_work_item = selected_by_rule.get("refactor_work_item", {})
    if isinstance(refactor_work_item, dict) and str(refactor_work_item.get("id", "")).strip():
        return "graph_refactor"
    return "ordinary_refine"


def performance_execution_profile(payload: dict[str, Any]) -> str:
    explicit = str(payload.get("execution_profile", "")).strip()
    if explicit:
        return explicit
    selected_by_rule = payload.get("selected_by_rule", {})
    if not isinstance(selected_by_rule, dict):
        return ""
    return str(selected_by_rule.get("execution_profile", "")).strip()


def performance_child_model(payload: dict[str, Any]) -> str:
    return str(payload.get("child_model", "")).strip()


def performance_run_duration_sec(payload: dict[str, Any], path: Path) -> float | None:
    explicit = payload.get("run_duration_sec")
    if isinstance(explicit, (int, float)):
        return round(float(explicit), 3)
    started_at = parse_iso_datetime(payload.get("started_at_utc", ""))
    finished_at = parse_iso_datetime(payload.get("finished_at_utc", ""))
    if started_at is None or finished_at is None:
        return None
    duration = (finished_at - started_at).total_seconds()
    if duration < 0:
        return None
    return round(duration, 3)


def performance_validation_findings(payload: dict[str, Any]) -> list[dict[str, Any]]:
    return coerce_validation_findings(payload.get("validation_findings", []))


def performance_queue_transition(payload: dict[str, Any], queue_name: str) -> dict[str, Any]:
    decision_inspector = payload.get("decision_inspector", {})
    if not isinstance(decision_inspector, dict):
        return {}
    queue_effects = decision_inspector.get("queue_effects", {})
    if not isinstance(queue_effects, dict):
        return {}
    transition = queue_effects.get(queue_name, {})
    if not isinstance(transition, dict):
        return {}
    return transition


def performance_new_child_materialized_count(payload: dict[str, Any]) -> int:
    explicit = payload.get("new_child_materialized_count")
    if isinstance(explicit, int):
        return max(explicit, 0)
    materialized = payload.get("materialized_child_paths", [])
    if isinstance(materialized, list):
        return sum(1 for item in materialized if str(item).strip())
    changed_files = payload.get("changed_files", [])
    spec_id = str(payload.get("spec_id", "")).strip()
    source_path = f"specs/nodes/{spec_id}.yaml" if spec_id else ""
    if not isinstance(changed_files, list):
        return 0
    return sum(
        1
        for item in changed_files
        if is_spec_node_path(str(item).strip()) and str(item).strip() != source_path
    )


def performance_accepted_canonical_diff(payload: dict[str, Any]) -> bool:
    explicit = payload.get("accepted_canonical_diff")
    if isinstance(explicit, bool):
        return explicit
    if performance_run_kind(payload) == "apply_split_proposal":
        validator_results = payload.get("validator_results", {})
        if isinstance(validator_results, dict):
            return bool(validator_results.get("canonical_writeback"))
    if bool(payload.get("auto_approved")):
        return True
    before_status = str(payload.get("before_status", "")).strip()
    final_status = str(payload.get("final_status", "")).strip()
    if before_status and final_status and before_status != final_status:
        return True
    before_maturity = payload.get("before_maturity")
    final_maturity = payload.get("final_maturity")
    if isinstance(before_maturity, (int, float)) and isinstance(final_maturity, (int, float)):
        return float(final_maturity) > float(before_maturity)
    return False


def performance_productive_split_required(payload: dict[str, Any]) -> bool:
    explicit = payload.get("productive_split_required")
    if isinstance(explicit, bool):
        return explicit
    outcome = str(payload.get("outcome", "")).strip()
    changed_files = payload.get("changed_files", [])
    return outcome == "split_required" and isinstance(changed_files, list) and bool(changed_files)


def performance_runtime_status(
    payload: dict[str, Any],
    findings: list[dict[str, Any]],
) -> tuple[str, list[str]]:
    validator_results = payload.get("validator_results", {})
    if not isinstance(validator_results, dict):
        validator_results = {}
    reasons: list[str] = []
    if validator_results.get("executor_environment") is False:
        reasons.append("executor_environment")
    if validator_results.get("runtime_artifacts") is False:
        reasons.append("runtime_artifacts")
    finding_codes = {
        str(finding.get("code", "")).strip()
        for finding in findings
        if str(finding.get("code", "")).strip()
    }
    if "executor_machine_protocol_failure" in finding_codes:
        reasons.append("executor_machine_protocol")
    if reasons:
        return "runtime_failed", sorted(set(reasons))
    yaml_repair_paths = payload.get("yaml_repair_paths", [])
    if isinstance(yaml_repair_paths, list) and any(str(item).strip() for item in yaml_repair_paths):
        return "runtime_degraded", ["yaml_repair_applied"]
    return "runtime_clean", []


def performance_yield_status(
    payload: dict[str, Any],
    *,
    runtime_status: str,
    accepted_canonical_diff: bool,
    productive_split_required: bool,
    proposal_emitted: bool,
    review_required: bool,
    changed_files: list[str],
) -> tuple[str, bool]:
    if runtime_status == "runtime_failed":
        return "runtime_blocked", False
    if accepted_canonical_diff:
        return "accepted_change", True
    if proposal_emitted:
        return "proposal_emitted", True
    if productive_split_required:
        return "productive_split_required", True
    if review_required and changed_files:
        return "review_pending_candidate", True
    return "low_yield", False


def performance_graph_impact_status(
    *,
    runtime_status: str,
    yield_status: str,
    before_status: str,
    final_status: str,
    before_maturity: float | None,
    final_maturity: float | None,
    new_child_materialized_count: int,
    gate_state: str,
) -> str:
    maturity_increased = (
        before_maturity is not None
        and final_maturity is not None
        and float(final_maturity) > float(before_maturity)
    )
    if yield_status == "accepted_change" and (
        before_status != final_status or maturity_increased or new_child_materialized_count > 0
    ):
        return "canonical_improvement"
    if yield_status == "proposal_emitted":
        return "proposal_only"
    if yield_status == "review_pending_candidate":
        return "pending_review"
    if yield_status == "productive_split_required":
        return "structural_pressure"
    if (
        runtime_status == "runtime_failed"
        or gate_state in SUPERVISOR_PERFORMANCE_BLOCKED_GATE_STATES
    ):
        return "blocked_or_regressed"
    return "neutral"


def build_supervisor_performance_index() -> dict[str, Any]:
    grouped_runtime_status: dict[str, list[str]] = {}
    grouped_yield_status: dict[str, list[str]] = {}
    grouped_graph_impact_status: dict[str, list[str]] = {}
    grouped_run_kind: dict[str, list[str]] = {}
    grouped_execution_profile: dict[str, list[str]] = {}
    named_filters = {name: [] for name in SUPERVISOR_PERFORMANCE_NAMED_FILTERS}
    entries: list[dict[str, Any]] = []
    run_logs_scanned = 0
    skipped_invalid_run_logs: list[dict[str, str]] = []

    run_records: list[tuple[dt.datetime | None, Path, dict[str, Any]]] = []
    for path in run_log_paths():
        payload, error = load_json_object_report(path, artifact_kind="run log")
        if payload is None:
            skipped_invalid_run_logs.append(
                {
                    "path": path.relative_to(ROOT).as_posix(),
                    "error": error,
                }
            )
            continue
        run_logs_scanned += 1
        run_records.append((performance_run_timestamp(payload, path), path, payload))

    run_records.sort(
        key=lambda item: (
            item[0] is None,
            item[0] or dt.datetime.min.replace(tzinfo=dt.timezone.utc),
            str(item[2].get("run_id", item[1].stem)),
        )
    )

    durations: list[float] = []
    spec_run_counts: dict[str, int] = {}
    per_day_buckets: dict[str, dict[str, Any]] = {}

    for timestamp, path, payload in run_records:
        run_id = str(payload.get("run_id", "")).strip() or path.stem
        spec_id = str(payload.get("spec_id", "")).strip()
        spec_run_counts[spec_id] = spec_run_counts.get(spec_id, 0) + 1
        same_spec_repeat_count = max(spec_run_counts[spec_id] - 1, 0) if spec_id else 0

        findings = performance_validation_findings(payload)
        run_kind = performance_run_kind(payload)
        execution_profile = performance_execution_profile(payload)
        child_model = performance_child_model(payload)
        duration_sec = performance_run_duration_sec(payload, path)
        if duration_sec is not None:
            durations.append(duration_sec)
        before_status = str(payload.get("before_status", "")).strip()
        final_status = str(payload.get("final_status", "")).strip()
        gate_state = str(payload.get("gate_state", "")).strip() or "none"
        before_maturity_raw = payload.get("before_maturity")
        final_maturity_raw = payload.get("final_maturity")
        before_maturity = (
            float(before_maturity_raw) if isinstance(before_maturity_raw, (int, float)) else None
        )
        final_maturity = (
            float(final_maturity_raw) if isinstance(final_maturity_raw, (int, float)) else None
        )
        changed_files = (
            [str(item).strip() for item in payload.get("changed_files", []) if str(item).strip()]
            if isinstance(payload.get("changed_files", []), list)
            else []
        )
        proposal_queue_transition = performance_queue_transition(payload, "proposal_queue")
        refactor_queue_transition = performance_queue_transition(payload, "refactor_queue")
        proposal_emitted = bool(proposal_queue_transition.get("emitted_ids")) or (
            run_kind in SUPERVISOR_PERFORMANCE_PROPOSAL_RUN_KINDS
            and str(payload.get("proposal_artifact_path", "")).strip()
            and str(payload.get("outcome", "")).strip() == "done"
        )
        accepted_canonical_diff = performance_accepted_canonical_diff(payload)
        productive_split_required = performance_productive_split_required(payload)
        new_child_materialized_count = performance_new_child_materialized_count(payload)
        review_required = gate_state in SUPERVISOR_PERFORMANCE_REVIEW_PENDING_GATE_STATES
        runtime_status, runtime_failure_reasons = performance_runtime_status(payload, findings)
        yield_status, productive_run = performance_yield_status(
            payload,
            runtime_status=runtime_status,
            accepted_canonical_diff=accepted_canonical_diff,
            productive_split_required=productive_split_required,
            proposal_emitted=proposal_emitted,
            review_required=review_required,
            changed_files=changed_files,
        )
        graph_impact_status = performance_graph_impact_status(
            runtime_status=runtime_status,
            yield_status=yield_status,
            before_status=before_status,
            final_status=final_status,
            before_maturity=before_maturity,
            final_maturity=final_maturity,
            new_child_materialized_count=new_child_materialized_count,
            gate_state=gate_state,
        )
        graph_health = payload.get("graph_health", {})
        if isinstance(graph_health, dict) and isinstance(graph_health.get("signals", []), list):
            graph_signals = [
                str(item).strip() for item in graph_health.get("signals", []) if str(item).strip()
            ]
        else:
            graph_signals = []
        validation_summary_payload = payload.get("validation_summary", {})
        if not isinstance(validation_summary_payload, dict):
            validation_summary_payload = {}
        benchmark_payload = payload.get("benchmark", {})
        if not isinstance(benchmark_payload, dict):
            benchmark_payload = {}
        benchmark_metadata = {
            "benchmark_id": str(
                benchmark_payload.get("benchmark_id", payload.get("benchmark_id", ""))
            ).strip(),
            "scenario_id": str(
                benchmark_payload.get("scenario_id", payload.get("benchmark_scenario_id", ""))
            ).strip(),
            "batch_id": str(
                benchmark_payload.get("batch_id", payload.get("benchmark_batch_id", ""))
            ).strip(),
            "seed_id": str(
                benchmark_payload.get("seed_id", payload.get("benchmark_seed_id", ""))
            ).strip(),
        }

        entry = {
            "run_id": run_id,
            "spec_id": spec_id,
            "title": str(payload.get("title", "")).strip(),
            "run_kind": run_kind,
            "execution_profile": execution_profile,
            "child_model": child_model,
            "timestamp_utc": _iso_or_empty(timestamp),
            "started_at_utc": _iso_or_empty(parse_iso_datetime(payload.get("started_at_utc", ""))),
            "finished_at_utc": _iso_or_empty(
                parse_iso_datetime(payload.get("finished_at_utc", ""))
                or parse_iso_datetime(payload.get("timestamp_utc", ""))
            ),
            "run_duration_sec": duration_sec,
            "runtime_status": runtime_status,
            "runtime_failure_reasons": runtime_failure_reasons,
            "yield_status": yield_status,
            "graph_impact_status": graph_impact_status,
            "productive_run": productive_run,
            "accepted_canonical_diff": accepted_canonical_diff,
            "proposal_emitted": proposal_emitted,
            "productive_split_required": productive_split_required,
            "review_required": review_required,
            "new_child_materialized_count": new_child_materialized_count,
            "same_spec_repeat_count": same_spec_repeat_count,
            "completion_status": str(payload.get("completion_status", "")).strip(),
            "outcome": str(payload.get("outcome", "")).strip(),
            "blocker": str(payload.get("blocker", "")).strip(),
            "gate_state": gate_state,
            "status_delta": {
                "before": before_status,
                "after": final_status,
                "changed": bool(before_status and final_status and before_status != final_status),
            },
            "maturity_delta": {
                "before": before_maturity,
                "after": final_maturity,
                "delta": (
                    round(final_maturity - before_maturity, 3)
                    if before_maturity is not None and final_maturity is not None
                    else None
                ),
            },
            "graph_signal_summary": {
                "signal_count": len(graph_signals),
                "signals": graph_signals,
            },
            "intervention_cost": {
                "changed_file_count": len(changed_files),
                "validation_finding_count": len(findings),
                "proposal_queue_emission_count": len(
                    [
                        item
                        for item in proposal_queue_transition.get("emitted_ids", [])
                        if str(item).strip()
                    ]
                ),
                "refactor_queue_emission_count": len(
                    [
                        item
                        for item in refactor_queue_transition.get("emitted_ids", [])
                        if str(item).strip()
                    ]
                ),
            },
            "validation_summary": copy.deepcopy(validation_summary_payload),
            "benchmark": benchmark_metadata,
        }
        entries.append(entry)

        grouped_runtime_status.setdefault(runtime_status, []).append(run_id)
        grouped_yield_status.setdefault(yield_status, []).append(run_id)
        grouped_graph_impact_status.setdefault(graph_impact_status, []).append(run_id)
        if run_kind:
            grouped_run_kind.setdefault(run_kind, []).append(run_id)
        if execution_profile:
            grouped_execution_profile.setdefault(execution_profile, []).append(run_id)

        if runtime_status == "runtime_failed":
            named_filters["runtime_failures"].append(run_id)
        if runtime_status == "runtime_degraded":
            named_filters["runtime_degraded"].append(run_id)
        if productive_run:
            named_filters["productive_runs"].append(run_id)
        if yield_status == "accepted_change":
            named_filters["accepted_changes"].append(run_id)
        if yield_status == "proposal_emitted":
            named_filters["proposal_emitted"].append(run_id)
        if yield_status == "productive_split_required":
            named_filters["split_productive_runs"].append(run_id)
        if yield_status == "review_pending_candidate":
            named_filters["review_pending_candidates"].append(run_id)
        if yield_status == "low_yield":
            named_filters["low_yield_runs"].append(run_id)
        if graph_impact_status in {"canonical_improvement", "proposal_only"}:
            named_filters["positive_graph_impact"].append(run_id)
        if graph_impact_status == "blocked_or_regressed":
            named_filters["negative_graph_impact"].append(run_id)
        if (
            duration_sec is not None
            and duration_sec >= SUPERVISOR_PERFORMANCE_SLOW_RUN_THRESHOLD_SECONDS
        ):
            named_filters["slow_runs"].append(run_id)

        day_key = timestamp.date().isoformat() if timestamp is not None else "unknown"
        bucket = per_day_buckets.setdefault(
            day_key,
            {
                "day_utc": day_key,
                "run_ids": [],
                "run_count": 0,
                "productive_run_count": 0,
                "runtime_failed_count": 0,
                "accepted_canonical_diff_count": 0,
                "proposal_emitted_count": 0,
                "new_child_materialized_count": 0,
                "durations": [],
            },
        )
        bucket["run_ids"].append(run_id)
        bucket["run_count"] += 1
        bucket["productive_run_count"] += 1 if productive_run else 0
        bucket["runtime_failed_count"] += 1 if runtime_status == "runtime_failed" else 0
        bucket["accepted_canonical_diff_count"] += 1 if accepted_canonical_diff else 0
        bucket["proposal_emitted_count"] += 1 if proposal_emitted else 0
        bucket["new_child_materialized_count"] += new_child_materialized_count
        if duration_sec is not None:
            bucket["durations"].append(duration_sec)

    repeat_hotspots = sorted(
        (
            {"spec_id": spec_id, "run_count": count}
            for spec_id, count in spec_run_counts.items()
            if spec_id and count >= SUPERVISOR_PERFORMANCE_REPEAT_HOTSPOT_RUN_COUNT
        ),
        key=lambda item: (-int(item["run_count"]), str(item["spec_id"])),
    )
    named_filters["repeat_hotspot_specs"] = [item["spec_id"] for item in repeat_hotspots]

    batches_by_day = []
    for day_key in sorted(per_day_buckets):
        bucket = per_day_buckets[day_key]
        batches_by_day.append(
            {
                "day_utc": day_key,
                "run_count": bucket["run_count"],
                "productive_run_count": bucket["productive_run_count"],
                "runtime_failed_count": bucket["runtime_failed_count"],
                "accepted_canonical_diff_count": bucket["accepted_canonical_diff_count"],
                "proposal_emitted_count": bucket["proposal_emitted_count"],
                "new_child_materialized_count": bucket["new_child_materialized_count"],
                "median_run_duration_sec": median_float(bucket["durations"]),
                "run_ids": list(bucket["run_ids"]),
            }
        )

    runtime_status_counts = grouped_identifier_counts(grouped_runtime_status)
    yield_status_counts = grouped_identifier_counts(grouped_yield_status)
    graph_impact_status_counts = grouped_identifier_counts(grouped_graph_impact_status)
    run_kind_counts = grouped_identifier_counts(grouped_run_kind)
    execution_profile_counts = grouped_identifier_counts(grouped_execution_profile)
    accepted_canonical_diff_count = sum(
        1 for entry in entries if bool(entry.get("accepted_canonical_diff"))
    )
    proposal_emitted_count = sum(1 for entry in entries if bool(entry.get("proposal_emitted")))
    productive_split_required_count = sum(
        1 for entry in entries if bool(entry.get("productive_split_required"))
    )
    review_pending_candidate_count = sum(
        1
        for entry in entries
        if str(entry.get("yield_status", "")).strip() == "review_pending_candidate"
    )
    productive_run_count = sum(1 for entry in entries if bool(entry.get("productive_run")))
    runtime_failed_count = runtime_status_counts.get("runtime_failed", 0)
    runtime_degraded_count = runtime_status_counts.get("runtime_degraded", 0)

    return {
        "artifact_kind": SUPERVISOR_PERFORMANCE_INDEX_ARTIFACT_KIND,
        "schema_version": SUPERVISOR_PERFORMANCE_INDEX_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": supervisor_performance_policy_reference(),
        "source_artifacts": {
            "run_logs_dir": RUNS_DIR.relative_to(ROOT).as_posix(),
            "run_logs_scanned": run_logs_scanned,
            "skipped_invalid_run_log_count": len(skipped_invalid_run_logs),
        },
        "entry_count": len(entries),
        "entries": entries,
        "aggregates": {
            "runtime_status_counts": runtime_status_counts,
            "yield_status_counts": yield_status_counts,
            "graph_impact_status_counts": graph_impact_status_counts,
            "run_kind_counts": run_kind_counts,
            "execution_profile_counts": execution_profile_counts,
            "productive_run_count": productive_run_count,
            "accepted_canonical_diff_count": accepted_canonical_diff_count,
            "proposal_emitted_count": proposal_emitted_count,
            "productive_split_required_count": productive_split_required_count,
            "review_pending_candidate_count": review_pending_candidate_count,
            "runtime_failed_count": runtime_failed_count,
            "runtime_degraded_count": runtime_degraded_count,
            "new_child_materialized_count": sum(
                int(entry.get("new_child_materialized_count", 0)) for entry in entries
            ),
            "median_run_duration_sec": median_float(durations),
            "max_run_duration_sec": round(max(durations), 3) if durations else None,
            "same_spec_repeat_hotspots": repeat_hotspots,
        },
        "batches": {
            "time_bucket": str(supervisor_performance_policy_lookup("batch_contract.time_bucket")),
            "by_day_utc": batches_by_day,
        },
        "viewer_projection": {
            "runtime_status": {
                key: sorted(value) for key, value in sorted(grouped_runtime_status.items())
            },
            "yield_status": {
                key: sorted(value) for key, value in sorted(grouped_yield_status.items())
            },
            "graph_impact_status": {
                key: sorted(value) for key, value in sorted(grouped_graph_impact_status.items())
            },
            "run_kind": {key: sorted(value) for key, value in sorted(grouped_run_kind.items())},
            "execution_profile": {
                key: sorted(value) for key, value in sorted(grouped_execution_profile.items())
            },
            "named_filters": {key: sorted(value) for key, value in sorted(named_filters.items())},
        },
        "skipped_invalid_run_logs": skipped_invalid_run_logs,
    }


def write_supervisor_performance_index(report: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = supervisor_performance_index_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


def bootstrap_smoke_entry_matches(entry: dict[str, Any]) -> bool:
    benchmark_id = BOOTSTRAP_SMOKE_BENCHMARK_ID.strip()
    run_selection = bootstrap_smoke_benchmark_policy_lookup("run_selection")
    run_kind = str(run_selection.get("run_kind", "")).strip()
    run_id_prefix = str(run_selection.get("run_id_prefix", "")).strip()
    benchmark_payload = entry.get("benchmark", {})
    if not isinstance(benchmark_payload, dict):
        benchmark_payload = {}
    entry_benchmark_id = str(benchmark_payload.get("benchmark_id", "")).strip()
    entry_run_kind = str(entry.get("run_kind", "")).strip()
    entry_run_id = str(entry.get("run_id", "")).strip()
    if benchmark_id:
        if entry_benchmark_id:
            return entry_benchmark_id == benchmark_id
        return bool(run_id_prefix and entry_run_id.startswith(run_id_prefix))
    return bool(run_kind and entry_run_kind == run_kind) or bool(
        run_id_prefix and entry_run_id.startswith(run_id_prefix)
    )


def bootstrap_smoke_latest_batch(entries: list[dict[str, Any]]) -> list[dict[str, Any]]:
    batch_groups: dict[str, list[dict[str, Any]]] = {}
    for entry in entries:
        benchmark_payload = entry.get("benchmark", {})
        if not isinstance(benchmark_payload, dict):
            benchmark_payload = {}
        batch_id = str(benchmark_payload.get("batch_id", "")).strip()
        if not batch_id:
            batch_id = "default"
        batch_groups.setdefault(batch_id, []).append(entry)
    if not batch_groups:
        return []

    def batch_sort_key(item: tuple[str, list[dict[str, Any]]]) -> tuple[str, str]:
        batch_id, batch_entries = item
        latest_timestamp = max(
            (str(entry.get("timestamp_utc", "")).strip() for entry in batch_entries),
            default="",
        )
        return latest_timestamp, batch_id

    _, latest_entries = max(batch_groups.items(), key=batch_sort_key)
    return sorted(
        latest_entries,
        key=lambda entry: (
            str(entry.get("timestamp_utc", "")).strip(),
            str(entry.get("run_id", "")).strip(),
        ),
    )


def bootstrap_smoke_criterion(
    *,
    criterion_id: str,
    observed: int | bool | None,
    required: int | bool | str,
    passed: bool,
) -> dict[str, Any]:
    return {
        "criterion_id": criterion_id,
        "passed": passed,
        "observed": observed,
        "required": required,
    }


def build_bootstrap_smoke_benchmark(
    supervisor_performance_index: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if supervisor_performance_index is None:
        supervisor_performance_index = build_supervisor_performance_index()

    all_entries = [
        entry
        for entry in supervisor_performance_index.get("entries", [])
        if isinstance(entry, dict)
    ]
    matching_entries = [entry for entry in all_entries if bootstrap_smoke_entry_matches(entry)]
    selected_entries = bootstrap_smoke_latest_batch(matching_entries)
    selected_run_ids = [str(entry.get("run_id", "")).strip() for entry in selected_entries]

    pass_criteria = bootstrap_smoke_benchmark_policy_lookup("pass_criteria")
    seed_fixture = bootstrap_smoke_benchmark_policy_lookup("seed_fixture")
    fixed_budget = bootstrap_smoke_benchmark_policy_lookup("fixed_budget")
    seed_node_count = int(seed_fixture.get("seed_node_count", 1) or 1)
    max_iterations = int(fixed_budget.get("max_iterations", 0) or 0)

    productive_run_count = sum(1 for entry in selected_entries if bool(entry.get("productive_run")))
    runtime_failed_count = sum(
        1
        for entry in selected_entries
        if str(entry.get("runtime_status", "")).strip() == "runtime_failed"
    )
    low_yield_count = sum(
        1 for entry in selected_entries if str(entry.get("yield_status", "")).strip() == "low_yield"
    )
    blocked_or_regressed_count = sum(
        1
        for entry in selected_entries
        if str(entry.get("graph_impact_status", "")).strip() == "blocked_or_regressed"
    )
    new_child_materialized_count = sum(
        int(entry.get("new_child_materialized_count", 0) or 0) for entry in selected_entries
    )
    estimated_final_node_count = seed_node_count + new_child_materialized_count
    terminal_yield_status = (
        str(selected_entries[-1].get("yield_status", "")).strip() if selected_entries else ""
    )
    allowed_terminal_yield_statuses = {
        str(item).strip()
        for item in pass_criteria.get("allowed_terminal_yield_statuses", [])
        if str(item).strip()
    }

    criteria_results = [
        bootstrap_smoke_criterion(
            criterion_id="min_productive_run_count",
            observed=productive_run_count,
            required=int(pass_criteria.get("min_productive_run_count", 0) or 0),
            passed=productive_run_count
            >= int(pass_criteria.get("min_productive_run_count", 0) or 0),
        ),
        bootstrap_smoke_criterion(
            criterion_id="min_new_child_materialized_count",
            observed=new_child_materialized_count,
            required=int(pass_criteria.get("min_new_child_materialized_count", 0) or 0),
            passed=new_child_materialized_count
            >= int(pass_criteria.get("min_new_child_materialized_count", 0) or 0),
        ),
        bootstrap_smoke_criterion(
            criterion_id="max_runtime_failed_count",
            observed=runtime_failed_count,
            required=int(pass_criteria.get("max_runtime_failed_count", 0) or 0),
            passed=runtime_failed_count
            <= int(pass_criteria.get("max_runtime_failed_count", 0) or 0),
        ),
        bootstrap_smoke_criterion(
            criterion_id="max_low_yield_count",
            observed=low_yield_count,
            required=int(pass_criteria.get("max_low_yield_count", 0) or 0),
            passed=low_yield_count <= int(pass_criteria.get("max_low_yield_count", 0) or 0),
        ),
        bootstrap_smoke_criterion(
            criterion_id="max_blocked_or_regressed_count",
            observed=blocked_or_regressed_count,
            required=int(pass_criteria.get("max_blocked_or_regressed_count", 0) or 0),
            passed=blocked_or_regressed_count
            <= int(pass_criteria.get("max_blocked_or_regressed_count", 0) or 0),
        ),
        bootstrap_smoke_criterion(
            criterion_id="min_estimated_final_node_count",
            observed=estimated_final_node_count,
            required=int(pass_criteria.get("min_estimated_final_node_count", 0) or 0),
            passed=estimated_final_node_count
            >= int(pass_criteria.get("min_estimated_final_node_count", 0) or 0),
        ),
        bootstrap_smoke_criterion(
            criterion_id="terminal_yield_status_allowed",
            observed=terminal_yield_status or None,
            required=", ".join(sorted(allowed_terminal_yield_statuses)),
            passed=bool(
                terminal_yield_status and terminal_yield_status in allowed_terminal_yield_statuses
            ),
        ),
        bootstrap_smoke_criterion(
            criterion_id="within_fixed_budget",
            observed=len(selected_entries),
            required=max_iterations,
            passed=bool(max_iterations and len(selected_entries) <= max_iterations),
        ),
    ]

    over_fixed_budget = bool(max_iterations and len(selected_entries) > max_iterations)

    if not selected_entries:
        benchmark_status = "not_run"
        review_state = "not_observed"
        next_gap = "run_bootstrap_smoke_benchmark"
    elif runtime_failed_count > int(pass_criteria.get("max_runtime_failed_count", 0) or 0):
        benchmark_status = "blocked_by_runtime"
        review_state = "advisory_fail"
        next_gap = "repair_bootstrap_runtime"
    elif over_fixed_budget:
        benchmark_status = "insufficient_data"
        review_state = "advisory_fail"
        next_gap = "rerun_with_fixed_smoke_budget"
    elif all(bool(result["passed"]) for result in criteria_results):
        benchmark_status = "passed"
        review_state = "advisory_pass"
        next_gap = "none"
    else:
        benchmark_status = "failed"
        review_state = "advisory_fail"
        next_gap = "inspect_bootstrap_smoke_regression"

    named_filters = {name: [] for name in BOOTSTRAP_SMOKE_BENCHMARK_NAMED_FILTERS}
    named_filters.setdefault(benchmark_status, []).append(BOOTSTRAP_SMOKE_BENCHMARK_ID)
    if productive_run_count:
        named_filters["productive_smoke_runs"].extend(selected_run_ids)
    if runtime_failed_count:
        named_filters["runtime_failed_smoke_runs"].extend(
            str(entry.get("run_id", "")).strip()
            for entry in selected_entries
            if str(entry.get("runtime_status", "")).strip() == "runtime_failed"
        )
    if low_yield_count:
        named_filters["low_yield_smoke_runs"].extend(
            str(entry.get("run_id", "")).strip()
            for entry in selected_entries
            if str(entry.get("yield_status", "")).strip() == "low_yield"
        )
    if new_child_materialized_count:
        named_filters["new_child_materialized"].extend(
            str(entry.get("run_id", "")).strip()
            for entry in selected_entries
            if int(entry.get("new_child_materialized_count", 0) or 0) > 0
        )
    for key in list(named_filters):
        named_filters[key] = sorted({item for item in named_filters[key] if str(item).strip()})

    return {
        "artifact_kind": BOOTSTRAP_SMOKE_BENCHMARK_ARTIFACT_KIND,
        "schema_version": BOOTSTRAP_SMOKE_BENCHMARK_SCHEMA_VERSION,
        "generated_at": utc_now_iso(),
        "policy_reference": bootstrap_smoke_benchmark_policy_reference(),
        "source_artifacts": {
            "supervisor_performance_index": {
                "artifact_path": supervisor_performance_index_path().relative_to(ROOT).as_posix(),
                "generated_at": supervisor_performance_index.get("generated_at"),
                "entry_count": supervisor_performance_index.get("entry_count", 0),
            }
        },
        "benchmark_id": BOOTSTRAP_SMOKE_BENCHMARK_ID,
        "benchmark_status": benchmark_status,
        "review_state": review_state,
        "next_gap": next_gap,
        "seed_fixture": copy.deepcopy(seed_fixture),
        "fixed_budget": copy.deepcopy(fixed_budget),
        "run_selection": copy.deepcopy(bootstrap_smoke_benchmark_policy_lookup("run_selection")),
        "selected_run_count": len(selected_entries),
        "selected_run_ids": selected_run_ids,
        "summary": {
            "productive_run_count": productive_run_count,
            "runtime_failed_count": runtime_failed_count,
            "low_yield_count": low_yield_count,
            "blocked_or_regressed_count": blocked_or_regressed_count,
            "new_child_materialized_count": new_child_materialized_count,
            "estimated_final_node_count": estimated_final_node_count,
            "terminal_yield_status": terminal_yield_status,
        },
        "criteria_results": criteria_results,
        "entries": [
            {
                "run_id": str(entry.get("run_id", "")).strip(),
                "spec_id": str(entry.get("spec_id", "")).strip(),
                "timestamp_utc": str(entry.get("timestamp_utc", "")).strip(),
                "run_kind": str(entry.get("run_kind", "")).strip(),
                "execution_profile": str(entry.get("execution_profile", "")).strip(),
                "runtime_status": str(entry.get("runtime_status", "")).strip(),
                "yield_status": str(entry.get("yield_status", "")).strip(),
                "graph_impact_status": str(entry.get("graph_impact_status", "")).strip(),
                "productive_run": bool(entry.get("productive_run")),
                "new_child_materialized_count": int(
                    entry.get("new_child_materialized_count", 0) or 0
                ),
                "benchmark": copy.deepcopy(entry.get("benchmark", {})),
            }
            for entry in selected_entries
        ],
        "viewer_projection": {
            "benchmark_status": {
                benchmark_status: [BOOTSTRAP_SMOKE_BENCHMARK_ID],
            },
            "named_filters": {key: value for key, value in sorted(named_filters.items())},
        },
    }


def write_bootstrap_smoke_benchmark(report: dict[str, Any]) -> Path:
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    path = bootstrap_smoke_benchmark_path()
    with artifact_lock(path):
        atomic_write_json(path, report)
    return path


