    build_specpm_export_preview_mode: bool = False,
    build_specpm_handoff_packets_mode: bool = False,
    materialize_specpm_export_bundles_mode: bool = False,
    build_specpm_import_preview_mode: bool = False,
    build_specpm_import_handoff_packets_mode: bool = False,
    build_specpm_delivery_workflow_mode: bool = False,
    build_specpm_feedback_index_mode: bool = False,
    build_specpm_public_registry_index_mode: bool = False,
    build_metrics_delivery_workflow_mode: bool = False,
    build_metrics_feedback_index_mode: bool = False,
    build_metrics_source_promotion_index_mode: bool = False,
    build_metric_pack_index_mode: bool = False,
    build_metric_pack_registry_drift_mode: bool = False,
    build_metric_pack_adapter_index_mode: bool = False,
    build_metric_pack_runs_mode: bool = False,
    build_metric_pricing_provenance_mode: bool = False,
    build_model_usage_telemetry_mode: bool = False,
    build_conversation_memory_index_mode: bool = False,
    build_conversation_memory_map_mode: bool = False,
    build_conversation_memory_promotion_pressure_mode: bool = False,
    build_metric_signal_index_mode: bool = False,
    build_metric_threshold_proposals_mode: bool = False,
    build_supervisor_executor_adapter_index_mode: bool = False,
